-- Poems batch 312
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('310488c4-8427-4268-a769-cd499de316c5','擺繡雞  其二','韋驤','宋','宋诗','song-poetry','','[]','一片垂丹臆，鮮明錦不如。',48,'全唐诗/poet.song.41000.json','["一片垂丹臆，鮮明錦不如。", "殷紅間深翠，半斂又全舒。", "未遇奪真畫，猶虛博物書。", "雖非孔鸞比，儻可詫其餘。"]'),
('3b05b4ce-2579-4be9-bbcb-d5e938f86b97','戲答宋茂宗','韋驤','宋','宋诗','song-poetry','','[]','穿山君蹈險，逆浪我乘危。',48,'全唐诗/poet.song.41000.json','["穿山君蹈險，逆浪我乘危。", "玉事以勤濟，人生少暇時。", "多材看騰踔，無補愧衰遲。", "巳飽殊鄉味，何煩覺後知。"]'),
('13e557b4-23ab-4d63-a61f-4f0bbc9e9fe2','寄李世美','韋驤','宋','宋诗','song-poetry','','[]','都門執别再經春，相望天涯引脰頻。',64,'全唐诗/poet.song.41000.json','["都門執别再經春，相望天涯引脰頻。", "峽外山川愁倦翼，江西風月羡怡神。", "來書雖闊情還密，舊咏重窺意似新。", "聊寄短篇追往好，莫緣無雁便因循。"]'),
('08f176e4-0c78-4e60-a16e-33bba9493d28','送宋茂宗','韋驤','宋','宋诗','song-poetry','','[]','三年持節使巴夔，今日飄然受代歸。',64,'全唐诗/poet.song.41000.json','["三年持節使巴夔，今日飄然受代歸。", "去棹勇爭江水急，前旌遥趁峽雲飛。", "陟明佇聽躋華貫，榮覲應欣著綵衣。", "肯記天涯留咏處，翠巖幽洞亦幾稀。"]'),
('5e31e21a-1d65-4392-be6f-7e4d3cc1135c','渝南九日','韋驤','宋','宋诗','song-poetry','','[]','草草開筵重九日，區區奉使第三年。',64,'全唐诗/poet.song.41000.json','["草草開筵重九日，區區奉使第三年。", "黄花不肯趁時節，薄酒可堪無管弦。", "秋雨岷山猶漲水，夕陽巴嶠自生煙。", "登高興味空惆悵，萬里鄉關在目前。"]'),
('381ae7d6-a106-4ac7-bba8-e728e7b8afc4','南陵坡','韋驤','宋','宋诗','song-poetry','','[]','南陵坡對巫山縣，直上青冥百八盤。',64,'全唐诗/poet.song.41000.json','["南陵坡對巫山縣，直上青冥百八盤。", "此日身由歲巡到，他年愁向畫圖看。", "可堪雨濕羊腸險，更怯風衝狐腋寒。", "却想九天朝謁罷，禁街平穩躍金鞍。"]'),
('74e4f942-e7de-4876-a2e2-bcdfd47d1145','金山','韋驤','宋','宋诗','song-poetry','','[]','金山目逆路之隅，峭壁奇峰畫不如。',32,'全唐诗/poet.song.41000.json','["金山目逆路之隅，峭壁奇峰畫不如。", "若使崢嶸近京雒，未應聲價減南徐。"]'),
('e170687e-9824-438e-882c-3ef528ccdb9c','瘦驢嶺','韋驤','宋','宋诗','song-poetry','','[]','馬瘏前咏閔馳驅，登嶺今朝歉瘦驢。',32,'全唐诗/poet.song.41000.json','["馬瘏前咏閔馳驅，登嶺今朝歉瘦驢。", "自是老來情味減，欲圖靡盬可安居。"]'),
('f529dcd6-1ba4-43c2-ac8d-5b48975f66a7','石榻平望七峰山','韋驤','宋','宋诗','song-poetry','','[]','路過黔江石榻平，七峰奇傑翠崢嶸。',32,'全唐诗/poet.song.41000.json','["路過黔江石榻平，七峰奇傑翠崢嶸。", "祇應自有神仙宅，肯向人間浪得名。"]'),
('5cc0277d-e5b2-4ff9-a3fe-677370c0bbb5','宿木宗驛','韋驤','宋','宋诗','song-poetry','','[]','暮投荒驛傍巖隈，更柝聲頻夢易迴。',64,'全唐诗/poet.song.41000.json','["暮投荒驛傍巖隈，更柝聲頻夢易迴。", "半夜忽驚飛霰急，凌晨還喜凍雲開。", "雪凝山表平如截，梅發林坳迥若堆。", "問俗觀風何所補，勤勞唯有馬虺隤。"]'),
('895838cb-03af-4172-a0b2-b60ea76fd723','二月','韋驤','宋','宋诗','song-poetry','','[]','二月渝南春已老，西園桃李頓蕭然。',64,'全唐诗/poet.song.41000.json','["二月渝南春已老，西園桃李頓蕭然。", "傍簷飛絮紛如雪，貼水圓荷大似錢。", "覽物未能忘感概，紓情聊且綴詩篇。", "馮郎白髪知多少，更向巴山聽杜鵑。"]'),
('4108ab57-380a-4626-9481-05463317c938','鄰垣','韋驤','宋','宋诗','song-poetry','','[]','官路蹉跎晚景斜，更堪蹤跡在天涯。',64,'全唐诗/poet.song.41000.json','["官路蹉跎晚景斜，更堪蹤跡在天涯。", "江春已老猶寒色，山雨相仍減物華。", "留滯唯知搔白首，衰疲何可泥丹砂。", "無聊情思翻成喜，喜見鄰垣架上花。"]'),
('7f21543a-6d8e-4f9f-98f8-190fb271a3ad','壽安縣君挽詞一首','韋驤','宋','宋诗','song-poetry','','[]','鄉黨推賢懿，宗婣慕孝慈。',48,'全唐诗/poet.song.41000.json','["鄉黨推賢懿，宗婣慕孝慈。", "享年非及耄，造物固難知。", "神護銘旌遠，龜從葬宅宜。", "幽冥復何恨，夫子映清時。"]'),
('d004d506-cdc4-4605-8a4f-1408370fa1ac','再和張從道 二月','韋驤','宋','宋诗','song-poetry','','[]','天氣融融近禁烟，巴渝風俗自熙然。',64,'全唐诗/poet.song.41000.json','["天氣融融近禁烟，巴渝風俗自熙然。", "排門沽酒易成市，著處看花不用錢。", "一带江山入圖畫，幾番雲雨促詩篇。", "獨嗟久使無裨補，終日歸心趁杜鵑。"]'),
('d1a42a18-fe7b-4ed7-8685-be511b60e225','再和張從道 鄰垣','韋驤','宋','宋诗','song-poetry','','[]','官舍相依吾二家，碧山之麓水之涯。',64,'全唐诗/poet.song.41000.json','["官舍相依吾二家，碧山之麓水之涯。", "祇知閒暇交談屑，不覺逡巡改歲華。", "坐喜良農得麰麥，行聞異俗貢氈砂。", "銜杯且盡兵廚釀，安用呼兒索五花。"]'),
('cbfbebbe-ac57-402e-9b86-51db4057942a','和唐韋相國盛山十二咏 宿雲亭','韋驤','宋','宋诗','song-poetry','','[]','無心固無戀，猶愛宿危簷。',24,'全唐诗/poet.song.41000.json','["無心固無戀，猶愛宿危簷。", "況復尋幽客，高情豈易厭。"]'),
('c8d71d72-8bbb-417b-a409-41393152c8fd','和唐韋相國盛山十二咏 隱月岫','韋驤','宋','宋诗','song-poetry','','[]','隱月月非隱，岫名誠强名。',24,'全唐诗/poet.song.41000.json','["隱月月非隱，岫名誠强名。", "清光中夜滿，誰謂礙崢嶸。"]'),
('ff519bce-f0c2-41aa-86d1-5f0bf96156ba','和唐韋相國盛山十二咏 茶嶺','韋驤','宋','宋诗','song-poetry','','[]','種茶當嶺上，日近地先春。',24,'全唐诗/poet.song.41000.json','["種茶當嶺上，日近地先春。", "始自鈞陶手，遺芳及後人。"]'),
('b45a32eb-1a63-43cb-8a70-aa9762976f78','和唐韋相國盛山十二咏 梅谿','韋驤','宋','宋诗','song-poetry','','[]','清影籠寒水，幽香逐晚風。',24,'全唐诗/poet.song.41000.json','["清影籠寒水，幽香逐晚風。", "和羮人已遠，谿上自芳叢。"]'),
('a7fa5021-934e-4844-8dc7-90761ce631b8','和唐韋相國盛山十二咏 流杯渠','韋驤','宋','宋诗','song-poetry','','[]','渠灣水流速，杯漾酒行遲。',24,'全唐诗/poet.song.41000.json','["渠灣水流速，杯漾酒行遲。", "莫誚經營巧，清懽得所施。"]'),
('4cb5a9c4-2fe6-4f05-8474-e39898018725','和唐韋相國盛山十二咏 盤石磴','韋驤','宋','宋诗','song-poetry','','[]','盤石以爲磴，縈紆上翠岑。',24,'全唐诗/poet.song.41000.json','["盤石以爲磴，縈紆上翠岑。", "披雲矚佳境，適此慰登臨。"]'),
('701e66c9-3769-494d-bf67-4c6fa97acfc7','和唐韋相國盛山十二咏 桃塢','韋驤','宋','宋诗','song-poetry','','[]','當日桃花塢，多應傚武陵。',24,'全唐诗/poet.song.41000.json','["當日桃花塢，多應傚武陵。", "春風今寂寞，猶以舊名稱。"]'),
('12cd683e-d433-4483-9476-2b453a6104d2','和唐韋相國盛山十二咏 竹巖','韋驤','宋','宋诗','song-poetry','','[]','櫛密翠嬋娟，結根巖石前。',24,'全唐诗/poet.song.41000.json','["櫛密翠嬋娟，結根巖石前。", "不饒塵土地，自信雪霜天。"]'),
('0dd10cd1-4b32-4dec-9dd7-ef5bb2e0a69e','和唐韋相國盛山十二咏 琵琶臺','韋驤','宋','宋诗','song-poetry','','[]','象物名臺勢，琵琶出自然。',24,'全唐诗/poet.song.41000.json','["象物名臺勢，琵琶出自然。", "登臨得真趣，所樂類無弦。"]'),
('a37834e6-ab6d-498e-84e1-930f6d84fa43','和唐韋相國盛山十二咏 胡蘆沼','韋驤','宋','宋诗','song-poetry','','[]','沼有胡蘆狀，成非疏鑿功。',24,'全唐诗/poet.song.42000.json','["沼有胡蘆狀，成非疏鑿功。", "霄澄星月影，彷彿似壺中。"]'),
('120bfbab-ba70-4aa8-a772-4deb298d84c8','和唐韋相國盛山十二咏 繡衣石榻','韋驤','宋','宋诗','song-poetry','','[]','繡衣無已久，石榻尚依然。',24,'全唐诗/poet.song.42000.json','["繡衣無已久，石榻尚依然。", "不識尋山客，幾人能愛賢。"]'),
('a43232b8-fbf2-49c3-813f-9c02fb790f9b','和唐韋相國盛山十二咏 上士瓶泉','韋驤','宋','宋诗','song-poetry','','[]','上士體虛無，瓶泉與道俱。',24,'全唐诗/poet.song.42000.json','["上士體虛無，瓶泉與道俱。", "倘餘涓滴潤，可救衆焦枯。"]'),
('bfe02e09-e6c8-41cc-b2fc-28708b49480d','清遠閣','韋驤','宋','宋诗','song-poetry','','[]','屹然虛閣並蓮宫，似出塵寰擾擾中。',64,'全唐诗/poet.song.42000.json','["屹然虛閣並蓮宫，似出塵寰擾擾中。", "浩蕩乾坤來爽氣，崢嶸欄楯倚晴空。", "江奔吳楚流何急，山接岷峨望不窮。", "清遠榜題真有意，登臨聊以裕吾衷。"]'),
('f1b5ae79-3f6c-40d6-874f-d19f3bca32e6','横翠亭','韋驤','宋','宋诗','song-poetry','','[]','勝概本天成，增營智亦精。',48,'全唐诗/poet.song.42000.json','["勝概本天成，增營智亦精。", "何年丹檻敞，終日碧山横。", "青靄飄來薄，澄江瀉去明。", "官居況相邇，杖屨不勝情。"]'),
('e0373511-22e4-492c-9e90-0035543cc41d','九日','韋驤','宋','宋诗','song-poetry','','[]','四逢九日峽江湄，竊祿無功祇自嗤。',64,'全唐诗/poet.song.42000.json','["四逢九日峽江湄，竊祿無功祇自嗤。", "把酒又遲今歲菊，開編還愧去年詩。", "牛山悽感何其昧，藍水歡吟乃所宜。", "白髪不辭吹帽落，更登山閣醉佳時。"]'),
('0322b9c7-351b-441c-9e38-b2e6c2dead79','答王晉叔','韋驤','宋','宋诗','song-poetry','','[]','區區行役臨南浦，忽奉來書墨未乾。',64,'全唐诗/poet.song.42000.json','["區區行役臨南浦，忽奉來書墨未乾。", "見報新恩移亳社，便疑衰跡近長安。", "山危水惡行將免，宦思鄉情日漸寛。", "朝夕放船來就别，贈言應許遺琅玕。"]'),
('1090a779-d08a-42cf-a583-f0dbafcab533','遇黄志仁','韋驤','宋','宋诗','song-poetry','','[]','舟楫逢迎涪水濱，久違應訝鬢霜新。',64,'全唐诗/poet.song.42000.json','["舟楫逢迎涪水濱，久違應訝鬢霜新。", "按廉雖共相望闊，邂逅於斯兩喜鈞。", "對艤晴沙旗影動，交談寒夜燭花春。", "遲明又向東西去，回首滄江霧色勻。"]'),
('711bd33c-343b-48cc-a236-28b30f888b64','别張從道','韋驤','宋','宋诗','song-poetry','','[]','官居相並日相過，盈歲光陰不覺多。',64,'全唐诗/poet.song.42000.json','["官居相並日相過，盈歲光陰不覺多。", "每幸開心互詢度，都忘倦跡久蹉跎。", "新除忽遂東歸欲，雅好其如遠别何。", "把酒不辭金盞溢，預將離索就消磨。"]'),
('db2f0b03-6a87-45e6-9b27-414c5cffec7c','别王叔重','韋驤','宋','宋诗','song-poetry','','[]','區區奉使越三年，晚得渝南刺史賢。',64,'全唐诗/poet.song.42000.json','["區區奉使越三年，晚得渝南刺史賢。", "美政日聞行舊學，高懷時見發新篇。", "近違方得揮談麈，遠别俄驚徹祖筵。", "回首寒江初放鷁，牙城隱隱隔雲煙。"]'),
('3987a9e9-3ad3-4367-ace8-8b898e7bf178','送張公度之官南安','韋驤','宋','宋诗','song-poetry','','[]','盡道清時多汲引，夫何高翮尚卑棲。',64,'全唐诗/poet.song.42000.json','["盡道清時多汲引，夫何高翮尚卑棲。", "迢迢别乘欣然去，苒苒輕裝寡所齎。", "坐想推餘先嶠北，行聞流譽出江西。", "更將學行規逢掖，桃李無言下自蹊。"]'),
('513ea669-634b-4fb0-9a3c-6b7d3c947543','送勝之宰仁和','韋驤','宋','宋诗','song-poetry','','[]','霜風掠野卷愁雲，紞紞催船畫鼓頻。',64,'全唐诗/poet.song.42000.json','["霜風掠野卷愁雲，紞紞催船畫鼓頻。", "方喜鄉閭得賢宰，却驚燕席失佳賓。", "去鄞迤邐窮殘臘，渡浙依稀傍早春。", "恰幸主人真愷悌，承宣相與慰斯民。"]'),
('b4951260-d08c-48d9-a0b6-4411d292940e','和舒信道中丞','韋驤','宋','宋诗','song-poetry','','[]','臘月纔飛玉律灰，物情已若在春臺。',64,'全唐诗/poet.song.42000.json','["臘月纔飛玉律灰，物情已若在春臺。", "高懷果動山中興，秀句歘從塵外來。", "兵釀可應隨日熟，官梅能不爲時開。", "何當舉白西河上，茗艼須容倒載回。"]'),
('c2032c8d-35e8-4a69-9434-f32e792faff4','又和','韋驤','宋','宋诗','song-poetry','','[]','淺雪初成玉石灰，冒寒擁腋上層臺。',64,'全唐诗/poet.song.42000.json','["淺雪初成玉石灰，冒寒擁腋上層臺。", "那嗟晚景催人老，且喜新春入手來。", "戢戢庭萱芽始迸，娟娟池柳眼先開。", "卻□疏騁南湖轍，坐想高談腸九回。"]'),
('9ff5ccf9-f888-4f05-b17a-5753de98a31b','臘月十八日乙卯立春丁卯會飲開元呈信道中丞','韋驤','宋','宋诗','song-poetry','','[]','瀟灑江城雪後天，訪尋幽境就開筵。',64,'全唐诗/poet.song.42000.json','["瀟灑江城雪後天，訪尋幽境就開筵。", "數聲晚角催殘照，三日新春入舊年。", "鼎坐探題頻擊鉢，杯行度曲有危弦。", "莫論俯仰成陳跡，頃刻清歡亦可憐。"]'),
('ae25e392-2497-4d67-ac9d-a66120ceb820','再和','韋驤','宋','宋诗','song-poetry','','[]','湖山清迥雪霜天，結客尋幽布錦筵。',64,'全唐诗/poet.song.42000.json','["湖山清迥雪霜天，結客尋幽布錦筵。", "猛作清歡送殘臘，冥搜佳句待新年。", "共欣愛日臨樽俎，暗覺和風入管弦。", "數品香葩爲時發，潛知造物以相憐。"]'),
('8a58fe99-9b6b-4154-a33e-751c3f2504d9','春後五日即事呈信道中丞致平學士','韋驤','宋','宋诗','song-poetry','','[]','閏餘中朔蚤，歲暮已春回。',48,'全唐诗/poet.song.42000.json','["閏餘中朔蚤，歲暮已春回。", "沼沚全消凍，林園半落梅。", "南風濕舊礎，暮雨送新雷。", "節物逡巡變，衰顔忍不開。"]'),
('38e26340-c4ff-4fd0-b707-403414d0e30d','再和二首  其一','韋驤','宋','宋诗','song-poetry','','[]','會飲臨登燕，逢春第一回。',48,'全唐诗/poet.song.42000.json','["會飲臨登燕，逢春第一回。", "筝移未歸雁，笛送巳飄梅。", "北海俄空酒，南山忽隱雷。", "交談幸投隙，塵慮此時開。"]'),
('1b51dfd2-9308-4855-81a5-e43c2e14de46','再和二首  其二','韋驤','宋','宋诗','song-poetry','','[]','春歸雖斗頓，寒去尚裴回。',48,'全唐诗/poet.song.42000.json','["春歸雖斗頓，寒去尚裴回。", "已放沙茸草，猶將雪掩梅。", "清吟陵鮑謝，高誼薄陳雷。", "倘緩西行興，芳筵願數開。"]'),
('61076802-8033-4dcd-ae96-b6a0745203ba','復以前韻示别','韋驤','宋','宋诗','song-poetry','','[]','泛鷁兹辰去，前騶幾日回。',48,'全唐诗/poet.song.42000.json','["泛鷁兹辰去，前騶幾日回。", "離觴釂浮螘，暮角聽吹梅。", "雪嶠初消玉，濤江遠震雷。", "應多解頤句，歸覲錦囊開。"]'),
('bdc4bbf9-b876-473c-8bf8-7d2728766423','元正二日小宴呈席客','韋驤','宋','宋诗','song-poetry','','[]','二日新年半月春，朝來小雨破輕塵。',64,'全唐诗/poet.song.42000.json','["二日新年半月春，朝來小雨破輕塵。", "依稀带雪梅枝老，彷彿籠金柳色勻。", "投隙會并宜勉强，轉頭光景祇逡巡。", "不應萬點花飛後，方許傷多酒入脣。"]'),
('eb730b77-b0cd-4687-8836-74a9c8953aa2','和章致平西興見寄二首  其一','韋驤','宋','宋诗','song-poetry','','[]','金玉來音忽邇聞，開緘恍若對風神。',64,'全唐诗/poet.song.42000.json','["金玉來音忽邇聞，開緘恍若對風神。", "始知渡浙元宵逼，遥想乘時樂事頻。", "恨不銜杯同此夕，可應聯咏屬他人。", "果然佳句先垂寄，依舊餘輝返照鄰。"]'),
('cea3ccc9-0b62-46ee-a80f-635f6de2b436','和章致平西興見寄二首  其二','韋驤','宋','宋诗','song-poetry','','[]','天爲元宵卷暮雲，團團放出月精神。',64,'全唐诗/poet.song.42000.json','["天爲元宵卷暮雲，團團放出月精神。", "隨時行樂與民共，若處觀燈徹席頻。", "玉斝坐邀同醉客，瓊枝懷想未歸人。", "更抽鄙句招回棹，早復官居壯德鄰。"]'),
('e4581a8d-8754-4488-b69e-6014888d0046','石都講仲謨挽辭二首  其一','韋驤','宋','宋诗','song-poetry','','[]','高翮欲騰超，年華忽早彫。',48,'全唐诗/poet.song.42000.json','["高翮欲騰超，年華忽早彫。", "名言在宗室，休譽滿公朝。", "卜遠靈輿逝，傷春挽鐸搖。", "南明此時路，花草爲蕭條。"]'),
('2fd8f969-d0ec-4430-846f-c2bc79608a89','石都講仲謨挽辭二首  其二','韋驤','宋','宋诗','song-poetry','','[]','桂科名舊峻，玉殿對新歸。',48,'全唐诗/poet.song.42000.json','["桂科名舊峻，玉殿對新歸。", "異寵行將及，英魂遽巳飛。", "貴來年不待，志在命先違。", "還葬春山曉，空歌薤露晞。"]'),
('3ec31747-b629-485c-94a7-82be7976a10e','嘉燕堂','韋驤','宋','宋诗','song-poetry','','[]','屋角翬飛棟宇深，簷前老木翠森森。',64,'全唐诗/poet.song.42000.json','["屋角翬飛棟宇深，簷前老木翠森森。", "琤琮雖欠泉聲玉，瑣碎仍多竹影金。", "勝概豈顓供主席，清驩唯欲浹朋簪。", "但令廣座嘉賓滿，不惜融樽罄所斟。"]'),
('e6e0e537-eb68-4d01-9f53-4aed61f7e13b','九經堂','韋驤','宋','宋诗','song-poetry','','[]','屹屹危堂近紫煙，傍堂雙檜亦參天。',64,'全唐诗/poet.song.42000.json','["屹屹危堂近紫煙，傍堂雙檜亦參天。", "四時風月收羅盡，千里山川矚望全。", "阮屐登來何必蠟，陶琴攜上不須弦。", "賜經雖缺名猶在，此樂終爲古所賢。"]'),
('aef425e6-8a05-4bf5-8342-5f692c235ae6','鑒亭','韋驤','宋','宋诗','song-poetry','','[]','虛亭屹立沼中央，古匠施工亦異常。',64,'全唐诗/poet.song.42000.json','["虛亭屹立沼中央，古匠施工亦異常。", "略彴相聯虹對影，漣漪四面鏡涵光。", "雕楹圓檻環然敞，碧瓦飛甍勢欲翔。", "杖履時來滌塵慮，可能隨事見毫芒。"]'),
('3a8cd589-21fc-4e65-8046-e797dff9ea17','探春軒','韋驤','宋','宋诗','song-poetry','','[]','東園亭榭巧相因，更闢東軒探早春。',64,'全唐诗/poet.song.42000.json','["東園亭榭巧相因，更闢東軒探早春。", "面直小橋通沼沚，背臨宏搆擁松筠。", "鳥鳴魚躍先時得，柳綻桃苞入眼新。", "造物也知搖落久，應憐著意伺芳辰。"]'),
('3acff5c3-b9f0-4f45-86e4-380dedcc9749','宿鳳亭','韋驤','宋','宋诗','song-poetry','','[]','碧梧千尺覆簷楹，宿鳳何年被美名。',64,'全唐诗/poet.song.42000.json','["碧梧千尺覆簷楹，宿鳳何年被美名。", "燕雀不棲如有畏，煙雲常近豈無情。", "林間日月於兹永，物外塵埃豈復生。", "危坐忽驚年籥晚，漫吟嘉瑞樂昇平。"]'),
('60ee80d2-4a0a-4d9e-b13a-763318723747','和舒信道二首  其一','韋驤','宋','宋诗','song-poetry','','[]','樽前雖闕舊年人，舊事重論迥若新。',32,'全唐诗/poet.song.42000.json','["樽前雖闕舊年人，舊事重論迥若新。", "記得長春爲絕唱，依稀難和似陽春。"]'),
('eb2e1d73-3421-47de-a8d8-99377adbe12b','和舒信道二首  其二','韋驤','宋','宋诗','song-poetry','','[]','謫仙居處枕湖邊，手種垂楊已繫船。',32,'全唐诗/poet.song.42000.json','["謫仙居處枕湖邊，手種垂楊已繫船。", "勿謂門庭岑寂久，天將巨用理當然。"]'),
('691f5762-d888-4f35-a5e0-bf5b20e7f992','和信道以詩見邀','韋驤','宋','宋诗','song-poetry','','[]','搖搖畫隼過寒汀，爲得新詩欲餞行。',32,'全唐诗/poet.song.42000.json','["搖搖畫隼過寒汀，爲得新詩欲餞行。", "飲散十洲回首處，暝煙疏柳不勝情。"]'),
('bbf19918-1079-4765-b593-53c1d281c05b','次韻周開祖清明會景之作','韋驤','宋','宋诗','song-poetry','','[]','難并四者重良辰，寒食風光澤國春。',64,'全唐诗/poet.song.42000.json','["難并四者重良辰，寒食風光澤國春。", "日滉湖光千頃綠，煙披汀柳萬條新。", "鈴齋投隙登臨好，吟筆裁篇氣格淳。", "顧我不能酬絕唱，聊将鄙句慰邦人。"]'),
('d242592b-c023-4565-82c4-68332900e845','又和會月波樓與范德鎮賡唱之什','韋驤','宋','宋诗','song-poetry','','[]','屹屹樓依檇李城，月波標榜映雙楹。',64,'全唐诗/poet.song.42000.json','["屹屹樓依檇李城，月波標榜映雙楹。", "未逢秋夕披襟坐，且向春風曳履行。", "詩伯高篇先獨唱，使君健筆許誰爭。", "還朝滯客方無賴，對此飄然思亦生。"]'),
('6af77d6a-60fa-4ca3-92b0-28f211fc71c2','吳大夫挽詞二首  其一','韋驤','宋','宋诗','song-poetry','','[]','浩氣忽凌虛，飄然厭虎符。',48,'全唐诗/poet.song.42000.json','["浩氣忽凌虛，飄然厭虎符。", "風流失循吏，術學喪醇儒。", "飛旐衝霜外，哀歌慘路隅。", "螭坳有賢嗣，遺憾想公無。"]'),
('1e59539a-f165-40d2-be3d-18da441485eb','吳大夫挽詞二首  其二','韋驤','宋','宋诗','song-poetry','','[]','邂逅淮東别，逡巡二紀餘。',48,'全唐诗/poet.song.42000.json','["邂逅淮東别，逡巡二紀餘。", "豈期還故里，止得望靈輿。", "直道欽遺譽，高門仰舊居。", "鄙情憑薤唱，聊以解欷歔。"]'),
('295ef849-94e7-4350-87d7-5853f80e0637','至節蔣穎叔見召以病不赴','韋驤','宋','宋诗','song-poetry','','[]','一陽潛復自黄宫，難變霜髯作少容。',64,'全唐诗/poet.song.42000.json','["一陽潛復自黄宫，難變霜髯作少容。", "方伯以時均宴衎，野人不幸困龍鍾。", "望塵修敬慚無及，舉白承懽恨莫供。", "但有誠心騰善頌，願隨壽斝祝椿松。"]'),
('435049eb-a9c1-48e2-baf5-a86933ec8919','和周開祖即席','韋驤','宋','宋诗','song-poetry','','[]','海雲收雨作新晴，春日開筵趣早成。',64,'全唐诗/poet.song.42000.json','["海雲收雨作新晴，春日開筵趣早成。", "六席共年誰獨少，千齡幾半互相兄。", "須憐東道情尤厚，況是西歸蓋始傾。", "更玩掌中珍句好，不知簾外玉蟾生。"]'),
('d137bfaa-9a43-4d67-83e6-1c8077f3201c','和周開祖賦會有美堂呈權府察院','韋驤','宋','宋诗','song-poetry','','[]','共陪紅旆陟巍峨，有美軒楹氣候和。',64,'全唐诗/poet.song.42000.json','["共陪紅旆陟巍峨，有美軒楹氣候和。", "樽酒融融懽廣座，梁塵拂拂應清歌。", "風隨江浦霜濤急，日下湖山翠靄多。", "何處追談此佳趣，主人不晚在鸞坡。"]'),
('4a322fd6-a157-48c6-a9e7-9a065520a343','和宇文伯修侍郎會中和堂二首  其一','韋驤','宋','宋诗','song-poetry','','[]','燕堂高會勢峨峨，拂面薰風氣候和。',64,'全唐诗/poet.song.42000.json','["燕堂高會勢峨峨，拂面薰風氣候和。", "廣座初陪文字飲，滿城重聽袴襦歌。", "錦裀藉舞矜回雪，玉麈揮談沛決河。", "牧伯娛賓同衆樂，庾公清興未爲多。"]'),
('557c2f58-d3df-4639-adee-9e1b6ae6b6de','和宇文伯修侍郎會中和堂二首  其二','韋驤','宋','宋诗','song-poetry','','[]','華構崢嶸倚碧霄，開筵瀟灑聚英僚。',64,'全唐诗/poet.song.42000.json','["華構崢嶸倚碧霄，開筵瀟灑聚英僚。", "衣霑翠靄天收雨，目送銀山海上潮。", "半日清歡浹觴咏，幾番涼吹韻笙簫。", "醺酣老客依帡庇，歸隱而今豈俟招。"]'),
('968f91d4-da56-4005-bdcc-926433b203a0','憶遊金華洞一首寄婺守陳子文','韋驤','宋','宋诗','song-poetry','','[]','不到金華四十年，碧溪深洞想依然。',32,'全唐诗/poet.song.42000.json','["不到金華四十年，碧溪深洞想依然。", "故人爲郡應多暇，何日雙旌翠靄邊。"]'),
('fb602be1-5d7c-4c72-b2d1-27132b1e75d9','和宇文侍郎觀潮','韋驤','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','江上雙峰屹若門，秋潮湧出勢横奔。',128,'全唐诗/poet.song.42000.json','["江上雙峰屹若門，秋潮湧出勢横奔。", "先聲何翅雲雷震，猛逝直疑溟海翻。", "壯觀平分吳與越，激波遥自巽之坤。", "驅除殘暑長空凜，噴薄晴光列岫昏。", "衝涉唯驚兀舟楫，遷騰那復論鵬鯤。", "仙槎遠泛時相際，野馬兼馳力更掀。", "華信築塘無宿恨，子胥乘浪有忠魂。", "吳兒勿詫輕身弄，自古馮河豈足言。"]'),
('61f92445-9756-4d2a-bfec-48d53af83523','送吳聖取給事','韋驤','宋','宋诗','song-poetry','','[]','忠嘉早結九重知，隙駟徒驚晷景馳。',64,'全唐诗/poet.song.42000.json','["忠嘉早結九重知，隙駟徒驚晷景馳。", "祥鼓素琴猶累月，恩除青瑣已先期。", "秋風慘處違丘壟，霜柳疏中即路岐。", "得志澤民賢者事，佇觀功業映清時。"]'),
('1edd7e7a-5f13-42f0-8f05-8e3f97620415','送深闍梨之越開講','韋驤','宋','宋诗','song-poetry','','[]','家世事簪紳，方袍早出塵。',48,'全唐诗/poet.song.42000.json','["家世事簪紳，方袍早出塵。", "詩書捐舊習，戒律悟前身。", "杯度吳川雪，經繙越嶠春。", "逆知專講席，著意警迷津。"]'),
('5d74300f-3d66-4c56-928e-449b9c974551','和韓琯山齋','韋驤','宋','宋诗','song-poetry','','[]','愛君築室據青山，高躅寧容俗士攀。',64,'全唐诗/poet.song.42000.json','["愛君築室據青山，高躅寧容俗士攀。", "吏隱幽懷潛物外，詩成秀句落人間。", "濤江遠向窗扉見，竹塢靜宜巾履閒。", "顧我衰殘倦登覽，偶來聊此共開顔。"]'),
('c1599278-8ea8-4601-9b29-5ceb0db181ea','劉握大夫挽詞二首  其一','韋驤','宋','宋诗','song-poetry','','[]','平生端素履，四紀仕清朝。',48,'全唐诗/poet.song.42000.json','["平生端素履，四紀仕清朝。", "移守將前邁，修齡忽後彫。", "琴書遺淡泊，几杖捨逍遥。", "有子光承績，幽堂慰寂寥。"]'),
('5c6f67ec-3b4b-4229-a15b-fbb75a12429b','劉握大夫挽詞二首  其二','韋驤','宋','宋诗','song-poetry','','[]','棄養臨茗水，傳聲到武林。',48,'全唐诗/poet.song.42000.json','["棄養臨茗水，傳聲到武林。", "仁賢沒何遽，老友慟尤深。", "珠玉藏前咏，風標起舊欽。", "靈輿不克送，薤唱寓空音。"]'),
('31b15467-208c-486d-aee1-27277f2925ca','劉欽止承務挽詞一首','韋驤','宋','宋诗','song-poetry','','[]','年始踰强仕，俄從逝水沄。',48,'全唐诗/poet.song.42000.json','["年始踰强仕，俄從逝水沄。", "祇應懷永慕，遂爾繼先君。", "利器方施手，高翔未及雲。", "嗚呼今已矣，衆歎謾紛紛。"]'),
('71f9d15f-ac60-441f-af2a-8feb73becbb8','過笠澤三賢堂詩三首  其一','韋驤','宋','宋诗','song-poetry','','[]','舟繫小橋楊柳月，帆移平浦芰荷風。',32,'全唐诗/poet.song.42000.json','["舟繫小橋楊柳月，帆移平浦芰荷風。", "當時不向煙波老，霸業功名一歸空。"]'),
('5d401f35-4332-4035-8168-5a6c9c93e890','過笠澤三賢堂詩三首  其二','韋驤','宋','宋诗','song-poetry','','[]','鱸鱠白鮮盤玉縷，蓴羹涎滑煮龍髯。',32,'全唐诗/poet.song.42000.json','["鱸鱠白鮮盤玉縷，蓴羹涎滑煮龍髯。", "可憐水月交光夜，一笛西風自捲簾。"]'),
('a5573983-f818-46e6-b2a7-110937c327ba','過笠澤三賢堂詩三首  其三','韋驤','宋','宋诗','song-poetry','','[]','醉夢幾尋芳草渡，吟魂飛上月明樓。',32,'全唐诗/poet.song.42000.json','["醉夢幾尋芳草渡，吟魂飛上月明樓。", "散人已出形骸外，肯作鄉聲效楚囚。"]'),
('39408f41-9729-4222-929c-254e92154df9','和提刑度支遊永康靈巖','韋驤','宋','宋诗','song-poetry','','[]','天下被澤久，詩人歌旱麓。',120,'全唐诗/poet.song.42000.json','["天下被澤久，詩人歌旱麓。", "廉按重時選，巡行當歲熟。", "優游今日心，憩息茲山腹。", "峰危齊鳥道，巖邃容佛屋。", "長松揭臣蓋，修篁削青玉。", "塵遠疑僊隱，景遠如畫簇。", "還轅興有餘，過隙光何速。", "據雲出蒼翠，回首辨重復。", "留止念所之，吟咏生不足。", "不獲睹勝遊，空言繼郎宿。"]'),
('dd11dbf9-739c-4b2a-9d40-5f6608756614','懷永康顔明府','韋驤','宋','宋诗','song-poetry','','[]','寒山晴望青重重，我居山西君在東。',111,'全唐诗/poet.song.42000.json','["寒山晴望青重重，我居山西君在東。", "縣疆有守不往，遲想休誼如饑空。", "反思六月君假道，夜對樽酒乘清風。", "高談落落破畦畛，不許俗語咻其中。", "撇然傾蓋信若舊，誠通氣洽知所同。", "別來慰釋尚可賴，時獲佳句開惛蒙。", "所嗟室邇人甚遠，安得邂逅還相逢。"]'),
('94f45e4c-4aa5-4c6b-a249-bce78423d286','石室洞','韋驤','宋','宋诗','song-poetry','','[]','天王峰南石室洞，怪特不與尋常同。',320,'全唐诗/poet.song.42000.json','["天王峰南石室洞，怪特不與尋常同。", "石門巉巖天所鑿，門內夷曠驅車通。", "偃然靈穴邃且廣，步履出沒忘西東。", "其間異狀多所類，懸乳往往成鼓鍾。", "龜頭俯視露巖腹，壽與歲月應無窮。", "團團一竅透千尺，天使日月光來容。", "洞前佛氏殿閣峻，相直氣象增其雄。", "我爲俗吏雖跼蹐，所至安肯遺幽蹤。", "金華靈巖著於婺，每越疆境爲遊從。", "嘗恨昔年之富川，便道不得尋龜峰。", "塵懷不愜十餘載，每見圖畫加忡忡。", "去春來此路復過，籃輿暮觸煙靄重。", "縱觀雖未盡吾興，聊塞所欲平饑空。", "到官萍邑已逾歲，坐擁民事勞顓蒙。", "滯祛敝革固用日，佳趣不暇先牢籠。", "稱來公餘得茲洞，疏爽爲我開情悰。", "金華龜峰雖未及，此地有此爲難逢。", "謾拈禿筆寫白石，但記姓字於其中。", "卻登凈宇祇獨宿，蒲牢壓旦還撞舂。", "歸鞭遽去有餘約，後會結客臨春風。"]'),
('306bf18c-9794-4b81-a506-f2d3ab8c93da','幽懷十二首  其一','馮山','宋','宋诗','song-poetry','','[]','秋風蕭然起，喬木葉飛翻。',48,'全唐诗/poet.song.42000.json','["秋風蕭然起，喬木葉飛翻。", "勁聲薄以怒，肅氣傷無痕。", "洪鈞運不私，至義中有恩。", "華滋脱塵滓，生意還本根。"]'),
('1fc40bfc-91b4-4ed1-a240-1bda174abdf7','幽懷十二首  其二','馮山','宋','宋诗','song-poetry','','[]','嵯峨羣峰高，蓊鬰萬木滋。',48,'全唐诗/poet.song.42000.json','["嵯峨羣峰高，蓊鬰萬木滋。", "一容樵夫手，誤落長松枝。", "煙雲慘無色，禽鳥鳴且悲。", "人心不爲慮，山意從此衰。"]'),
('b7526536-c640-4933-b54f-6423a6209061','幽懷十二首  其三','馮山','宋','宋诗','song-poetry','','[]','晚林脱餘照，栖鴉上林端。',48,'全唐诗/poet.song.42000.json','["晚林脱餘照，栖鴉上林端。", "危枝不容足，踏踏殊未安。", "相乘狐狸暴，寧苦風霜寒。", "微生尚憂患，物理幾相殘。"]'),
('d74a93e8-2c8e-4f1c-b532-169b9c80d6d7','幽懷十二首  其四','馮山','宋','宋诗','song-poetry','','[]','李渤隱嵩高，愈退名愈重。',48,'全唐诗/poet.song.42000.json','["李渤隱嵩高，愈退名愈重。", "區區水南北，一呼輙爲用。", "沽激本同轍，出處或異動。", "善閉不可窺，少室有餘頌。"]'),
('ac5ff10d-bf60-4a42-878a-40f048578a6d','幽懷十二首  其五','馮山','宋','宋诗','song-poetry','','[]','少年氣力壯，巾車騁遊歷。',48,'全唐诗/poet.song.42000.json','["少年氣力壯，巾車騁遊歷。", "行人不能到，貪遠未有適。", "昔人六十化，萬事豈如一。", "誰爲持寸光，環中照心跡。"]'),
('042208fa-006a-44f6-aded-ab2a8d7f2bbf','幽懷十二首  其六','馮山','宋','宋诗','song-poetry','','[]','高架環四壁，古書浩萬卷。',48,'全唐诗/poet.song.42000.json','["高架環四壁，古書浩萬卷。", "腐儒坐相守，大義老不斷。", "羣言幾可用，吾道一能貫。", "巨賢已經世，博士方浩歎。"]'),
('d5c52b3b-3135-45d8-a925-db9354e054be','幽懷十二首  其七','馮山','宋','宋诗','song-poetry','','[]','秋後無多日，山中已倍寒。',48,'全唐诗/poet.song.42000.json','["秋後無多日，山中已倍寒。", "蟲聲聞壁脚，霧氣出林端。", "農事黄時畢，天形碧處寛。", "騷人方適意，白露團幽蘭。"]'),
('bd65fd2b-6c6c-4a7e-bcc3-4e2f3b7a0f64','幽懷十二首  其八','馮山','宋','宋诗','song-poetry','','[]','吾羮畦有蔬，吾飯囷有粟。',48,'全唐诗/poet.song.42000.json','["吾羮畦有蔬，吾飯囷有粟。", "人事少還往，山田自充足。", "雞犬盡日閒，藤蘿照門綠。", "物外乃如此，熙熙古風俗。"]'),
('6c308719-3d5a-4036-8b50-065bd07ef427','幽懷十二首  其九','馮山','宋','宋诗','song-poetry','','[]','衆呼楚比死，瘈走華氏驚。',48,'全唐诗/poet.song.42000.json','["衆呼楚比死，瘈走華氏驚。", "仲尼厄兵守，不輟弦歌聲。", "外物匪憂患，中懷自險平。", "古人縱天機，以道不以兵。"]'),
('926ee052-b743-4d8b-9206-4a8165046b97','幽懷十二首  其一○','馮山','宋','宋诗','song-poetry','','[]','鷙禽出東海，矯翮與天鄰。',48,'全唐诗/poet.song.42000.json','["鷙禽出東海，矯翮與天鄰。", "初從網羅誤，遂與韝臂親。", "一肉戀主意，擊搏豈爲身。", "飛飛山間雉，耿介不可馴。"]'),
('91bcc727-6f85-45ae-9af8-bcf50665ce60','幽懷十二首  其一一','馮山','宋','宋诗','song-poetry','','[]','山溪漲易涸，爲無千里源。',60,'全唐诗/poet.song.42000.json','["山溪漲易涸，爲無千里源。", "桐孫繞雲枝，下有百尺根。", "物理不虚發，本厚末始繁。", "功名豈易力，舊德資深蟠。", "不知所從来，意氣行軒軒。"]'),
('2759c3f5-c058-4f0e-8e0d-b3999ba63c6e','幽懷十二首  其一二','馮山','宋','宋诗','song-poetry','','[]','花草弄顔色，盛衰數日間。',48,'全唐诗/poet.song.42000.json','["花草弄顔色，盛衰數日間。", "富貴無定姿，迭起如循環。", "外物偶相附，固有不肯還。", "造化弗示私，力禦何其艱。"]'),
('80862611-442e-4195-94e6-0963fe29518d','春意','馮山','宋','宋诗','song-poetry','','[]','賞花不須折，一折春思闌。',96,'全唐诗/poet.song.42000.json','["賞花不須折，一折春思闌。", "飲酒不必醉，一醉無餘歡。", "相知共清賞，所屬聊孤彈。", "朝繁坐臨池，暮惜行遶欄。", "醒醉無異趣，開落同一觀。", "鄰花隔墻悲，憔悴枝葉單。", "鄰翁貪酩酊，疾起春向殘。", "但知芳菲意，常作悠久看。"]'),
('8d815782-ce47-412c-9379-8614fe6fdf13','送鼎倅陳安仁虞部','馮山','宋','宋诗','song-poetry','','[]','峨峨陽山，民資以仁。',110,'全唐诗/poet.song.42000.json','["峨峨陽山，民資以仁。", "僭陽欺天，不需不神。", "而乞於民，泱泱沅江。", "城繄以寧，横流潰川。", "不畜不靈，將坎於城。", "暴政殘俗，劇於懷襄。", "猾胥擾民，甚於凶荒。", "借公後時，吾民幾亡。", "舞公入城，若旱而雨。", "若霖而晴，頌公之還。", "孰靈沅江，孰神陽山。"]'),
('5de57d84-dcc5-40fb-9f29-ddcec6c66190','題澧州石門縣蹇周輔蟠翁太博三愛堂','馮山','宋','宋诗','song-poetry','','[]','石門險且僻，人煙萬山罅。',240,'全唐诗/poet.song.42000.json','["石門險且僻，人煙萬山罅。", "蟠翁老才望，来此屈英駕。", "破漏煩補綴，嚬呻索慰藉。", "力致乃坐享，少勞豈豐暇。", "臨觀閴無有，游燕久以謝。", "廢園近城邑，丘墟甚原壩。", "高松困藤蔓，嘉果没荆柘。", "斬荒使之出，蒼翠若圖畫。", "直前走橋閣，當中建臺榭。", "雍容賓朋席，左右書史架。", "命亭以三愛，作詩盛誇詫。", "韻險語怪絕，竊讀驚汗下。", "嗟予苦覊束，相去止數舍。", "深思一登覽，若渴不得蔗。", "知君羣公表，甫爲兵民借。", "復以三者樂，何時動歸靶。", "吾鄉富風景，草木芬蘭麝。", "錦水清於漢，岷峨不讓華。", "蔡圃豈足道，寧爲耳目乍。", "苟以吾言然，煩君少譏罵。"]'),
('ddb6ed02-97c7-4c22-bc62-e85208a32c66','謝夔守賈昌言禮賓','馮山','宋','宋诗','song-poetry','','[]','伯樂善相馬，相內不相外。',204,'全唐诗/poet.song.42000.json','["伯樂善相馬，相內不相外。", "造父善御馬，御成不御敗。", "沙丘有病馬，志遠力未憊。", "盤身怯泥土，俛首困草稗。", "强起時奮迅，悲鳴輙喑噫。", "駑駘倦相逐，童僕幾見賣。", "斯人一回顧，世俗始驚怪。", "冀北有駿馬，散蹄雨雹快。", "去勢馳滅没，朝荆暮燕代。", "銜轡苟庸拙，道途足險隘。", "斯人一駷手，千里瞬息屆。", "二者豈不偉，繄人而否泰。", "相也命所係，御也才所賴。", "名馬世常有，伏櫪固有待。", "伯造不世出，古今重遭會。", "相得互相起，兩致一無礙。", "所以馬與人，功名各自大。"]'),
('63c0142f-8403-4e0a-86b4-2e61ddde7779','與蒲宗孟傳正察推','馮山','宋','宋诗','song-poetry','','[]','五月熱無事，訟庭若掃刷。',288,'全唐诗/poet.song.42000.json','["五月熱無事，訟庭若掃刷。", "眼底簿書靜，獨坐癡悶發。", "上馬出門去，不避煩與渴。", "幕中訪賢友，且欲紓擁閼。", "灑水延我坐，解带意思活。", "清談破塵滓，快若飲冰雪。", "青衫雖同服，所處類巾襪。", "道均語言合，殊不間毫髪。", "十篇詩總解，金玉自磨戞。", "往時草草讀，恨不見本末。", "全編使我盡，萬漏都一括。", "諸君好詩學，論議每相軋。", "破碎失本源，十嘗見七八。", "聖途久荒廢，怜君力鋤鏺。", "漢安隆中集，應和類控楬。", "馳騁氣力壯，嵩岱可手揭。", "形容若繪畫，譏諷過賞罰。", "迴頭索平淡，春興最清越。", "意外得真巧，漫不露彫割。", "此皆緒餘爾，太倉出圭撮。", "予雖素無聞，少小頗姦黠。", "僻澀追古意，芬芳慕賢哲。", "獨自狂妄走，屢遭流輩喝。", "中道偶成病，兩眼痛欲瞎。"]'),
('9bf86bf2-4cbe-4e0c-ab9d-c9f81ae161f2','辰陽館','馮山','宋','宋诗','song-poetry','','[]','辰陽號難理，五溪地相跨。',204,'全唐诗/poet.song.42000.json','["辰陽號難理，五溪地相跨。", "邊臣重綏撫，蠻獠愈驕詐。", "封陲苦侵暴，文書困譏罵。", "誰爲太守樂，一笑不得暇。", "張公抗辰旆，烽障幾欲罷。", "偃息有餘地，登臨無一舍。", "迺興辰陽館，城東兩山胯。", "泉聲落溪谷，湖光照亭榭。", "花木親種植，朋僚日追迓。", "投壺征虜祭，圍棋太傅謝。", "高風邈難繼，維公並驅駕。", "有客嘗一至，席參鄒枚亞。", "覽物言思闊，醒魂耳目乍。", "欲記傳之久，恨無文章價。", "願公賁泉石，遊宴日来藉。", "新詩上碑刻，佳景若圖畫。", "旦暮趣召還，歸爲中州詫。"]'),
('711909f0-2cce-4a9d-9549-b82b0ec6d910','開州盛山十二題 宿雲亭','馮山','宋','宋诗','song-poetry','','[]','基構白石層，風物青山圍。',24,'全唐诗/poet.song.42000.json','["基構白石層，風物青山圍。", "野雲戀幽寂，長遶軒窗飛。"]'),
('66fd93e7-791b-44fc-839a-e2b3b8194e0a','開州盛山十二題 梅嶺','馮山','宋','宋诗','song-poetry','','[]','繁梅照溪谷，蜂蝶殊未省。',24,'全唐诗/poet.song.42000.json','["繁梅照溪谷，蜂蝶殊未省。", "巖風莫吹落，留妝臘前景。"]'),
('3544fb03-3f97-4a31-9382-af267644a54e','開州盛山十二題 茶嶺','馮山','宋','宋诗','song-poetry','','[]','新萌雨露濃，嶺頭春味足。',24,'全唐诗/poet.song.42000.json','["新萌雨露濃，嶺頭春味足。", "緣雲採擷人，争收火前綠。"]'),
('5050a2a4-1748-4d2d-96d2-6cb70329090f','開州盛山十二題 流杯渠','馮山','宋','宋诗','song-poetry','','[]','爲愛泉石飲，屢招賓朋遊。',24,'全唐诗/poet.song.42000.json','["爲愛泉石飲，屢招賓朋遊。", "浮觴来不倚，一水循環流。"]'),
('f13c2f3b-6296-4d82-b305-52013612b9c6','開州盛山十二題 隱月岫','馮山','宋','宋诗','song-poetry','','[]','月從海上来，清輝長礙山。',24,'全唐诗/poet.song.42000.json','["月從海上来，清輝長礙山。", "山前愛月人，唯看亭午間。"]'),
('0dba3d9f-cc5d-4586-8f83-0fdb9922e903','開州盛山十二題 盤石磴','馮山','宋','宋诗','song-poetry','','[]','數步即一息，始知登山勞。',24,'全唐诗/poet.song.42000.json','["數步即一息，始知登山勞。", "盤盤行徹時，跡與心俱高。"]'),
('bc9de8a3-0cbf-4f8b-b854-649f9c31ff4b','開州盛山十二題 胡盧沼','馮山','宋','宋诗','song-poetry','','[]','中虚得嘉名，水清石環環。',24,'全唐诗/poet.song.42000.json','["中虚得嘉名，水清石環環。", "天邊侍從人，來照冰雪顔。"]'),
('c1913ab0-9ae8-4d31-be38-15d6a51d1431','開州盛山十二題 琵琶亭','馮山','宋','宋诗','song-poetry','','[]','片石胡琴槽，構亭事登臨。',24,'全唐诗/poet.song.42000.json','["片石胡琴槽，構亭事登臨。", "考功閒中樂，非好世俗音。"]'),
('5ceac7c3-9990-4448-a633-7aa55ecc02b6','開州盛山十二題 桃塢','馮山','宋','宋诗','song-poetry','','[]','聞說舊桃塢，歲久無殘枝。',24,'全唐诗/poet.song.42000.json','["聞說舊桃塢，歲久無殘枝。", "春光已不到，猶有風騷知。"]'),
('65e6106b-968e-4dbc-848b-dfe5a53906cd','開州盛山十二題 繡衣石榻','馮山','宋','宋诗','song-poetry','','[]','御史來山中，拂石當優游。',24,'全唐诗/poet.song.42000.json','["御史來山中，拂石當優游。", "非人勿據兹，恐爲山神羞。"]'),
('5575e8b9-381a-4e0b-a4d6-195d7cb9f4ca','開州盛山十二題 上士泉瓶','馮山','宋','宋诗','song-poetry','','[]','爲愛禪翁遊，潄泉聽泉音。',24,'全唐诗/poet.song.42000.json','["爲愛禪翁遊，潄泉聽泉音。", "何當酌清泠，洗我塵垢心。"]'),
('1283d50d-d95f-4679-8209-7df7e812af58','開州盛山十二題 竹巖','馮山','宋','宋诗','song-poetry','','[]','倒影蔽山骨，引根出巖腹。',24,'全唐诗/poet.song.42000.json','["倒影蔽山骨，引根出巖腹。", "誰人萬仞間，團團種青玉。"]'),
('817827a9-a449-4961-9b6f-e01cd394943e','和程之才正輔感遇','馮山','宋','宋诗','song-poetry','','[]','天理貴自然，枉直各有病。',120,'全唐诗/poet.song.42000.json','["天理貴自然，枉直各有病。", "人情隨所得，是非本無定。", "此身寄軒冕，心與萬物競。", "低回就銜策，跳踼落機穽。", "巧求固爲累，矯枉亦過正。", "持之有原本，出處一以靜。", "所守以吾道，所安以吾命。", "不驟窮馬力，不决暴虎性。", "富貴偶而已，勿使憂喜並。", "感遇難我知，無言爲心聽。"]'),
('bec150e3-ccaf-43fa-827a-bfeead8f6c01','越公堂','馮山','宋','宋诗','song-poetry','','[]','古賢重遺愛，跡與江山遥。',96,'全唐诗/poet.song.42000.json','["古賢重遺愛，跡與江山遥。", "夸者恣而已，事隨草木彫。", "越公彼何人，構堂壓山椒。", "四阿無寸支，千載不可摇。", "自衒神鬼工，已窮草木妖。", "吾嘗讀素傳，拊髀悲前朝。", "無從借史冊，奮筆誅姦驕。", "尚能毁兹堂，立使沴氣銷。"]'),
('6d364a43-a609-440c-b193-7150a589d0c0','灔澦堆','馮山','宋','宋诗','song-poetry','','[]','巨石當江衝，江水皆倒還。',60,'全唐诗/poet.song.42000.json','["巨石當江衝，江水皆倒還。", "夏秋水石鬭，怒浪高於山。", "長年欲下峽，防石如防姦。", "乘流一無備，拳石皆險艱。", "獨使灔澦誇，千載不可刪。"]'),
('db44179e-5233-4069-b664-3dd270acf69e','岑公洞','馮山','宋','宋诗','song-poetry','','[]','武龍南浦南，秀拔異衆山。',132,'全唐诗/poet.song.42000.json','["武龍南浦南，秀拔異衆山。", "下有巖洞幽，嵌虚隱玄關。", "岑公江陵来，一寓不復還。", "養神脱塵滓，百歲如童顔。", "至今遺像存，寂寞空幢幡。", "老柏壯人氣，清泉遶回環。", "暫爲物外遊，偷向壺中閒。", "叟其靜者歟，深藏厭喧煩。", "或將避擾攘，甘此石穴艱。", "不虞身後聞，夐若高難攀。", "萬事皆偶爾，多在功名間。"]'),
('10283149-068d-45aa-bd15-040b2c50d16a','温湯寺','馮山','宋','宋诗','song-poetry','','[]','温湯氣如蒸，冷泉寒於冰。',108,'全唐诗/poet.song.42000.json','["温湯氣如蒸，冷泉寒於冰。", "並流不相入，洶湧爭奔騰。", "佛廬煥金碧，法地何時興。", "二泉灑其間，回環清且澄。", "維舟愛古柏，磴道垂千層。", "殿堂絕纖埃，瀟灑嚴香燈。", "敲欄施魚食，弄水摇懸藤。", "一掬洗病眼，再潄袪煩膺。", "遠訪豈憚勞，勝遊誠可矜。"]'),
('e58e32a7-b370-4f2a-9183-893513cbc556','塗山寺','馮山','宋','宋诗','song-poetry','','[]','巴山俗可厭，萬疊誇雄偉。',132,'全唐诗/poet.song.42000.json','["巴山俗可厭，萬疊誇雄偉。", "江前一峰秀，青林带孤起。", "長舟截巨浪，平輿登峻趾。", "古寺隱山背，来造神已喜。", "清泉遶修竹，野徑入葭葦。", "女媧舊生處，石坳勤戾止。", "聖神固有合，天作非偶爾。", "玉簡事恍惚，越書莽非是。", "孤亭凌絕頂，坐有千古意。", "二江錯交會，比屋聚紛蟻。", "把酒一長笑，忘情但高視。"]'),
('223106cf-92e7-4288-a9d0-9d33d10df423','豐都觀','馮山','宋','宋诗','song-poetry','','[]','横江聳孤峰，陟巘訪山境。',108,'全唐诗/poet.song.42000.json','["横江聳孤峰，陟巘訪山境。", "修廊轉空曲，古殿冠絕頂。", "漢柏撫骨立，唐碑獨孤挺。", "高踞自軒豁，遐追若俄頃。", "長生盡室来，避世或箕穎。", "逍遥奚所適，遺事傳緱嶺。", "藥巖已無竈，烟雲但枯井。", "風前凡幾過，物外初一省。", "清風誰與遊，高步跼難騁。"]'),
('066255ca-b994-4ed8-aa18-12496b17de31','利州漕宇八景 會景亭','馮山','宋','宋诗','song-poetry','','[]','天下臺府勝，益昌囿佳山。',156,'全唐诗/poet.song.42000.json','["天下臺府勝，益昌囿佳山。", "使者高世才，秀隱林樾間。", "仰山復仰人，昔旅無由攀。", "辟書就始志，来若遊子還。", "史公實賓從，與脱簿領艱。", "會景駕峰出，碧玉森周環。", "棟樑宿雲霧，欄檻平江關。", "杖屨從公遊，蕭散萬慮閒。", "酒隨至樂盡，詩到無疵刪。", "經年若朝夕，語去涕欲潸。", "屬余省親闈，看公趣天顔。", "此會不可再，鴻鵠方高翾。", "八詠風蹟存，二江聲潺潺。"]'),
('fff462a2-76ab-45cf-8a04-d1548cc20f9f','利州漕宇八景 巽堂','馮山','宋','宋诗','song-poetry','','[]','燕嬉各異處，君子時以居。',96,'全唐诗/poet.song.42000.json','["燕嬉各異處，君子時以居。", "虛堂背治開，面直東南隅。", "林巒照几席，花木紛庭除。", "委蛇外不煩，浩蕩中有餘。", "雄雄臺府間，寂若山中廬。", "美景開宴觴，清談會賓裾。", "孰窮吏隱趣，但見民情舒。", "鄙夫不知要，僕僕困簿書。"]'),
('ace6355f-863c-41bf-a83b-bce9a976a6ea','利州漕宇八景 桐軒','馮山','宋','宋诗','song-poetry','','[]','幽軒處清奥，前有雙桐起。',84,'全唐诗/poet.song.42000.json','["幽軒處清奥，前有雙桐起。", "婆娑勢初合，修聳意未已。", "葉分竹巖路，根漬石沼水。", "秋聲動素琴，曉影覆齋几。", "主人相對樂，性靜窮物理。", "純音藏未兆，孤榦直不倚。", "安得千仞禽，来哉共棲止。"]'),
('8b9f9582-51d0-4f32-abe1-d4319bdf57ec','利州漕宇八景 柏軒','馮山','宋','宋诗','song-poetry','','[]','昔時柏未栽，榜杏爲軒名。',72,'全唐诗/poet.song.42000.json','["昔時柏未栽，榜杏爲軒名。", "柏今已可愛，題柏軒始清。", "賢者安厥居，中懷渺無營。", "日来對柏坐，心適眼自明。", "草經謝今說，寄意遺俗聲。", "落落守歲寒，常恐爲柏輕。"]'),
('8e714c52-71a0-4287-b67c-4ee194e69639','利州漕宇八景 竹軒','馮山','宋','宋诗','song-poetry','','[]','翠筠清人心，愈少愈可愛。',72,'全唐诗/poet.song.42000.json','["翠筠清人心，愈少愈可愛。", "風騷靜中得，一室處以泰。", "北軒隱吟几，復與此君對。", "冺默追古意，蕭森散秋籟。", "淡薄世鮮味，俛仰誰與會。", "七賢非吾徒，心猶有名在。"]'),
('34066cf4-2e61-4532-8f19-7f221beec676','利州漕宇八景 山齋','馮山','宋','宋诗','song-poetry','','[]','層層梯巉巖，步步出杳茫。',72,'全唐诗/poet.song.42000.json','["層層梯巉巖，步步出杳茫。", "何人破峰臆，碧瓦臨疏篁。", "聊休邈回睇，人物分毫芒。", "惟見臺府雄，三軒鬰相望。", "不知身從来，但覺凌空翔。", "窮高自兹始，寶峰磨蒼蒼。"]'),
('fc37db77-a301-4294-abf3-513fd31440aa','利州漕宇八景 閒讌亭','馮山','宋','宋诗','song-poetry','','[]','徹頂造閒讌，據欄俯山齋。',84,'全唐诗/poet.song.42000.json','["徹頂造閒讌，據欄俯山齋。", "軒窗蔽修竹，磴道懸蒼崖。", "登臨快雙目，應接煩虚懷。", "羣峰病擁閼，次第隨天開。", "物色無定姿，變化紛難裁。", "高吟絕儔侣，但攜清罇偕。", "物理醉可一，逍遥付齊諧。"]'),
('c09a8bce-6e4c-42ac-9db3-47d541e3cb87','利州漕宇八景 寶峰亭','馮山','宋','宋诗','song-poetry','','[]','益昌萬山間，寶峰秀惟獨。',192,'全唐诗/poet.song.42000.json','["益昌萬山間，寶峰秀惟獨。", "使臺俯山下，氣象互盤覆。", "鬰勃尚南走，回環已西屬。", "古城削千仞，危棧轉幾曲。", "錦繡紛上領，琅玕翠摇腹。", "亭榭何參差，遠覽意尚局。", "絕頂躋石峰，超然脱覊束。", "城市裁唾落，二江可手掬。", "重開固天險，大道不停轂。", "古意劇滿眼，人事傷轉足。", "主人始經搆，高蹈非絕俗。", "幽懷卷雲霧，長笑動巖谷。", "鳥雀爭脱林，冥冥有鴻鵠。", "寸步異出處，虚心見榮辱。", "屈將經濟才，分繼騷雅躅。", "語默固可傳，誰爲寶峰録。"]'),
('1918a292-7391-4a9d-acef-09b825bbc4e2','中林道上','馮山','宋','宋诗','song-poetry','','[]','中林山谷間，出没緣畏途。',84,'全唐诗/poet.song.42000.json','["中林山谷間，出没緣畏途。", "楩楠蔽白日，落落樑棟軀。", "半爲野火燒，摧頹委樵蘇。", "清泉勞奔注，亦爲勢所驅。", "微芒濟物心，到海何其迂。", "吾物處其一，進退難與俱。", "置身木雁間，恐非斯人徒。"]'),
('bb836b85-55e7-47cf-a168-d538629d9363','西縣道中','馮山','宋','宋诗','song-poetry','','[]','漢水引我行，梁山邀我坐。',48,'全唐诗/poet.song.42000.json','["漢水引我行，梁山邀我坐。", "山水已清絕，春容碧相和。", "下馬取酒飲，梅飄酒中墮。", "日落醉不去，青茸草間卧。"]'),
('7afc7c52-0da7-41e0-b7c5-e95eb9e7b742','巴子臺','馮山','宋','宋诗','song-poetry','','[]','早渡鳴玉橋，竟登巴子臺。',108,'全唐诗/poet.song.42000.json','["早渡鳴玉橋，竟登巴子臺。", "雲林擁磅礴，磴道窮縈迴。", "古寺不足觀，猶有南軒開。", "浩蕩横深溝，逶迤環覆杯。", "古人去我遠，萬事隨塵埃。", "赤穴何渺茫，青山但崔嵬。", "聞名不知實，此意空悠哉。", "乍到輙復還，石滑倦去来。", "苟能厭耳目，未免勞筋骸。"]'),
('a9961988-be30-4bd2-af93-1c7690b63f74','答王載監簿惠詩依韻','馮山','宋','宋诗','song-poetry','','[]','梓士多好學，獨君用心苦。',144,'全唐诗/poet.song.42000.json','["梓士多好學，獨君用心苦。", "始策萬里足，相期一言遇。", "荏苒去歲月，差池晚途路。", "清節撓不變，雞鳴任風雨。", "一日起仕進，光華照門戶。", "謂予嘗遊從，復此再會聚。", "清談語言約，老筆文字古。", "新詩忽持贈，病目駭觀覩。", "蘭芷得遠思，從兹識賢矩。", "草木變秋節，悲風襲原鹵。", "自可追賦詠，何須倦貧窶。", "感慨無俗音，虹蜺俟重吐。"]'),
('b59288b5-b3ac-4ef6-8ee9-9f5085ea1675','答江安尉鮮于頃野翁','馮山','宋','宋诗','song-poetry','','[]','寶峰首相聚，錦屏袂一判。',132,'全唐诗/poet.song.42000.json','["寶峰首相聚，錦屏袂一判。", "音容阻良覿，歲月嗟易換。", "我觀潼江曲，君尉瀘水岸。", "到處逢酒徒，無人作詩伴。", "南風灑襟袖，佳句適我願。", "汶蜀幾萬里，信息偶中斷。", "三軒風雅會，蕭條各分散。", "孤吟少儔侣，衆喙易嘲囋。", "念君同所嗜，路近聲可喚。", "唱酬實相眷，牽率豈辭憚。", "亹亹郊籍心，無爲簿書亂。"]'),
('282bf943-139c-4131-b351-0578c322445e','送梓漕李竦端臣赴闕','馮山','宋','宋诗','song-poetry','','[]','道途去無窮，歲序嗟易改。',84,'全唐诗/poet.song.42000.json','["道途去無窮，歲序嗟易改。", "相知念遠别，遇物增感慨。", "悲懽勞寸心，喣沬異江海。", "南歸得嘉報，迅掉若旋凱。", "機穽觸不發，神明怳猶在。", "名因困愈重，事雖晚可待。", "去就勿自謀，冥冥付真宰。"]'),
('d3023efc-06cd-49b8-b60f-b742e6ef3c86','和李曼修孺職方謝梓守張靖子立龍圖遊春','馮山','宋','宋诗','song-poetry','','[]','潼川侈風俗，一春事嬉遊。',240,'全唐诗/poet.song.42000.json','["潼川侈風俗，一春事嬉遊。", "太守與民樂，高會邀良儔。", "年豐廷無訟，日夕爲歡謀。", "賓從相追隨，景物多訪求。", "名園布芳郊，寶刹依重丘。", "紅旗肅冠蓋，畫鼓翻倡優。", "人情殊未央，春意亦少留。", "最後司馬至，爲羅東山羞。", "觀棋緩带閒，試茗澄心幽。", "猖狂但醒醉，感慨還唱酬。", "清尊未放手，急景如轉頭。", "分司飽餘味，經世忘遠憂。", "来時蠶始眠，歸看場中麰。", "人生苟適性，不羡萬戶侯。", "丈夫負壯氣，安知餓填溝。", "得志位卿相，失時歸田疇。", "紛紛素所輕，大半登瀛洲。", "肯爲五斗米，折腰趨道周。", "區區事筆硯，頂踵稱恩庥。", "酒酣且勿去，爲我新聲謳。"]'),
('d9a9a52c-ff11-4e90-8c5a-7fe2dbfffb32','再和','馮山','宋','宋诗','song-poetry','','[]','飲酣起擊劍，恥從豪俠遊。',240,'全唐诗/poet.song.42000.json','["飲酣起擊劍，恥從豪俠遊。", "雍容詩酒歡，乃是神仙儔。", "風騷固有靈，造化陰爲謀。", "至音苟同調，曠世不可求。", "杜陵思江東，洪崖揖浮丘。", "自然風味殊，豈特文章優。", "嗟余萬事拙，吟咏心久留。", "自愧蘋藻微，恐爲王公羞。", "晚遇青河公，採蘭深林幽。", "修孺素蒙益，百贈無一酬。", "邂逅相撫掌，踉蹌容擡頭。", "雖然再鼓衰，且免三爵憂。", "吾儒學以仕，本代親禾麰。", "然多志高遠，擲筆思封侯。", "前時征南將，驅虜出塞溝。", "詩書非無助，爵賞不見疇。", "尚能解客嘲，相歡詠蘋洲。", "三術起商鞅，一言貴馬周。", "致身果有策，何地無餘庥。", "肯使韶濩音，變作巴渝謳。"]'),
('cfe2fd52-e69d-48c0-b345-bbecee30df56','再和','馮山','宋','宋诗','song-poetry','','[]','予始十五六，學賦場屋遊。',240,'全唐诗/poet.song.42000.json','["予始十五六，學賦場屋遊。", "聞君聲價高，已與班馬儔。", "少年取科第，復有經濟謀。", "孤聳不世合，獨行無名求。", "中道多邅迴，病驥盤沙丘。", "起爲瀘南守，政績稱最優。", "東海尋免歸，穎川尚借留。", "慷慨壯士懷，肯效兒女羞。", "投紱還故林，泉石甘清幽。", "區區尚遺恨，君恩未能酬。", "迴首名利場，彷彿裁蠅頭。", "君看縉紳士，誰爲天下憂。", "人情重軟熟，要若新炊麰。", "咿喔四至卿，峭拔奇不侯。", "一言反覆手，平地生重溝。", "世務傷賈誼，直道危田疇。", "何當與推移，歸釣滄浪洲。", "功名雖難期，歲月良易周。", "清風出襟袖，散爲生民庥。", "無使梁父吟，只成高唐謳。"]'),
('d1596125-7c36-4356-a641-e781f87f2d4e','苦寒寄任瀘州伋師中','馮山','宋','宋诗','song-poetry','','[]','嚴飈肅林莽，暖日沉煙霏。',72,'全唐诗/poet.song.42000.json','["嚴飈肅林莽，暖日沉煙霏。", "遊子事行邁，慘淡凌霜威。", "斂策倦修阻，跡往心自違。", "層雲眺孤鴻，徊翔鳴無依。", "雍容念儔侣，欲息洲渚非。", "此地正苦寒，盤身西南飛。"]'),
('e2e18c2b-9500-4fd4-bf64-87b9831415f7','除夕','馮山','宋','宋诗','song-poetry','','[]','一年倐已盡，四序循無端。',48,'全唐诗/poet.song.42000.json','["一年倐已盡，四序循無端。", "兒女競别歲，隨蔬具杯盤。", "長歌感時節，却羡僮僕歡。", "明朝四十六，重把青銅看。"]'),
('a9eb2cb7-59aa-4c2a-88fa-94e7164d07c6','幽懷','馮山','宋','宋诗','song-poetry','','[]','天地有常産，貨殖非善謀。',60,'全唐诗/poet.song.42000.json','["天地有常産，貨殖非善謀。", "桑耿發機械，已動莫復收。", "割膚啖其口，一身相爲讎。", "世餒味邪說，十九成贅疣。", "興王非管商，極治無裴劉。"]'),
('4ce513c1-da23-4fea-a56f-0ac9b7c9395a','獨坐','馮山','宋','宋诗','song-poetry','','[]','兀坐窗牖寂，桐葉擲瓦響。',48,'全唐诗/poet.song.42000.json','["兀坐窗牖寂，桐葉擲瓦響。", "哀彈動秋聽，遠寄勞夜想。", "擔荷幾踣面，自求不盈掌。", "未躍且自固，欲高又誰奬。"]'),
('4c7e4b5b-e097-4e70-9abe-e41e0825d166','有作','馮山','宋','宋诗','song-poetry','','[]','名塵愧屢拂，世垢思一澣。',48,'全唐诗/poet.song.42000.json','["名塵愧屢拂，世垢思一澣。", "急索脛已腫，虚驚背獨汗。", "窘步裁免跌，高談卒成謾。", "辰去將奈何，磨頭髻如彈。"]'),
('2ee72177-42c6-458a-b5ce-3bc7e0b0abb8','郊外','馮山','宋','宋诗','song-poetry','','[]','杖僻走世喧，吟靜追古意。',48,'全唐诗/poet.song.42000.json','["杖僻走世喧，吟靜追古意。", "解巾卧柔碧，虛懷揖爽氣。", "漏竹日脚紅，出亭山尖翠。", "偷閒興未足，遲遲動歸轡。"]'),
('eea83f5a-5b6e-4eda-83ba-28080580cef3','城南','馮山','宋','宋诗','song-poetry','','[]','散雪郊外風，含晴霧中日。',48,'全唐诗/poet.song.42000.json','["散雪郊外風，含晴霧中日。", "江流淺可渡，潺湲弄幽石。", "長堤塵未動，遊子念遠適。", "行止慎厥初，輪蹄有遺跡。"]'),
('fe135880-36ca-4a35-950f-295595e2c2b7','送王審言秘校潞州法曹','馮山','宋','宋诗','song-poetry','','[]','上黨緣青冥，勁氣西北隅。',168,'全唐诗/poet.song.42000.json','["上黨緣青冥，勁氣西北隅。", "黄河天際来，草木冬前枯。", "其地號嚴冽，燕隴莫與俱。", "氈罽護性命，冰霜結眉鬚。", "土人一犯寒，斗酒沃始蘇。", "中州宦遊士，未秋先嗟呼。", "我聞已心慄，凍粟生皮膚。", "而君風雪間，徑作壺關趨。", "少年始任氣，慷慨若有餘。", "自爲功名行，不憚氣候殊。", "犬戎熾將滅，鬰屈迎天誅。", "幕府收英才，富貴往何圖。", "埋頭簿書底，齷齪終非夫。", "功業彼何人，送子誠起予。"]'),
('96c483d3-ffcb-4f60-98c4-07bba6684e01','送張子立龍圖知鳳翔','馮山','宋','宋诗','song-poetry','','[]','公家濟水源，愛蜀如蜀人。',204,'全唐诗/poet.song.42000.json','["公家濟水源，愛蜀如蜀人。", "公凡五入蜀，東峽西峨岷。", "門生變交遊，故舊成姻親。", "蜀味皆吾餐，蜀音即吾民。", "潼川最後至，既至情亦均。", "惡不待公刑，善不須公仁。", "雍容如一家，笑語聞四鄰。", "山時參公府，堊鼻看斧斤。", "舉動出至誠，悠久疑爲神。", "詔書西出關，馬首北向秦。", "遲行客辭家，擁别兒戀親。", "公歸且大用，顧蜀還無因。", "風收彌勒花，雨壓長平塵。", "滑臺爲公壽，公飲不過唇。", "樂我奉公歡，榮虞適兹辰。", "物色莽牢落，人情浩酸辛。", "已辭尚可聽，少駐雙車輪。"]'),
('75a9a662-783d-4c63-904d-1ebf6e94b623','送蒲安行誠之秘丞興州簽判','馮山','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','春郊散輕靄，日出車馬動。',192,'全唐诗/poet.song.42000.json','["春郊散輕靄，日出車馬動。", "看君曉裝發，送客尊酒重。", "衆人别良易，我别情靡共。", "飛纓轉山曲，返頸即成夢。", "雖夢去奈何，不夢存者多。", "一言起相顧，慷慨成笑歌。", "清吟散泉石，醉墨蟠雲蘿。", "人生苦汲汲，浩如長江波。", "江波西南流，君行方北輈。", "林深足豺虎，路廢空亭郵。", "處常山中居，出亦山中遊。", "不嗟吾道窮，每爲斯民憂。", "憂民竟何爲，從事猶俛眉。", "晚達十六七，萬事懸難知。", "但窮聖賢意，莫賦離騷辭。", "有得常記我，以慰朝夕思。"]'),
('3e46ea61-5057-4dcd-b03a-b307bc356908','謝人惠兖墨','馮山','宋','宋诗','song-poetry','','[]','故人山東来，遺我數丸墨。',156,'全唐诗/poet.song.42000.json','["故人山東来，遺我數丸墨。", "握丸大如指，盥手重拂拭。", "濃磨向日看，古瓦增潤澤。", "經屑不見紙，清光隱深墨。", "書云舊所秘，聞今已難得。", "庭珪死已久，至寶世罕識。", "御府徒僅存，人間萬金直。", "兖州擅高價，比歙固少抑。", "古松亦將盡，神奇漸衰息。", "文章不見貴，筆硯豈可擲。", "牢落况此君，雖精淡無色。", "憐君情好古，投贈兼以臆。", "世事持此觀，噫嗟共冥默。"]'),
('02e434c3-31a3-45d9-a42d-feb43101ecac','送梓憲穆珣東美度支移京西漕','馮山','宋','宋诗','song-poetry','','[]','剛强多少恩，寛厚或太迂。',288,'全唐诗/poet.song.42000.json','["剛强多少恩，寛厚或太迂。", "峭直病不通，聰明至無徒。", "達人固貴全，天理常不俱。", "自非藴明識，暫解輙已紆。", "穆公淮海英，厚重如魯儒。", "疾惡鸇逐雀，養民烏哺雛。", "斷獄求以生，好善久不渝。", "孰謂公太嚴，威姦而惠愚。", "孰謂公太異，中異外不殊。", "然猶蔽高潔，不肯隨世趨。", "美成固在久，巨材期營都。", "西京近日邊，漕領出帝俞。", "使權雖云重，吏責意已粗。", "財利較圭撮，法制環刀殳。", "天聽卑不遺，人言紛可虞。", "公心公且明，應手萬事無。", "階此將顯用，逸驥臨長途。", "山也乏材技，盤薄困守株。", "身浮一芥舟，業散千金屠。", "衰遲戀鄉曲，荏苒歲月徂。", "擺袖不願行，俗指爭揶揄。", "惟公最見憐，情或昆弟踰。", "每憐沙丘病，不作饑鷹呼。", "秋風惜遠别，時去跡轉孤。"]'),
('6240401f-e9eb-4806-8ee8-d696de94840f','送梓憲胡揆少卿赴闕','馮山','宋','宋诗','song-poetry','','[]','富貴一鼎味，謂嘗須過食。',108,'全唐诗/poet.song.42000.json','["富貴一鼎味，謂嘗須過食。", "功名萬鈞器，負趨少量力。", "不勝苦爾體，不厭傷爾臆。", "誰能達涯涘，百動靡一息。", "古人去我遠，獨公抱清識。", "進退處以道，始終完無隙。", "車馬切嚴召，江湖正遥憶。", "賢達事如此，貪懦猶且惑。", "是豈時俗知，聱牙相緘嘿。"]'),
('b678ec5e-5734-4530-a0a7-cc60aa51de26','利漕劉忱明復見性堂','馮山','宋','宋诗','song-poetry','','[]','鑑蝕磨即明，水渾澄斯清。',132,'全唐诗/poet.song.42000.json','["鑑蝕磨即明，水渾澄斯清。", "雜然外滑銷，道在虚中生。", "達哉彭城公，養心浩無營。", "一覺自復本，妙用皆隨成。", "性通儒佛間，大抵寂與誠。", "云見非見故，執見流爲情。", "名堂雖取相，證實不證名。", "文書每叢委，賓客兹逢迎。", "二諦本無礙，安知堂虚盈。", "優游寄真賞，接引開羣盲。", "登堂一開豁，灑然塵勞輕。"]'),
('37b5bfa7-ef71-42a5-b933-bc4053351e5d','謝梓漕李琮獻甫寄餘甘','馮山','宋','宋诗','song-poetry','','[]','戎南煙瘴地，草木富嘉實。',288,'全唐诗/poet.song.42000.json','["戎南煙瘴地，草木富嘉實。", "名果蓋數品，餘甘乃其一。", "爛漫經暑雨，駢繁向秋日。", "顆肥櫻綴圓，膚嫩李带碧。", "始嘗猶餘木，酸澀固可斥。", "稍味復土性，華池變瓊液。", "冷冽祛酒毒，香芬破茶癖。", "豈徒雜肴核，自可名藥石。", "東蜀部刺史，江南夸聲蹟。", "道與荆公合，詩爲梅老敵。", "邊機屬未靖，使指煩遠適。", "絕塞偶相值，慇懃爲珍惜。", "殘菊雅趣尚，啖薤清讌逸。", "分甘病漳守，筠筒手封羃。", "三年官大道，襟抱塵土積。", "語言變爲市，風騷蕩無跡。", "開封命澡雪，一食至六七。", "冰霜快口吻，塵坌併疏滌。", "古意還五臟，清風生兩腋。", "與公始邂逅，一言甚疇昔。", "生芻感厚意，香草慕前述。", "人道成以友，直諒久無斁。", "磨厲出鋒刃，切磋至圭璧。", "諍友本仁義，拂士忘疹疾。"]'),
('c9a05265-6505-4fb6-81bc-f66c468ec795','送李獻甫知吉州','馮山','宋','宋诗','song-poetry','','[]','六經出晚周，日月懸太虛。',156,'全唐诗/poet.song.42000.json','["六經出晚周，日月懸太虛。", "幾蝕復幾明，微茫炎漢初。", "清識隱虚粹，高風激貪懦。", "翩翩起江湖，泛泛雜鳬雁。", "發揚始使蜀，奔走非素願。", "郎官雖內遷，相去才一間。", "朝廷訪耆艾，人物尚清簡。", "騫騰自兹始，寧慮歲月晏。", "區區無足道，鄉社久息偃。", "未契許投合，相濡念孤蹇。", "迅翮舉莫追，窘步行輙踠。", "把酒難一往，開琴試重援。", "别鶴如可彈，新聲謝悽婉。"]'),
('c1330fde-914a-4950-af48-3c5149e06b13','送上官基察推同年','馮山','宋','宋诗','song-poetry','','[]','我蜀君閩中，相去萬里餘。',48,'全唐诗/poet.song.42000.json','["我蜀君閩中，相去萬里餘。", "同年皆白頭，此别當何如。", "君行久或抳，一出無停車。", "相忘豈人情，時寄西南書。"]'),
('429318c7-d253-4649-8578-0686559eb4e1','送夔漕王宗望蟠叟大夫赴闕','馮山','宋','宋诗','song-poetry','','[]','君子不苟然，每以中道居。',216,'全唐诗/poet.song.42000.json','["君子不苟然，每以中道居。", "處身概有常，爲吏形其餘。", "太原大夫公，使蜀元豐初。", "蜩螗沸清晝，交道狼與狙。", "公時於其間，素藴唯所攄。", "紛擾目不瞬，開濟心自如。", "蜀人恃以安，至今芬名譽。", "更駕漕三峽，應手民瘼除。", "適逢惠澤新，禁網闊且疏。", "攫噬化爲麟，奔馳不能車。", "公無異他日，法度方得梳。", "均齊即人心，簡易平徭書。", "天邊促嚴召，歲晚巾歸輿。", "老成坐廟堂，收實攘浮虛。", "有常豈易得，得見將已歟。", "行看步臺省，自可風簪裾。", "非才共封略，况舊遊門閭。", "贈行期有知，知公當知予。"]'),
('164a31d2-8295-4e1f-a3f0-7740e2bceeea','和利漕徐師旦之才文龍山水之秀','馮山','宋','宋诗','song-poetry','','[]','臘雪洗頑碧，晴鳬浴澄𪑩。',48,'全唐诗/poet.song.42000.json','["臘雪洗頑碧，晴鳬浴澄𪑩。", "物色互磨錯，清輝深不變。", "滄浪與少室，幽人罕兼見。", "少憩託高懷，回頭簿書倦。"]'),
('bb23cf96-ea07-4dde-a8bb-9b9e7371047a','題范亦顔聖鄰同年集後','馮山','宋','宋诗','song-poetry','','[]','聖鄰生西南，豪傑如山東。',252,'全唐诗/poet.song.42000.json','["聖鄰生西南，豪傑如山東。", "倜儻負奇節，脱身起蒿蓬。", "文章學西漢，不作雕篆工。", "東京太學生，議論傾羣公。", "高適遊大梁，馬周隱新豐。", "酒酣吐素蜺，意氣横煙空。", "翻身落州縣，束手如兒童。", "無人解秋隼，摩天看飛冲。", "黄鶴垂兩翅，飲啄雞鶩籠。", "始知命使然，甘作冥冥終。", "資陽數尺墳，萬事隨秋風。", "相從嘉祐初，擊發每兒蒙。", "死生雖云異，坎坷略已同。", "然猶有子棄，孤芳秀珍叢。", "慷慨悲父書，收拾塵土中。", "蘭山四百首，玉佩清玲瓏。", "餘文隱圭璧，夜氣如長虹。", "古人身後名，乃是不世功。", "蜀士志不朽，存者唯卿雄。", "有子兼斯名，昔否今始通。", "聊書附篇末，相與傳無窮。"]'),
('f09f740a-5961-479d-b8a2-a83190efe992','愛石堂','馮山','宋','宋诗','song-poetry','','[]','雙石非梓石，厥初置者誰。',264,'全唐诗/poet.song.42000.json','["雙石非梓石，厥初置者誰。", "埋没不知歲，復有賢者知。", "王分逼漢邕，鄭篆源秦斯。", "今人竟未及，墨本收清奇。", "文字相稱古，銘記兼以詩。", "鐵畫隱石骨，鬰屈蟠蛟螭。", "李丞嗜奇古，見石喜且悲。", "眈眈建華屋，落落刊豐碑。", "爾来三十年，堂在石已移。", "幸未仆作橋，上有車馬馳。", "缺折從瓦礫，疊爲垣墻基。", "一見叢篠間，若與平生期。", "清泉去塵垢，始露金玉姿。", "殷勤還兹堂，如母逢厥兒。", "對以古書卷，環以秋竹枝。", "勝舍結高義，出處相與隨。", "夷齊秉達節，顛沛不少虧。", "豈事燕處玩，可爲終身規。", "嗟嗟石何有，三賞百見欺。", "好惡凡在人，顯晦若有時。", "官滿當捨去，棄置無復疑。", "聊書告神物，爲我當護持。"]'),
('0fe9bddd-0f63-47b2-a0da-8bd5e95e1215','送二十二舍弟赴金堂簿','馮山','宋','宋诗','song-poetry','','[]','巴中倦奔走，歲暮增慘戚。',48,'全唐诗/poet.song.42000.json','["巴中倦奔走，歲暮增慘戚。", "瞻望幾奮飛，那能季行役。", "距家才十舍，身苦萬里適。", "臨老如别何，相看數歸日。"]'),
('dbff4f45-ea83-4791-906b-bf53c20be22e','青塚行','馮山','宋','宋诗','song-poetry','','[]','郊外日暖春溶溶，十里不斷人相從。',168,'全唐诗/poet.song.42000.json','["郊外日暖春溶溶，十里不斷人相從。", "填填車馬上墳去，踏盡青草行人蹤。", "松柏影重楸葉開，一區塚舍全家来。", "展看酹酒聚頭哭，哭盡更把松楸栽。", "隔溪青塚高巍巍，塼片露出空餘碑。", "子孫因官往南北，温暖時節無人知。", "虚有官階又無食，舊日松楸已荆棘。", "不及尋常百姓家，泉中却得兒孫力。", "休休休，有子莫願爲公侯，有孫莫令從官遊。", "每到年年寒食節，尚有一杯羮，来到墳上頭。"]'),
('99759c25-dedf-4f51-ae5c-3944b184f41d','鄰家婦','馮山','宋','宋诗','song-poetry','','[]','鄰家婦，一貧復一富。',109,'全唐诗/poet.song.42000.json','["鄰家婦，一貧復一富。", "舅姑愛憎苦不常，憎貧愛富多心腸。", "富婦初嫁時，身上曄曄生輝光。", "舅姑好財不好義，婦道無復較短長。", "不如貧婦巧且勤，巧能養家勤養親。", "君不見古來烈女傳，往往多是貧中人。", "鄰家婦，一爲烏，一爲鴞，貧婦慈孝富婦驕。"]'),
('5c77a0e3-1d51-4cf3-ac2b-9708f9d5e494','俠少行','馮山','宋','宋诗','song-poetry','','[]','山東自古多才雄，輟耕隴上羞爲農。',172,'全唐诗/poet.song.42000.json','["山東自古多才雄，輟耕隴上羞爲農。", "鄉兵名在萬選中，一日聲價聞天聰。", "十石弩力三石弓，殿前野戰如飄風。", "白錦戰袍腰勒紅，詔容走馬出閶闔，都人仰看如飛鴻。", "歸来意氣人誰及，道逢刺史猶長揖。", "邯鄲白日袖劍行，振武青樓乘醉入。", "傳聞留後收蘭州，姓名御筆親點抽。", "府金百鎰輕一擲，且向塞外隨遨遊。", "自此鋤犂變任俠，夜事椎埋晝馳獵。", "有田無人耕，有子不養家，田間父老長咨嗟。"]'),
('ca003f61-ebc3-4365-a7a9-129d832c936e','採樵行','馮山','宋','宋诗','song-poetry','','[]','朝霞朦朧入林塢，零星背篝腰破斧。',112,'全唐诗/poet.song.42000.json','["朝霞朦朧入林塢，零星背篝腰破斧。", "田家無田有門戶，不免將身犯豺虎。", "禽驚鹿寒木丁丁，一篝數枝千萬聲。", "嚴風裂膚催出日，入澗飲水饑腸嗚。", "縫無尺布舂無粟，菜根掃葉燃難熟。", "留柴趁市將輸官，一錢不救長饑寒。", "年年採樵樵漸少，官家苗役無時了。"]'),
('a32e815c-beb0-45bb-90cb-5cdf2405f5f7','路傍柏','馮山','宋','宋诗','song-poetry','','[]','路傍有柏千尺高，數夫連臂環周遭。',184,'全唐诗/poet.song.42000.json','["路傍有柏千尺高，數夫連臂環周遭。", "十里煙雲護蒼翠，一天風雨寒蕭騷。", "縱横萬蛇入土鬭，扶搖千騎盤空走。", "豈能霜雪歲寒知，自有江山神物守。", "五月炎光燒草木，柏影重重似華屋。", "往還不擇貴與賤，借與清凉解炎酷。", "本来無情柏與人，偶然相值如相親。", "貴侯餘資萬鍾祿，不到流離親骨肉。", "前時仗節徒東歸，觀望風彩爭奔馳。", "族中俛首彈指意，安用富貴摩天爲。", "誰人試從貴侯道，莫從此路爭榮耀，恐爲路傍柏輕笑。"]'),
('8e696fd4-340d-44b0-a68c-5fa3a02f5004','黔江','馮山','宋','宋诗','song-poetry','','[]','黔江遠從思播来，黔中五溪此其一。',128,'全唐诗/poet.song.42000.json','["黔江遠從思播来，黔中五溪此其一。", "東出涪陵與涪會，日抱嵐光照城壁。", "去年黔安方解纜，久倦崎嶇喜飛疾。", "驚湍駭浪或當道，萬馬奔馳兩鋒鏑。", "偶然劃過脱重險，千悔中流無路出。", "瞿塘乘漲秋下峽，猿嘯穿流夜投驛。", "魚腹未葬身尚在，虎牙屢磨魂已失。", "巫陽一歲却歸来，還向江前酒重瀝。"]'),
('02ed4fda-383f-4777-b3ba-89611be0ebe2','八陣磧','馮山','宋','宋诗','song-poetry','','[]','永安宫前瀼西磧，萬流峽口爭奔激。',160,'全唐诗/poet.song.42000.json','["永安宫前瀼西磧，萬流峽口爭奔激。", "秋濤卷地裂山谷，水落依然陣圖出。", "陣形聚拳六十四，傳是武侯親手跡。", "斯人管蕭豈足道，身在巴東心漢室。", "從容所遇皆法制，浩蕩胸中萬分一。", "陰機暗與天地合，壯氣曾將鬼神役。", "至今千載矻不動，渺莽幾深難致詰。", "豈徒豪傑重嗟賞，應有神靈長護惜。", "廟偏裸裎七壯士，酒炙紛紛走巫覡。", "萬事顛倒皆偶然，卧龍無處沾餘瀝。"]'),
('e7ec6885-c84f-46a7-af71-13d6e9326ef9','哭景館吏立之','馮山','宋','宋诗','song-poetry','','[]','去年四月二十七，親見進之没磝盤。',208,'全唐诗/poet.song.42000.json','["去年四月二十七，親見進之没磝盤。", "今年二月十三日，又聞立之死卼白。", "身膏草野心爲誰，區區身後猶讒疾。", "進之一子久乃得，立之一子稱特恩。", "死封疆臣古所重，千載烈士多銜冤。", "立之才武世少敵，胸中意欲呑河湟。", "將軍一劍義自决，塞上擾擾多奔亡。", "前功委棄不復收，李蔡下士皆封侯。", "生人欺鬼不解語，天道反復終相讎。", "昨得二月三日書，猶云持重破賊鋒。", "等閒人事祇十日，使我淚落親書蹤。", "兒癡母老女未嫁，實事無一虛名存。", "相知抱恨寧復論，誰爲往弔洮西魂。"]'),
('87527e12-a950-4eb8-ba81-105721c6707f','答中江程建用知縣','馮山','宋','宋诗','song-poetry','','[]','嘉陵水落沙带霜，舟師治舟還故鄉。',64,'全唐诗/poet.song.42000.json','["嘉陵水落沙带霜，舟師治舟還故鄉。", "中江一别三四年，人情風物俱依然。", "故人寄我江前吟，幽蘭調高無報音。", "流水茫茫恨空瀉，會合合江江溉下。"]'),
('525bf739-b54b-498b-acfe-661c0b8f7724','送滿夷行秀才赴太學','馮山','宋','宋诗','song-poetry','','[]','漢唐諸儒經術淺，事業不及文章多。',128,'全唐诗/poet.song.42000.json','["漢唐諸儒經術淺，事業不及文章多。", "六經意義失原本，次第疏鑿成江河。", "聖朝羣公盡禹力，注海一導横流波。", "淵源太學得至寶，洗出光耀猶鑴磨。", "聖賢德業貴簡易，一氣自在生中和。", "鍼醫馬蹄鑿渾沌，或恐純粹成雕訛。", "君方茂年已知道，歸涉浩渺登嵯峨。", "置身爵祿慶賞外，人跡斷處逢丘軻。"]'),
('1c3ca745-98d2-4998-8141-5f0103fb28c1','寄題宇文之邵公南止亭','馮山','宋','宋诗','song-poetry','','[]','公南九亭名止止，亭不妄作名何爲。',256,'全唐诗/poet.song.42000.json','["公南九亭名止止，亭不妄作名何爲。", "羣公賦咏得深趣，清絕正與斯人宜。", "鋪張止義到無說，使我下筆先遲疑。", "聖賢出處無定轍，俯仰輕重爭毫釐。", "云行非行止非止，由賜狂病淵騫癡。", "公南少年負才術，試仕吐出胸中奇。", "一言齟齬便投袂，自道豈欲求人知。", "公卿文章強且起，舉手謝絕無還期。", "傳家萬卷書史樂，負郭五里松楸悲。", "岷峨嘉景照研席，事攪輒醉醒仍詩。", "有時日晏臥不動，鬰鬰經濟埋如脾。", "太師竹洞枕溫落，龍圖藥圃臨清伊。", "二公止跡不止道，力與名教相扶持。", "今君所處近伊洛，道在不必分高卑。", "文章自可敵行事，荀孟皆我知爲誰。", "亭非俗亭止非止，人物不到西南欺。"]'),
('e590b213-7805-4c32-820c-d925575b35dc','送江衍巨源提舉赴闕','馮山','宋','宋诗','song-poetry','','[]','潼川昔迎公西来，益昌今送公北迴。',320,'全唐诗/poet.song.42000.json','["潼川昔迎公西来，益昌今送公北迴。", "常平使者豈公志，遠地久淹經濟才。", "三年風績不勝頌，欲别有贈心胸開。", "江陽夷蠻互讎格，邊將生事驚風埃。", "連兵巨費久乃定，得失未可相償陪。", "去秋西師出四路，欲舉夏寇除根荄。", "精强挽運一蹉跌，十存四五良可哀。", "河南數州入封略，惡土棄壤如塵灰。", "傳聞敵氣漸衰弱，閫外復委將軍裁。", "借將賀蘭作都護，戍守尚恐難栽培。", "况今秦人極疲敝，菽粟貴重如瓊瑰。", "諸軍零落氣未振，肯聽號令傳風雷。", "看唐南詔吐蕃傳，往往因循成禍胎。", "太上神明照幽隱，廣謀博訪無嫌猜。", "近臣從容合公議，忍使漢地生蒿萊。", "每思一飯三四起，感慨與語何人哉。", "會公還朝方進用，不侍講殿歸霜臺。", "瀘南關右飽聞見，詎肯戲笑隨童孩。", "對揚上前苟可道，願持此語排姦回。", "平生磊落致君意，豈慮言出爲身災。"]'),
('118eb6f1-79fa-487f-a698-b0d7c109ba52','和果倅趙衮良弼平江亭','馮山','宋','宋诗','song-poetry','','[]','牛峰絕頂凌雲閣，形勝潼江照開廓。',160,'全唐诗/poet.song.42000.json','["牛峰絕頂凌雲閣，形勝潼江照開廓。", "涪水臺中隱凡菴，坐對西山横碧落。", "頃嘗登覽放懷抱，鈎掛軒窗捲帷幕。", "氣酣景熟狀不起，一片風騷情索寞。", "充城累身倦未出，無事門庭可羅雀。", "翠筠五瑞掃塵土，澄照清風易椽薄。", "平江最好最後到，隱几凌雲僅依約。", "屏星主人跼閒散，長句森森邀我作。", "漳濱病起吟魂耗，中散慵来筆鋒弱。", "鏗金入木將奈何，手把新篇空愧怍。"]'),
('1f8fa4d6-cf2a-4ebf-a8ef-cac4f811fe3e','送趙良弼知廣安軍','馮山','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','巴黔萬山横楚封，洞庭碧海蛟龍宫。',288,'全唐诗/poet.song.42000.json','["巴黔萬山横楚封，洞庭碧海蛟龍宫。", "潛靈蓄秀天疏通，楚人自古多材雄。", "江陵故都當其胸，人物蕭爽馳英風。", "良弼崛起聲其中，宏偉渾厚如山東。", "才思婉娩春華融，論議慷慨無約豐。", "高步壯領轅不容，徊翔盤紆巫與嵩。", "拏舟向蜀沿涪潼，嘉陵一曲城古充。", "鷹隼倒臂寧久籠，南榮霹靂醒愚聾。", "歸来破裳未及縫，籍才檄起如旋篷。", "瞿唐故交復相從，始適抱子今皆翁。", "天真逍遙飲量洪，世事歷遍詩尤工。", "有時語酣笑未終，環顧四坐皆虚空。", "寒飈戚戚凌疏桐，去路山遠秋溟濛。", "臨老合散情易攻，豈免淚下如兒童。", "髖髀始見斤斧功，鵷鸞一息荆棘叢。", "廣安地卑跼飛冲，席恐未暖行匆匆。", "平時物理相磨礲，郡樂不在卑與崇。", "唱酬自可輕開忠，無事日夕翻郵筒。"]'),
('42dd457b-385a-4cea-aa7e-bd9a0418fdc9','求劉忱明復龍圖爲畫山水','馮山','宋','宋诗','song-poetry','','[]','晉唐諸公重小筆，高價直與才名俱。',384,'全唐诗/poet.song.42000.json','["晉唐諸公重小筆，高價直與才名俱。", "然多華丹少泉石，清格往往人間無。", "至今百存無一二，存者真僞難分區。", "營丘李成稱絕跡，峰巖秀拔非常模。", "穆之灑落亦其亞，玉堂屏上瀟湘圖。", "董屈許范凡數輩，隱隱俗氣藏肌膚。", "乃知山水係絕品，筆墨造化非功夫。", "要之文章之緒餘，世上真巧歸吾儒。", "益昌臺府少文字，見性文室談毗盧。", "龍門雪景生坐隅，山潛水奥爭奔趨。", "倚空直幹鬭孤聳，緣險古道盤縈紆。", "擁衲禪僧對寂寞，攜琴朝士来崎嶇。", "主人肆筆聊自娛，新言默與天機符。", "公家清白傳數世，經濟滿腹冰霜壺。", "一言不用輙掉臂，五年蜀使甘馳驅。", "時將素毫寫胸臆，寧復意外分精粗。", "復古雖清尚許格，與可亦壯非燕徒。", "豈如公思脱覊束，破碎嵩華傾江湖。", "窮冬從公熟窺看，愛重不覺聲嗟吁。", "靈峰北菀助蕭爽，雪不到地風號枯。", "平生好畫已成癖，寧借不喜臨與摹。", "出公門下欠公筆，有類客海遺明珠。", "願公乘興一揮灑，束絹數幅光芬敷。", "異時解組還故廬，皎潔將伴林泉軀。"]'),
('abf437c8-c5c7-440d-b92f-2b0406a103a0','寄題榮守岑象求巖起太博清富樓','馮山','宋','宋诗','song-poetry','','[]','南榮太守傳詩郵，詩題清富城西樓。',224,'全唐诗/poet.song.42000.json','["南榮太守傳詩郵，詩題清富城西樓。", "樓中風物略已盡，行欲摸詠難爲酬。", "憐公謫官不累意，如與萬象同優游。", "偏州隨分與山水，好景散漫無人收。", "昔人知宴不知賞，俗氣未斷煙雲羞。", "凌靈把酒獨長嘯，歲久此地纔風流。", "公帆南國走欲遍，聳秀浩蕩皆窮搜。", "歸来耳目殊未厭，尚恐勝概遺遐幽。", "九疑巖洞識元叟，三湘泉石逢柳侯。", "名賢到處適所寓，非事筆硯搜林丘。", "五年留梓恣登覽，百刹照水江環州。", "得公新篇似相約，正上兜率吟清秋。", "塵中嗜好屑可鄙，恨不徑往追公遊。", "他時三老期一笑，愛閑豈是平生謀。"]'),
('28e8c82a-0c76-4e86-aa3f-a3aeab0cd528','送程嗣恭正基提刑赴闕','馮山','宋','宋诗','song-poetry','','[]','從来貴閥多豪俊，失在矜持驕與泰。',192,'全唐诗/poet.song.42000.json','["從来貴閥多豪俊，失在矜持驕與泰。", "白屋寒門亦有人，往往窮愁損英概。", "得時舊恩報不暇，安能與語功名會。", "驊騮擺首倦銜策，一蹶中途爲傷駃。", "簪纓要重畎畝壯，所養既完發亦大。", "磨礲寶刀挫圭璧，更向天資才術外。", "正基太師丞相後，學愽文清古冠带。", "天機不露驥盤櫪，雲氣雖升蜃沉海。", "平生胸中未一出，萬事食間宜少待。", "語默機巧孟軻盜，顔色睢盱次山丐。", "世故未能以身徇，家聲欲傳道猶在。", "遠别相知試一言，不是向人歌慷慨。"]'),
('6e5a9e9e-7088-4160-b933-591f48d3ac13','和蒲安行題鮮于秀才','馮山','宋','宋诗','song-poetry','','[]','羣峰屋背猿烏啼，二江門前鷗鷺飛。',64,'全唐诗/poet.song.42000.json','["羣峰屋背猿烏啼，二江門前鷗鷺飛。", "雅聞君居頗奇絕，長恨不到心依依。", "仙翁落拓少拘檢，解舞石上凌秋輝。", "整冠投袂或云起，塵土一踏何時歸。"]'),
('25a97274-ac37-42c6-a66a-f3779043d1fd','和任師中舟中見示','馮山','宋','宋诗','song-poetry','','[]','經年雅音曠不聞，客衣彼此俱紅塵。',64,'全唐诗/poet.song.42000.json','["經年雅音曠不聞，客衣彼此俱紅塵。", "六月赤日火照地，仙舟艤在支江濱。", "君年四十已顯官，去去榮路無涯津。", "丈夫未死功業在，但使道富何憂貧。"]'),
('0480b575-86b5-4941-804c-31e2a03ef974','寄上金陵王荆公','馮山','宋','宋诗','song-poetry','','[]','聖賢遺陳跡，文章隱至神。',288,'全唐诗/poet.song.42000.json','["聖賢遺陳跡，文章隱至神。", "北天開盛際，南國起斯人。", "兼濟希先覺，公傳襲大醇。", "卑飛隨世俗，默觀養經綸。", "僶俛懷鉛槧，徊翔表縉紳。", "英聲搖海岳，高步出風塵。", "去就遲難進，謀猷久未伸。", "兩朝雖顧遇，大節每逡巡。", "四海傾台輔，千齡偶聖辰。", "有爲今道德，無間古君臣。", "雕琢唐文盛，更張漢法新。", "風霆傳信令，束縳解生民。", "所志惟膏澤，當除亦斧斤。", "寸心勞遠御，獨手助洪鈞。", "鐘鼎無前蹟，江湖自在身。", "功名非雅意，出處自天真。", "鴻雁雲霄勢，芝蘭道路春。", "軻雄平可駕，房魏淺非倫。", "江漢無良産，衣冠竊濫巾。", "才非當世用，仕爲有時貧。", "銜策驅馳久，風波出没頻。", "古心終少合，老態强難馴。", "名教誰依託，文書但隱淪。", "師門常耿耿，相府舊循循。"]'),
('c04016f5-ce81-4e9b-977d-8446a0b8a4bb','寄上潁昌范蜀公','馮山','宋','宋诗','song-poetry','','[]','大老歸真主，前朝遺數公。',240,'全唐诗/poet.song.42000.json','["大老歸真主，前朝遺數公。", "精神時一會，出處道皆同。", "起潞儀刑地，煩温燮理功。", "及觀光祿表，深見古人風。", "聘幣来何厚，安車願不東。", "光華膺政殿，僶俛就祠宫。", "論議高踰武，文章遠繼雄。", "退身無少憾，憂國有餘忠。", "几杖誠先覺，衣冠爲一空。", "千齡重際遇，二聖極優崇。", "將相交游盛，朝廷禮數隆。", "一星容處士，四海望冥鴻。", "箕潁紛囂外，岷峨氣象中。", "楚詞清更適，舜律遠相通。", "庭玉連城價，孫枝百尺桐。", "聖賢今日是，河漢幾時窮。", "晚輩徒瞻仰，先生蓋始終。", "冰霜嚴皎潔，塵滓坐銷融。", "信史知將貴，聲詩恨不工。", "東齊如見録，光彩附垂虹。"]'),
('be1499a2-e8c3-479a-a09f-82c150edce7d','和文侍中錦雞','馮山','宋','宋诗','song-poetry','','[]','微生非自異，翠樾願深藏。',96,'全唐诗/poet.song.42000.json','["微生非自異，翠樾願深藏。", "谷口逢羅網，人間重采章。", "全身珠綴絡，一項錦成囊。", "易警烏啼早，難馴雉性剛。", "僅能逃鼎味，何幸識台光。", "黄閣恩優厚，青山思渺茫。", "鸚言來隴坻，孔翠别炎方。", "既獲安棲地，寧須憶故鄉。"]'),
('106a50c5-47a7-4b55-a25c-d54ff4d37c78','和梓漕陳帨誠伯弭節堂','馮山','宋','宋诗','song-poetry','','[]','妖氛憑絕塞，皇武慰羣情。',120,'全唐诗/poet.song.42000.json','["妖氛憑絕塞，皇武慰羣情。", "並命儒臣起，同謀將略明。", "前鋒殱醜虜，降仗委高旌。", "拓境新圖展，收功寸草横。", "投戈宜偃息，奠枕覺澄清。", "廣榭宏經構，羣公共落成。", "唱酬風月冷，談議鬼神驚。", "錦繡移將合，琅玕種即生。", "南方天外闊，北斗坐間傾。", "且享憂勤樂，除書恐再更。"]'),
('4c4b18d7-d5b4-4bbe-9049-2ed98fe9718f','閬中蒲氏園亭十詠 方湖','馮山','宋','宋诗','song-poetry','','[]','蒲柳春陰重，禽魚晚景多。',24,'全唐诗/poet.song.42000.json','["蒲柳春陰重，禽魚晚景多。", "輕舟乘酒去，明月扣舷歌。"]'),
('d21a42fb-49a7-4474-af2b-3ed0016e8de2','閬中蒲氏園亭十詠 清蟾橋','馮山','宋','宋诗','song-poetry','','[]','石面苔封合，波心月照空。',24,'全唐诗/poet.song.42000.json','["石面苔封合，波心月照空。", "仙翁行道處，清影露華中。"]'),
('20e4c34b-a215-42fb-afec-8cceba5f94a5','閬中蒲氏園亭十詠 芙蓉溪','馮山','宋','宋诗','song-poetry','','[]','野景宜花看，秋芳近水多。',24,'全唐诗/poet.song.42000.json','["野景宜花看，秋芳近水多。", "溪流光不斷，千尺粉紅羅。"]'),
('52aafd41-65cd-49d3-9fe9-9dbd7159e5b5','閬中蒲氏園亭十詠 蓮池','馮山','宋','宋诗','song-poetry','','[]','疊疊波紋綠，搖搖雨氣香。',24,'全唐诗/poet.song.42000.json','["疊疊波紋綠，搖搖雨氣香。", "菱歌誰與發，秋興似江鄉。"]'),
('33090ef5-9e6b-4d8f-b4b6-19ea863e3c22','閬中蒲氏園亭十詠 朝真臺','馮山','宋','宋诗','song-poetry','','[]','聳秀山崗合，回環斗柄臨。',24,'全唐诗/poet.song.42000.json','["聳秀山崗合，回環斗柄臨。", "焚香無俗慮，一息見天心。"]'),
('f576d5ca-e500-4f76-9816-b2f9f15f1a10','閬中蒲氏園亭十詠 白蓮堂','馮山','宋','宋诗','song-poetry','','[]','平池風菡萏，照岸雪玲瓏。',24,'全唐诗/poet.song.42000.json','["平池風菡萏，照岸雪玲瓏。", "無限騷人意，欄干霽色中。"]'),
('90cefb80-6fa1-4458-9117-de967624a05a','閬中蒲氏園亭十詠 涵碧亭','馮山','宋','宋诗','song-poetry','','[]','日影搖吟筆，煙光落酒盃。',24,'全唐诗/poet.song.42000.json','["日影搖吟筆，煙光落酒盃。", "猶嫌池外俗，移入鏡中来。"]'),
('ca8ab423-2fb2-4a5b-8cf5-f47fe121430a','閬中蒲氏園亭十詠 魚池','馮山','宋','宋诗','song-poetry','','[]','活水停無滓，嘉魚養不驚。',24,'全唐诗/poet.song.42000.json','["活水停無滓，嘉魚養不驚。", "休言濠上意，秋鱠與春羮。"]'),
('5f7da02d-68f3-4c71-8a84-3b3908475d14','閬中蒲氏園亭十詠 稻畦','馮山','宋','宋诗','song-poetry','','[]','物外溪山樂，窮中歲月優。',24,'全唐诗/poet.song.42000.json','["物外溪山樂，窮中歲月優。", "斯人招不起，十頃稻田秋。"]'),
('348803d0-84d1-4ab2-95b0-db92bd5a2d4d','閬中蒲氏園亭十詠 草菴','馮山','宋','宋诗','song-poetry','','[]','竹影搖金翠，泉聲響佩環。',24,'全唐诗/poet.song.42000.json','["竹影搖金翠，泉聲響佩環。", "菴前春日落，人向定中還。"]'),
('95cf0bd8-711a-4ecb-be55-eb8889a5496c','偶成','馮山','宋','宋诗','song-poetry','','[]','長歌詠考槃，灑落正休官。',48,'全唐诗/poet.song.42000.json','["長歌詠考槃，灑落正休官。", "愛竹臨溪倚，攜書坐石看。", "足煩猶解屨，髪禿自忘冠。", "願爲無多欲，持身到處安。"]'),
('f2dfc4f8-17fe-42a7-a23f-71de9254ba76','溪行','馮山','宋','宋诗','song-poetry','','[]','野景久不見，溪行如有逢。',48,'全唐诗/poet.song.42000.json','["野景久不見，溪行如有逢。", "長苔梳綠髪，淺水卧青龍。", "石出沙仍带，橋危柱半舂。", "日欹猶下馬，赤脚洗塵蹤。"]'),
('540da008-fec1-44e6-acfb-2ee619b3370b','春閒','馮山','宋','宋诗','song-poetry','','[]','好景雖心賞，多情半睡降。',48,'全唐诗/poet.song.42000.json','["好景雖心賞，多情半睡降。", "春聲蜂遶屋，晴意鳥臨窗。", "漸老依花徑，無機付酒缸。", "人生求適性，何苦自樅樅。"]'),
('94565d83-92a7-4a27-b034-31eb8c414118','即事二首  其一','馮山','宋','宋诗','song-poetry','','[]','閉戶塵緣息，忘機眼病除。',48,'全唐诗/poet.song.42000.json','["閉戶塵緣息，忘機眼病除。", "就閒因教子，臨老更知書。", "擺亞風前稻，婆娑雨後蔬。", "窮中方得趣，門外已巾車。"]'),
('754746a9-acbb-4ab2-a7fa-9582256dd1bb','即事二首  其二','馮山','宋','宋诗','song-poetry','','[]','舊病花浮眼，衰容雪到眉。',48,'全唐诗/poet.song.42000.json','["舊病花浮眼，衰容雪到眉。", "風塵憐客久，筋力恨歸遲。", "所得真如夢，無厭固巳癡。", "不知緣盡處，猶有幾多時。"]'),
('4a8ca46d-d4b5-488f-981f-4f1398b443b5','漁翁','馮山','宋','宋诗','song-poetry','','[]','短棹撥輕舟，風恬江上遊。',48,'全唐诗/poet.song.42000.json','["短棹撥輕舟，風恬江上遊。", "機心重浪底，生計一鈎頭。", "盡日不多得，中懷無寸憂。", "夜深何處宿，孤嶼笛聲秋。"]'),
('3fd248b4-fa6e-42e0-a557-7927f1f3048c','野澗','馮山','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','蒼莽長江迥，紆回小澗幽。',48,'全唐诗/poet.song.42000.json','["蒼莽長江迥，紆回小澗幽。", "勢尋山脚轉，聲傍草根流。", "暴雨沙汀漲，清風岸葦秋。", "行行須到海，毋爲曲灣留。"]'),
('7fe44359-580c-41b7-990d-0f38b27df801','和鮮于頃秀才見題小軒','馮山','宋','宋诗','song-poetry','','[]','一室僅容拙，新年尤好閒。',48,'全唐诗/poet.song.42000.json','["一室僅容拙，新年尤好閒。", "翻書消白晝，隱几有青山。", "人事少迎合，英流長往還。", "此心猶有恨，半在史文間。"]'),
('af21ca3b-9453-40db-a4c5-4528b4b7255c','和蒲安行誠之見喜新受梓倅','馮山','宋','宋诗','song-poetry','','[]','故國連芳草，吾親在白雲。',48,'全唐诗/poet.song.42000.json','["故國連芳草，吾親在白雲。", "榮歸慚主父，虛語類終軍。", "劍閣雖吟戀，潼江亦喜聞。", "惟愁良友别，分手復何云。"]'),
('d15a79a6-9ede-4d99-b697-169015ceb89f','擊甌樓','馮山','宋','宋诗','song-poetry','','[]','石上辭人賦，城高古郡樓。',48,'全唐诗/poet.song.42000.json','["石上辭人賦，城高古郡樓。", "能將天外意，寫盡曲中愁。", "湘瑟曾誰聽，巴江祇自流。", "倚欄吟月午，臨下更遲留。"]'),
('7ffd68e7-3422-4ce9-bd25-8d2e02199d35','龍門洞','馮山','宋','宋诗','song-poetry','','[]','古洞嵌巖活，青山氣象渾。',120,'全唐诗/poet.song.42000.json','["古洞嵌巖活，青山氣象渾。", "應龍常隱處，流水不知源。", "鬭險雙峰秀，凌虛古木尊。", "怪藤寒覆坐，修竹盡當門。", "混沌誰開鑿，雲煙自吐吞。", "深盤通海脉，横透露天痕。", "日影循崖腹，泉聲遶石根。", "江前塵不到，物外景常存。", "避地仙蹤跡，清人俗夢魂。", "功名歸未得，回首謝巖閽。"]'),
('2b3e0fc7-2d07-4733-a560-0bcbeec55bb5','題靈溪寺','馮山','宋','宋诗','song-poetry','','[]','野寺無俗氣，勝遊方此迴。',48,'全唐诗/poet.song.42000.json','["野寺無俗氣，勝遊方此迴。", "水清巴字近，僧慧錦屏来。", "秋閣山要起，溪門竹引開。", "塵蹤不須掃，留恨寄蒼苔。"]'),
('4a38e780-a3d0-477c-9c6c-fc9be6238d1c','曲細道中','馮山','宋','宋诗','song-poetry','','[]','一溪流石色，萬木聳山陰。',48,'全唐诗/poet.song.42000.json','["一溪流石色，萬木聳山陰。", "地僻有佳景，眼明勞寸心。", "墜猿猶掛壁，驚鳥忽移林。", "莫問去程遠，行人方苦吟。"]'),
('a505233a-cde3-47ff-9916-a5c028f9d14c','巴州聖壽寺小閣','馮山','宋','宋诗','song-poetry','','[]','危閣已可愛，野僧仍見邀。',48,'全唐诗/poet.song.42000.json','["危閣已可愛，野僧仍見邀。", "灘稀逢水靜，城近覺山朝。", "露發秋光潤，風吹雨意銷。", "巴童不知我，孤興在漁樵。"]'),
('e59a46a6-2407-403a-911e-20e8c1e7a272','廣灘驛寄知縣盧大年職方','馮山','宋','宋诗','song-poetry','','[]','轉步異南北，一程千萬盤。',48,'全唐诗/poet.song.42000.json','["轉步異南北，一程千萬盤。", "將身試豺虎，無路出林巒。", "數屋近相接，孤城猶認看。", "回惶中夜發，况守二年官。"]'),
('39d5c8f2-a8c4-47c8-bd4d-b00371a10f6c','詠雪','馮山','宋','宋诗','song-poetry','','[]','半夜風威壯，今朝瑞雪呈。',288,'全唐诗/poet.song.42000.json','["半夜風威壯，今朝瑞雪呈。", "徊翔如有待，附著不勝輕。", "疊疊雲篩下，番番雨簇成。", "雕鑴非衆巧，融結似無精。", "河漢潛欺没，乾坤欲混并。", "漫空雖結白，觸處已縱横。", "枯茂全妝出，窪隆一概平。", "參差相掩覆，散亂或逢迎。", "遠岫依稀失，高松獨自榮。", "光明通鬼穴，肅殺下天兵。", "揮霍偏隨馬，憑陵或遶城。", "威稜生劍戟，物色儼冠纓。", "樓閣危將墮，烏鳶噤不鳴。", "巖封蹲豺起，岸斷蟄龍驚。", "地軸猶疑折，林梢不易擎。", "穠寒排瘴毒，和氣入春耕。", "雖學峨峨勢，其如薄薄名。", "暗銷知地暖，坐對覺神清。", "交互當門舞，玲瓏照眼明。", "味宜茶品試，力與酒權爭。", "佳景誰能賞，幽吟似有情。", "開罇煩點綴，喣筆爲題評。", "舊說三農慶，量深一尺盈。", "憂民心正切，擊缶助歡聲。"]'),
('80bc29e5-bedc-429c-b30e-45ff346f3693','和普守勾士良輔元大夫見寄二首  其一','馮山','宋','宋诗','song-poetry','','[]','相知思命駕，見教每書紳。',48,'全唐诗/poet.song.42000.json','["相知思命駕，見教每書紳。", "咫尺去無路，奮飛嗟此身。", "貪廉雖異操，出處幸爲鄰。", "肯笑劉郎病，前頭萬木春。"]'),
('528baa32-a082-41a9-a84c-3d74075c3379','和普守勾士良輔元大夫見寄二首  其二','馮山','宋','宋诗','song-poetry','','[]','溪邊洗俗塵，林下解朝紳。',48,'全唐诗/poet.song.42000.json','["溪邊洗俗塵，林下解朝紳。", "車馬慵應客，漁樵暫寄身。", "置書煩有位，釀酒畏比鄰。", "又欲西州去，峨眉看一春。"]'),
('e4d140bb-ffd7-4d18-a316-f3f0b950f563','和眉守周尹正孺端公春遊醴泉','馮山','宋','宋诗','song-poetry','','[]','捧擁行飛蓋，嬉遊立避驄。',48,'全唐诗/poet.song.42000.json','["捧擁行飛蓋，嬉遊立避驄。", "風煙寒食近，笑語故人同。", "樂轉諸天外，川平一掌中。", "回頭相與愧，容易出塵籠。"]'),
('111179ba-8c2b-4ff7-b11a-cf7395e56ef7','和周正孺郡園新霽','馮山','宋','宋诗','song-poetry','','[]','湖上多幽景，囊中尚賜金。',48,'全唐诗/poet.song.42000.json','["湖上多幽景，囊中尚賜金。", "清尊宜北海，嘉節又山陰。", "曉日雲輕放，林花水倒沉。", "朅来相伴醉，應會主人心。"]'),
('1e10cac5-b17e-44a7-8d8c-a5e4ffd5d944','和程濬治之秘監贈楊竦中立朝散','馮山','宋','宋诗','song-poetry','','[]','身似悲鳴驥，家如濩落瓢。',48,'全唐诗/poet.song.42000.json','["身似悲鳴驥，家如濩落瓢。", "買居悲糞壤，數俸怯薪樵。", "壽隱三家近，征商百步遙。", "無心隨所寓，塵滓自冰銷。"]'),
('c15c9f21-2fb8-4e8d-96b6-06202c95c841','和吕開少蒙提刑家園茶','馮山','宋','宋诗','song-poetry','','[]','蜀品固難名，家園未有聲。',48,'全唐诗/poet.song.42000.json','["蜀品固難名，家園未有聲。", "曉籃親手擷，俗客尚心輕。", "瑞霧吹還合，仙風坐欲生。", "因知栽植意，留與子孫清。"]'),
('af654283-54d2-4780-b836-5f00a45e731b','和張若愚子發秘丞同年見寄二首  其一','馮山','宋','宋诗','song-poetry','','[]','歲月磨將老，蛟龍蟄未伸。',48,'全唐诗/poet.song.42000.json','["歲月磨將老，蛟龍蟄未伸。", "文章俱不意，功業竟何人。", "孤跡每一轍，衰鄉餘幾春。", "扁舟思共濟，滄海闊無津。"]'),
('d8ee0412-fb69-4728-883c-9b9d65a6dfda','和張若愚子發秘丞同年見寄二首  其二','馮山','宋','宋诗','song-poetry','','[]','意氣同歸趣，生平幾合離。',48,'全唐诗/poet.song.42000.json','["意氣同歸趣，生平幾合離。", "遙懷初得信，相喣似忘機。", "世態分難合，人情老自知。", "莫將身徇物，憔悴變鬚眉。"]'),
('06f51914-0aef-4592-80c6-033849e266a6','和湖州文同與可學士見寄','馮山','宋','宋诗','song-poetry','','[]','聞乞湖州去，交親不與謀。',48,'全唐诗/poet.song.42000.json','["聞乞湖州去，交親不與謀。", "京塵收馬足，汴水放船頭。", "試茗春歸渚，題詩月滿樓。", "散人吟不盡，苕霅一溪秋。"]'),
('10cf04eb-a728-4959-91c5-4a8791308136','送利漕劉明復朝議','馮山','宋','宋诗','song-poetry','','[]','中山元魏後，數世十三傳。',288,'全唐诗/poet.song.42000.json','["中山元魏後，數世十三傳。", "皆在河南葬，初從代北遷。", "中書謀定策，大理力扶顛。", "渝國乘機日，唐公起義年。", "議高都尉識，名累侍郎賢。", "原武輸期集，東阿舊俗悛。", "河陰才被詔，戶部志繩愆。", "八子生中葉，三台共一躔。", "洪洞城不下，工待政無前。", "昭輔書儀集，明宗禮意全。", "中丞安出處，藝祖首詳延。", "學士清臺閣，咸平起澗瀍。", "斯文醇復古，宏議自摧堅。", "江漢源何巨，公侯兆已圓。", "信辭師魯誌，佳氣尹樊阡。", "秘監花儒將，緱山酒地仙。", "看公承遠構，發跡向孤騫。", "浩蕩窮經笥，縱横信筆椽。", "巾箱遺紫綬，伯仲襲青氈。", "辨論多兵略，澄清累使權。", "鳳鳴雄屏翰，鶉首富刀泉。", "詔自南臺下，車隨北斗旋。", "鵷鴻思舊侣，嵩少望歸鞭。", "師節頻輕伏，戎腥未一湔。"]'),
('81625c7d-2c6f-43e9-ac0d-6266811852bb','送王求柬之寺丞歸戎州','馮山','宋','宋诗','song-poetry','','[]','喜作送君詩，戎南人物稀。',48,'全唐诗/poet.song.42000.json','["喜作送君詩，戎南人物稀。", "文章詹首變，錦繡助先歸。", "門卷容高蓋，江山照綵衣。", "不須攻錯節，鵰鶚自横飛。"]'),
('2e9a9d05-4456-48f1-aa05-79dcdd40037d','效皮陸體藥名詩寄李獻甫','馮山','宋','宋诗','song-poetry','','[]','半夏勞奔走，當歸計未成。',240,'全唐诗/poet.song.42000.json','["半夏勞奔走，當歸計未成。", "向烏頭雪白，雖遠志澄清。", "白屋遊偏早，青雲夢數驚。", "預知皆係命，無患可傷生。", "泉水懷鄉國，靈仙得古城。", "萎蕤差病力，安息媿民情。", "蘭草園池靜，槐花道路平。", "野翁宜散誕，故紙任縱横。", "問話思黄葉，論文憶長卿。", "餘糧添瓮盎，亂髪散簪纓。", "紫蒨江山秀，婆娑桂柏榮。", "楓香餘雨氣，桐葉變秋聲。", "險語嘗鉤吻，昏瞳屢决明。", "鸕鷀閒自酌，琥珀向誰傾。", "莨宕官資淺，螵蠨活計輕。", "每將蘇子校，多謝使君名。", "滿把黄金屑，知音白玉英。", "青箱空聚古，敗將敢論兵。", "苦練詩方就，旁通筆未精。", "前賢如及已，海藻願題評。"]'),
('d10b745b-ff22-42b5-850c-1e36bdb902af','和新成都知府鄧潤甫温伯內翰道中見寄','馮山','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','畫舸秋離峽，長江水齧堤。',288,'全唐诗/poet.song.42000.json','["畫舸秋離峽，長江水齧堤。", "郡樓高送别，客袂摻分睽。", "前後聲難繼，升沉分不齊。", "私心常有待，得意幸相攜。", "千里聞鳴鳳，三年倦割雞。", "一哀纒性命，萬事錯端倪。", "英俊聯翩起，清華直上躋。", "平生依筆硯，俛首失鋤犂。", "同嗜餐秋菊，忘言病夏畦。", "精粗分玉石，去住即雲泥。", "近列多鴛鷺，誰人享駃騠。", "徊翔趨鳳閣，隱約駕雞栖。", "訓誥資温潤，衣冠出品題。", "風流清憲府，威望肅朝閨。", "戲彩江湖樂，觀濤歲月稽。", "還朝垂拱北，易帥華陽西。", "舊德傾中外，歡謠浹庶黎。", "忽聞旌棨近，頓解簿書迷。", "一笑何勝喜，高談爲少低。", "長篇追杜老，餘論及曹谿。", "把酒聽新闋，尋山傍小蹊。", "欹斜行疊嶂，空曠上危梯。", "拾掇留樽俎，蕭疏愧糗藜。", "故人難會遇，壯士合悲啼。"]'),
('7e48a895-e85e-4e1a-8f3c-b38aaef31391','和鄧內翰遊烏奴寺','馮山','宋','宋诗','song-poetry','','[]','萬險初離峽，三程未到關。',48,'全唐诗/poet.song.42000.json','["萬險初離峽，三程未到關。", "相歡才把酒，偷暇更尋山。", "古意登臨外，人生笑語間。", "一茶遊興盡，簫鼓欲催還。"]'),
('04282d68-376f-4412-96bb-b77343cc97c6','和徐之才雪','馮山','宋','宋诗','song-poetry','','[]','農事方春作，田苗待雪催。',288,'全唐诗/poet.song.42000.json','["農事方春作，田苗待雪催。", "忽從天外降，尤勝臘前来。", "枯槁全妝飾，勾萌暗養培。", "格清徒自照，體弱不勝挼。", "有勢離還合，無情去却迴。", "乾坤迷境界，造化始元胎。", "氣凜侵帷幌，身輕寄草莱。", "匿瑕漫糞壤，銜巧綴條枚。", "空際如難集，毫端已共偎。", "濃寒流遠蜀，嘉兆叶清臺。", "既渾山兼澤，寧分石與瑰。", "饑鳶蹲木杪，凍虎卧巖隈。", "積恐江城滿，重疑棧閣摧。", "誰居梁苑右，或遡剡溪洄。", "凝沍陰雖勝，沾濡旱可摧。", "雕鑴窮物象，皎潔離風埃。", "雨脚紛猶雜，雲頭重不擡。", "豪門張燕席，貧竈擁寒灰。", "且喜蒙膏澤，仍知免沴災。", "斯民爭慶賀，高會與歡咍。", "把酒看宜醉，洪爐守至煨。", "傳聞詩句好，罷聽樂聲嗺。", "灑落吟情健，玲瓏霽色開。", "營丘無復見，誰爲寫皚皚。"]'),
('0aec45aa-c3b4-4abf-8f7b-fd87a5d320ec','和徐之才浮萍','馮山','宋','宋诗','song-poetry','','[]','瀟灑春容靜，飄搖水性柔。',288,'全唐诗/poet.song.42000.json','["瀟灑春容靜，飄搖水性柔。", "根從何處起，身任此生浮。", "得地輕依託，隨波旋去留。", "潢汙深不采，溟渤望空悠。", "花蕊看還落，蕉心久未抽。", "豈知經夜雨，便欲障江流。", "晚入吳歌唱，晴邀漢女遊。", "翠連芳草渡，寒映綠楊樓。", "碎剪神工巧，平鋪澤國幽。", "微軀焉足道，浪跡更誰收。", "踏破閒行鷺，衝開暖上鰌。", "但能知委順，何用校稀稠。", "謾欲通河漢，寧虞踐馬牛。", "迸從菱芡密，如把芰荷揉。", "寂寂苔成陣，紛紛芥作舟。", "屈騷遺故事，湛賦壯前猷。", "蛙躍沾雙股，龜行蔽六眸。", "聯居如有守，遠近亦無求。", "别浦千重恨，吟塘萬點愁。", "生涯隨所寓，細域浩難籌。", "野色宜茶竈，仙姿泛酒甌。", "清芬傳澗沚，餘思滿汀洲。", "暗與蓴絲結，多爲荇蔕鈎。", "豈專嬉雁鶩，自可覆蛟虬。"]'),
('b355e706-26d5-47cf-9c9e-424eac11b511','和徐之才巡按見寄','馮山','宋','宋诗','song-poetry','','[]','捫參趨遠道，首蜀下青泥。',288,'全唐诗/poet.song.42000.json','["捫參趨遠道，首蜀下青泥。", "江遶縈紆带，山盤屈曲梯。", "何時巖腹斷，自古客心低。", "峽盡逢寧武，天寛類寶雞。", "東窮巴嶺北，南轉梓潼西。", "地共猿猱食，居同鳥雀栖。", "風霜傳一檄，玉帛走千蹊。", "力責多傭父，窮輸或嫁妻。", "上憂分使節，僉議輟朝圭。", "素志施膏澤，虛懷去町畦。", "垂鞭防馬憊，含哺止兒啼。", "夜寢無寧席，朝餐或茹梨。", "驅馳宣詔令，歌舞慰童齯。", "按部經雙劍，迎壺滿見溪。", "政清冰出凌，民附水淫堤。", "指穴收毚兔，搜羣去狠羝。", "吏悛藏乳虎，人樂戲春麛。", "驛轉悠千里，秋霖動一犂。", "憂勞如有病，暴露欲生黧。", "委箧書爭報，封囊藥自題。", "茶塵思鳥觜，羮野憶駝蹄。", "過雁晴逾叫，殘蟬曉更嘶。", "萬愁休入耳，數酌且温臍。", "聖治幾仁壽，宸衷念庶黎。"]'),
('3cc8247c-869c-472f-a7b9-9a2206a20a37','和徐之才宿孔溪亭驛早行','馮山','宋','宋诗','song-poetry','','[]','孔憂寧煖席，劉髀不禁鞍。',48,'全唐诗/poet.song.42000.json','["孔憂寧煖席，劉髀不禁鞍。", "夜永無歸夢，山深正苦寒。", "行鉦催早發，晨鼎薦芳酸。", "誰識驅馳意，憂民萬事端。"]'),
('73b44c67-7f42-4a92-9a3e-fc868aac3901','和徐之才春晴偶成句皆雙關','馮山','宋','宋诗','song-poetry','','[]','雲容收雨意，草色妬花妍。',48,'全唐诗/poet.song.42000.json','["雲容收雨意，草色妬花妍。", "詩苦是真樂，酒醒方爛眠。", "園亭無限景，笋蕨不論錢。", "耳目因成僻，江山似有緣。"]'),
('28b2008c-f48f-465a-89e1-d4b177e7e95e','寄高梁守勾輔元','馮山','宋','宋诗','song-poetry','','[]','北按經時出，南歸計日趨。',48,'全唐诗/poet.song.42000.json','["北按經時出，南歸計日趨。", "幽花明澗水，細雨潤春途。", "就歇開新醖，催行趁早餔。", "故人休問吏，相見且歡娛。"]'),
('41cc3678-7d2a-4fc0-a710-00c0d10bea29','發新安驛','馮山','宋','宋诗','song-poetry','','[]','偃蹇隨雞起，衰羸索酒扶。',48,'全唐诗/poet.song.42000.json','["偃蹇隨雞起，衰羸索酒扶。", "風鉦嚴道從，霧燭轉崎嶇。", "迎馬開熊幟，環舁簇虎殳。", "山中耳根靜，清曉厭騶呼。"]'),
('7e0faf19-24eb-47ad-b466-8a00c3861196','武侯廟','馮山','宋','宋诗','song-poetry','','[]','四百源流盡，三分氣燄高。',288,'全唐诗/poet.song.42000.json','["四百源流盡，三分氣燄高。", "西州稱險隘，玄德夸英豪。", "統正圖王策，關張汗馬勞。", "相雄爭勝負，所得僅纖毫。", "當世安危慮，斯人智識滔。", "潛身規去就，擇主事遊遨。", "仗順親歸漢，平凶首問曹。", "河間屠血肉，江表戰風濤。", "雅意存中國，單師靜不毛。", "安知深政術，指畫露兵韜。", "顧託情尤重，君臣義可褒。", "南征才解甲，北伐遽投醪。", "渭水開營壁，祁山擁節旄。", "乾坤悲拆裂，荆棘誓鋤薅。", "遠結孫權援，親將仲達鏖。", "劉宗難再起，郭塢已長號。", "家國猶殷富，衣冠亦俊髦。", "中途亡轡策，束手類猿猱。", "事業垂千載，風流尚一陶。", "民思夔子國，廟枕蜀江皋。", "壽史徒譏議，裴碑自固牢。", "丹青嚴壯觀，松檜盡蕭騷。", "醜虜終爲患，長弓未見櫜。", "吁嗟擒縱術，祠下涕霑袍。"]'),
('60bd95a3-6a43-43d7-8b16-e85ed23b3c43','瞿塘峽','馮山','宋','宋诗','song-poetry','','[]','勝絕瞿塘險，西陵古地形。',288,'全唐诗/poet.song.42000.json','["勝絕瞿塘險，西陵古地形。", "巴江深洞穴，蜀主舊門庭。", "王氣吞三峽，神工出五丁。", "斜長天一綫，相對石雙屏。", "瀑擊巖巒瘦，雲蒸草木腥。", "衆流趨灔澦，遠意會滄溟。", "顧盼如無地，幽陰似有靈。", "白鹽懸日月，黑石鼓雷霆。", "鑱鑿餘痕在，高深巨勢停。", "魚龍憑險怪，煙霧鎖沉冥。", "念昔窮探賾，嘗言駭觀聽。", "波濤真激箭，舟楫遽奔星。", "倒掛傷猿足，横飛羡鳥翎。", "死生期一瞬，出没類浮萍。", "葉上憑忠信，胸中混醉醒。", "人煙逢瀼岸，語笑落沙汀。", "瀝酒重灘下，回頭萬仞青。", "停橈詢故老，借筆潤圖經。", "二孟連稱帝，三川恃建瓴。", "關防雖鞏固，基業旋飄零。", "藝祖收長策，神旗指不寧。", "彦疇空死節，曹翰首開扃。", "五嶺劉歸國，重湖馬就刑。", "磨崖誰刻此，遠續孟陽銘。"]'),
('abe7b1b8-27cc-4bfe-bc8e-5d5b30acbfa4','東陽灘','馮山','宋','宋诗','song-poetry','','[]','蠢肕山窮處，東陽石鬭間。',48,'全唐诗/poet.song.42000.json','["蠢肕山窮處，東陽石鬭間。", "數傾舡簸蕩，萬觸水回環。", "遊子真亡命，忠臣固厚顔。", "捨舟途入險，平地幾時還。"]'),
('90248829-2311-4e95-b8a9-01f01cdcac0c','施州道上遇雪','馮山','宋','宋诗','song-poetry','','[]','易下山中雪，初寒塞上途。',48,'全唐诗/poet.song.42000.json','["易下山中雪，初寒塞上途。", "郵燈催客起，澗水雜猿呼。", "密綴林驚秀，輕蒙石變枯。", "無人来寫取，十幅李成圖。"]'),
('b0b74280-9106-48ce-9ff1-da8e52edd167','宿水轉寺','馮山','宋','宋诗','song-poetry','','[]','殿閣逢僧刹，煙嵐瀉路隅。',48,'全唐诗/poet.song.42000.json','["殿閣逢僧刹，煙嵐瀉路隅。", "徑深羣柏老，溪轉一峰孤。", "已到身猶聳，纔閒氣便蘇。", "巗禽知客意，臨曉解相呼。"]'),
('6caa1005-deb8-4b39-bd4f-7fe356e35650','丁卯除夜','馮山','宋','宋诗','song-poetry','','[]','庭罷驅儺戲，門收爆竹盤。',48,'全唐诗/poet.song.42000.json','["庭罷驅儺戲，門收爆竹盤。", "酒香添臘味，夜氣雜春寒。", "歲序張燈守，人情遇節歡。", "明朝五十八，消息近休官。"]'),
('49a19967-a078-4611-8ba3-c0e457fb41e2','黄甘寄李獻甫','馮山','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','果山多果遍林丘，惟有黄甘格最優。',384,'全唐诗/poet.song.42000.json','["果山多果遍林丘，惟有黄甘格最優。", "繁結幾經秋雨熟，完滋宜带晚霜收。", "霞餘點綴青林遠，星散玲瓏綠葉稠。", "秀色盈衢爭委市，穠香浮水半通舟。", "金苞爛漫差三等，乳蒂龍鐘占上游。", "一宴嘗珍皆絕品，萬錢要價或輕酬。", "盤筵皎潔如圓蓋，梨栗粗凡似贅疣。", "藴藉佳賓忻共賞，芬芳醇酎雅相投。", "殷勤食指嘗先動，顧盼饞涎已自流。", "花瓣瓊瑤紛落爪，雲腴冰雪冷侵喉。", "蒲萄鎖碎終非匹，荔子肥甘僅可儔。", "但效兒童貪磊落，不知牙齒怯颼飀。", "力蠲消渴多年病，清釀騷吟一腹秋。", "屬饜且行猶掌上，悶餘雖卧亦床頭。", "膚輕漸密衣猶重，種好懸囊子尚留。", "憔悴瀼西三寸小，酸寒東望一枚休。", "檉均奴僕知郎貴，橘類砆砥比玉羞。", "美實舊嗟遺貢禹，嘉名今愧下温州。", "多栽厚利羸梔茜，一熟經時汗馬牛。", "晚歲幸爲安漢守，眼明重到洞庭遊。", "已將滋味千時好，寧免苞苴徇世求。", "大嚼有誰能快意，素餐無事却成憂。", "徐陵奬識詩辭古，胡濟矜誇賦筆遒。", "願得新篇聊假借，庶幾聲望出遐陬。"]'),
('35db8834-f48c-41f3-9887-bd7e4170c6b6','送宋構成之運判赴闕','馮山','宋','宋诗','song-poetry','','[]','曾留先帝紫宸班，高議雍容數刻間。',128,'全唐诗/poet.song.42000.json','["曾留先帝紫宸班，高議雍容數刻間。", "使節光華金口賜，鄉枌歌舞繡衣還。", "鑪錘應手皆良法，斤斧投虛輙大姦。", "坐席賢勞殊未暖，歸軺嚴召遽難攀。", "豪曹自是青雲器，騏驥應無白日閒。", "蘇孺故人聊養拙，君公行部每開顔。", "新知邂逅情猶在，遠别逡巡涕欲潸。", "人事去來寧可問，試看莊叟道中環。"]'),
('63ae7e3a-e7ec-44a4-b40e-5a5f205a4dfe','送徐之才赴洋州','馮山','宋','宋诗','song-poetry','','[]','三河使指皆精選，八座郎官最上遊。',176,'全唐诗/poet.song.42000.json','["三河使指皆精選，八座郎官最上遊。", "袖手看人趨要職，息肩隨分領偏州。", "遐方暫屈嚴明府，舊部爭迎郭細侯。", "常愛昔人爲郡樂，不妨循吏與民休。", "枌榆指顧秦川近，臺榭周環灙水流。", "闕下子牟心感慨，天涯賓客老淹留。", "方將振羽趨庭鷺，豈便忘機狎海鷗。", "青漢遶山迎隼旆，北風吹雪犯貂裘。", "從来恩館深仁遇，依舊鄰封竊庇庥。", "遠别不惟思酒盞，相忘何事更書郵。", "郢中無和陽春曲，時寄新聲欲强酬。"]'),
('05f53e17-cdb0-4526-8b43-b9fdc1bc92a1','和劉明復鐵老君觀','馮山','宋','宋诗','song-poetry','','[]','放轡逍遙物外情，登真一境照人清。',96,'全唐诗/poet.song.42000.json','["放轡逍遙物外情，登真一境照人清。", "巍然道德玄元像，傳得胚渾太古精。", "造化工夫應默運，神仙儀相自隨成。", "江山地勝空遺跡，聖智長存即久生。", "寂寞黄冠猶好事，微茫丹竈不知名。", "淮南英胄来瞻仰，驟起清風化蜀氓。"]'),
('1255788b-6e43-4a85-98e3-7ded88a67bf9','寄潭州何正臣君表待制二首  其一','馮山','宋','宋诗','song-poetry','','[]','繡指初從劍外還，文章開府冠羣仙。',64,'全唐诗/poet.song.42000.json','["繡指初從劍外還，文章開府冠羣仙。", "忽聞五管傳邊警，又出三湘領使權。", "偃息湖山非久計，翺翔鴻鵠待殊遷。", "不同宣室因循召，台輔明時屬少年。"]'),
('1e25d429-5841-4645-b9b1-f8af6ecc0a9d','寄潭州何正臣君表待制二首  其二','馮山','宋','宋诗','song-poetry','','[]','高卑鵬鷃分難攀，豈意相知邂逅間。',64,'全唐诗/poet.song.42000.json','["高卑鵬鷃分難攀，豈意相知邂逅間。", "北海舊時曾薦鶚，愚公終日尚移山。", "平生泯默無他技，一顧差池已厚顔。", "猶有功名心尚在，鑪錘當手待公還。"]'),
('de0cf941-592b-48de-8659-88ac61db1e1c','寄上范蜀公二首  其一','馮山','宋','宋诗','song-poetry','','[]','去就人兼衆美難，侍郎高望肅衣冠。',64,'全唐诗/poet.song.42000.json','["去就人兼衆美難，侍郎高望肅衣冠。", "每尋當世羣公議，更在清流絕等看。", "楚屈辭多誰謗國，漢疏名重只休官。", "求仁已得無餘憾，自向冥冥著羽翰。"]'),
('8fb3cf8d-95f5-4275-b4e4-37009ffb5f0f','寄上范蜀公二首  其二','馮山','宋','宋诗','song-poetry','','[]','拱極星文動少微，西南風物重光輝。',64,'全唐诗/poet.song.42000.json','["拱極星文動少微，西南風物重光輝。", "平生親友傾心望，共慶功名畢手歸。", "車馬歡聲傳里巷，松楸佳氣雜煙霏。", "長卿兒戲揚雄拙，未足公前較是非。"]'),
('38b70eb1-b278-4862-9ac8-7472f21209ce','寄上北京文侍中','馮山','宋','宋诗','song-poetry','','[]','四紀三朝會遇同，陪京猶望節旄雄。',64,'全唐诗/poet.song.42000.json','["四紀三朝會遇同，陪京猶望節旄雄。", "欲知元老經綸跡，盡在生民鼓舞中。", "漢府重歸黄閣相，商山難訪紫芝翁。", "陶鈞末士慚無報，惟解聲詩寫至公。"]'),
('e9f97673-0f49-4bb2-b2a8-4efe5f2d1d67','和東川吳幾復辨叔朝議見寄','馮山','宋','宋诗','song-poetry','','[]','幕府參差恨莫追，公車才下我親闈。',64,'全唐诗/poet.song.42000.json','["幕府參差恨莫追，公車才下我親闈。", "高談乍聽曾心死，前會難尋但肉飛。", "千里有時重咳唾，一言何處盡精微。", "惟思旌棨趨嚴召，雙劍西南望落暉。"]'),
('5d0ae6e1-821e-47f6-9521-6ed9d5a980de','和陳圖南道中見寄','馮山','宋','宋诗','song-poetry','','[]','故人重見老相看，江上秋風已薄寒。',64,'全唐诗/poet.song.42000.json','["故人重見老相看，江上秋風已薄寒。", "曾約浮沉俱里社，豈期僥倖亦侯籓。", "休嗟華髪多年别，且喜清罇數日歡。", "惟有舊遊難得處，風騷遺恨滿三軒。"]'),
('8651f2bf-285b-4621-9a89-8439eb8329d3','和李獻甫見寄','馮山','宋','宋诗','song-poetry','','[]','别腸回轉似車輪，千里相忘一水濱。',64,'全唐诗/poet.song.42000.json','["别腸回轉似車輪，千里相忘一水濱。", "自愧卑飛徒衮衮，過蒙高義最恂恂。", "已違蘭養三經歲，猶恐瓜期再見春。", "趨府何當聽約束，分爲膏澤與鄉民。"]'),
('6ac5b24b-bfd6-47b9-b3af-185bf067c2f5','和朱牧宣德','馮山','宋','宋诗','song-poetry','','[]','英游相聚日相歡，休唱還家蜀道難。',64,'全唐诗/poet.song.42000.json','["英游相聚日相歡，休唱還家蜀道難。", "爲愛尊前文字飲，不知門外雪霜寒。", "酒酣依約羣仙夢，談劇飛揚巨海瀾。", "從此追隨頻語笑，莫教憔悴恥儒冠。"]'),
('33b17b5f-0e5b-49d0-94fa-3b2027c357ea','運使李獻甫有書云千山萬水之間泥濘勞苦不可勝言者因以詩答之','馮山','宋','宋诗','song-poetry','','[]','使車東按宕渠還，霖潦千山萬水間。',64,'全唐诗/poet.song.42000.json','["使車東按宕渠還，霖潦千山萬水間。", "爲把仁恩行郡國，肯教愁色到容顔。", "高賢本爲蒼生起，良驥應無白日閒。", "從此促歸天上去，翺翔鵷鷺紫宸班。"]'),
('0bd73464-b209-482c-936b-05c6e6e28017','送梓憲鞏彦輔中散二首  其一','馮山','宋','宋诗','song-poetry','','[]','宏才高望出簪裾，尤向持平意豁如。',64,'全唐诗/poet.song.42000.json','["宏才高望出簪裾，尤向持平意豁如。", "輦轂聲名三輔最，西南恩惠十年餘。", "諸公每恨歸朝晚，美職行聞半道除。", "今日老成應不次，中臺煩劇在刑書。"]'),
('1b02a788-f5a0-4e27-90cd-061de1b5a3ca','送梓憲鞏彦輔中散二首  其二','馮山','宋','宋诗','song-poetry','','[]','繡衣三峽始歸來，孤跡青天道上回。',64,'全唐诗/poet.song.42000.json','["繡衣三峽始歸來，孤跡青天道上回。", "牛馬經年馳使檄，雲霓終日望行臺。", "鵷鴻去勢看千里，桃李遺芳占一栽。", "都邑羣公如見問，漳濱衰病已難材。"]'),
('3ca1f708-5122-413e-9642-0a5a31d0cc82','和知資州許廣淵澤翁同年朝奉見寄','馮山','宋','宋诗','song-poetry','','[]','每思同榜多零落，忽見新篇慰寂寥。',64,'全唐诗/poet.song.42000.json','["每思同榜多零落，忽見新篇慰寂寥。", "今日抗塵俱白首，當時聯翮共青霄。", "休嗟遠地猶沈俊，况是深知已滿朝。", "饑渴未能親一笑，祗憂嚴召促歸軺。"]'),
('85d4e64e-55bc-4d84-a023-4a558087062a','和周正孺遊醴泉寺蠶叢','馮山','宋','宋诗','song-poetry','','[]','衰遲猶有少年心，十里名藍共訪尋。',64,'全唐诗/poet.song.42000.json','["衰遲猶有少年心，十里名藍共訪尋。", "抹綠郊原逢雨後，殘妝桃李覺春深。", "諠譁歌舞隨流俗，瀟灑溪山憶故林。", "一醉不辭繁上酒，簿書迴首費光陰。"]'),
('b5c16d9e-0c1c-4b3f-81f2-d0a078191254','和周正孺春遊','馮山','宋','宋诗','song-poetry','','[]','路入江村五馬遊，江邊生俗弄春毬。',64,'全唐诗/poet.song.42000.json','["路入江村五馬遊，江邊生俗弄春毬。", "客愁無地時分請，樂看能俳預點抽。", "趁賞不辭花欲老，勸農偏喜雨新收。", "經年多病無歡意，强逐雙旌一舉頭。"]'),
('003b10d9-3793-4b92-9f27-435e5608b84e','和李曼修孺戶曹','馮山','宋','宋诗','song-poetry','','[]','青雲回首即紅塵，且向卑官事隱淪。',64,'全唐诗/poet.song.42000.json','["青雲回首即紅塵，且向卑官事隱淪。", "衮衮泥途方索足，區區天地不容身。", "前頭功業安知命，滿腹文章未稱貧。", "深愧相知空握手，羽書邊上輟嘉賓。"]'),
('0252b8bf-9c4a-4f44-9670-65181a86217d','和徐之才回紋','馮山','宋','宋诗','song-poetry','','[]','行軺使指屢襟分，路去重看思糾紛。',64,'全唐诗/poet.song.42000.json','["行軺使指屢襟分，路去重看思糾紛。", "清夜峽前江照月，霽天郊外劍横雲。", "情多苦近歸褒漢，景物應難會見聞。", "榮慮俗緣因刺按，燕堂虛愧有移文。"]'),
('b540cb62-601f-4611-8df1-d233cf903c7e','和劉涇巨濟教授','馮山','宋','宋诗','song-poetry','','[]','卷地嚴風動馬蹄，忽聞投館到雞棲。',64,'全唐诗/poet.song.42000.json','["卷地嚴風動馬蹄，忽聞投館到雞棲。", "路隨黄鶴翺翔遠，詩壓青山氣象低。", "我已衰年思故國，君方高步陟丹梯。", "遲留且伴臨江醉，剩聽清猿峽口啼。"]'),
('23c8d36a-36f5-43fb-9078-4af16b154997','和吕少蒙蠶市','馮山','宋','宋诗','song-poetry','','[]','何處青衣舊俗酣，峨嵋東畔蜀江南。',64,'全唐诗/poet.song.42000.json','["何處青衣舊俗酣，峨嵋東畔蜀江南。", "從來歲首爭爲市，大半民間已不蠶。", "幾日笙歌常繼燭，晚春桃李尚仍藍。", "嬉遊果獲神明助，太守雖貧亦薺甘。"]'),
('273bbea6-ee8d-4bc9-924a-1920ee998c7b','往時與今錢唐蒲資政傳正修史鄧內翰温伯同和唐韋考功張水部盛山十二詠畀開江吳令使榜於宿雲亭二十三年矣因緣登覽感慨疇昔復爲短篇以紀故事元祐二年正月二十八日安岳馮允南','馮山','宋','宋诗','song-poetry','','[]','曾繼唐賢舊唱酬，宿雲亭傳爲遲留。',64,'全唐诗/poet.song.42000.json','["曾繼唐賢舊唱酬，宿雲亭傳爲遲留。", "韋温石上尋遺跡，蒲鄧天邊憶俊遊。", "亭榭寂爲閒處所，溪山清带古風流。", "神交冥漠相知遠，重把狂吟此暗投。"]'),
('4db165f5-c983-4588-8f0a-ce9aee7fb926','中巖封崇寺','馮山','宋','宋诗','song-poetry','','[]','萬竹林間一徑升，滿巖金碧靜香燈。',64,'全唐诗/poet.song.42000.json','["萬竹林間一徑升，滿巖金碧靜香燈。", "飛泉散亂垂千尺，危閣欹斜擁數層。", "雨氣或從簷際落，風光時向坐中凝。", "荒碑文字那能讀，合眼煎茶問老僧。"]'),
('ea264d96-7789-4e2a-9e9e-5a86d5301155','扶歡驛王衮居也梁承秀居今隆化縣李光吉居今榮懿寨皆土豪犯法禁以取夷滅','馮山','宋','宋诗','song-poetry','','[]','僭田收盡連蠻徼，舊版從来實漢民。',64,'全唐诗/poet.song.42000.json','["僭田收盡連蠻徼，舊版從来實漢民。", "草染華風能不瘴，山離汙俗自無塵。", "連城解喪吳王濞，鉅積終刑石季倫。", "一代英豪猶不免，咄嗟三叛爾何人。"]'),
('17809226-651a-4691-aa02-8b749ee9f8f4','三家兄書報薦起樓屋喜而有詩','馮山','宋','宋诗','song-poetry','','[]','臨街樓觀百餘年，司馬辛勤五世傳。',64,'全唐诗/poet.song.42000.json','["臨街樓觀百餘年，司馬辛勤五世傳。", "凡在子孫俱肯構，敢憂門戶或先顛。", "亢宗本是先人意，幹蠱成於伯氏賢。", "他日舉杯相屬處，爲留書閣井東偏。"]'),
('3507ec5b-cec3-4363-8c1b-825d34552cb5','寄陳蓬州圖南','馮山','宋','宋诗','song-poetry','','[]','臨老蹉跎来劍閣，故人留滯在蓬池。',64,'全唐诗/poet.song.42000.json','["臨老蹉跎来劍閣，故人留滯在蓬池。", "光陰一别六七載，功業半生多少時。", "謫宦可憐嗟子駿，徑歸難學羡誠之。", "何當江上重攜手，同到三軒看舊詩。"]'),
('b3e9de7c-d009-4d0f-83c7-5f07cad21221','和鄧温伯二首  其一','馮山','宋','宋诗','song-poetry','','[]','不獨高文耀世奇，曾將宏議振天維。',64,'全唐诗/poet.song.42000.json','["不獨高文耀世奇，曾將宏議振天維。", "誰人才術能爭首，自古功名貴及時。", "暫别鵷鴻蓬海上，少留旌旆蜀江陲。", "西州筆硯雖衰落，會有中和樂職詩。"]'),
('b10416b2-23e2-4c49-815d-2ac6d6148873','和鄧温伯二首  其二','馮山','宋','宋诗','song-poetry','','[]','虛譽交遊共借推，清途俛首倦重窺。',64,'全唐诗/poet.song.42000.json','["虛譽交遊共借推，清途俛首倦重窺。", "方將素志隨鷗鷺，敢拂華巓望鵔鸃。", "衰晚欲成漳浦病，嗟矜猶得鄭公詩。", "相逢少置升沉事，且把金蓮爲倒垂。"]'),
('2e220d63-ab57-4592-8470-d62128f9a16d','送鄧温伯','馮山','宋','宋诗','song-poetry','','[]','長羡横飛霄漢遠，多慚窘步路途窮。',64,'全唐诗/poet.song.42000.json','["長羡横飛霄漢遠，多慚窘步路途窮。", "如何會合青天道，俱是衰遲白髪翁。", "萬里每嗟音信絕，一樽還喜笑言同。", "遨遊莫作經春計，佇看高旌促召東。"]'),
('0f76ee6a-bf93-49cd-82ab-bb4cfbce19d4','和劉漕明復觀吳生畫','馮山','宋','宋诗','song-poetry','','[]','古觀蕭條昔未名，却因吳筆助神靈。',96,'全唐诗/poet.song.42000.json','["古觀蕭條昔未名，却因吳筆助神靈。", "能將萬化豪端意，寫出羣仙物外形。", "俊逸狀如裴劍舞，周環時見蜀山青。", "陰兵聳動驚魑魅，真仗飄搖擁戶庭。", "按部每来除枳棘，題詩留與禦風霆。", "因嗟畫癖無由見，魂逐車塵爲一經。"]'),
('cfa5c452-cb09-4e86-b5e2-e065600d0646','和題成都諸公唱和集','馮山','宋','宋诗','song-poetry','','[]','諸公高詠蜀人編，唱和舂容近百篇。',64,'全唐诗/poet.song.42000.json','["諸公高詠蜀人編，唱和舂容近百篇。", "厚重江山藏古氣，軒翔鵰鶚在秋天。", "不徒神物陰相護，兼有風謠樂共傳。", "誰謂開州新集好，退之題後始完全。"]'),
('496db8a8-791c-4354-8e20-5b486bb39dde','和劉明復再遊劍州東園二首  其一','馮山','宋','宋诗','song-poetry','','[]','孤城寥落萬山圍，惟有東溪景最奇。',64,'全唐诗/poet.song.42000.json','["孤城寥落萬山圍，惟有東溪景最奇。", "擁傳使華尋舊賞，滿園春色待多時。", "援琴故故彈流水，隱几蕭蕭聽竹枝。", "擺脱風光情不盡，停車門外欲行遲。"]'),
('5aff8364-3d34-4527-aeb0-a4b76bfd5156','和劉明復再遊劍州東園二首  其二','馮山','宋','宋诗','song-poetry','','[]','危亭飛閣照寒溪，重到依然杜宇啼。',64,'全唐诗/poet.song.42000.json','["危亭飛閣照寒溪，重到依然杜宇啼。", "好事且看韋守記，補亡思覓義山題。", "頻來已免山移誚，久坐翻爲水樂迷。", "一宿有情非雅素，他年嵩洛是真棲。"]'),
('d85c5191-4080-4deb-9c93-6fb74eddadf3','和徐之才喜雨','馮山','宋','宋诗','song-poetry','','[]','憫雨何須事禱祈，霈然未足便晴暉。',64,'全唐诗/poet.song.42000.json','["憫雨何須事禱祈，霈然未足便晴暉。", "潤通壠畝麥禾起，香遍園林櫻笋肥。", "浮藻水生魚聚戲，落花泥熟燕交飛。", "民謠已洽豐年望，惟恐使車將北歸。"]'),
('6112e950-1792-4162-8311-a6b831ebb736','和徐之才觜體','馮山','宋','宋诗','song-poetry','','[]','菜蔓全除看綠槐，木陰穠合乍聞雷。',64,'全唐诗/poet.song.42000.json','["菜蔓全除看綠槐，木陰穠合乍聞雷。", "田間雖荷沾濡澤，水際先憂蕩溺災。", "火氣已隨妖焰出，山光尤喜晚晴開。", "門前雅致無餘事，惟見詩筒競往来。"]'),
('80053385-bbdb-4feb-840c-06914503d503','寄新先輩蹇頎子長書記','馮山','宋','宋诗','song-poetry','','[]','年少才華自不羣，果然飛步出儒紳。',64,'全唐诗/poet.song.42000.json','["年少才華自不羣，果然飛步出儒紳。", "漢廷大對無雙手，蜀學巍科第四人。", "暫屈鵷鸞棲枳棘，行看鵰鶚離風塵。", "東川佳氣因相待，共作榮歸晝錦春。"]'),
('4f27c201-4222-45f1-b050-94c114b519cd','和楊壽祺承事見寄','馮山','宋','宋诗','song-poetry','','[]','道屈文章價不低，誤傳新句落天西。',64,'全唐诗/poet.song.42000.json','["道屈文章價不低，誤傳新句落天西。", "忽聞命駕趨雲棧，猶憶同舟上井溪。", "爭嘆科名淹舊發，誰憐簿領困沉迷。", "相逢且約嘉陵酒，爲洗關中數尺泥。"]'),
('cbb801c5-f3c2-4582-99ac-2c0ed693638b','送苗子君運使赴河東漕二首  其一','馮山','宋','宋诗','song-poetry','','[]','聖君宵旰尚憂邊，移領并汾將漕權。',64,'全唐诗/poet.song.42000.json','["聖君宵旰尚憂邊，移領并汾將漕權。", "漢使已更三數節，壺關才下十餘年。", "民情姑息方師後，兵計從容試上前。", "卿相通途從此致，横飛鵰鶚上秋天。"]'),
('dca7d553-b01b-4987-a004-5e71d5634620','送苗子君運使赴河東漕二首  其二','馮山','宋','宋诗','song-poetry','','[]','一顧生平於我厚，十年門下見公親。',64,'全唐诗/poet.song.42000.json','["一顧生平於我厚，十年門下見公親。", "祗知談笑無難事，誰識襟懷似古人。", "遽别未遑論出處，相看何用惜沉淪。", "清朝勳業誰相問，已向籓籬託此身。"]'),
('e2ed5915-1326-417b-9b81-6d1d1742e58b','寄李獻甫運使','馮山','宋','宋诗','song-poetry','','[]','江淮勳績已優殊，重使西南出帝俞。',64,'全唐诗/poet.song.42000.json','["江淮勳績已優殊，重使西南出帝俞。", "被澤民謠千里遠，望風邊事十分無。", "文書頃刻隨談笑，騷雅雍容命僕奴。", "旦暮即聞嚴召速，扶搖三省上鵬圖。"]'),
('ce7ae0f7-2b51-4fa4-ac75-a138a699027c','和趙良弼初秋即事','馮山','宋','宋诗','song-poetry','','[]','尊酒相看白髪翁，重来寧復問窮通。',64,'全唐诗/poet.song.42000.json','["尊酒相看白髪翁，重来寧復問窮通。", "十年舊事資談柄，一箧新詩載古風。", "楚客遠行經素節，蜀人歸興羡冥鴻。", "登山臨水無多日，且伴閒中說苦空。"]'),
('336d3b76-891d-4a77-9d53-1c22b2406f3e','甲子鹿鳴燕上呈諸秀才二首  其一','馮山','宋','宋诗','song-poetry','','[]','詔書天上頒春澤，經義人間沸海濤。',64,'全唐诗/poet.song.42000.json','["詔書天上頒春澤，經義人間沸海濤。", "俊秀一時隨品藻，文章萬選即英豪。", "溟鵬乍見摶風起，郡守寧辭勸駕勞。", "當有奇才爲時出，中元佳氣似嵩高。"]'),
('200002a4-a25d-4d5a-8bb1-188d068af936','甲子鹿鳴燕上呈諸秀才二首  其二','馮山','宋','宋诗','song-poetry','','[]','重陽高會最風流，爲禮賢書席俊遊。',64,'全唐诗/poet.song.42000.json','["重陽高會最風流，爲禮賢書席俊遊。", "已愛食萍歌小雅，更宜攀菊賞清秋。", "榮觀坐見邦人喜，壯志行期國士酬。", "酒到從容當盡醉，登仙名籍在瀛洲。"]'),
('af661da0-3ddb-4cb5-945b-ca310627c217','重和四首  其一','馮山','宋','宋诗','song-poetry','','[]','羣俊爭求一字褒，諸公清識晉山濤。',64,'全唐诗/poet.song.42000.json','["羣俊爭求一字褒，諸公清識晉山濤。", "蓬仙寥落誰人繼，史筆縱横自古豪。", "勝爵頻傾知得雋，劇談無極坐忘勞。", "勉行無負題評意，東蜀斯文價已高。"]'),
('c51c64a6-8e0e-41a6-a0e1-6e3c84aea248','重和四首  其二','馮山','宋','宋诗','song-poetry','','[]','郡筵瀟灑宴清流，疏懶相從伴奐游。',64,'全唐诗/poet.song.42000.json','["郡筵瀟灑宴清流，疏懶相從伴奐游。", "但喜狂歌猶應節，不知衰髪已傷秋。", "多情共把金英看，厚贈慚無玉案酬。", "未去且爲詩酒會，蕭蕭休詠白蘋洲。"]'),
('6ed82882-7ed8-4a6e-9a43-53c4ac09b916','重和四首  其三','馮山','宋','宋诗','song-poetry','','[]','整此笙歌散鬰陶，雨簷飛瀑瀉秋濤。',64,'全唐诗/poet.song.42000.json','["整此笙歌散鬰陶，雨簷飛瀑瀉秋濤。", "吟情徹骨清尤健，飲量隨人喜更豪。", "黄菊光容嗟向晚，哀箏言語恨徒勞。", "相逢宜共冥冥醉，回首青雲路轉高。"]'),
('1d943bbc-871d-48c7-a77a-d6d05e0498c6','重和四首  其四','馮山','宋','宋诗','song-poetry','','[]','年少相看自輩流，深知惟喜舊交游。',64,'全唐诗/poet.song.42000.json','["年少相看自輩流，深知惟喜舊交游。", "休言白髪參差老，只恐朱顔次第秋。", "歡笑且從今日起，功名能有幾人酬。", "逍遙不必分高下，鳬雁翩翩蘆葦洲。"]'),
('d9d9d5ba-d953-4bad-8b3c-3aba226f30e1','和陳興州見寄','馮山','宋','宋诗','song-poetry','','[]','音信昜傳臨一水，道途相去隔三州。',64,'全唐诗/poet.song.42000.json','["音信昜傳臨一水，道途相去隔三州。", "何時樽酒同爲會，無補篇章約共休。", "鄉思豁從歸後少，貪心宜向靜中收。", "此情惟有君知我，不羡人間萬戶侯。"]'),
('c202934e-8679-41a7-9f2e-3eb099115589','戲謝趙良弼寄薏苡山藥','馮山','宋','宋诗','song-poetry','','[]','𦼮珠舂出真珠顆，山藥鍬開白玉團。',64,'全唐诗/poet.song.42000.json','["𦼮珠舂出真珠顆，山藥鍬開白玉團。", "本草經中俱上品，故人書寄善加餐。", "輕投已獲琅玕報，每飲兼資菽水歡。", "欲把長篇酬厚意，吟腸無味苦搜難。"]'),
('3d01c850-b714-4bae-8166-8f6f580275d9','問江巨源求茶','馮山','宋','宋诗','song-poetry','','[]','語笑嘉陵醉别辰，曾留一角建陽春。',64,'全唐诗/poet.song.42000.json','["語笑嘉陵醉别辰，曾留一角建陽春。", "不將閒碾無佳客，每到開嘗憶主人。", "蒙頂縱甘餘草氣，月團雖有隔年陳。", "吟魂半去難招些，願得蘭溪數片新。"]'),
('4538fe18-8939-4696-b11b-557bc50b1178','謝李獻甫寄鳳茶','馮山','宋','宋诗','song-poetry','','[]','雙鳳婆娑綠玉團，初綱猶怯禁中寒。',64,'全唐诗/poet.song.42000.json','["雙鳳婆娑綠玉團，初綱猶怯禁中寒。", "貴從侍從時宣賜，傳到西南作寶看。", "旋碾合留清浩氣，親題何事寄麤官。", "感公珍惠寧須試，一嗅煩懷已自寛。"]'),
('e6a7dd58-e0ec-4a25-8927-04d2d5349a91','再和','馮山','宋','宋诗','song-poetry','','[]','此品何嘗下小團，分甘仍值雪霜寒。',64,'全唐诗/poet.song.42000.json','["此品何嘗下小團，分甘仍值雪霜寒。", "恐塵竹葉微蒸過，要細銀杆旋碾看。", "紫盞烘時愁俗客，清風来處屬仙官。", "平江一啜吟佳句，起舞不知天地寛。"]'),
('d0e1e753-74e7-4d15-a8a2-96efdf94b95c','和李曼長官約遊郊園','馮山','宋','宋诗','song-poetry','','[]','郊園聞葺舊亭臺，曉訪冰鬚凍結腮。',64,'全唐诗/poet.song.42000.json','["郊園聞葺舊亭臺，曉訪冰鬚凍結腮。", "野景豁從江上見，雲扃深向霧中開。", "早知閒處登臨好，何恨忙時取次来。", "夢草新詩酬不得，謝家兄弟盡清才。"]'),
('ce4f2920-5707-4cc4-9a79-2e98726e94ca','和李獻甫雲頂','馮山','宋','宋诗','song-poetry','','[]','舉首看山不到山，每来留恨翠微間。',64,'全唐诗/poet.song.42000.json','["舉首看山不到山，每来留恨翠微間。", "禪關但有經年約，使傳終無一日閒。", "春到柏林香渺渺，雨餘巖漏瀉潺潺。", "虎溪莫過虚邀客，猿鶴鐘峰悵未還。"]'),
('fc6e6c8f-c9e5-4ee4-8e5a-ec2dc8fd3433','和鮮于頃節推惠詩','馮山','宋','宋诗','song-poetry','','[]','英駕能来慰寂寥，相看衰鬢共飄摇。',64,'全唐诗/poet.song.42000.json','["英駕能来慰寂寥，相看衰鬢共飄摇。", "風騷會裏多年别，談笑盃中萬事銷。", "休歎轅駒方跼蹐，不知籓鷃已逍遙。", "如將巧思鳴孤憤，爲我商聲更一謠。"]'),
('bb960a82-11ff-4ea1-ac58-fa86a0318416','下黔江','馮山','宋','宋诗','song-poetry','','[]','崎嶇才喜下荆岑，一水奔騰萬石林。',64,'全唐诗/poet.song.42000.json','["崎嶇才喜下荆岑，一水奔騰萬石林。", "使節敢辭重險阻，客舟將命寄浮沉。", "可憐幽竇非人境，猶有清泉慰我心。", "勞逸賢愚寧可問，但嗟衰晚愧臨深。"]'),
('3c8dc5c9-b0af-4991-a28d-7686f8dfced0','和王子嚴南平道中寄示','馮山','宋','宋诗','song-poetry','','[]','雨隨行色過重闉，路有思歸送别人。',64,'全唐诗/poet.song.42000.json','["雨隨行色過重闉，路有思歸送别人。", "未省幾時趨北闕，且同回首望西鄰。", "黄花漸近羞重見，白酒猶期醉一巡。", "三峽苦辛嘗欲遍，置杯休要問澆醇。"]'),
('af522ccd-2d69-480a-8f65-d48eaf7cf1e6','寄賀李修孺移利憲','馮山','宋','宋诗','song-poetry','','[]','纔出關来又入關，欲閒天意未教閒。',64,'全唐诗/poet.song.42000.json','["纔出關来又入關，欲閒天意未教閒。", "一生孤直知心處，三度交承隔政間。", "食蔗羡君方有味，過屠憐我尚何顔。", "功名不是蹉跎物，猶惜清時共仰攀。"]'),
('dafe3466-804d-4cf0-ba6a-304650421c54','牟仲甫作雞終有意趣爲予寫鬭雞矜驕自得猶有餘勇因以絕句題其畫云','馮山','宋','宋诗','song-poetry','','[]','忘身爲利得忘形，棄彈莊生只自驚。',32,'全唐诗/poet.song.42000.json','["忘身爲利得忘形，棄彈莊生只自驚。", "嗟汝虛憍氣方盛，何時全得似無情。"]'),
('011f7fb1-012d-4250-8906-ae11e0acbc3b','寄利憲張充宗司勳','馮山','宋','宋诗','song-poetry','','[]','曾言英館願重尋，猶記當時戀别心。',64,'全唐诗/poet.song.42000.json','["曾言英館願重尋，猶記當時戀别心。", "千里江山勞客思，一年風物又春深。", "夢中花發人將老，關外愁生酒不禁。", "引領使臺歸未得，且疏懷抱寄知音。"]'),
('2c4d81d2-6d9d-4d1a-af6e-c53b3127588c','木門早行','馮山','宋','宋诗','song-poetry','','[]','白虎前峰數尺高，露華蕭颯滿征袍。',64,'全唐诗/poet.song.42000.json','["白虎前峰數尺高，露華蕭颯滿征袍。", "只知眼底簿書靜，豈意山中車馬勞。", "石夾雨餘重按轡，草間風動幾横刀。", "通途聞說無多地，踴躍身輕意氣豪。"]'),
('8b9feaa2-2e35-4256-b723-add980864afc','送趙悦道叅政大資知越州二首  其一','馮山','宋','宋诗','song-poetry','','[]','乖崖威重兼之恕，正獻純風重以和。',64,'全唐诗/poet.song.42000.json','["乖崖威重兼之恕，正獻純風重以和。", "高世清名公取盡，經邦餘事蜀霑多。", "二江遺愛流長在，雙劍銘功壁屢磨。", "聞向蓬莱指歸路，其如朝野具瞻何。"]'),
('6fff4df2-28fe-4683-9053-db12c7d9d42d','送趙悦道叅政大資知越州二首  其二','馮山','宋','宋诗','song-poetry','','[]','徒御紛紛擁劍關，蜀人感泣送公還。',64,'全唐诗/poet.song.42000.json','["徒御紛紛擁劍關，蜀人感泣送公還。", "欲知千里謳歌意，半在百篇文字間。", "風霰道途方過闕，煙霞旌旆更尋山。", "重金不負扁舟約，賀老鑑湖春水閒。"]'),
('1e7420cc-c4a6-4564-92ef-0fab6667e724','和鮮于子駿遊沙溪洞','馮山','宋','宋诗','song-poetry','','[]','放轡深窮物外天，少償遊恨十餘年。',64,'全唐诗/poet.song.42000.json','["放轡深窮物外天，少償遊恨十餘年。", "諸仙羽化曾由此，千載巖居尚宛然。", "門轉青溪空水石，室存丹竈養雲煙。", "冰骸坐久雖清澈，獨有區中世俗緣。"]'),
('912e58f5-a98b-4963-95ec-be0654a06cd7','興州坐卧二仙','馮山','宋','宋诗','song-poetry','','[]','莫逆真心際混茫，豈將生死係存亡。',64,'全唐诗/poet.song.42000.json','["莫逆真心際混茫，豈將生死係存亡。", "已驂雲霧朝丹闕，猶蛻衣冠寄異鄉。", "姓氏不傳靈祕録，精神長在發圓光。", "洪肩丘袂攀無及，分向塵中到老忙。"]'),
('acf2127d-cecb-41d7-8c6c-445abfc36227','寄子駿郎中','馮山','宋','宋诗','song-poetry','','[]','疊疊巴山走使軺，不辭巖險奉寛條。',64,'全唐诗/poet.song.42000.json','["疊疊巴山走使軺，不辭巖險奉寛條。", "頻来馬足行應慣，重見民情喜自謠。", "雨過寒林微带雪，風生幽谷靜聞樵。", "清奇定入騷吟筆，乞取郵筒寄下僚。"]'),
('2b53172e-ee8f-432d-9911-9f0bde1a0fb5','送李杞省句赴闕','馮山','宋','宋诗','song-poetry','','[]','使軺西走奉軍期，萬貨泉流向武威。',64,'全唐诗/poet.song.42000.json','["使軺西走奉軍期，萬貨泉流向武威。", "纔伴江聲關外去，又隨秋色日邊歸。", "千尋蜀嶺供吟藁，一道秦川照錦衣。", "莫歎奔馳傷浩氣，出羣鴻雁已高飛。"]'),
('d82653d2-45ad-4a26-890a-ce3c7ccf0c95','和子駿郎中登高','馮山','宋','宋诗','song-poetry','','[]','曾對炎蒸憶靜便，偶逢佳節思超然。',64,'全唐诗/poet.song.42000.json','["曾對炎蒸憶靜便，偶逢佳節思超然。", "相將絕頂孤高處，剩看清秋幾許天。", "雖欠笙簧留席上，猶勝風雨傍籬邊。", "好看菊蕊殷勤别，旦暮除書落枕前。"]'),
('8fd41479-424d-4a61-8bef-55d605a31594','和子駿郎中文臺','馮山','宋','宋诗','song-poetry','','[]','地接松扶絕塞邊，星居人戶種畬田。',64,'全唐诗/poet.song.42000.json','["地接松扶絕塞邊，星居人戶種畬田。", "語音高亢關中俗，風物蕭疏劍外天。", "一失覊縻生堡障，十分流運費刀泉。", "閭閻謾作封侯計，幾輩伻圖到上前。"]'),
('c223e85e-0a68-4c3b-8c0f-7c7eaf0e2625','和山路梅花','馮山','宋','宋诗','song-poetry','','[]','傳聞山下數枝梅，不免車帷暫一開。',64,'全唐诗/poet.song.42000.json','["傳聞山下數枝梅，不免車帷暫一開。", "試向林梢親手折，早知春意逼人來。", "何方歸路參差見，更託嚴風次第催。", "莫作尋常花卉看，江南音信隔年回。"]'),
('63f46c22-975b-4fa3-b2b8-39dd825b3006','和清暉亭','馮山','宋','宋诗','song-poetry','','[]','亭榭軒窗處處開，清暉嘉致號爲魁。',64,'全唐诗/poet.song.42000.json','["亭榭軒窗處處開，清暉嘉致號爲魁。", "羣峰有景互爭出，一水無聲相向来。", "已借寒光搖棨戟，莫辭歡賞費瓶罍。", "新詩自屬風騷將，何苦登臨愧不才。"]'),
('1853d29d-1b80-45b8-96f2-5b0e53736667','送范百祿子功學士知諫院二首  其一','馮山','宋','宋诗','song-poetry','','[]','天庭高議破羣姦，先帝曾將侍從班。',64,'全唐诗/poet.song.42000.json','["天庭高議破羣姦，先帝曾將侍從班。", "談笑一辭雙闕去，縉紳遺恨十年間。", "傾朝每憶劉蕡對，側席纔聞賈誼還。", "言責逡巡非久計，行看鳴玉上鼇山。"]'),
('4991eb95-ba06-415f-a577-0ab7aa1cc1ec','送范百祿子功學士知諫院二首  其二','馮山','宋','宋诗','song-poetry','','[]','聖賢中道意何如，歷歷樊川論諌書。',64,'全唐诗/poet.song.42000.json','["聖賢中道意何如，歷歷樊川論諌書。", "要在致君成德業，不當沽直徇名譽。", "平生忠義傾心際，後日經綸試手初。", "得意古人多氣義，彈冠應有舊簪裾。"]'),
('e93cd24c-e1ea-49b4-bb18-53dca8e7188d','和苗時中子君運判亭溪道中雙白猿','馮山','宋','宋诗','song-poetry','','[]','雪白霜猿久已靈，江山但覺有餘清。',64,'全唐诗/poet.song.42000.json','["雪白霜猿久已靈，江山但覺有餘清。", "優游此地不常出，皎潔一身能自明。", "高掛豈知神氣王，仰看誰爲骨毛驚。", "因吟佳句成遺恨，安得風前聞嘯聲。"]'),
('ad83dc7c-e337-4b63-b337-582a77a45a94','和子駿郎中清江道中','馮山','宋','宋诗','song-poetry','','[]','繚繞川原又載馳，人情風物共依依。',64,'全唐诗/poet.song.42000.json','["繚繞川原又載馳，人情風物共依依。", "膠舟野水涸將盡，捲雨嶺雲寒不飛。", "豈憚長途勞使傳，尚尋清景扣禪扉。", "前山次第看梅發，剩带新年春色歸。"]'),
('f4298f82-d34b-4ddf-914e-a356b02e61cc','赴辟利臺吕少蒙運判以詩回贈依韻謝之','馮山','宋','宋诗','song-poetry','','[]','隨和箧笥號藏珍，物理求多漸失真。',64,'全唐诗/poet.song.42000.json','["隨和箧笥號藏珍，物理求多漸失真。", "騏驥已勝千里足，鷦鷯才寄一枝身。", "自憐蹭蹬居前粃，豈意蹉跎接後塵。", "窮達聖賢知有分，不同非望澤中人。"]'),
('83d0a4cc-5a17-4ad4-bbdd-1f80f0c2af9a','和岑巖起莫軒','馮山','宋','宋诗','song-poetry','','[]','聞在幽軒隱使華，合歸清望戴重紗。',64,'全唐诗/poet.song.42000.json','["聞在幽軒隱使華，合歸清望戴重紗。", "手持温詔方行道，堂有慈親即是家。", "得意鄉山頻上看，異時蓬島合重誇。", "登臨强欲留詩句，苦恨風騷力未加。"]'),
('51ff11ed-d431-46d5-af76-258c315f578c','送文與可知洋州','馮山','宋','宋诗','song-poetry','','[]','何事年年擁使麾，放身閒處避危機。',64,'全唐诗/poet.song.42000.json','["何事年年擁使麾，放身閒處避危機。", "爲思清漢還重去，猶厭承明未肯歸。", "天上榮途方策足，林間輕靄尚沾衣。", "區區斥鷃寧能嘯，只得蓬蒿自在飛。"]'),
('fe955c1e-8de8-4f80-9e73-0973eaded82f','賞梅呈李待制才元','馮山','宋','宋诗','song-poetry','','[]','鎮雅牆陰看早梅，滿城惟此一株開。',64,'全唐诗/poet.song.42000.json','["鎮雅牆陰看早梅，滿城惟此一株開。", "已驅禽鳥工夫盡，才共賓僚宴賞来。", "月照寒姿凌畫燭，風傳香蕊墮清杯。", "玉堂深切歸期近，少住花前醉幾回。"]'),
('63ac3a06-9d88-46ac-8467-a4729957129b','讀劉賓客外集','馮山','宋','宋诗','song-poetry','','[]','七言常愛中山好，百首猶存外集多。',64,'全唐诗/poet.song.42000.json','["七言常愛中山好，百首猶存外集多。", "大約晚年知性命，一時清韻入中和。", "森張劍戟雖無敵，隱約瑕疵惜未磨。", "三遶花欄俱讀盡，杜陵回首鬰嵯峨。"]'),
('23f33933-6c25-4f94-93dc-0715fa88e1fc','還楊恬天隱長官家集','馮山','宋','宋诗','song-poetry','','[]','經世才高若命何，微茫騷雅寄編摩。',64,'全唐诗/poet.song.42000.json','["經世才高若命何，微茫騷雅寄編摩。", "純音已落人間久，孤憤猶存集外多。", "喜看仙巢鳴鸑鷟，重聞古匣奏雲和。", "殷勤歸秩非無報，誰爲沉文弔汨羅。"]'),
('059cc8ec-5f9e-44c1-9634-2c9fd94d644b','寄題合江知縣楊壽祺著作野亭','馮山','宋','宋诗','song-poetry','','[]','野亭何處訪仙翁，安樂風煙逈不同。',64,'全唐诗/poet.song.42000.json','["野亭何處訪仙翁，安樂風煙逈不同。", "千里清泉来塞外，四時佳景出山中。", "偷身暫逐禽魚樂，放意翻成筆硯工。", "醉伴逍遥無計去，鈎藤新熟荔枝紅。"]'),
('e0e70dd3-d208-46c6-96b4-e90a189c4264','和吕少蒙題大卿林下軒','馮山','宋','宋诗','song-poetry','','[]','歸来何處解塵襟，幽徑尋軒入茂林。',64,'全唐诗/poet.song.42000.json','["歸来何處解塵襟，幽徑尋軒入茂林。", "身到靜中方有我，事除詩外更無心。", "江山相就能清景，桂柏新成已翠陰。", "聞說逍遙樽酒會，三卿魚袋鬭黄金。"]'),
('0efafc51-4ad7-41f9-8b19-31c0da826ab8','題馮公舉郎中清音亭','馮山','宋','宋诗','song-poetry','','[]','山水清音遶翠微，一亭風物里中稀。',64,'全唐诗/poet.song.42000.json','["山水清音遶翠微，一亭風物里中稀。", "爲憐魚釣生平處，還向功名事了歸。", "白傅歌童聊自適，莊生鷗鳥自相依。", "區區貧阮長嗟嘆，纔有林居便拂衣。"]'),
('b28abf9d-9775-49c2-a8f2-89e158ce1407','行縣道中遇暴風雨寄吕少蒙太博','馮山','宋','宋诗','song-poetry','','[]','霖潦經時路未通，公言行縣太匆匆。',64,'全唐诗/poet.song.42000.json','["霖潦經時路未通，公言行縣太匆匆。", "安知風雨欺人處，正在溪山絕險中。", "一出到頭餘日在，少留隨分覺途窮。", "却因下馬心方悟，欲速無成萬事同。"]'),
('d3ead960-e5a9-4fbb-aa5a-adbce020cf3e','重陽寄文與可','馮山','宋','宋诗','song-poetry','','[]','牛峰秋色翠相摩，還上凌雲宴綺羅。',64,'全唐诗/poet.song.42000.json','["牛峰秋色翠相摩，還上凌雲宴綺羅。", "黄菊縱逢佳節好，清歡不似去年多。", "僧房次第依重到，霜月蕭條且强歌。", "聞說洋州時節盛，不知高興定如何。"]'),
('8963e66d-68fb-4cdd-93a7-5e83af931353','過永泰文與可宅因寄','馮山','宋','宋诗','song-poetry','','[]','數程奔走倦征車，喜過蓬仙舊隱居。',64,'全唐诗/poet.song.42000.json','["數程奔走倦征車，喜過蓬仙舊隱居。", "秀氣峰巒排戶牖，清風樓閣鎖圖書。", "一從高步東山起，重見深秋少室虛。", "無計墨君堂上看，林間猿鶴共躊躇。"]'),
('a1858033-acac-4d16-a499-522dc3b3547b','聞內舍榜將至','馮山','宋','宋诗','song-poetry','','[]','元豐內舍初公選，開寶中秋定試期。',64,'全唐诗/poet.song.42000.json','["元豐內舍初公選，開寶中秋定試期。", "四海諸生趨盛集，一朝新議破羣疑。", "人傳學榜才張後，驛遞家音未到時。", "莫怪虚名隨分喜，文章門戶欲支持。"]'),
('ed9d08ca-ffe1-4176-adbe-289b6be7442a','和苗子君新井道中','馮山','宋','宋诗','song-poetry','','[]','閬水兼山鬭曉光，星軺親按古村鄉。',64,'全唐诗/poet.song.42000.json','["閬水兼山鬭曉光，星軺親按古村鄉。", "臨江麥隴煙雲翠，夾道林花錦繡香。", "使旨天邊勞按察，人情車下見歡康。", "東風相伴行寛詔，敢恨年来鬢髪蒼。"]'),
('3d7f461b-87a3-4a10-bfb9-99870405bd53','和蒲安行誠之秘丞遊烏奴寺','馮山','宋','宋诗','song-poetry','','[]','共隨春色探幽奇，春到山中未幾時。',64,'全唐诗/poet.song.42000.json','["共隨春色探幽奇，春到山中未幾時。", "嘯傲煙霞凌絕頂，毫芒人物亂交逵。", "已登高閣臨清曠，更羡輕舟泛渺瀰。", "落筆停杯遂陳跡，莫辭鐘鼓下山遲。"]'),
('f7f1da61-842b-41e5-a2dc-056e1cff86d7','送李才元待制二首  其一','馮山','宋','宋诗','song-poetry','','[]','直道崎嶇出禁林，江湖長有愛君心。',64,'全唐诗/poet.song.42000.json','["直道崎嶇出禁林，江湖長有愛君心。", "五年漢法更張際，千里潼江惠澤深。", "天下鵷鴻方得侣，道傍桃李正垂陰。", "邦人不用留行色，滿旆薫風入舜琴。"]'),
('9090a2d2-472d-42ac-8e32-378bd2b3bb3b','送李才元待制二首  其二','馮山','宋','宋诗','song-poetry','','[]','爲掾初逢幕府開，便將清望屬非才。',64,'全唐诗/poet.song.42000.json','["爲掾初逢幕府開，便將清望屬非才。", "重来門下經年後，始見天邊促召回。", "况有平生餘事業，此行高步脫風埃。", "孤蹤已作溝中斷，休費工夫爲剪裁。"]'),
('f17f69f1-c4b7-4ab2-acc9-6883261d3286','李待制寄僧詩有歇定之語兼聞有岷峨之遊因作詩以寄之二首  其一','馮山','宋','宋诗','song-poetry','','[]','無心宜與物相期，既歇須行似不疑。',64,'全唐诗/poet.song.42000.json','["無心宜與物相期，既歇須行似不疑。", "出處休將人事說，功名多在老成時。", "胸中白練何妨潔，足下青雲豈自知。", "好取聖賢權進退，莫教輕重失毫釐。"]'),
('4b651c7f-48c7-4883-875e-60fbb1faafc5','李待制寄僧詩有歇定之語兼聞有岷峨之遊因作詩以寄之二首  其二','馮山','宋','宋诗','song-poetry','','[]','春遊遊盡欲尋山，杖屨岷峨只等閒。',64,'全唐诗/poet.song.42000.json','["春遊遊盡欲尋山，杖屨岷峨只等閒。", "但放高懷窮物外，不知清譽滿人間。", "經年綠野常沉醉，幾日香峰暫往還。", "自笑塵轅盤未得，逍遙無路一追攀。"]'),
('bf227baf-5785-42ad-b4b2-79617def4f18','和普守勾輔元郎中見寄均逸亭詩','馮山','宋','宋诗','song-poetry','','[]','春風獵獵卷雙旌，太守開罇上子城。',64,'全唐诗/poet.song.42000.json','["春風獵獵卷雙旌，太守開罇上子城。", "地僻養成山水趣，民和流入管弦聲。", "林花遠近參差發，野景朝昏次第生。", "引領英游歸未得，東溪遺恨幾時平。"]'),
('89292b95-9269-4b87-84fc-72a3a0f57d3c','和賞海棠','馮山','宋','宋诗','song-poetry','','[]','三春花卉滿州城，渠占風流第一名。',64,'全唐诗/poet.song.42000.json','["三春花卉滿州城，渠占風流第一名。", "老杏酸寒誇錦繡，野梨乾强學瑤瓊。", "穠妝雨後頻来看，尤物年深特地榮。", "爲是翰林親手植，莫辭歡賞慰民情。"]'),
('b1201f15-23b1-4c77-985c-2e7b5fe5bc25','送韓存寶閤使','馮山','宋','宋诗','song-poetry','','[]','君常慷慨論兵機，喜見韓侯定遠歸。',64,'全唐诗/poet.song.42000.json','["君常慷慨論兵機，喜見韓侯定遠歸。", "將略無窮雖世出，秋毫不犯似君稀。", "封侯氣骨青春在，報主功名白日飛。", "齷齪簿書何所戀，擬投儒服換戎衣。"]'),
('651e6154-9fe0-4425-9cd2-424fea5535f4','和岑巖起見寄','馮山','宋','宋诗','song-poetry','','[]','一别江皋能幾時，相從鷗鷺久無依。',64,'全唐诗/poet.song.42000.json','["一别江皋能幾時，相從鷗鷺久無依。", "樓前流水常東去，塞上征鴻又北歸。", "交分每傳雙鯉信，鄉心同望白雲飛。", "孤吟長嘯無儔侣，惟向清宵共月輝。"]'),
('c37f7a8c-6e79-4d23-baad-e80ba8cd4eea','和後唐王仁裕舍人留題自然觀','馮山','宋','宋诗','song-poetry','','[]','黄鶴仙音久寂然，嘉陵江上碧峰端。',64,'全唐诗/poet.song.42000.json','["黄鶴仙音久寂然，嘉陵江上碧峰端。", "惟餘寂寞煙霞館，空老陰森檜柏壇。", "藥竈遶行雲彩動，詩牌吟拂玉聲寒。", "虛無蹤跡何須問，自有清名不死丹。"]'),
('2ba2d8d4-60fb-4db2-81ae-418f357eb083','與陳萬石','馮山','宋','宋诗','song-poetry','','[]','千首詩兼百首文，宗韓之子拾遺孫。',64,'全唐诗/poet.song.42000.json','["千首詩兼百首文，宗韓之子拾遺孫。", "吾鄉此道嗟幾絕，先世餘風喜僅存。", "三變聲名徒自惜，平生襟抱向誰論。", "相知惟有貧相見，撥置窮愁付酒樽。"]'),
('6bcee326-22a5-4d91-bc3d-b1de2c53fb16','開州道中逢王子嚴中散惠詩依韻和之','馮山','宋','宋诗','song-poetry','','[]','經年東北望陽臺，阻奉從容一笑開。',64,'全唐诗/poet.song.42000.json','["經年東北望陽臺，阻奉從容一笑開。", "良會俱從江上得，清風潛向坐中来。", "詩成不倦乘閒寫，酒好何妨盡醉陪。", "百老篇章今少見，滿懷歸去重瓊瑰。"]'),
('e50fdabf-1897-4877-bf7b-df1ffdab0dd8','再和子嚴','馮山','宋','宋诗','song-poetry','','[]','歸舡才泊古巴臺，遙見詩筒眼豁開。',64,'全唐诗/poet.song.42000.json','["歸舡才泊古巴臺，遙見詩筒眼豁開。", "摩壘只憂輕挑去，報瓊何意誤投来。", "老知仙夢終難到，清喜英游屢得陪。", "對酒孤吟重相憶，江前微霰屑瑤瑰。"]'),
('b412177e-df98-4533-99b4-f245d0742fd2','渝州春雪','馮山','宋','宋诗','song-poetry','','[]','青帝雲車碾玉塵，陰機和雨付江神。',64,'全唐诗/poet.song.42000.json','["青帝雲車碾玉塵，陰機和雨付江神。", "巧將清冷三巴景，妝出繁華二月春。", "已凜寒威驅瘴癘，更流和氣助陶鈞。", "勸農使者雖歡賞，猶念無衣索拊循。"]'),
('69606edf-eff6-4693-81fa-c893a508c56a','寄仲賢朝議','馮山','宋','宋诗','song-poetry','','[]','仙雛曾伴學飛翻，三紀光陰一夢間。',64,'全唐诗/poet.song.42000.json','["仙雛曾伴學飛翻，三紀光陰一夢間。", "龍坂舊游今獨在，鳳池高步已難攀。", "衣冠每恨功名晚，風月誰兼富貴閒。", "契闊人情應見念，故人憔悴老巴山。"]'),
('c29e3fff-3bf9-4e73-89e2-f22a8aafbe66','壽春穆東美有節亭','馮山','宋','宋诗','song-poetry','','[]','淮上仙翁倚歲寒，遶亭閒種碧琅玕。',64,'全唐诗/poet.song.42000.json','["淮上仙翁倚歲寒，遶亭閒種碧琅玕。", "林泉莫恨歸時晚，風月偏宜靜處看。", "爲愛蕭森從葉密，欲令蕃衍放根蟠。", "階庭已見清陰合，更長龍孫百十竿。"]'),
('0dd2aeae-5fca-495b-9b7b-ee6bf877bae0','送李之純寶文二首  其一','馮山','宋','宋诗','song-poetry','','[]','平生玉帳恥論兵，勸學儒風已自成。',64,'全唐诗/poet.song.42000.json','["平生玉帳恥論兵，勸學儒風已自成。", "惟有愛民常慘怛，况曾廉俗舊澄清。", "直將經濟爲仁術，不假中和助政聲。", "從此回翔歸柄用，更推忠厚福羣生。"]'),
('ae166250-328a-4b1a-9132-e41813d04243','送李之純寶文二首  其二','馮山','宋','宋诗','song-poetry','','[]','邂逅當年最見知，台光雲霧阻重披。',64,'全唐诗/poet.song.42000.json','["邂逅當年最見知，台光雲霧阻重披。", "忽聞潁上還朝日，正是漳濱養病時。", "劍外江山愁遠别，天邊鴻鵠望歸期。", "西南遺愛情何限，千載羊公墮淚碑。"]'),
('3ea2a8ae-36fc-40e9-bfb9-1ec4d0328518','寄題希元承詔堂希元惠詩因次其韻','馮山','宋','宋诗','song-poetry','','[]','鸑鷟峰前舊隱亭，仙翁曾此被弓旌。',64,'全唐诗/poet.song.42000.json','["鸑鷟峰前舊隱亭，仙翁曾此被弓旌。", "雲山每恨未能到，松桂向人如有情。", "共把清尊慚北海，更聽餘論學南榮。", "何須酩酊爲真賞，歸袖瓊瑰已自盈。"]'),
('ccc9adc9-24d4-405f-915e-32e48125f2ba','小溪尉丘君父母年皆九十康强精明尚能讀書挫箴如五六十歲人相繼受恩命某固未嘗見也亦未嘗聞也因作詩遺丘君且以傳諸士大夫如果未嘗見聞則宜相與樂道其美而形於歌頌云','馮山','宋','宋诗','song-poetry','','[]','人間夫婦老難期，九十俱全古亦稀。',64,'全唐诗/poet.song.42000.json','["人間夫婦老難期，九十俱全古亦稀。", "滄海蟠桃堪結子，碧梧棲鳳久忘歸。", "君恩黄髪頒新誥，兒戲青衫著彩衣。", "一尉三公無此樂，百年琴瑟在庭闈。"]'),
('8e87da65-5f59-4b2d-aa48-620a47fcbaa9','春遊','馮山','宋','宋诗','song-poetry','','[]','邀約東風共出城，雲容羞日弄陰晴。',96,'全唐诗/poet.song.42000.json','["邀約東風共出城，雲容羞日弄陰晴。", "看人牆外衝花氣，下馬石間聞水聲。", "林蘖半從樵刃起，草牙還傍燒痕生。", "趁時桃李參差發，得意禽蟲各自鳴。", "開謝眼前窮物態，豐登時下見民情。", "悔將詩筆隨春酒，萬景投懷醉不成。"]'),
('1b7a865d-bc7c-467e-b4bd-1b367f79066b','戲題辛叔儀花園','馮山','宋','宋诗','song-poetry','','[]','前載聞君說種花，重来軒檻早芬葩。',64,'全唐诗/poet.song.42000.json','["前載聞君說種花，重来軒檻早芬葩。", "只知造化隨人力，豈覺光陰換歲華。", "風雨不容孤客賞，馨香寧待主翁誇。", "牡丹珍重偏開晚，料得開時已到家。"]'),
('d74c0a8b-cf01-48f8-822e-0d5e29a90dba','和馮太博歸州春望','馮山','宋','宋诗','song-poetry','','[]','聞說巴東暫解顔，兩回曾到十年間。',64,'全唐诗/poet.song.42000.json','["聞說巴東暫解顔，兩回曾到十年間。", "咤灘自古風波險，玉洞無人水竹閒。", "霜雪憑虛千尺瀑，煙嵐彌望四圍山。", "登臨欲伴春遊去，惟恐藤蘿不易攀。"]'),
('5b53fd93-f72d-4437-a9da-004c71789fe0','和八舍弟贊賢司理  其一','馮山','宋','宋诗','song-poetry','','[]','湖外閒官四見春，就中吟咏費精神。',64,'全唐诗/poet.song.42000.json','["湖外閒官四見春，就中吟咏費精神。", "青山借得風騷古，白髪相將意思新。", "每向孤高雖得意，要知閒淡苦無人。", "歸來幸有鴒原識，爲惜鴻毛抵萬鈞。"]'),
('f7b0ee72-3da3-4b0a-ad2c-9e1971a2f2c5','和八舍弟贊賢司理  其二','馮山','宋','宋诗','song-poetry','','[]','兄弟當年粗有聲，家風傳得至今清。',64,'全唐诗/poet.song.42000.json','["兄弟當年粗有聲，家風傳得至今清。", "爭先蹤跡雖相讓，投老情懷共一驚。", "富貴有時當自致，文章無價可能輕。", "期君正在青雲上，何止新詩幾首行。"]'),
('07b70b3e-0618-492a-af30-4482afe4c2da','再和二首  其一','馮山','宋','宋诗','song-poetry','','[]','歸来相值故園春，坐對春風忽愴神。',64,'全唐诗/poet.song.42000.json','["歸来相值故園春，坐對春風忽愴神。", "十里溪山依舊好，一番花木爲誰新。", "青雲功業雖留我，白日光陰奈趁人。", "道在不須論用舍，惟將時命托洪鈞。"]'),
('b41bc86b-9579-40c2-a756-2d705f5f04f6','再和二首  其二','馮山','宋','宋诗','song-poetry','','[]','新詩才讀眼惺惺，照見詞源徹底清。',64,'全唐诗/poet.song.42000.json','["新詩才讀眼惺惺，照見詞源徹底清。", "白雪乍聞高唱喜，明珠翻值暗投驚。", "兒童一輩年將晚，研席平生分不輕。", "爲愛惠連才思好，登臨重寄遠山行。"]'),
('247ed7e2-a0ee-459d-9a27-f7dc350d32c3','再和  其一','馮山','宋','宋诗','song-poetry','','[]','莫厭詩筒来往頻，閒中無物可怡神。',64,'全唐诗/poet.song.42000.json','["莫厭詩筒来往頻，閒中無物可怡神。", "追回風雅篇篇好，鍊盡襟懷日日新。", "自笑支離多病客，更隨憔悴苦吟人。", "陽州不識英雄器，重問顔高借六鈞。"]'),
('a5572729-3a4d-47d7-8cab-34570fa8f728','再和  其二','馮山','宋','宋诗','song-poetry','','[]','休向詩中恨不平，范滂留意在澄清。',64,'全唐诗/poet.song.42000.json','["休向詩中恨不平，范滂留意在澄清。", "煙霄鴻鵠飛將到，雷雨龍蛇蟄未驚。", "聲價得来知道長，窮愁消盡覺身輕。", "榮途咫尺非難至，俯拾功名在此行。"]'),
('7efa24bd-cb7c-4e18-964d-f768d4678aed','滴水巖','馮山','宋','宋诗','song-poetry','','[]','飛泉分下一巖寒，誰識神功借意難。',64,'全唐诗/poet.song.42000.json','["飛泉分下一巖寒，誰識神功借意難。", "瀉出龍漦投石上，綴成仙佩落雲端。", "離山便有江流雜，當道寧辭宿眼看。", "幾把狂吟題不就，十年餘思在欄干。"]'),
('84b0b3a2-1580-455c-9c3b-417673ef22c6','重遊滴水巖','馮山','宋','宋诗','song-poetry','','[]','仙佩玲瓏白玉寒，每來常與寺僧看。',32,'全唐诗/poet.song.42000.json','["仙佩玲瓏白玉寒，每來常與寺僧看。", "憂民未有林泉約，重到巖前爲解鞍。"]'),
('6f7c1824-cba1-4548-a86a-7884a8762d7a','存目','馮山','宋','宋诗','song-poetry','','[]','詩題：馮堯民希元先生承詔堂首句：名南山出。',21,'全唐诗/poet.song.42000.json','["詩題：馮堯民希元先生承詔堂首句：名南山出。"]'),
('54929b9f-d37b-4b00-a942-04a1a68a7581','承詔堂','馮堯民','宋','宋诗','song-poetry','','[]','名因南山出，跡爲南山止。',48,'全唐诗/poet.song.42000.json','["名因南山出，跡爲南山止。", "少室價自高，大勞招不起。", "君恩動林壑，古道變閭里。", "堂下松桂栽，清陰從此始。"]'),
('7a9c9fd1-3f4a-4742-b393-e56ebe291826','鴻鵠詩','王安禮','宋','宋诗','song-poetry','','[]','鴻鵠慕稲粱，日夜疑罝罘。',96,'全唐诗/poet.song.42000.json','["鴻鵠慕稲粱，日夜疑罝罘。", "蜻蛉善蜚翔，不爲食飲留。", "膠絲竹竿杪，童子與我仇。", "出處或類此，明明君子羞。", "近世喜高論，罔知道沉浮。", "朵頤非吉人，赴海豈善謀。", "萬事固有理，彼哉寧易求。", "愛子智慮明，吾言非暗投。"]'),
('c7d36052-c1a2-4a7d-b3e1-6e5e19f5a61e','常州寄吕進之五言一首','王安禮','宋','宋诗','song-poetry','','[]','峨峨霍邱上，可以望九州。',108,'全唐诗/poet.song.42000.json','["峨峨霍邱上，可以望九州。", "衮衮蔡河底，日夜無停留。", "子與山水近，官冗亦少休。", "登高望我居，寄書託東舟。", "非唯慰我思，亦以解子憂。", "我欲問子訊，冰泥塞邗溝。", "又欲識子處，東山豈高邱。", "惜哉所處異，會合寧易求。", "何時春風來，從我繁臺游。"]'),
('fa1f528d-8ad6-4329-b62c-21ae2b3b5b22','遊集禧中元東軒分題得東字','王安禮','宋','宋诗','song-poetry','','[]','策馬從仙子，探春遊帝宫。',48,'全唐诗/poet.song.42000.json','["策馬從仙子，探春遊帝宫。", "愛此高尚志，開軒池水東。", "鴨綠漾殘日，樹碧留清風。", "生我瀟灑思，超然塵世中。"]'),
('4c9a88e1-6074-4d9a-a369-eeb85c831714','昔日','王安禮','宋','宋诗','song-poetry','','[]','昔日登名級，天街是勝遊。',48,'全唐诗/poet.song.42000.json','["昔日登名級，天街是勝遊。", "昔日初得志，潘鬢未驚秋。", "逸馭乘風遠，遷鶯出谷幽。", "瓊林頒宴處，樓殿彩雲浮。"]'),
('e502311f-a584-41b6-af0b-b2bba2777d5f','丙寅九月二十日同蔣穎叔從長干雨中登高座寺詩','王安禮','宋','宋诗','song-poetry','','[]','弭節蕭帝寺，驅車成子岡。',120,'全唐诗/poet.song.42000.json','["弭節蕭帝寺，驅車成子岡。", "莽卉翳塗泥，霖雨霑衣裳。", "躋攀踰百尋，險滑步寸量。", "生公不可見，雨花空此堂。", "當時聽說法，神鬼久已藏。", "烟雲渺無窮，凄風來我旁。", "山川萬邑屋，所見未毫芒。", "駕言吾將歸，重勞徒御將。", "遲明羲與和，宇宙觀暄晹。", "安行凌太虛，曠朗觀八荒。"]'),
('e4427943-4cb7-44fd-a3e0-ebc6187c4afb','送别范希聲','王安禮','宋','宋诗','song-poetry','','[]','驛吏闖曉鼓，僕夫樂晨征。',120,'全唐诗/poet.song.42000.json','["驛吏闖曉鼓，僕夫樂晨征。", "叙别何草草，君今千里行。", "捧檄近京國，拜親還洛城。", "層巒望太行，慷慨無俗情。", "嗟我寔僚友，追攀勞至誠。", "贈言豈無意，愛子智慮明。", "抱才太華高，視利鴻毛輕。", "世路有夷險，君行常直清。", "朝廷正博采，幕府詎久攖。", "少别勉自愛，他年看名卿。"]'),
('d581449d-cb59-4396-be1c-962931adf4db','麴院輸麥二十二韻呈開父','王安禮','宋','宋诗','song-poetry','','[]','自訟愚且鄙，平生事辭翰。',264,'全唐诗/poet.song.42000.json','["自訟愚且鄙，平生事辭翰。", "爲文謝超卓，得祿未盈寸。", "一官走窮僻，百事真黽勉。", "昨者得州帖，輸租被公選。", "麴舍只容膝，侍立如牛喘。", "逢逢鼓咽耳，漠漠塵翳眼。", "微風六月息，烈日四簷短。", "一座灑腥雨，萬夫揮午汗。", "斗升煩較量，朱墨謾勾竄。", "豈惟畏刑書，農事寧可緩。", "頼有葛衣翁，志趣頗高簡。", "愛民一心勞，慰我百憂遣。", "誰人坐華堂，玉簟羅婉孌。", "清樽近美竹，冰紈依素扇。", "賢愚定勞逸，貴賤天所綰。", "賦分乃自然，何須慕華弁。", "况予山野姿，夙尚本蕭散。", "縈纒正自取，有類蠶作蠒。", "得桷未知漸，盈庭巳占艮。", "怳怪舊學凋，冥羞素期舛。", "便當謝官長，趨墀來斂板。", "才譾又不力，引去非宜款。"]'),
('d9a78bd0-f99f-4a08-b4d6-0f649eeae5dd','酒罩','王安禮','宋','宋诗','song-poetry','','[]','妙絕因心匠，華堂此集英。',48,'全唐诗/poet.song.42000.json','["妙絕因心匠，華堂此集英。", "輕塵避綠蟻，密影占香瓊。", "醉有陶彭澤，狂如阮步兵。", "甕頭籬菊下，棄擲任縱横。"]'),
('9e3c69e7-d2be-42de-8223-91682fabbbaa','捧香人','王安禮','宋','宋诗','song-poetry','','[]','綺席延佳士，香來似有情。',48,'全唐诗/poet.song.42000.json','["綺席延佳士，香來似有情。", "當年漫拱默，終日費携擎。", "偶以朱藍僣，還因刻畫成。", "猶勝海上客，逐臭了平生。"]'),
('aa9c9402-712c-4734-81f2-65af7cadf577','贈道光法師','王安禮','宋','宋诗','song-poetry','','[]','聞名非一日，許見便忘年。',48,'全唐诗/poet.song.42000.json','["聞名非一日，許見便忘年。", "宴坐得真際，與遊無俗緣。", "杖藜尋古刹，洗鉢試幽泉。", "稍寄鍾山約，臨風但慨然。"]'),
('eb836787-cbfd-41e9-9321-836f286e9864','爲愛','王安禮','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','爲愛詩家景，分題晝幕褰。',48,'全唐诗/poet.song.42000.json','["爲愛詩家景，分題晝幕褰。", "寒生洞庭石，翠滴華峰蓮。", "刷羽天門過，潛鱗海窟眠。", "未饒元白輩，争購百金傳。"]'),
('de807b4b-fbf8-408e-a6cd-8037eda83657','中父禮院學士挽詞','王安禮','宋','宋诗','song-poetry','','[]','漢殿曾親册，收科咫尺間。',48,'全唐诗/poet.song.42000.json','["漢殿曾親册，收科咫尺間。", "文成疾翻水，學富似登山。", "夷路方騰駕，重泉忽掩關。", "鄉人灑涙送，猶想去車還。"]'),
('efd183d3-0158-47e5-8c2b-36f973f39c42','王夫人挽詞二首  其一','王安禮','宋','宋诗','song-poetry','','[]','僊去還緱嶺，喪行指洛川。',48,'全唐诗/poet.song.42000.json','["僊去還緱嶺，喪行指洛川。", "松楸閑故壠，笳鼓咽新阡。", "制詔隆名定，銘詩具美傳。", "王宫盡恩舊，雨泣望雲軿。"]'),
('0265545b-1461-44f6-9204-4e6226ff0ddf','王夫人挽詞二首  其二','王安禮','宋','宋诗','song-poetry','','[]','啟國恩章稱，頒恩典册徽。',48,'全唐诗/poet.song.42000.json','["啟國恩章稱，頒恩典册徽。", "都人瞻鹵簿，王子泣縗衣。", "落日隨丹旐，悲風引素幃。", "西城供祖奠，惆悵昔遊非。"]'),
('e46335dc-7cef-4687-b116-7b71085737e0','贈别君重安撫太尉','王安禮','宋','宋诗','song-poetry','','[]','簫鼓紛紛倒酒樽，賢侯於此駐高軒。',64,'全唐诗/poet.song.42000.json','["簫鼓紛紛倒酒樽，賢侯於此駐高軒。", "平明受詔辭龍闕，睿聖分憂在雁門。", "種落望塵迎漢使，吏民填道看王孫。", "一瞻車馬人皆樂，寧識安邊策略存。"]'),
('ed7b34d9-54d1-4a9c-90f0-3b6346c9d95b','宿直二首  其一','王安禮','宋','宋诗','song-poetry','','[]','天上春風水外寒，瑠璃瓦濕月團團。',64,'全唐诗/poet.song.42000.json','["天上春風水外寒，瑠璃瓦濕月團團。", "千門納鑰塵飛遠，一夕聯文火禁寛。", "人想柝聲來睥睨，鳥驚花影墮欄干。", "少陵老去唯便静，此地優容欲報難。"]'),
('624a331d-d1bc-4224-bbde-c7c97af60e20','宿直二首  其二','王安禮','宋','宋诗','song-poetry','','[]','燭淚漼漼罷賦詩，幅巾乘興步東西。',64,'全唐诗/poet.song.42000.json','["燭淚漼漼罷賦詩，幅巾乘興步東西。", "銀河逼夜光芒墮，玉宇參天次第迷。", "稍夢荆江三里鵠，忽驚漢殿五時鷄。", "平生出處無心較，亦似莊周萬物齊。"]'),
('723a2285-6fd2-462d-a4ba-829df2cc19f2','題靈壁蘭皋張氏園亭','王安禮','宋','宋诗','song-poetry','','[]','池塘脉脉春泉動，亭館陰陰夏木凉。',64,'全唐诗/poet.song.42000.json','["池塘脉脉春泉動，亭館陰陰夏木凉。", "砌葉亂風摇月色，簷枝留雪宿年芳。", "四時氣象誰長見，一夜追遊我太忙。", "從此與君携酒後，夢魂應不隔滄浪。"]'),
('a3f75552-798e-45e2-b341-a8a809c6a998','次韻徽之學士馬上口占','王安禮','宋','宋诗','song-poetry','','[]','料峭風來午漏遲，壁門䡾䡾敞輕支。',64,'全唐诗/poet.song.42000.json','["料峭風來午漏遲，壁門䡾䡾敞輕支。", "侵尋出谷春鶯囀，約略營巢社燕期。", "隱几稍同南郭嗒，濫巾未望北山移。", "值君佳句吟哦久，等是官曹得暇時。"]'),
('67cdb896-943e-4499-a71c-a7aa062176d3','遊齊山','王安禮','宋','宋诗','song-poetry','','[]','曾隨嘉客在層巒，秋色陰晴一望間。',64,'全唐诗/poet.song.42000.json','["曾隨嘉客在層巒，秋色陰晴一望間。", "洞外暫乘雲縹緲，林端時露水灣環。", "維舟暇日來尋勝，經世高才却愛閑。", "聞說使君歌舞去，盛遊應不減東山。"]'),
('0ebc9326-e781-433b-99e5-1a4ebc25a564','瓊林苑賜燕餞别留守太尉輒繼元韻','王安禮','宋','宋诗','song-poetry','','[]','名德從來重四夷，朝廷今日見官儀。',64,'全唐诗/poet.song.42000.json','["名德從來重四夷，朝廷今日見官儀。", "陪祠自冠三公位，分陜猶爲百辟師。", "金谷望塵多眷舊，瓊林賜餞盡丞疑。", "都人喜看旂旄美，寧識勳庸在鼎彛。"]'),
('f10861ac-7cac-4834-8614-21f230742f73','次韻僕射相公侍燕集英長句  其一','王安禮','宋','宋诗','song-poetry','','[]','天授嘉符帝祖宫，仙枝産秀福來崇。',64,'全唐诗/poet.song.42000.json','["天授嘉符帝祖宫，仙枝産秀福來崇。", "金莖對峙靈根固，雲朵交升聖澤通。", "法駕留觀知錫羡，從臣稱慶未辭窮。", "詩人只解歌行葦，寧識君王造化功。"]'),
('2eb9c73b-9d2e-43e3-b100-e232c1b58006','次韻僕射相公侍燕集英長句  其二','王安禮','宋','宋诗','song-poetry','','[]','御沼環流瑞景長，集英宫殿紫宸旁。',64,'全唐诗/poet.song.42000.json','["御沼環流瑞景長，集英宫殿紫宸旁。", "香隨銀漏留春色，花壓瓊筵鬬日光。", "仙樂緩調瞻鳳扆，天人高拱對龍章。", "皇家多慶千官喜，萬歲聲中獻一觴。"]'),
('1a9120a0-e4cf-49a9-ada1-a9b2bcf82542','春日即席有題','王安禮','宋','宋诗','song-poetry','','[]','早是天涯多病客，可堪春末少年時。',64,'全唐诗/poet.song.42000.json','["早是天涯多病客，可堪春末少年時。", "風流任使花王笑，懽樂除非酒伯知。", "荆岫定爲郊社器，渭川終作帝王師。", "琅玕未實烟空老，不恨年来紫鳳饑。"]'),
('4cb9ad86-a257-4c0c-ba94-2f0a399e91be','七言一章贈别吳興太守中父學士兄','王安禮','宋','宋诗','song-poetry','','[]','蓬山仙子任天真，乞領南麾奏疏頻。',64,'全唐诗/poet.song.42000.json','["蓬山仙子任天真，乞領南麾奏疏頻。", "金鏁闕邊辭黼座，水晶宫裏得朱輪。", "公庭事簡煩丞掾，齋閣詩多泣鬼神。", "莫爲行春戀苕霅，鑾坡揮筆待詞臣。"]'),
('2ac774bc-2b61-4481-9b71-76f2fc3f4613','送盧大雅赴闕','王安禮','宋','宋诗','song-poetry','','[]','簫鼓紛紛載酒醪，送行汾水覺秋高。',64,'全唐诗/poet.song.42000.json','["簫鼓紛紛載酒醪，送行汾水覺秋高。", "吏民遮道瞻思切，車馬還朝氣勢豪。", "聖主詢謨忘旰昃，明庭收選盡英髦。", "看君才業何人似，哿矣趨榮勿告勞。"]'),
('d1f52281-33c6-4155-ac53-3f0dd73fafd8','送吕陶赴闕','王安禮','宋','宋诗','song-poetry','','[]','賦比相如已絕倫，即論才識又名臣。',64,'全唐诗/poet.song.42000.json','["賦比相如已絕倫，即論才識又名臣。", "致身可但諸公右，發策宜爲上國珍。", "今日朝廷思讜直，一時賢俊待經綸。", "行看致主唐虞術，與笑淄川曲學人。"]'),
('8eb279d1-cef8-4d1f-87fc-d5c7ec523141','送子玉赴闕','王安禮','宋','宋诗','song-poetry','','[]','寂寞揚雄與世疏，頼逢佳友慰窮居。',64,'全唐诗/poet.song.42000.json','["寂寞揚雄與世疏，頼逢佳友慰窮居。", "深沉智慮三冬學，磊落胸懷萬卷書。", "自古賢豪今日盛，看君才調幾人如。", "還朝好作登瀛客，聞說元臣薦子虛。"]'),
('364bbc70-689b-4662-b747-3f8f86bf826d','和踏青','王安禮','宋','宋诗','song-poetry','','[]','踏青爭惜賞春葩，盡日無辭到月華。',64,'全唐诗/poet.song.42000.json','["踏青爭惜賞春葩，盡日無辭到月華。", "金谷正宜開錦帳，曲江翻想映氈車。", "俠卿醖藉歌飛雪，遊女娉婷臉奪花。", "更詠漢宫傳蠟燭，青烟散入五侯家。"]'),
('d2b1b73b-40c5-421d-a457-1307f06ffca5','清明日賜宴瓊林苑奉酬宫使太師相公','王安禮','宋','宋诗','song-poetry','','[]','清明春律十分回，草色連雲花盡開。',64,'全唐诗/poet.song.42000.json','["清明春律十分回，草色連雲花盡開。", "禁籞幸隨諸彦入，安車仍賜上師陪。", "百壺未許都門餞，九奏先從帝所來。", "魚鑰恩留方錫勸，柳邊遲日莫相催。"]'),
('e1fd6929-cd1c-4b49-9a9b-87d083269fc5','送吳殿中知景陵','王安禮','宋','宋诗','song-poetry','','[]','柘上論功使節臨，奏書傾動士人林。',64,'全唐诗/poet.song.42000.json','["柘上論功使節臨，奏書傾動士人林。", "沙墀通籍霑新寵，澤國鳴弦試好音。", "郭畔黄蘆宜日晚，水邊紅橘與秋深。", "君才八九吞雲夢，應笑離騒向此吟。"]'),
('37859d91-105a-4cb3-955b-c67a8c7818aa','贈無爲張居士','王安禮','宋','宋诗','song-poetry','','[]','余學無爲無所成，每聞風論便神清。',64,'全唐诗/poet.song.42000.json','["余學無爲無所成，每聞風論便神清。", "鄉人來問真如理，居士能忘物我情。", "勝業久應三界護，妙言非止百金輕。", "世途多少冥行客，好與分明說化城。"]'),
('df0c01b4-2a74-49b8-b4f6-156bf79fd243','過王整狀元墓寄薛唐卿郎中','王安禮','宋','宋诗','song-poetry','','[]','始任監州便殞身，我來臨奠重悲君。',64,'全唐诗/poet.song.42000.json','["始任監州便殞身，我來臨奠重悲君。", "一名曾冠千人榜，三尺翻如百姓墳。", "古木带風號晚照，野花和雨泣秋雲。", "賢侯若爲刊碑碣，乞取東床內翰文。"]'),
('fee22c9a-cc64-4c4d-a5ea-e3346439f336','恭和御製上元觀燈','王安禮','宋','宋诗','song-poetry','','[]','鑾輿清曉出瑶臺，羽衛瞻迎扇影開。',64,'全唐诗/poet.song.42000.json','["鑾輿清曉出瑶臺，羽衛瞻迎扇影開。", "鳳闕張燈天上坐，鷄林獻曲海邊來。", "修文可笑秦無策，能賦休誇楚有才。", "星漢末斜鈞樂闋，君王宣示萬年杯。"]'),
('7ad2ec51-37aa-4b9c-be7b-4ed58e524373','謹賦五言一章贈别致政太師','王安禮','宋','宋诗','song-poetry','','[]','封國營邱近，行臚洛水渾。',72,'全唐诗/poet.song.42000.json','["封國營邱近，行臚洛水渾。", "位齊師尚父，名重相公孫。", "勳業歸宗祏，威聲寄塞垣。", "安居今日老，魏闕此心存。", "祖燕臨華省，賡歌屈至尊。", "里門多喜色，雲漢在瑶琨。"]'),
('2158cecb-17ce-43ef-889d-d07a062d805f','奉和留守太尉賜燕玉津園','王安禮','宋','宋诗','song-poetry','','[]','將相儀刑久，師儒典册新。',72,'全唐诗/poet.song.42000.json','["將相儀刑久，師儒典册新。", "乘車朝魏闕，銘鼎頌輿人。", "高會開名苑，多懽浹輔臣。", "僊葩分巨麗，宸藻賜全醇。", "自昔修天爵，平時秉國鈞。", "誰如始終遇，奕葉荷君仁。"]'),
('4e8e78ca-1fb1-4a00-a3c5-24fa430a9c2f','上王端明生日','王安禮','宋','宋诗','song-poetry','','[]','夢帝資良輔，生申恊聖期。',240,'全唐诗/poet.song.42000.json','["夢帝資良輔，生申恊聖期。", "妙齡談國體，初筮得家規。", "侃侃當官色，循循待士辭。", "法冠曾觸佞，諌紙詎容私。", "外歷蕃宣久，歸參待從宜。", "政聲雖召杜，學術本皋夔。", "業履今安匹，賢勞上所知。", "都畿重尹正，延閣舊論思。", "治出諸公右，經爲大帝師。", "三邊更惠愛，一體繫安危。", "羌虜跳西夏，朝家念北陲。", "祕庭還舊秩，左轄正新儀。", "暫屈并門重，其蘇晉國饑。", "指麾柔旅拒，談笑妥惸嫠。", "鄴邑祠河急，荆州禱雨遲。", "怒波回潬磧，旱種變京坻。", "道與千齡遇，身將百祿隨。", "民瞻方有裕，天寵蓋無疑。", "俊乂思皇日，欽明樂胥時。", "緇衣如寵慶，願續武公詩。"]'),
('216548a6-0a55-48f1-a1c4-0d0e7ef740a3','夢長','王安禮','宋','宋诗','song-poetry','','[]','夢長隨永漏，吟苦雜疏鐘。',24,'全唐诗/poet.song.42000.json','["夢長隨永漏，吟苦雜疏鐘。", "動蓋荷風勁，沾裳菊露濃。"]'),
('7b9e9fd8-9a0d-4eca-9c28-0987040119dd','寄君重安撫太尉','王安禮','宋','宋诗','song-poetry','','[]','三伏重冰上五臺，葡萄生摘薦新醅。',32,'全唐诗/poet.song.42000.json','["三伏重冰上五臺，葡萄生摘薦新醅。", "雁門太守佳公子，應喜王孫擁節來。"]'),
('65b7e296-ba1f-4204-9295-915c59dc7cdf','春日感懷','王安禮','宋','宋诗','song-poetry','','[]','柳亭暮靄籠金眼，茶嶺寒輕卓翠旗。',32,'全唐诗/poet.song.42000.json','["柳亭暮靄籠金眼，茶嶺寒輕卓翠旗。", "春色正濃人未老，擲觴飛筆好追隨。"]'),
('a1d5409e-e220-408d-8ca7-a6350f93a78c','清明日賜宴瓊林苑奉酬宫使太師相公  其一','王安禮','宋','宋诗','song-poetry','','[]','幾年留滯起邊愁，只憶家園爛熳遊。',32,'全唐诗/poet.song.42000.json','["幾年留滯起邊愁，只憶家園爛熳遊。", "今日西來更愁索，却令人意憶并州。"]'),
('5a88c9ef-66fc-46fe-914e-4aa72b218444','清明日賜宴瓊林苑奉酬宫使太師相公  其二','王安禮','宋','宋诗','song-poetry','','[]','戎鼙聲裏冷雲秋，投老難堪此段愁。',32,'全唐诗/poet.song.42000.json','["戎鼙聲裏冷雲秋，投老難堪此段愁。", "說似旁人都不管，待凴書劄到并州。"]'),
('95b6a778-81fb-4e13-aa7f-220705f16530','清明日賜宴瓊林苑奉酬宫使太師相公  其三','王安禮','宋','宋诗','song-poetry','','[]','月墀繡屐想無蹤，庭戶新凉綠簟空。',32,'全唐诗/poet.song.42000.json','["月墀繡屐想無蹤，庭戶新凉綠簟空。", "寄語金泥舊裙衩，莫敎放盡石榴紅。"]'),
('0549a271-6b34-4e55-9b33-4fdf3d1d9ab0','駕幸太學','梁燾','宋','宋诗','song-poetry','','[]','原廟親持十月觴，天迴寶輦款虞庠。',64,'全唐诗/poet.song.42000.json','["原廟親持十月觴，天迴寶輦款虞庠。", "當陽赭幄翔龍座，屬地霜袍振鷺行。", "拭目嚮儒移美俗，虛懷稽古自興王。", "太平重見清風頌，嘉句飛傳到玉堂。"]'),
('b4dca974-9cae-4e94-81d8-b4eb7cfd0437','駕幸太學','周商','宋','宋诗','song-poetry','','[]','雲覆鸞輿五色章，鳴鞘聲肅下儒庠。',64,'全唐诗/poet.song.42000.json','["雲覆鸞輿五色章，鳴鞘聲肅下儒庠。", "佩衿霧集三千子，儀衛星羅十二行。", "位列夔龍陪帝聖，經陳戊甲獻成王。", "元龜象齒方來供，不用論兵政事堂。"]'),
('f70fa72a-1955-4bc4-8819-2c9df8e8a89e','走筆代書寄岊仲七弟','錢勰','宋','宋诗','song-poetry','','["\u897f\u6e56"]','東方千騎擁朱輪，衣錦歸逢故國春。',32,'全唐诗/poet.song.42000.json','["東方千騎擁朱輪，衣錦歸逢故國春。", "莫向西湖戀風月，鴒原知有望歸人。"]'),
('401ef946-20ce-4d7f-846f-9602330ca868','次秦少游春日偶題韻二首  其一','錢勰','宋','宋诗','song-poetry','','[]','藏室委蛇詠素絲，春風初動萬年枝。',32,'全唐诗/poet.song.42000.json','["藏室委蛇詠素絲，春風初動萬年枝。", "如何愁嘆無行路，卻似袁安臥雪時。"]'),
('481164de-1c73-4516-87c3-eb774e48f427','次秦少游春日偶題韻二首  其二','錢勰','宋','宋诗','song-poetry','','[]','春雪唯添鑑裏絲，慵將淚眼看花枝。',32,'全唐诗/poet.song.42000.json','["春雪唯添鑑裏絲，慵將淚眼看花枝。", "𨃟躋伏枕呻吟日，枉過還家一笑時。"]'),
('0c683242-88d8-420e-954d-6992ff9c59bf','又二十八字輒送來米二石','錢勰','宋','宋诗','song-poetry','','[]','儒館優賢蓋取頤，校讎猶自困朝饑。',32,'全唐诗/poet.song.42000.json','["儒館優賢蓋取頤，校讎猶自困朝饑。", "西鄰餘祿無多子，稀薄纔堪作淖糜。"]'),
('f099d670-cdf8-4283-ac1b-4d7dff7b11da','再答二十八字','錢勰','宋','宋诗','song-poetry','','[]','春雪嚴凝暖未回，圍爐猶擁已燃灰。',32,'全唐诗/poet.song.42000.json','["春雪嚴凝暖未回，圍爐猶擁已燃灰。", "明朝知是長齋畢，準擬衝泥踏水來。"]'),
('ea0bf94b-7077-4d7f-b806-73fb5e3e2fd0','出省馬上有懷蔣穎叔二首  其一','錢勰','宋','宋诗','song-poetry','','[]','春雪京城一尺泥，並鞍還憶蔣征西。',32,'全唐诗/poet.song.42000.json','["春雪京城一尺泥，並鞍還憶蔣征西。", "碧幢紅旆出關去，一路東風送馬蹄。"]'),
('1e1d545b-ab96-48ab-b2c4-595d605face3','出省馬上有懷蔣穎叔二首  其二','錢勰','宋','宋诗','song-poetry','','[]','不論埃壒與塗泥，封印還家日已西。',32,'全唐诗/poet.song.42000.json','["不論埃壒與塗泥，封印還家日已西。", "豈比元戎碧油下，貔貅繞帳馬千蹄。"]'),
('4da2a84c-50a6-42f5-8e1b-be3a09293fc5','睦州秀亭','錢勰','宋','宋诗','song-poetry','','[]','秀色四時好，探春來此亭。',48,'全唐诗/poet.song.42000.json','["秀色四時好，探春來此亭。", "花初擁檻發，山晚與雲青。", "得鱠嚴陵瀨，評泉陸羽經。", "歡餘不盡醉，鼓角限重扃。"]'),
('8b6f7044-2be9-498d-aefe-43757d967d23','甘棠樓','錢勰','宋','宋诗','song-poetry','','[]','樓曲開三面，山重合四圍。',48,'全唐诗/poet.song.42000.json','["樓曲開三面，山重合四圍。", "溪衝朝靄出，帆並夕陽飛。", "芳杜供春望，晴雲渡袷衣。", "樊川猶未識，清興莫忘歸。"]'),
('393eea26-843f-48ac-b09f-9857b54b7778','高峰寺','錢勰','宋','宋诗','song-poetry','','[]','苒苒郡城東，穿雲入幾重。',48,'全唐诗/poet.song.42000.json','["苒苒郡城東，穿雲入幾重。", "已窮難上路，才到最高峰。", "竹老龍孫瘦，泉甘馬酒濃。", "何當來潄石，安穩飽疏慵。"]'),
('9cd0bcf0-1307-4441-bfc5-8d150cbf5d15','東館樓','錢勰','宋','宋诗','song-poetry','','[]','簾影隔朝暾，雲低晝尚昏。',48,'全唐诗/poet.song.42000.json','["簾影隔朝暾，雲低晝尚昏。", "山形分歙翠，溪色到江渾。", "日盡天垂幕，歌餘酒滿尊。", "欄干不堪倚，歸思斷鄉魂。"]'),
('5fc5cc45-f8e8-4e26-a14f-451e684432c9','玉泉菴','錢勰','宋','宋诗','song-poetry','','[]','遙派落天潢，分崖射璧光。',48,'全唐诗/poet.song.42000.json','["遙派落天潢，分崖射璧光。", "山從千古潤，江得一源長。", "風雨無時作，珠璣滿谷量。", "淄澠欲誰辨，願借易牙嘗。"]'),
('b64e422e-4fa8-494f-8f36-151651d8bf7e','分韻奉送中濟侍郎出帥環慶得啟字','錢勰','宋','宋诗','song-poetry','','[]','除戎問邊鎖，謀帥繫國體。',120,'全唐诗/poet.song.42000.json','["除戎問邊鎖，謀帥繫國體。", "遴簡出絲緡，光華建旌棨。", "威謀重兼濟，垢翫當一洗。", "游刃無全牛，豈復論肯綮。", "勇猛不爲邊，九伐秉周禮。", "行期凱歌還，宸廷聊聚米。", "遊從惜暌離，合醵置甘醴。", "靈囿鬰敷腴，天潢湛清泚。", "偕賦踵前修，銀鈎閟方底。", "從予輕若飛，吾方慚七啟。"]'),
('38f93d9a-baa9-4843-9520-775b7adb0996','赴越書呈杭州熊侍郎','錢勰','宋','宋诗','song-poetry','','[]','鑑湖清泚對胥山，兩地相望一水間。',64,'全唐诗/poet.song.42000.json','["鑑湖清泚對胥山，兩地相望一水間。", "共佩天涯太守印，猶聯丹陛侍臣班。", "君方白傅才何愧，我比微之思苦慳。", "莫把舊詩猶見詫，繁雄未必勝清閑。"]'),
('07a0043d-6fc4-49db-a535-5f0c7c73a155','題萬年妙蓮閣','錢勰','宋','宋诗','song-poetry','','[]','應真飛錫靄靈蹤，智者遺杉尚灌叢。',64,'全唐诗/poet.song.42000.json','["應真飛錫靄靈蹤，智者遺杉尚灌叢。", "寶構迥臨清鑑上，妙蓮高擢汙泥中。", "甚深祕藏資談席，最上真乘振祖風。", "嗟我拘攣猶未歷，坐馳神爽愧興公。"]'),
('29b4b7ff-53c3-4636-a22a-226d8896c979','與辯才東坡道潛倡和詩','錢勰','宋','宋诗','song-poetry','','[]','幻泡昧空色，真夢迷黄邱。',120,'全唐诗/poet.song.42000.json','["幻泡昧空色，真夢迷黄邱。", "宦學類狂走，爾來三十秋。", "齒髪非他時，歲月不我留。", "古剎插亂石，蟄龍蟠霞湫。", "天人大導師，駐錫今白頭。", "安住善護念，晚節非沉浮。", "昔嘗同出處，未用相劣優。", "權寔分二乘，股肱均九流。", "今知攪攪者，詎得逍遙游。", "從茲許禮足，尚可治幽憂。"]'),
('812f2608-7711-46dc-8cc0-146ab59cf3a7','詠辯才大師','錢勰','宋','宋诗','song-poetry','','[]','辯才天人師，一意演說法。',72,'全唐诗/poet.song.42000.json','["辯才天人師，一意演說法。", "猶如一雨傾，藥草皆萌達。", "甕盎及湖海，各觀天一月。", "以是度衆生，報身隨數滅。", "舊龕留香燈，想像瞻華髪。", "應供無時窮，龍淵莫之竭。"]'),
('488f3ef1-3038-4f82-b4b0-46afdc54fae7','和閣老舍人曝書會','錢勰','宋','宋诗','song-poetry','','[]','天祿圖書府，芸籤歲曝頻。',48,'全唐诗/poet.song.42000.json','["天祿圖書府，芸籤歲曝頻。", "繙經窮藏室，賜會集儒紳。", "顧陸高標好，鍾王妙入神。", "司無槧俗吏，來預石渠賓。"]'),
('82bf618c-bfa1-4388-850c-ca2cb48324dd','送奉使鈐轄高侯之任成都','錢勰','宋','宋诗','song-poetry','','[]','烈士由來不徇名，西南萬里不留行。',64,'全唐诗/poet.song.42000.json','["烈士由來不徇名，西南萬里不留行。", "熊羆訓整屯千計，尊俎雍容鎮百城。", "閫外使華新報聘，山西家法舊論兵。", "封侯富貴須由命，請訪沈冥賣卜生。"]'),
('ffb7fdbc-3014-4e16-a671-b1c79eb72e52','謝子瞻內翰浙西開府','錢勰','宋','宋诗','song-poetry','','[]','雋庭鴛鷺集珍叢，病翮摧頹下九門。',48,'全唐诗/poet.song.42000.json','["雋庭鴛鷺集珍叢，病翮摧頹下九門。", "罪戾我慚非晝錦，回翔公亦暫朱輪。", "龔黄政化知應爾，夔契謀謨想自存。"]'),
('6d2beffc-376d-4e56-87b6-6819843a8c6e','成都','錢勰','宋','宋诗','song-poetry','','[]','武侯千載有餘靈，盤石刀痕尚未平。',64,'全唐诗/poet.song.42000.json','["武侯千載有餘靈，盤石刀痕尚未平。", "巴婦自饒丹穴富，漢庭還負碧砮征。", "雨經蜀市應和酒，琴到臨卭別寄情。", "知有忠臣能叱馭，不論雲棧更崢嶸。"]'),
('f030ff9e-8b38-4220-bd07-9c11099f5be7','題齊山寺壁','錢勰','宋','宋诗','song-poetry','','[]','來逢采石連江雪，坐見齊山拂檻梅。',32,'全唐诗/poet.song.42000.json','["來逢采石連江雪，坐見齊山拂檻梅。", "惆悵佳人隔煙水，碧雲空谷未歸來。"]'),
('edeb914d-2c02-4c9e-a949-2b25ec0ff5d3','句  其一','錢勰','宋','宋诗','song-poetry','','[]','一來亦甘草，無使君子疑。',12,'全唐诗/poet.song.42000.json','["一來亦甘草，無使君子疑。"]'),
('9854a3be-6054-48b8-9705-c09c6a4df02c','句  其二','錢勰','宋','宋诗','song-poetry','','[]','敢云霹靂手，且免鶻鷺蹄。',12,'全唐诗/poet.song.42000.json','["敢云霹靂手，且免鶻鷺蹄。"]'),
('4ebcbef6-b27e-4b42-868c-67f8e4abde45','句  其三','錢勰','宋','宋诗','song-poetry','','[]','夢澤盤山長卿賦，朱欄流水牧之詩。',16,'全唐诗/poet.song.42000.json','["夢澤盤山長卿賦，朱欄流水牧之詩。"]'),
('dd1e7739-2b9b-4c44-80e3-2b99054e5e54','句  其四','錢勰','宋','宋诗','song-poetry','','[]','衰遲猶許望光塵。',8,'全唐诗/poet.song.42000.json','["衰遲猶許望光塵。"]'),
('ca89ba37-c9e2-40fd-b108-f34aefc27a92','句  其五','錢勰','宋','宋诗','song-poetry','','[]','碧玉簪長生洞府，黄金杯重壓銀臺。',16,'全唐诗/poet.song.42000.json','["碧玉簪長生洞府，黄金杯重壓銀臺。"]'),
('15e90b2d-5285-4b04-89e4-f5264ad4e746','句  其六','錢勰','宋','宋诗','song-poetry','','[]','列聖公規修盛典，萬方和氣助升煙。',16,'全唐诗/poet.song.42000.json','["列聖公規修盛典，萬方和氣助升煙。"]'),
('40cc1669-3090-4fd4-ab20-9197f9ce8223','次韻穆父兄見寄','錢龢','宋','宋诗','song-poetry','','[]','烏衣巷裏走雙輪，正是家山二月春。',32,'全唐诗/poet.song.42000.json','["烏衣巷裏走雙輪，正是家山二月春。", "明日湖平定歸去，蓬萊還見謫仙人。"]'),
('d5b94356-56ec-4534-adcb-44dc76e4d41e','浯溪','錢龢','宋','宋诗','song-poetry','','[]','唐室中興頌德碑，元顔文字孰宜爲。',32,'全唐诗/poet.song.42000.json','["唐室中興頌德碑，元顔文字孰宜爲。", "天齊崖石磨鐫久，萬世功名不可隳。"]'),
('9db60639-9db5-4fca-bbe5-b2966102d4df','重題江干初雪圖','安燾','宋','宋诗','song-poetry','','[]','曾遊滄海困驚瀾，晚涉風波路更難。',32,'全唐诗/poet.song.42000.json','["曾遊滄海困驚瀾，晚涉風波路更難。", "從此江湖無限興，不如祇向畫圖看。"]'),
('22d3e003-ea33-465f-ab26-8eae7fe849ec','清明日赴玉津園宴集','安燾','宋','宋诗','song-poetry','','[]','帝眷三朝輔弼臣，詔頒禁籞燕慈均。',64,'全唐诗/poet.song.42000.json','["帝眷三朝輔弼臣，詔頒禁籞燕慈均。", "已驚貴老恩榮厚，重嘆優賢禮意新。", "使至屢聞天上語，酒酣想見洞中春。", "太平無事忘情久，更接人間事了人。"]'),
('8d41ec6f-e2de-490d-9752-4b2dc6743f6c','葛仙洞','孫載','宋','宋诗','song-poetry','','[]','九載功成駕鶴駢，空遺丹竈冷無煙。',64,'全唐诗/poet.song.42000.json','["九載功成駕鶴駢，空遺丹竈冷無煙。", "衣冠昔日猶埋塚，雞犬當時亦上天。", "高步瑤池觀日月，幾經滄海變桑田。", "可憐黄野歸來晚，留與人間作地仙。"]'),
('305fc5bf-3eae-4e8b-a206-3b62312b45b3','景泰禪閣','孫載','宋','宋诗','song-poetry','','[]','二山環合壁相重，禪閣欹危杳靄中。',64,'全唐诗/poet.song.42000.json','["二山環合壁相重，禪閣欹危杳靄中。", "雲塔孤標淩絕巘，石樓雙峙聳晴空。", "靈泉冷透千巖翠，古木陰生萬壑風。", "自笑塵勞促歸思，懶將身世問禪翁。"]'),
('9bcd15b2-0ab0-481c-8b13-a6565f458a61','題中閣','孫載','宋','宋诗','song-poetry','','[]','中閣猶追舊寺名，淩虛闌檻拂雲平。',63,'全唐诗/poet.song.42000.json','["中閣猶追舊寺名，淩虛闌檻拂雲平。", "煙迷勾漏燒丹竈，雨雜尚書舊履聲。", "泉水幾年明鑑曲，甽田一日布枰。", "卻收謝客尋山屐，且共禪師語此生。"]'),
('bf448ad8-6448-4754-8ce0-95a20c4fdb8b','句  其一','孫載','宋','宋诗','song-poetry','','[]','地據淮西盡，江吞石壁寬。',12,'全唐诗/poet.song.42000.json','["地據淮西盡，江吞石壁寬。"]'),
('424ac766-1bb3-4381-9100-20c5a50c1407','句  其二','孫載','宋','宋诗','song-poetry','','[]','雲夢南州富物華。',8,'全唐诗/poet.song.42000.json','["雲夢南州富物華。"]'),
('d6a1df70-7d08-4cd6-8d44-188288977f0b','碧巖亭和許門下韻','王汝舟','宋','宋诗','song-poetry','','[]','亭開幽谷草堂邊，朝暮清音落檻前。',64,'全唐诗/poet.song.42000.json','["亭開幽谷草堂邊，朝暮清音落檻前。", "人去日昇蓬島路，客來空愛玉溪泉。", "仙翁世界藏沈洞，佛子樓臺出半天。", "誰爲琢磨巖下石，擬將遺事記當年。"]'),
('d11b6238-7421-4c8e-b891-15c1f29a5730','蘆花','王汝舟','宋','宋诗','song-poetry','','[]','琵琶亭前夜泊舟，荻花瑟瑟風颼颼。',32,'全唐诗/poet.song.42000.json','["琵琶亭前夜泊舟，荻花瑟瑟風颼颼。", "潯陽夜靜月如晝，琵琶寂寞江空流。"]'),
('58927a27-6a6e-49d9-8927-e294116f8f4f','翠微峰','王汝舟','宋','宋诗','song-poetry','','[]','塵囂十里清，秀嶺半空插。',156,'全唐诗/poet.song.42000.json','["塵囂十里清，秀嶺半空插。", "縈紆疑無路，兩石開一峽。", "豁然見天宇，四顧皆峭拔。", "入門上石級，傴僂如登塔。", "懸巖置樓殿，飛棟相匼匝。", "徐行雲影動，低語谷聲答。", "仰視絕壁間，勢恐千仞壓。", "側身過幽谷，洞口若呀呻。", "仙英去何許，遺像寄山脅。", "浴池弄清泚，不敢着脚踏。", "顧余倦遊者，一宿借雲榻。", "天風吹夜籟，客興亦蕭颯。", "幽尋約重來，吾屐當再蠟。"]'),
('4a0e530a-be25-46f2-9cdf-1edde8fe995e','詠歸堂隱鱗洞  其一','王汝舟','宋','宋诗','song-poetry','','[]','先生名利比塵灰，綠竹青松手自栽。',32,'全唐诗/poet.song.42000.json','["先生名利比塵灰，綠竹青松手自栽。", "擬把一竿盤石上，幅巾閑過峽山來。"]'),
('41cf0a84-34b1-49a9-81da-83a682fea77c','詠歸堂隱鱗洞  其二','王汝舟','宋','宋诗','song-poetry','','[]','清時通退一何忙，撫志山西漢仲長。',32,'全唐诗/poet.song.42000.json','["清時通退一何忙，撫志山西漢仲長。", "靜覺眼根無俗物，翛然一室自焚香。"]'),
('d28a6060-89bd-4fbb-a4c7-40f05109499e','詠歸堂隱鱗洞  其三','王汝舟','宋','宋诗','song-poetry','','[]','隱德家聲累世聞，考槃幽澗作閑人。',32,'全唐诗/poet.song.42000.json','["隱德家聲累世聞，考槃幽澗作閑人。", "夭紅過眼隨榮謝，菊秀蘭香自占春。"]'),
('d537b4d3-2a4b-4fcd-ae51-5e1a27c09a15','詠歸堂隱鱗洞  其四','王汝舟','宋','宋诗','song-poetry','','[]','種竹淇園遠致君，生平孤節負辛勤。',32,'全唐诗/poet.song.42000.json','["種竹淇園遠致君，生平孤節負辛勤。", "需賢側席非無意，地遠言輕豈易聞。"]'),
('2176ebf0-d71e-4e90-802b-4a9cefeb21cc','藏春秋','王汝舟','宋','宋诗','song-poetry','','[]','短樓矮閣小亭臺，中有高人避世埃。',64,'全唐诗/poet.song.42000.json','["短樓矮閣小亭臺，中有高人避世埃。", "寒翠自憐霜後竹，清香誰辨雪中梅。", "喧囂祇爲鶯聲巧，漏泄多應柳眼開。", "只恐藏春藏不得，東君勾勒下山來。"]'),
('7aaa151d-42de-4e97-8528-1c450677bfe8','和秦少游贈劉景文韻','王欽臣','宋','宋诗','song-poetry','','[]','每愛揚莊解薦雄，喜君歸興自江東。',64,'全唐诗/poet.song.42000.json','["每愛揚莊解薦雄，喜君歸興自江東。", "軒昂豈爲兵家學，磊落真餘國士風。", "垂橐忽驚詩滿卷，論文常負酒樽空。", "邊州千騎新居上，莫憶鱸魚記棹蓬。"]'),
('252cb7df-70d9-436e-85bd-f037a5a855fb','召試學士院試罷作','王欽臣','宋','宋诗','song-poetry','','[]','翠木陰陰白玉堂，老來方此試文章。',32,'全唐诗/poet.song.42000.json','["翠木陰陰白玉堂，老來方此試文章。", "日斜奏罷長楊賦，閑拂塵埃看畫牆。"]'),
('925dfafe-c7bc-4a1d-b6bb-bf99ef3f4001','宿華岳觀','王欽臣','宋','宋诗','song-poetry','','[]','凌空老樹雲垂葉，壓屋梨花雪照人。',32,'全唐诗/poet.song.42000.json','["凌空老樹雲垂葉，壓屋梨花雪照人。", "深愧地仙教俗客，殷勤留看華山香。"]'),
('6dd34762-b07e-4941-a271-0f975309e3b3','再題華岳觀','王欽臣','宋','宋诗','song-poetry','','[]','石壇流水共蒼苔，青竹林間一徑開。',32,'全唐诗/poet.song.42000.json','["石壇流水共蒼苔，青竹林間一徑開。", "可惜梨花飛已盡，前年遊客始重來。"]'),
('13498a89-df16-4d90-950c-735458568226','魏宮彈棋局','王欽臣','宋','宋诗','song-poetry','','[]','鄴城臺殿付塵埃，玉局依然獨未灰。',64,'全唐诗/poet.song.42000.json','["鄴城臺殿付塵埃，玉局依然獨未灰。", "妙手一彈那復得，寶奩當日爲誰開。", "飄零久已拋紅子，埋沒惟斯近紫苔。", "此藝不傳真可惜，摩挲聊記再看來。"]'),
('37e7ea7e-cd90-4d93-9c60-0e47f9082e5c','使遼回竟恭敏李公席上作','王欽臣','宋','宋诗','song-poetry','','[]','穹廬三月已淹留，白草黄雲見即愁。',32,'全唐诗/poet.song.42000.json','["穹廬三月已淹留，白草黄雲見即愁。", "滿袖塵埃何處說，李家池上海棠洲。"]'),
('2bc62ff2-9d6a-4603-86a0-5656c32f2ee0','戲書長老院','王欽臣','宋','宋诗','song-poetry','','[]','蜀國相如最好辭，武皇深恨不同時。',32,'全唐诗/poet.song.42000.json','["蜀國相如最好辭，武皇深恨不同時。", "凌雲賦罷還無事，寂寞文園興可知。"]'),
('48e78027-8153-41c0-a66b-071456e6eba5','與秦少游于恭敏李公閑燕堂聯句','王欽臣','宋','宋诗','song-poetry','','[]','黄葉山頭初带雪，綠波尊酒暫回春。',64,'全唐诗/poet.song.42000.json','["黄葉山頭初带雪，綠波尊酒暫回春。", "已聞璧月瓊枝句，更著朝雲暮雨人。", "老愧紅妝翻曲妙，喜逢佳客放懷新。", "天明又出桃源去，仙境何時再問津。"]'),
('46c31cb9-2a93-4b1d-b7c4-6e7621924174','述夢','王欽臣','宋','宋诗','song-poetry','','[]','曉雪誰驚最後時，土膏方得助甘滋。',64,'全唐诗/poet.song.42000.json','["曉雪誰驚最後時，土膏方得助甘滋。", "歲功已覺三元近，春事何憂一覽遲。", "不著寒梅容觸冒，半留紅杏惜離披。", "神交彼此無勞辨，更爲公題述夢詩。"]'),
('4d93443e-c0c2-4db0-9cc3-feb0a8aa7391','次韻蘇子由詠李伯時所藏韓幹馬','王欽臣','宋','宋诗','song-poetry','','[]','天閑不遇頭亦垂，真姓本不求青絲。',162,'全唐诗/poet.song.42000.json','["天閑不遇頭亦垂，真姓本不求青絲。", "由來奇骨類奇士，立見俱似囊中錐。", "鳳頭初踏蔥嶺至，繡膊東由青海馳。", "春風宛轉白玉鐙，晚日照耀黄金羈。", "李侯對此意匠發，造物真比毫端奇。", "方歅之相豈可擬，顛倒未免雄稱雌。", "翰林相繼寫高韻，何止羊何共和之。", "玉花照夜古稱美，顔色乃是論其皮。", "固知神駿不易寫，心與道合方能知。", "文章書畫固一理，不見摩詰前身應畫師。"]'),
('31f4e175-81ac-44b5-beb4-70c502c4a7fa','題萬年妙蓮閣','王欽臣','宋','宋诗','song-poetry','','[]','石橋飛錫斷遺蹤，揮塵談禪想舊叢。',64,'全唐诗/poet.song.42000.json','["石橋飛錫斷遺蹤，揮塵談禪想舊叢。", "萬萼蓮新青嶂外，十圍松老白雲中。", "他年宴坐開華構，當日咨承擬順風。", "歲晚丹丘如可約，杖藜相引欲煩公。"]'),
('2f67e001-fb22-47e4-a8f5-5bbc9256735a','奉送中濟經略侍郎赴鎮慶州得元字','王欽臣','宋','宋诗','song-poetry','','[]','遠馭寡上策，羈縻有前言。',120,'全唐诗/poet.song.42000.json','["遠馭寡上策，羈縻有前言。", "平生徙戎論，感慨江應元。", "家世近三河，遊歷多塞垣。", "誰言一方面，十載滯上恩。", "前日詔書下，旌麾方及門。", "部曲已稍集，始知旗鼓尊。", "邊書尚羽急，戍卒仍雲屯。", "東山舊部落，自昔爲牆藩。", "銛鋒固可用，內實須禾虋。", "胸中自有策，肯爲淺見論。"]'),
('58f8a345-e979-4402-a658-d7911ec5bc88','遊王官谷','王欽臣','宋','宋诗','song-poetry','','[]','鐘鼎山林出處明，中間不合枉高情。',32,'全唐诗/poet.song.42000.json','["鐘鼎山林出處明，中間不合枉高情。", "有錢須買王官谷，流水聲中過一生。"]'),
('d1a33308-c96c-436d-b579-0e0b27925cbf','句  其一','王欽臣','宋','宋诗','song-poetry','','[]','誰知第七車中客，天遣歸來助慶禋。',16,'全唐诗/poet.song.42000.json','["誰知第七車中客，天遣歸來助慶禋。"]'),
('7b1265a2-256b-421e-a555-3aaa705a86a3','句  其二','王欽臣','宋','宋诗','song-poetry','','[]','西曹深處見春來。',8,'全唐诗/poet.song.42000.json','["西曹深處見春來。"]'),
('affd9c32-9ccb-4342-8851-e8e6fb992f04','句  其三','王欽臣','宋','宋诗','song-poetry','','[]','碧瓦朱欄相照明。',8,'全唐诗/poet.song.42000.json','["碧瓦朱欄相照明。"]'),
('f4c95b95-2bc2-4470-ae33-602e2b6f01dd','讚死心禪師偈  其一','釋惟久','宋','宋诗','song-poetry','','[]','韶陽死心，靈源甚深。',50,'全唐诗/poet.song.42000.json','["韶陽死心，靈源甚深。", "耳中見色，眼裏聞聲。", "凡明聖昧，後富前貧。", "利生濟物，點鐵成金。", "丹青徒狀，非古非今。"]'),
('28419d85-997b-4103-9ff7-653260ad345e','讚死心禪師偈  其二','釋惟久','宋','宋诗','song-poetry','','[]','死心非真，真非死心。',30,'全唐诗/poet.song.42000.json','["死心非真，真非死心。", "虛空無狀，妙有無形。", "絕後再蘇，親見死心。"]'),
('7d0b3ec7-c8a7-4a75-ae15-a261b915fd3e','讀法界觀','釋惟久','宋','宋诗','song-poetry','','[]','物我元無二，森羅鏡象同。',48,'全唐诗/poet.song.42000.json','["物我元無二，森羅鏡象同。", "明明超主伴，了了徹真空。", "一體含多法，交參帝網中。", "重重無盡意，動靜悉圓通。"]'),
('01fc8b6e-d79b-4168-a098-3ef4cc86876c','斑石枕聯句','向宗道','宋','宋诗','song-poetry','','[]','斸得西山骨，磨礱露斑駮。',291,'全唐诗/poet.song.42000.json','["斸得西山骨，磨礱露斑駮。", "凝結一何怪，形模萬難學。", "直疑彩雲根，又訝紫珉𮁅。", "中瘦{脅皮}蛟腹，外文灼龜殻。", "冷剖清泉肝，𥡥榰老鼇脚。", "堅方君子性，清純聖人璞。", "有氣當補天，無暇應並瑴。", "定漬盤古苔，想漏神農藥。", "堪作夢寐寶，尤是炎蒸託。", "眠月病頭愈，橫風酲肺濯。", "珊瑚侈可唾，陶甄脃堪撲。", "夜深魘鬼驚，晝冷詩魔愕。", "首愜無俗夢，心清去煩惡。", "蘄簟方敢友，蜀筇良可攫。", "何必檄愈風，何必文驅瘧。", "質任兒女嗤，頑宜童僕謔。", "枕流固迂誕，藉糟徒落魄。", "潤生審將雨，輝發疑有珏。", "髑髏莊生狂，虎魄宋武薄。", "欲鑱中郎銘，文章體猶弱。", "欲祕淮南書，神仙志非樂。", "我疑混沌鑛，誰與礱竅鑿。", "可作甘寢輿，華胥詣冥寞。", "子道足施爲，我拙困嬰縛。"]'),
('7b7ca568-2c17-490c-a856-882a3fe9a25a','別諸禪衆  其一','向宗道','宋','宋诗','song-poetry','','[]','四絕之名豈浪傳，千巖萬石五雲間。',32,'全唐诗/poet.song.42000.json','["四絕之名豈浪傳，千巖萬石五雲間。", "無才可述無窮景，祇愛真山似假山。"]'),
('1f5913dd-bae4-4212-8721-10010e537f42','別諸禪衆  其二','向宗道','宋','宋诗','song-poetry','','[]','古殿瑯璫木魚響，匆匆策馬長松間。',32,'全唐诗/poet.song.42000.json','["古殿瑯璫木魚響，匆匆策馬長松間。", "迴頭卻恨歸時早，月淡煙昏不見山。"]'),
('dbcf7692-e9eb-4c48-bd43-542d634f62c8','寶華山','向宗道','宋','宋诗','song-poetry','','[]','松風山月送人歸，幾處溪聲拂馬蹄。',32,'全唐诗/poet.song.42000.json','["松風山月送人歸，幾處溪聲拂馬蹄。", "殿角參差浦雲隱，回頭真似武陵迷。"]'),
('a48571e1-d58f-4bc9-ae15-5af43e964a56','被詔還闕過碧落洞觀元伯兄留題悵然久之兼成拙詩以紀勝概','向宗旦','宋','宋诗','song-poetry','','[]','洞府穹隆罩碧津，雲扃岫幌謝囂塵。',64,'全唐诗/poet.song.42000.json','["洞府穹隆罩碧津，雲扃岫幌謝囂塵。", "泉聲激激撞羣玉，乳溜垂垂掛萬巾。", "絕景多藏窮僻處，勝遊少有放閑人。", "剝苔洗壁三遺刻，惆悵難兄筆尚新。"]'),
('5f192373-4cf1-4bc1-939e-6adc16f26741','桐林驛','向宗旦','宋','宋诗','song-poetry','','[]','落日低垂一兩竿，煙嵐殊未厭躋攀。',32,'全唐诗/poet.song.42000.json','["落日低垂一兩竿，煙嵐殊未厭躋攀。", "馬頭漸近銅林驛，誤認真山做假山。"]'),
('9aa524d1-9180-44a8-a4a6-67eb3d29e2b6','虎跑泉','張彥卿','宋','宋诗','song-poetry','','[]','乳泉發穴漏巖根，亂石成池溜始分。',64,'全唐诗/poet.song.42000.json','["乳泉發穴漏巖根，亂石成池溜始分。", "鴻漸當時高品第，虎跑今日信傳聞。", "山僧勺供疑甘露，野史烹茶勝白雲。", "應是靈源遲出地，不然須冠季卿文。"]'),
('dd1a8fc9-1ac3-4357-8c16-4e07864dd742','司馬太史廟  其一','李奎','宋','宋诗','song-poetry','','[]','生在龍門境，葬臨韓奕坡。',48,'全唐诗/poet.song.42000.json','["生在龍門境，葬臨韓奕坡。", "荒祠鄰后土，孤塚壓黄河。", "澽水愁聲遠，梁山慘色多。", "一言遭顯戮，將奈漢君何。"]'),
('37430e57-468f-414e-9ed5-89097ab9a384','司馬太史廟  其二','李奎','宋','宋诗','song-poetry','','[]','著書雖已先三史，論道如何後六經。',64,'全唐诗/poet.song.42000.json','["著書雖已先三史，論道如何後六經。", "因雪李陵爲國士，豈期武帝有宮刑。", "叢生荆棘迷墳塚，舊畫龍蛇照廟庭。", "爲覽遺文來一奠，不知何在子長靈。"]'),
('bf10fcc7-5110-4e6e-83fc-5df13a763e12','賈司倉祠','趙嗣業','宋','宋诗','song-poetry','','[]','抱負如公屈不伸，古來無有達詩人。',48,'全唐诗/poet.song.42000.json','["抱負如公屈不伸，古來無有達詩人。", "聲名豈似官資小，才調寧如掾俸貧。", "東野舊稱濤湧骨，退之曾說膽過身。"]'),
('0306a281-5f18-4462-9993-ee785538960a','中山廣軒','劉握','宋','宋诗','song-poetry','','[]','天邊登覽處，雕檻俯層岑。',48,'全唐诗/poet.song.42000.json','["天邊登覽處，雕檻俯層岑。", "山到三吳盡，江連百粵深。", "柳煙含晚色，花雨伴春陰。", "騷雅知多助，清虛在當心。"]'),
('740f3015-9557-4521-b0f8-e107f18eb740','句','劉握','宋','宋诗','song-poetry','','[]','玉乳何年終始見，金沙疇昔謾曾聞。',16,'全唐诗/poet.song.42000.json','["玉乳何年終始見，金沙疇昔謾曾聞。"]'),
('e8b0236d-609f-465f-9602-086f1865b58b','句','郭知古','宋','宋诗','song-poetry','','[]','塞草遠連吳會去，羈懷易逐峽江平。',16,'全唐诗/poet.song.42000.json','["塞草遠連吳會去，羈懷易逐峽江平。"]'),
('a3baf342-1543-4eee-9072-98239f7ca35f','通山洞','林通','宋','宋诗','song-poetry','','[]','爲愛通山景致幽，攜琴載酒任遨遊。',64,'全唐诗/poet.song.42000.json','["爲愛通山景致幽，攜琴載酒任遨遊。", "雲封路徑人煙少，翠擁峰巒樹木稠。", "棋石閑敲偏自樂，新詩賦就頓忘憂。", "管他世個塵凡事，春自春來秋自秋。"]'),
('11bac466-1f05-4dfc-824c-ab8a27fda8f7','石床','林通','宋','宋诗','song-poetry','','[]','一榻涵虛洞，岡巒勢若堆。',48,'全唐诗/poet.song.42000.json','["一榻涵虛洞，岡巒勢若堆。", "夢魂迷蛺蝶，枕簟鎖莓苔。", "白晝晴宵裏，清風明月來。", "欲知臥雲趣，不必意崔嵬。"]'),
('ed8e5333-e377-42ac-b0da-531c9f35d6b8','平江亭邀馮山允南同作','趙衮','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','文公昔記滕王閣，氣象終天拂寥廓。',160,'全唐诗/poet.song.42000.json','["文公昔記滕王閣，氣象終天拂寥廓。", "崔顥題詩黄鶴樓，今日聲華還磊落。", "安漢城頭有佳處，江山清氣歸簾幕。", "少陵無人謫仙死，不遇才豪終寂寞。", "蒼苔滿地荆棘生，梁棟塵埃喧鳥雀。", "風流賢守一登臨，久倚闌干情不薄。", "夜來風月覺澄清，天意人心如素約。", "仙葩當見浮空來，幾百年來無此作。", "嗟予好古今白頭，到底支離材力弱。", "木桃或見致瓊瑤，免對江山負慚作。"]'),
('39b2cfdf-7d02-4cdc-99c4-d8b5bc8284b2','句  其一','王安上','宋','宋诗','song-poetry','','[]','歷陽城外桃花塢，臺榭廢來名已古。',16,'全唐诗/poet.song.42000.json','["歷陽城外桃花塢，臺榭廢來名已古。"]'),
('ff29a593-89ea-4c4b-92bc-f19986fcf86e','句  其二','王安上','宋','宋诗','song-poetry','','[]','將軍馬上設良謀，遙望青山指梅樹。',32,'全唐诗/poet.song.42000.json','["將軍馬上設良謀，遙望青山指梅樹。", "日往月來時已久，萬古千年名不朽。"]'),
('57fe2164-af73-4272-9d8a-51339bf6817a','句  其三','王安上','宋','宋诗','song-poetry','','[]','戰士觸熱衝暑霧，舌燥唇乾憚長路。',64,'全唐诗/poet.song.42000.json','["戰士觸熱衝暑霧，舌燥唇乾憚長路。", "將軍馬上設良謀，遙望青山指梅樹。", "齒牙不覺流津津，比似投醪同飲醇。", "漢鼎未扶竟分裂，惜哉不是調羹人。"]'),
('8de499a5-4a7c-472e-af31-728e54a73fb4','句','王彥博','宋','宋诗','song-poetry','','[]','黄鬚戰士據鞍聽，白髮將軍撫劍嘆。',16,'全唐诗/poet.song.42000.json','["黄鬚戰士據鞍聽，白髮將軍撫劍嘆。"]'),
('ce343c67-48dd-4636-bdcb-11981a1504f4','趨石橋初登山嶺','趙屼','宋','宋诗','song-poetry','','[]','天梯欲上使人愁，身御長風不自由。',64,'全唐诗/poet.song.42000.json','["天梯欲上使人愁，身御長風不自由。", "下視白雲生澗底，仰看紅日在山頭。", "共傳此處迷劉阮，自恐今朝犯斗牛。", "歸路似從霄漢墮，卻來塵世得羈囚。"]'),
('b1ad79fe-ad13-4394-9cad-d07cda4c67bb','岑崎山磨崖','趙㞦','宋','宋诗','song-poetry','','[]','洞門喬木晝陰陰，洞穴嵌空透碧岑。',32,'全唐诗/poet.song.42000.json','["洞門喬木晝陰陰，洞穴嵌空透碧岑。", "偶約騷人同此樂，搖毫靜坐發清吟。"]'),
('a52300e8-8205-4374-b212-d10ba0aa5351','萊公竹','李逢','宋','宋诗','song-poetry','','[]','已枯斷竹再成林，既歿賢公帝念深。',32,'全唐诗/poet.song.42000.json','["已枯斷竹再成林，既歿賢公帝念深。", "仆木偃禾如不起，至今誰識大忠心。"]'),
('051e6d79-cc74-4093-875e-304c9a61ee30','送程給事知越州','蔡承禧','宋','宋诗','song-poetry','','[]','萬室羅紈千舸蓬，遶山樓榭滿溪風。',64,'全唐诗/poet.song.42000.json','["萬室羅紈千舸蓬，遶山樓榭滿溪風。", "舟移菡萏芬芳渚，旌倚蓬萊縹緲宮。", "翁子印還多事後，微之名辱宦人中。", "昌時青瑣朱轓貴，白首誰何得似公。"]'),
('8f740cce-129d-44db-a40d-59d2dab0bf98','句','蔡承禧','宋','宋诗','song-poetry','','[]','天上玉欄花已折，人間方士術何施。',16,'全唐诗/poet.song.42000.json','["天上玉欄花已折，人間方士術何施。"]'),
('ec6dc57b-f9a5-45da-8ae4-f7605c1a08d1','題泰山靈巖寺','陳一向','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','石龜泉畔鐵袈裟，上有猿銜五色花。',32,'全唐诗/poet.song.42000.json','["石龜泉畔鐵袈裟，上有猿銜五色花。", "見說道人時掛搭，旋將青拂掃煙霞。"]'),
('7dd54789-91b0-4569-8280-5b1b817f1e57','贈靈巖元長老  其一','陳一向','宋','宋诗','song-poetry','','[]','杖錫池邊六月寒，一泓泉鑑潄瑯玕。',32,'全唐诗/poet.song.42000.json','["杖錫池邊六月寒，一泓泉鑑潄瑯玕。", "直疑夜半天風起，吹落仙人沆瀣盤。"]'),
('7d914965-b3b9-4177-b626-7ee59923d21e','贈靈巖元長老  其二','陳一向','宋','宋诗','song-poetry','','[]','證明臺上玉爐煙，童子生雲不計年。',32,'全唐诗/poet.song.42000.json','["證明臺上玉爐煙，童子生雲不計年。", "對面飛橋架丹壑，此中別有一家山。"]'),
('44ff6afa-709d-4294-9c3c-86482f94a836','贈靈巖元長老  其三','陳一向','宋','宋诗','song-poetry','','[]','濃嵐滴翠曉氤氳，洗我塵襟一二分。',32,'全唐诗/poet.song.42000.json','["濃嵐滴翠曉氤氳，洗我塵襟一二分。", "歸步怪來輕欲舉，朝衣猶带北山雲。"]'),
('02c25b36-5f60-4b53-b343-72d78a0844e9','贈靈巖元長老  其四','陳一向','宋','宋诗','song-poetry','','[]','五花殿角片是間，又被紅塵引出山。',32,'全唐诗/poet.song.42000.json','["五花殿角片是間，又被紅塵引出山。", "第一山前聊駐馬，幾聲雞犬吠雲間。"]'),
('712c0fe9-2499-4859-99b0-e9a7cd91aa8a','淮陰有韓亭枚亭步艤舟亭下作','晁端彥','宋','宋诗','song-poetry','','[]','韓枚步騭建三亭，故顯當時將相名。',32,'全唐诗/poet.song.42000.json','["韓枚步騭建三亭，故顯當時將相名。", "遐想古人興廢事，迺知英傑此中生。"]'),
('1faeb1df-ef00-47f4-9454-15d6c78e9c2c','無心亭','晁端彥','宋','宋诗','song-poetry','','[]','偶坐茲亭上，清風吹客襟。',24,'全唐诗/poet.song.42000.json','["偶坐茲亭上，清風吹客襟。", "孤雲方出岫，相對兩無心。"]'),
('7f3c6c41-8ff0-47d2-90d9-0b1a43dbd4ba','醉眠亭','晁端彥','宋','宋诗','song-poetry','','[]','人生有出處，兩事固希全。',240,'全唐诗/poet.song.42000.json','["人生有出處，兩事固希全。", "達則都廊廟，致君堯舜前。", "聲名喧宇宙，指顧生雲煙。", "不然早晦隱，縱意樂當年。", "第一莫如醉，第二莫如眠。", "無悔水鄉士，子瞻稱其賢。", "埋照不干世，作亭臨清泉。", "歡來即痛飲，酣謔竟長筵。", "陶陶非假寐，泯絕平生緣。", "盡得杯中趣，常爲枕上仙。", "影從明月照，名任清風傳。", "願君遂此志，其樂更相先。", "醉無三日醒，欲盡百斛船。", "境界如古莽，魂夢遊鈞天。", "莫學不佞者，狥祿遭纏牽。", "進無濟世志，退無負郭田。", "獨醒少意緒，寡睡多煩煎。", "風波驚性命，鞍馬積胝胼。", "未得立籬下，應難臥甕邊。", "區區爲宿仕，短詠愧非妍。"]'),
('7ca4e35f-ae32-4834-b440-ea5910e5e7f8','龍湫觀瀑','晁端彥','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','萬丈龍湫水，飛流翠碧開。',48,'全唐诗/poet.song.42000.json','["萬丈龍湫水，飛流翠碧開。", "瀉疑雲漢落，湧若海潮來。", "飄灑四時雪，喧闐萬壑雷。", "廬山吾未到，氣象勝天台。"]'),
('a6a693e4-eeb7-43aa-a219-b86198c35f0e','丹霞山','晁端彥','宋','宋诗','song-poetry','','[]','白鶴山頭飛瀑，玉簫峰頂生煙。',28,'全唐诗/poet.song.42000.json','["白鶴山頭飛瀑，玉簫峰頂生煙。", "溪上空聞流水，竹間不見真仙。"]'),
('fc8b384d-e632-4190-9014-9c455b3fd6b3','詔修兩朝國史開局日史院賜筵首相吳公席上有作奉和原韻','林希','宋','宋诗','song-poetry','','[]','調元台極貴，頒宴帝恩餘。',48,'全唐诗/poet.song.42000.json','["調元台極貴，頒宴帝恩餘。", "昔副名山錄，今裁史觀書。", "天心憂作者，國論屬誰欺。", "寂寞懷鉛客，容瞻相府車。"]'),
('cbaf4674-2681-4fcc-b93a-d9c48056bfb6','初至吳門示諸弟兼呈伯原教授','林希','宋','宋诗','song-poetry','','[]','夢寐家山忽五春，君恩乞與守符新。',64,'全唐诗/poet.song.42000.json','["夢寐家山忽五春，君恩乞與守符新。", "便推白傅爲前政，更得梁鴻作部民。", "入境喜逢餘秉穗，舉杯無復嘆鱸蒓。", "左司西掖誠非據，尤是詩情愧昔人。"]'),
('0c73a998-1469-4131-b0cb-1fe4c227a5a1','將之宣城留別吳門效白樂天體','林希','宋','宋诗','song-poetry','','[]','被詔守東吳，夜渡揚子津。',180,'全唐诗/poet.song.42000.json','["被詔守東吳，夜渡揚子津。", "拭目迎家山，洗我京洛塵。", "此邦多賢豪，況復平生親。", "初欲循故事，公宴月三旬。", "庶以敘契闊，豈徒樂吾身。", "臨州未閱月，吏牘方紛紜。", "避嫌俄得請，主地翻爲賓。", "樽酒未重持，行樂知何因。", "物理可勝嘆，俯仰迹已陳。", "趣整震澤帆，遙挹敬亭春。", "五月而報政，速哉彼齊人。", "今我若置郵，何德於吳民。", "舉手謝吳民，自笑行役頻。", "使君不能詩，煩汝迎送勤。", "來慚白太守，去愧謝宣城。"]'),
('2f46d50e-5bcd-4b2f-8400-5ded26d6944a','疊嶂樓有懷吳門朱伯原','林希','宋','宋诗','song-poetry','','[]','虎丘換得敬亭山，句水松陵數舍間。',64,'全唐诗/poet.song.42000.json','["虎丘換得敬亭山，句水松陵數舍間。", "天下難如兩州好，君恩乞與一身閑。", "漸無牒訴煩敲朴，喜有林泉數往還。", "猶想朋雲隱君子，思歸時見鬢毛斑。"]'),
('66451b12-0406-439f-9641-59d6775f68e9','賀滕元發守吳興','林希','宋','宋诗','song-poetry','','[]','清風樓下兩溪春，三十餘年一夢新。',32,'全唐诗/poet.song.42000.json','["清風樓下兩溪春，三十餘年一夢新。", "欲識玉皇香案吏，水晶宮主謫僊人。"]'),
('5d244dba-3797-40eb-a484-921d93b82ef4','吳興贈賈收二絕句  其一','林希','宋','宋诗','song-poetry','','[]','樂天遺句滿吳門，謝朓窻中列岫存。',32,'全唐诗/poet.song.42000.json','["樂天遺句滿吳門，謝朓窻中列岫存。", "試問白蘋洲上客，詩人賈島有曾孫。"]'),
('bee1d071-b2eb-4379-8398-80d02d6877d4','吳興贈賈收二絕句  其二','林希','宋','宋诗','song-poetry','','[]','歲中謾說易三麾，風月可嘗有別離。',32,'全唐诗/poet.song.42000.json','["歲中謾說易三麾，風月可嘗有別離。", "盡是昔賢吟醉地，惜哉此老不能詩。"]'),
('5375157c-166b-4bef-a274-58ec17783d04','送程給事知越州','林希','宋','宋诗','song-poetry','','[]','政事縱橫絕世才，文章侍從冠鄒枚。',64,'全唐诗/poet.song.42000.json','["政事縱橫絕世才，文章侍從冠鄒枚。", "南州節制金城固，東省深嚴瑣闥開。", "笑別道山探禹穴，暫辭玉案下蓬萊。", "賀家湖上中秋月，遙聽新詩落酒盃。"]'),
('cc45c032-0247-44ba-89bd-6fb797d5541a','詩一首','林希','宋','宋诗','song-poetry','','[]','山川圖寫幾時休，再過蕭山歲已周。',32,'全唐诗/poet.song.42000.json','["山川圖寫幾時休，再過蕭山歲已周。", "客枕夢中南又北，此身大似一虛舟。"]'),
('1a7ddc09-5157-439c-b2eb-a8d9442dcfb9','吳興','林希','宋','宋诗','song-poetry','','[]','遶郭芙蕖拍岸平，花深蕩槳不聞聲。',32,'全唐诗/poet.song.42000.json','["遶郭芙蕖拍岸平，花深蕩槳不聞聲。", "萬家笑語荷花裏，知是人間極樂城。"]'),
('54e42943-e642-42e7-8734-922108a451ca','句  其一','林希','宋','宋诗','song-poetry','','[]','壺嶺共傾銀霅水，墨皇猶展玉樓風。',16,'全唐诗/poet.song.42000.json','["壺嶺共傾銀霅水，墨皇猶展玉樓風。"]'),
('e592b95f-a83e-41af-8c72-579c56148bac','句  其二','林希','宋','宋诗','song-poetry','','[]','傷心父老江津路，猶想當年上塚行。',16,'全唐诗/poet.song.42000.json','["傷心父老江津路，猶想當年上塚行。"]'),
('f35ccbde-122b-485c-ad3a-1e1a03b05459','句  其三','林希','宋','宋诗','song-poetry','','[]','爭覓山林遠城市，不知城市有山林。',16,'全唐诗/poet.song.42000.json','["爭覓山林遠城市，不知城市有山林。"]'),
('02d48afe-f7cc-40f8-8535-c3212e603bb2','句  其四','林希','宋','宋诗','song-poetry','','[]','江聲遠落西岷外，山色都橫北固前。',16,'全唐诗/poet.song.42000.json','["江聲遠落西岷外，山色都橫北固前。"]'),
('53f7c1d1-7be2-4684-84a9-25c0039b5bf0','句  其五','林希','宋','宋诗','song-poetry','','[]','雨過淮山格嫩綠，日銜滄海露殘紅。',16,'全唐诗/poet.song.42000.json','["雨過淮山格嫩綠，日銜滄海露殘紅。"]'),
('8a216a47-0dde-44d4-a8fe-b3935628b051','句  其六','林希','宋','宋诗','song-poetry','','[]','江入海門吞百粵，樓橫鐵甕跨三山。',16,'全唐诗/poet.song.42000.json','["江入海門吞百粵，樓橫鐵甕跨三山。"]'),
('cc7686f5-5523-470a-90cd-97df86296000','余至象山得邑西山谷佳處暇日過遊因其亭榭泉木離爲十詠 西谷','林旦','宋','宋诗','song-poetry','','[]','平昔山林性，今來水石鄉。',48,'全唐诗/poet.song.42000.json','["平昔山林性，今來水石鄉。", "栽花尋秀壠，泛酒掬滄浪。", "地暖春常早，雲陰夏自涼。", "歲成還北去，魂夢此難忘。"]'),
('ca9939e9-1489-4298-ba32-2a582443bc99','余至象山得邑西山谷佳處暇日過遊因其亭榭泉木離爲十詠 應真亭','林旦','宋','宋诗','song-poetry','','[]','我愛井泉清，來逢井上銘。',48,'全唐诗/poet.song.42000.json','["我愛井泉清，來逢井上銘。", "佳名知故里，絕巘爲開亭。", "目外仙舟遠，雲閑拱木青。", "茫然千古意，誰與問滄溟。"]'),
('905670a7-df68-4f1a-a869-7401d3867e02','余至象山得邑西山谷佳處暇日過遊因其亭榭泉木離爲十詠 桃源徑','林旦','宋','宋诗','song-poetry','','[]','十畝紅桃徑，穿花過水西。',48,'全唐诗/poet.song.42000.json','["十畝紅桃徑，穿花過水西。", "清泉來不斷，行客到應迷。", "露錦披芳塢，晴霞倒碧溪。", "年年春意在，當會自成蹊。"]'),
('9ca138cd-3bf7-4561-b311-2f5180a26807','余至象山得邑西山谷佳處暇日過遊因其亭榭泉木離爲十詠 蓬萊泉','林旦','宋','宋诗','song-poetry','','[]','採藥瀛洲去，扁舟竟不還。',48,'全唐诗/poet.song.42000.json','["採藥瀛洲去，扁舟竟不還。", "黄金成海外，故井獨人間。", "乳滴巖花潤，苔封石字斑。", "空令千載後，猶復望三山。"]'),
('95b1082f-5627-4a55-8379-dbdfd18b696c','余至象山得邑西山谷佳處暇日過遊因其亭榭泉木離爲十詠 濯纓亭','林旦','宋','宋诗','song-poetry','','[]','早歲逐浮名，塵埃已倦行。',49,'全唐诗/poet.song.42000.json','["早歲逐浮名，塵埃已倦行。", "浩然而臨絕岸，聊此振煩纓。", "世事隨波遠，吾心自水清。", "營營朝市露，誰識孺歌聲。"]'),
('c3830db0-1879-460c-aa98-26c89750db76','竹閑亭','林旦','宋','宋诗','song-poetry','','[]','昔人嘗種竹，此意爲山林。',48,'全唐诗/poet.song.42000.json','["昔人嘗種竹，此意爲山林。", "野翠何凌亂，羈懷得放吟。", "化龍知有節，待鳳豈無心。", "悵望山陰客，飄然不可尋。"]'),
('79dd08f0-2c8f-48dd-9517-a23db9a4f05c','竹閑亭 曲水亭','林旦','宋','宋诗','song-poetry','','[]','巖溜抱山急，傳觴何太頻。',48,'全唐诗/poet.song.42000.json','["巖溜抱山急，傳觴何太頻。", "迴看野客醉，還笑濁醪醇。", "漢曲人方遠，蘭亭迹已陳。", "勞生無足校，酣放即天真。"]'),
('833e3760-2a2d-409e-81d2-a3912a610f28','竹閑亭 灌木亭','林旦','宋','宋诗','song-poetry','','[]','行行竹間徑，時此一登臨。',48,'全唐诗/poet.song.42000.json','["行行竹間徑，時此一登臨。", "爲有凌霄幹，長垂滿座陰。", "海雲生遠目，山月照閑心。", "幸免材爲累，無言棄擲深。"]'),
('892588a6-aefd-4ad0-9204-603108f0f543','竹閑亭 觀瀾亭','林旦','宋','宋诗','song-poetry','','[]','萬古淵源會，憑欄誙一觀。',48,'全唐诗/poet.song.42000.json','["萬古淵源會，憑欄誙一觀。", "雲濤誰可際，勺水自爲難。", "日月閑中永，乾坤物外寬。", "幽人休悵望，平地亦波瀾。"]'),
('25dd1404-991d-4ddb-9cca-37b35269abdd','竹閑亭 射圃','林旦','宋','宋诗','song-poetry','','[]','百步開新圃，彎弧注采正。',48,'全唐诗/poet.song.42000.json','["百步開新圃，彎弧注采正。", "樽罍供樂事，金鼓疊歡聲。", "敏手徒爲妙，中心自要平。", "何人能舉觶，觀堵定縱橫。"]'),
('297ce552-688f-4282-9862-9739984ad552','虎丘示子虙昔與次中遊題榜尚存','林旦','宋','宋诗','song-poetry','','[]','一望家山上虎丘，凄然魄動念同遊。',64,'全唐诗/poet.song.42000.json','["一望家山上虎丘，凄然魄動念同遊。", "林巒不改如平日，蒲柳先衰又幾秋。", "敢學登臨小東魯，卻因零落恨西州。", "鴒原寂寞歸鴻斷，未拂前題已淚流。"]'),
('4387be31-0cbc-430f-a5fc-1f12baebe192','和張祜韻','林邵','宋','宋诗','song-poetry','','[]','山中多白雲，雲氣歸如吞。',48,'全唐诗/poet.song.42000.json','["山中多白雲，雲氣歸如吞。", "目無塵埃污，耳足清凈根。", "僧歸踏層徑，鳥遠迷孤村。", "來過人跡少，無客掃松門。"]'),
('6cd280b2-81ab-4415-bdf9-8b936c090c07','和孟郊韻','林邵','宋','宋诗','song-poetry','','[]','山僧龐眉蒼，翻徑坐禪床。',48,'全唐诗/poet.song.42000.json','["山僧龐眉蒼，翻徑坐禪床。", "層軒豁遠目，靜室便異香。", "微風仙籟響，過雨晴嵐光。", "何須向廬阜，此即真道場。"]'),
('22826af3-e790-4a4b-8ded-4d674e582bf5','詩一首','林邵','宋','宋诗','song-poetry','','[]','西來漢水接流流，大別山前舊沔州。',32,'全唐诗/poet.song.42000.json','["西來漢水接流流，大別山前舊沔州。", "看到夕陽無盡興，一行飛鷺下汀州。"]'),
('4995fe53-d4a0-4b00-9405-b7928f0e388a','賦贈玉巖  其一','林顔','宋','宋诗','song-poetry','','[]','人在通天第幾巖，玉巖形勝最潭潭。',64,'全唐诗/poet.song.42000.json','["人在通天第幾巖，玉巖形勝最潭潭。", "三鍾攘臂適吾樂，五斗折腰真爾慚。", "漫浪著書酬素志，逍遙齊物載清談。", "超然此道人知少，人日先生爲指南。"]'),
('e17d84eb-fd7d-4ee2-8021-33e6f506e1e9','賦贈玉巖  其二','林顔','宋','宋诗','song-poetry','','[]','萬卷收書肯爲貧，長年石室謝紛紜。',64,'全唐诗/poet.song.42000.json','["萬卷收書肯爲貧，長年石室謝紛紜。", "冥鴻有志難尋跡，野鹿無心不出羣。", "拔俗風標清似水，視人富貴薄於雲。", "柄臣欲強東山起，只恐東山未放君。"]'),
('402de764-0944-41de-b811-8ef26b4bb046','贈玉巖二絕','林顔','宋','宋诗','song-poetry','','[]','一童一鹿自相隨，不覺山間筍蕨肥。',64,'全唐诗/poet.song.42000.json','["一童一鹿自相隨，不覺山間筍蕨肥。", "看盡榮枯彈指頃，燒痕青處認春歸。", "瞥然飛電□雙瞳，短褐長絛如瘦松。", "白玉巖中無一事，爲君題作玉巖翁。"]'),
('89c0e56c-d1c0-4afd-a411-8e94cf6d2c6b','夜樂池','林顔','宋','宋诗','song-poetry','','[]','石室巉巖五十重，洞房七十二芙蓉。',32,'全唐诗/poet.song.42000.json','["石室巉巖五十重，洞房七十二芙蓉。", "夜池惟有仙家樂，笙鶴時來古澗松。"]'),
('a5c3bcaf-22d1-4639-a83f-167ffbc50ab3','彩雲軒','林顔','宋','宋诗','song-poetry','','[]','曾是麻姑此降真，玉峰依舊碧桃春。',32,'全唐诗/poet.song.42000.json','["曾是麻姑此降真，玉峰依舊碧桃春。", "他年欲洗塵埃眼，得見紅顔散髪人。"]'),
('602f20da-3b01-400c-a22d-eb6b3848eed0','送君歸護國寺','林顔','宋','宋诗','song-poetry','','[]','巋然傍勢浙江東，不羨金庭第一峰。',64,'全唐诗/poet.song.42000.json','["巋然傍勢浙江東，不羨金庭第一峰。", "法境常清五十里，妙蓮今現幾千重。", "清涼解洗枝頭露，變現能飛鉢底龍。", "平日舊遊今復到，蒼崖邃谷抱長松。"]'),
('a42c6871-30e5-45ce-9d67-8e0bd9b93707','偶見蜘蛛因成四韻','翟嗣宗','宋','宋诗','song-poetry','','[]','織絲來往疾如梭，長愛騰空作網羅。',64,'全唐诗/poet.song.42000.json','["織絲來往疾如梭，長愛騰空作網羅。", "害物身心雖甚小，漫天綱紀亦無多。", "林間宿鳥應嫌汝，簾外飛蛾亦懼他。", "莫學螳螂捕蟬勇，須知黄雀奈君何。"]'),
('20a58ac5-18c7-461d-8176-fb2480d05d6b','古松行','郭祥正','宋','宋诗','song-poetry','','[]','空山古松閱人代，黛色銅姿終不改。',160,'全唐诗/poet.song.42000.json','["空山古松閱人代，黛色銅姿終不改。", "蚴蟉詰曲還相向，千尋氣結雲靉靆。", "風雨冥冥秋氣深，耳邊往往蒼龍吟。", "蓬萊仙子有無間，往來白鶴晝常陰。", "百尺樛枝拓金戟，山中十月飛霹靂。", "千年化作虬龍形，流脂下見成靈珀。", "方今樓閣連飛甍，斧斤未敢來相傾。", "晦冥神物共訶護，一物鍾靈無不輕。", "我來撫此重嘆息，造物由來貴孤直。", "趺坐松前日將暝，謖謖寒風落巾幘。"]'),
('6c30fe7b-a652-409c-982b-4a664cf7443d','醉歌行','郭祥正','宋','宋诗','song-poetry','','[]','明月珠，不可襦，連城璧，不可餔。',150,'全唐诗/poet.song.42000.json','["明月珠，不可襦，連城璧，不可餔。", "世間所有皆虛無，百年光景駒過隙，功名富貴將焉如。", "君不見北邙山，石羊石虎排無數。", "舊時多有帝王墳，今日纍纍蟄狐兔，殘碑斷碣爲行路。", "又不見秦漢都，百二山河能險固，舊時宮闕亘雲霄。", "今日原田但禾黍，古恨新愁迷草樹。", "不如且買葡萄醅，攜壺挈榼閒往來。", "日日大醉春風臺，何用感慨生悲哀。"]'),
('3150a2b1-83cc-4543-9eef-0479f9806c2c','古劍歌','郭祥正','宋','宋诗','song-poetry','','[]','古有名劍似秋水，龍盤虎拏焰欲起。',212,'全唐诗/poet.song.42000.json','["古有名劍似秋水，龍盤虎拏焰欲起。", "雞林削鐵不足言，昆吾百煉安足齒。", "淬花曾瑩鸊鵜膏，掉箾卻敲鸞鳳髓。", "憶昔破敵如破竹，带霜飛渡桑乾曲。", "電光晝閃白日匿，魑魅走逃罔魎伏。", "於今鏽澀混鉛刀，夜涼風雨青龍哭。", "冰翼雲淡雪花白，血痕冷剝苔花綠。", "我來拔鞘秋風前，毛髪凜凜肝膽寒。", "書生無用暫掛壁，夜來虎氣騰重泉。", "酒酣聞雞起欲舞，明星錯落銀河旋。", "吾聞神物不終藏，豐城紫氛斗牛旁。", "及時與人成大功，豈肯棄置鈍鋒鋩。", "會當斬蛟深入吳潭裏，不然仗汝西域擊名王。"]'),
('f90714b6-f2fc-41f5-b728-a4c7bb279831','漁舟歌','郭祥正','宋','宋诗','song-poetry','','[]','四山颯沓江水流，兩岸西風蘆荻秋。',96,'全唐诗/poet.song.42000.json','["四山颯沓江水流，兩岸西風蘆荻秋。", "漁歌杳杳隔港浦，煙波冥冥來孤舟。", "漁人舉網得赤鯉，魚尾簁簁相顧喜。", "撐船就岸維樹旁，夕陽篷底炊煙起。", "白鷺洲邊隨意浴，孤雲巖際無心逐。", "月明煙岸撇波去，格磔一聲山水綠。"]'),
('aa79e9c1-0606-46cd-839e-735013d6bbd1','楚江行','郭祥正','宋','宋诗','song-poetry','','[]','吾生磊落無滯留，一生好作大江遊，任爾龜鼉跋浪蛟龍愁。',123,'全唐诗/poet.song.42000.json','["吾生磊落無滯留，一生好作大江遊，任爾龜鼉跋浪蛟龍愁。", "昨夜天風下荆楚，我來此地重懷古。", "洛妃湘女不足數，渺渺兮三閭在何所。", "浩蕩煙波江水闊，冥寞神交兩相許。", "倒提金斗傾濁醪，滴瀝招魂寂無語。", "斜陽銜山暝潮退，兩兩漁舟迷向背。", "便欲因之垂釣竿，六鼇一擲天門外。"]'),
('c3eba302-3dc6-4bb8-b981-db47cc991701','九華山行','郭祥正','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','羣山秀色堆寒空，九華一簇青芙蓉。',170,'全唐诗/poet.song.42000.json','["羣山秀色堆寒空，九華一簇青芙蓉。", "誰云九子化爲石，聚頭論道扶天公。", "深巖自積太古雪，燭龍縮爪羞無功。", "湍流萬丈射碧落，此源直與銀河通。", "塵埃一點入不得，烟霧五色朝陽烘。", "有時昏昏雷電怒，崩崖裂壁揮長松。", "龍作雨，虎嘯風。", "白日變明晦，九子亦慘容，褐冠釋氏胡爲笑傲于其中。", "我將學彼術，卷舌切愧求童蒙。", "天公信玉女，號令不爾從。", "嗟爾九子竟何補，非泰非華非衡嵩。"]'),
('e42ed345-be71-4eff-b022-11c064c43f86','廬山三峽石橋行','郭祥正','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','銀河源源天上流，新秋織女望牽牛。',161,'全唐诗/poet.song.42000.json','["銀河源源天上流，新秋織女望牽牛。", "洪波欲渡渡不得，叱鵲爲橋誠拙謀。", "胡不見廬山三峽水，此源亦接明河底。", "擘崖裂嶂何其雄，崩雷泄雲勢披靡。", "飛鳥難過虎豹愁，四時白雪吹不收。", "燭龍此地無行跡，六月游子披貂裘。", "誰將巨斧鑿大石，突兀長橋跨蒼壁。", "行車走馬安如山，下視龍門任淙激。", "寄言牛女勿相疑，地下神工尤更奇。", "喚取河邊作橋棟，一年不必一佳期。"]'),
('27aa483c-2fd2-4da7-b321-9189d77e51e2','谷簾水行','郭祥正','宋','宋诗','song-poetry','','[]','嶄嶄青壑仙人居，水精簾掛光浮浮。',128,'全唐诗/poet.song.42000.json','["嶄嶄青壑仙人居，水精簾掛光浮浮。", "中有天樂振天響，真珠琤淙碎珊瑚。", "嫦娥擁月夜相照，天光地瑩倒玉壺。", "又云玉皇醉玉液，瓊簟千尺從空鋪。", "卧來北斗諫以起，驚風吹落青山隅。", "溶溶萬古萬萬古，竟誰能辨爲真虚。", "我來吟哦不知晚，山雲四暗山魈呼。", "安得長鯨駕天險，下視靈源知有無。"]'),
('c8af343e-dc8e-4396-93a4-cf8e7b2a8482','鸚鵡洲行','郭祥正','宋','宋诗','song-poetry','','[]','猛虎磨牙齒九州，禰生何事來擨。',147,'全唐诗/poet.song.42000.json','["猛虎磨牙齒九州，禰生何事來擨。", "黄雲屯屯宴賓客，故衣脱去更岑牟。", "漁陽摻撾曲聲苦，壯士銜悲寂無語。", "漢朝社稷四百年，海瀉濤淙一抔土。", "嗟哉鼓史狂而癡，天運往矣安能追。", "四方血戰殊未已，三尺棁杖真何爲。", "君不見武昌之國鸚鵡洲，至今芳草含春愁。", "可行則行止則止，死無所益令人羞。", "死無所益令人羞，黄祖曹公均一丘。"]'),
('e1414905-1c2c-4df4-b565-0053ce967202','金山行','郭祥正','宋','宋诗','song-poetry','','[]','金山杳在滄溟中，雪崖冰柱浮仙宫。',192,'全唐诗/poet.song.42000.json','["金山杳在滄溟中，雪崖冰柱浮仙宫。", "乾坤扶持自今古，日月彷彿躔西東。", "我泛靈槎出塵世，搜索異境窺神功。", "一朝登臨重歎息，四時想像何其雄。", "捲簾夜閣挂北斗，大鯨駕浪吹長空。", "舟摧岸斷豈足數，往往霹靂搥蛟龍。", "寒蟾八月蕩瑤海，秋光上下磨青銅。", "鳥飛不盡暮天碧，漁歌忽斷蘆花風。", "蓬萊久聞未成往，壯觀絕致遙應同。", "潮生潮落夜還曉，物與數會誰能窮。", "百年形影浪自苦，便欲此地安微躬。", "白雲南來入我望，又起歸興隨征鴻。"]'),
('185d5a21-9854-4573-9132-b8b3f3e6d288','潛山行','郭祥正','宋','宋诗','song-poetry','','[]','笑别姑熟州，來作潛山遊。',235,'全唐诗/poet.song.42000.json','["笑别姑熟州，來作潛山遊。", "潛山聞名三十載，寫望可以銷吾憂。", "晴雲如綿掛寒木，廣溪鏡靜涵明秋。", "山頭石齒夜璨璨，疑是太古之雪吹不收。", "信哉帝祖駐鑾蹕，異景怪變誰能求。", "若非青崖見白鹿，安得此地排珠樓。", "羣仙長哦空洞絕，綠章封事乘虚輈。", "靈鳥盤旋老鶴舞，華燈散采祥飈浮。", "噫吁嚱，漢武登壇求不得，明皇夜夢推五百。", "寧知司命抱真符，爲宋真人開社稷。", "詔書數下修琳宫，殿閣縹緲平諸峰。", "六朝德澤施愈遠，九天福祐來無窮。", "君不見潛山之下，潛水之涯。", "菖蒲有九節，白术多紫花。", "採之百拜獻君壽，陛下盛德如重華。"]'),
('25f53f95-1ab4-43e9-9514-666e45414796','山中吟','郭祥正','宋','宋诗','song-poetry','','[]','山中吟，白日長，碧霄泉暖菖蒲香。',108,'全唐诗/poet.song.42000.json','["山中吟，白日長，碧霄泉暖菖蒲香。", "仙翁勸我採爲食，登高遂覺足力强。", "登高望遠遠思發，春風浩浩天茫茫。", "美人一别隔滄海，青鳥寄與雙明璫。", "青鳥東飛亦不返，草色綠縟雲徜徉。", "草色幾回綠，雲飛無故鄉。", "魂迷夢斷意何在，山中吟，白日長。"]'),
('caed01d2-4945-4b7f-87b8-9321d60a7ada','山中樂','郭祥正','宋','宋诗','song-poetry','','[]','尋山佳興發，一夜渡江月。',234,'全唐诗/poet.song.42000.json','["尋山佳興發，一夜渡江月。", "首到廬江元放家，水洞清光數毫髮。", "愛之便欲久棲息，又聞靈仙之境敞金闕。", "清風吹我衣，不覺過皖溪。", "危梁千步玉虹卧，松行十里青龍歸。", "烟霞繞脚變明晦，忽見殿閣鋪琉璃。", "重簷却在迥漢上，倚欄俯視白日低。", "虚庭自作簫籟響，屋角更無飛鳥飛。", "霓幡重重蔽真御，彷彿遙見星文垂。", "長廊紗籠絕筆畫，老龜穩載青瑤碑。", "更逢逍遙不死客，齒清髪翠桃花肌。", "簫臺可到亦非遠，雲間况有白鹿騎。", "細窺絕景輒大笑，吾曹何事塵中爲。", "安得良田三百畝，可以飽我妻與兒。", "長年只在名山裏，萬事紛紛都不知。"]'),
('86e7f314-f05c-45dd-ab92-47da406355ae','將歸行','郭祥正','宋','宋诗','song-poetry','','[]','男兒四十無所成，可憐鬢髮霜華生。',322,'全唐诗/poet.song.42000.json','["男兒四十無所成，可憐鬢髮霜華生。", "長書朝奏夕命相，此事故非言不行。", "低徊却入邵陵幕，梅嶺招降建城郭。", "論功第一遭衆讒，斷木浮沈委溝壑。", "噫吁嚱，數奇不獨李將軍，株坐桐鄉三見春。", "桐鄉雖好大兒死，風物滿眼唯悲辛。", "邇來又赴肥上辟，碌碌隨人亦何益。", "法網深懸無縱鱗，斂翼饑禽憂彈射。", "噫吁嚱，一寸丹心不堪折，扁舟却憶姑溪月。", "溪如凝冰月如雪，天地清光迥交澈。", "釣絲千丈入琉璃，六鼇一舉三山隨。", "人生快意莫如此，腰束黄金多横死。", "君不見日暮途窮逆行客，一餉榮華速誅殛。", "又不見都市朝衣就劍人，誰道忠言能殺身。", "休休休，歸去來。", "芝田石室雲長在，瑤草琪花春不回。", "收帆銀濤即平陸，跨青牛兮驅白鹿。", "莫向人間歧路行，豈有悲歡與榮辱。", "休休休，歸去來，計已決。", "肯學腐儒空有言，辜負春鵑口流血。"]'),
('ce27b1bd-8c5f-4b5c-ac0d-de05f018c9bd','東林行','郭祥正','宋','宋诗','song-poetry','','[]','龍蟠大地藏山腹，瑞氣蒙籠紫金屋。',168,'全唐诗/poet.song.42000.json','["龍蟠大地藏山腹，瑞氣蒙籠紫金屋。", "香爐萬丈擎碧霄，二澗斜飛落寒玉。", "晉朝遺事唐人辭，皴斮龜螭尚堪讀。", "樓煩真人應夢來，夜斧丁丁神伐木。", "安帝親留步輦迎，靈運開池素華馥。", "會隨流轉不成塵，燈焰明明自相續。", "遊人未達此理元，安得清凉滅貪欲。", "我今棄官脱塵網，僧寶瞻依無不足。", "跨黄牛，騎白鹿，時時自唱無生曲。", "無生曲，君試聽，五音六律和不得，爲君寫作東林行。"]'),
('3a5c057c-8e1a-4661-acf8-6f79c09b236d','圓通行簡慎禪師','郭祥正','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山之西形勝聚，無位真人依位住。',208,'全唐诗/poet.song.42000.json','["廬山之西形勝聚，無位真人依位住。", "地祗掣鏁金城開，石龍噴水銀潢注。", "峰巒約勒萬馬回，杉松自作千兵護。", "寶殿崢嶸跨碧霄，圓容麗服微西顧。", "江南妃子親施田，香飯供僧無億數。", "法焰相傳十二人，師泛鐵船揚子渡。", "楊子渡，秋風高，霹靂駕雪翻驚濤。", "中有漁家妙絕手，一釣三山連六鼇。", "縱時大地悉震恐，收來塵刹無纖毫。", "當年曾許心莫逆，今朝又作圓通客。", "挂冠已脱塵垢緣，一心願住清凉國。", "清凉之國誰能知，日長馬倦人多迷。", "從來聞說曹溪路，只今蹋斷廬山西。"]'),
('1e2876f1-84fe-40ae-a215-c2a5098bacb0','韶石行','郭祥正','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','扁舟未下連虞灘，韶石羅列誰雕刓。',236,'全唐诗/poet.song.42000.json','["扁舟未下連虞灘，韶石羅列誰雕刓。", "化工有意露怪變，待彼虞舜來觀翫。", "泊舟登岸始遠覽，兩峰直裂諸峰巑。", "青鸞低徊欲下飲，翠鳳却舞摶修翰。", "蟄龍钁雷怒奮角，帝子出震初峨冠。", "日光撲撲散金蕊，蓮花透澈琉璃盤。", "行衣十里仙霧濕，暝色一抹輕綃寒。", "我將仙崖想韶樂，北風忽變陰漫漫。", "松搖長空吼萬壑，溪走石脚淙驚湍。", "遺音自與天地響，聽不以耳精神完。", "重曈一去無復還，隨風波兮陟雲間。", "瀟湘洞庭亦何有，竹上血淚千年斑。", "九成不作至道息，紛紛後世疇能攀。", "登韶石兮情飄飄而未盡，飭彼柴車兮且將造乎蒼梧九疑之深山。"]'),
('a2923775-c70a-49a1-9ab7-dfee9ea15e54','武溪深呈廣帥蔣修撰','郭祥正','宋','宋诗','song-poetry','','[]','滔滔武溪一何深，源源不斷來從郴。',307,'全唐诗/poet.song.42000.json','["滔滔武溪一何深，源源不斷來從郴。", "流到瀧頭聲百變，誰將玉笛傳餘音。", "潺潺泠泠兮可以冰人心，胡爲其氣兮能毒淫。", "漢兵卷甲未得渡，飛鳶跕跕墮且沈。", "天乎此水力可任，蠻血安足腥吾鐔。", "功名難成壯心恥，馬革裹尸亦徒爾。", "伏波一去已千年，古像蕭蕭篁竹裏。", "風來尚作笛韻悲，宛轉悠揚逐船尾。", "如今天子治文明，柔遠懷憶昌黎氏。", "始末緣何不相類，能言佛骨本無靈。", "可惜咨嗟問瀧吏，湘妃之碑尤近怪。", "頗學女巫專自媚，固當褒馬聊黜韓。", "湘妃之碑尤近怪，頗學女巫專自媚。", "固當褒馬聊黜韓，補葺須令賢者備。", "元戎喜遇蓬瀛仙，武溪探古傳新篇。", "東君吁嘻龍蜃走，北斗挹酌河漢懸。", "勸君莫倚隴笛之悲音些，勸君清歌兮投玉琴些。", "琴聲爲出堯舜心，堯舜愛民無遠邇。", "君不見薰風來自南些。"]'),
('9fda551d-8449-4771-8e06-0db1ba93c3ab','松門阻風望廬山有懷李白','郭祥正','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','北風阻船泊湖漘，北望廬阜青無痕。',192,'全唐诗/poet.song.42000.json','["北風阻船泊湖漘，北望廬阜青無痕。", "晴雲自舒仍自卷，白龍欲眠猶宛轉。", "秋空漠漠秋氣淺，碧天蘸水如刀剪。", "篙師畏浪不敢行，却憶李白騎長鯨。", "倒回玉鞭擊鯨尾，錦袍濺雪洪濤裏。", "霓光溢目精神閒，終日高歌去復還。", "飛流直下三千尺，風吹銀漢落人間。", "天送醇醪傾北斗，羣仙吹簫龍鳳吼。", "李白一飲還一醉，醉來豈知生死累。", "倐然却返玉皇家，不騎鯨魚駕鸞車。", "留連自摘蟠桃花，嚼花吐津染朝霞。", "不信如今三百載，頑鯨駭浪空相待。"]'),
('cc3bfb3e-f6eb-4e78-9f50-dc5859a9165c','苦寒行二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','江南饒暖衣絺綌，今歲春寒人未識。',64,'全唐诗/poet.song.42000.json','["江南饒暖衣絺綌，今歲春寒人未識。", "溪流冰合地成拆，一月三旬雪三尺。", "去年大潦民無食，子母生離空歎息。", "只今道路多横屍，安忍催科更誅殛。"]'),
('29dcc223-1c5b-4c58-93e1-8e3b4d28d932','苦寒行二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','下溪捕魚一丈冰，上山採樵三尺雪。',64,'全唐诗/poet.song.42000.json','["下溪捕魚一丈冰，上山採樵三尺雪。", "人人饑餓衣裳單，骨月相看眼流血。", "乾坤失色雲未收，鵰鶚無聲翅將折。", "官倉斗米餘百金，願見春回二三月。"]'),
('fb7fa8b5-59ca-402d-8cb5-177a96ace547','武夷行寄劉侍郎','郭祥正','宋','宋诗','song-poetry','','[]','平生愛仙山，最聞武夷好。',204,'全唐诗/poet.song.42000.json','["平生愛仙山，最聞武夷好。", "千峰巑岏月倒掛，萬木陰森春不老。", "羣仙浮舟出寥廓，未濟明河半空泊。", "世人可見不可攀，静夜天風吹寶樂。", "須信仙家日月長，塵埃下土空茫茫。", "賢愚得失竟何益，坐十綠髪催秋霜。", "人感感悟有誰早，丈人尋真歸故鄉。", "故鄉宅在武夷址，山勢迴環碧城起。", "仙棋一局一番春，幾見桃花滿流水。", "他年功成趨帝闕，醉唤常娥擁明月。", "照開三十六洞天，玉樹瑤花恣攀折。", "丈人之樂其無央，我今欲往親在堂。", "側身南望未能到，耿耿寸心思夢長。"]'),
('d6d3fdeb-2bd5-4bc6-8238-ee1cd5e6ae08','姑熟堂歌贈朱太守','郭祥正','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','姑熟太守真賢豪，洗滌弊垢明官曹。',320,'全唐诗/poet.song.42000.json','["姑熟太守真賢豪，洗滌弊垢明官曹。", "民閒吏竦郡無事，華堂新構臨江皋。", "朱簷斜飛傍星漢，碧瓦不動蟠鯨鼇。", "釀成玉液宴賓從，手提大筆降風騷。", "四時景物换耳目，萬古治亂評秋毫。", "嗟予末坐重感激，胸中茅塞時耘耨。", "山雞卑栖竟何取，豈合鸞鳳返翔翺。", "紫蓴茸蕨味正美，鮮鱭玉縷鳴霜刀。", "爲公一飲直醉倒，坐看萬室皆陶陶。", "誰云江南地偏小，姑熟之堂天下少。", "丹湖千里浸城東，蒲葦藏烟春渺渺。", "牛渚對峙凌歊臺，長江倒掛天門開。", "風吹玉烏億萬疋，漢兵卷甲沙場迴。", "有時浪止皓月滿，琉璃宇宙無纖埃。", "帆檣隱隱鳥飛没，漁歌細下天邊來。", "謝元暉，李太白，一生好作江南客。", "至今遺恨人不知，孤雲尚鏁青山宅。", "請公瀝酒一弔之，聽我長吟壯靈魄。", "人世百年能幾何，高會難逢離别多。", "一朝公去調鼎鼐，斯堂永作甘棠歌。"]'),
('ab7db5d5-42e9-4045-86f9-b70d27ad39fa','宣詔廳歌贈朱太守','郭祥正','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','使君心畫天下無，構廳宣詔西南隅。',265,'全唐诗/poet.song.42000.json','["使君心畫天下無，構廳宣詔西南隅。", "曉光初散射簷桷，夜氣欲合吞江湖。", "甓甃摩挲滑瑤玉，重窻窈窕明青朱。", "胡生畫手出前輩，素壁爲寫巫山圖。", "一條江練澄碧落，十二峰色峨珊瑚。", "元猿老虎嘯彷彿，長松瘦石寒扶疏。", "中間皓鶴最恬淡，九霄獨立形神孤。", "君去班春勸耕稼，君歸命客同歡娱。", "三冬垂簾醉春瓮，六月静坐臨冰壺。", "巴牋血色灑醉筆，五字七字排璣珠。", "和風匝地怨氣滅，險吏縮手窮氓蘇。", "地隨人盛古今好，姑熟自此爲名區。", "君不見滕王閣庾公樓，樽罍千載誇風流。", "又不見宴寢一詩尚不滅，至今人道韋蘇州。", "噫吁嚱，四座勿歌聽我歌，宣詔之名君謂何。", "守臣不壅帝王澤，六合長靜無干戈。"]'),
('306df837-f627-4acd-9bc7-c1cccb9c5643','濟源草堂歌贈傅欽之學士','郭祥正','宋','宋诗','song-poetry','','[]','秀氣鴻濛濟州曲，十歌清池萬竿竹。',227,'全唐诗/poet.song.42000.json','["秀氣鴻濛濟州曲，十歌清池萬竿竹。", "竹裏修椽架草堂，不羡長安買華屋。", "春生廣野碧玉柔，月擁翠嵐銀粉撲。", "低飛白鷺揀晴沙，聞曉黄鸝囀喬木。", "明明長劍倚太行，拂拂愁烟蔽盤谷。", "重岡漸遠勢愈高，雲開青出分秋毫。", "龍蛇鱗甲雪霜洗，壯士四顧空提刀。", "陰晴萬變恣吟寫，三疊琴聲猿夜嗥。", "君不見古來功名輸隱叟，種桃採芝皆皓首。", "不將機械攪靈源，能使形骸頗長久。", "明公何年歸草堂，扁舟我即浮滄浪。", "江魚有味四時美，一蓑醉臨蘆花傍。", "男兒彼此送終畢，自算此身無得失。", "江東片月過河陽，爲照兩處無何鄉。"]'),
('b11cfcec-0c44-4168-8e57-2b7ed581971f','寄題蘄州涵輝閣呈太守章子平集賢','郭祥正','宋','宋诗','song-poetry','','[]','讀君涵輝記，恍若登蓬萊。',204,'全唐诗/poet.song.42000.json','["讀君涵輝記，恍若登蓬萊。", "天垂星斗數尋近，地卷雲山千里來。", "冰壺倒景露華洗，玉竇溶雪蟾光頽。", "塵寰何處路歧絕，三十六洞森然開。", "武夷真孫佩符印，選勝得此將金罍。", "文章欲會造化手，藩屏暫屈巖廊材。", "謝公寄意東山妓，嚴生把釣桐廬臺。", "功名談笑出千古，長與泰華青崔嵬。", "其餘齪齪何足數，百年易得成寒灰。", "爲君高吟豈知倦，十分美酒誰相陪。", "我欲乘風一飛往，病翅零落秋霜摧。", "涵輝閣，寧久游，重瞳法堯垂冕旒。", "側聞下詔十六相，真孫第一還瀛洲。"]'),
('9c11a83f-7e7b-4ff8-a0e9-4be640392bef','宣州雙溪閣夜宴呈太守余光祿','郭祥正','宋','宋诗','song-poetry','','[]','陵陽三峰壓千里，百尺危樓勢相倚。',204,'全唐诗/poet.song.42000.json','["陵陽三峰壓千里，百尺危樓勢相倚。", "海波不動蛟龍盤，疊玉無塵霜雪洗。", "溪光冷浥山光潤，色接金陵古名郡。", "青猿嘯斷四五聲，白鳥歸飛兩三陣。", "四時之景皆可觀，六月來遊膚髪寒。", "有時下瞰北山雨，只道林林銀竹竿。", "賢哉光祿余太守，昨引佳賓列樽酒。", "朝飲三百杯，暮吟三百首。", "不爲陰慘嚴刑誅，長吐陽春活殘杇。", "御史曾書治績碑，州人盡祝靈椿壽。", "沈沈羅幕更漏稀，燈如撒星公醉歸。", "絲篁前引後鼓鼙，珠履交錯行遲遲。", "丈夫得意不爲樂，借問百年能幾時。"]'),
('9ba78135-79ad-42db-b29e-5adf85d4e157','寄題洪州潘延之家園清逸樓','郭祥正','宋','宋诗','song-poetry','','[]','南昌城中潘令宅，清逸樓高二千赤。',236,'全唐诗/poet.song.42000.json','["南昌城中潘令宅，清逸樓高二千赤。", "斜飛四角河漢躔，密排萬瓦鴛鴦碧。", "樓中至樂無人知，掃盡寰區别名跡。", "霜華吹月雁横空，湖水浸天秋一色。", "櫓聲斷，漁歌起，西山却在蘆花裏。", "行客紛紛嗟白頭，纓塵不解滄浪洗。", "愛君年少先拂衣，古人歸去無今時。", "上有明明垂衣之堯舜，下有錯落戴主之皐夔。", "湟中不用一簫取，繚繞驛道通犍爲。", "更看牧馬天山草，澡心雪恥幽燕兒。", "朝廷大業昔未有，志士獨往吾何譏。", "陶彭澤，阮步兵，回首晉道方飄零。", "絲桐欲彈悲思盈，豈如潘令逢昇平。", "倚欄一醉弦索鳴，紅綃燃蜜爛華星，玉人舞徹東方明。"]'),
('6537264d-d823-4b21-b05a-4210d5a42bdc','寄題德興余氏聚遠亭','郭祥正','宋','宋诗','song-poetry','','[]','暗空風卷浮雲落，萬里秋毫瑩寥廓。',160,'全唐诗/poet.song.42000.json','["暗空風卷浮雲落，萬里秋毫瑩寥廓。", "姮娥泛月中夜來，撲撲山川銀粉薄。", "天垂斗柄掛簾鈎，地接明河浸欄角。", "誰傾世界入冰壺，滉滉仙春迷海嶽。", "嗟予南望未能往，小宰塵勞真齪齪。", "感君寄我羣公篇，覽記方驚子先作。", "詞源奔激吼波濤，筆畫縱横挫矛槊。", "搆名措意豈徒然，景物化爲仁智學。", "丈人教子惇義方，宴息時來命樽酌。", "何當勇起挐扁舟，夢寐思陪衆賓樂。"]'),
('e94241bd-ddfa-4a08-ba5e-ed66d363465d','留題潛山山谷寺','郭祥正','宋','宋诗','song-poetry','','[]','山如連環不可解，玉溜穿崖鯨尾擺。',256,'全唐诗/poet.song.42000.json','["山如連環不可解，玉溜穿崖鯨尾擺。", "中天化出清凉宫，汗漫琉璃翠光灑。", "回頭無路通人間，毛髪森森神魄駭。", "長碑突兀壓巨鼇，字刻雄文入模楷。", "乃知梁僧挈刀尺，來此幽棲聊脱屣。", "地祗掣鏁巖戶開，縱有堆金豈能買。", "粲祖傳衣當第三，至今異骨藏斯巖。", "我朝重賜七寶塔，舍利感應符至誠。", "誰曾磨崖記名姓，習之健筆深鐫鑱。", "盤鼉皴鱗想風概，雲霧慘淡遮松杉。", "至寶不獨世所惜，定有山鬼長扃監。", "願借雷公霹靂斧，堅珉斫斷載以函。", "高僧邀我恐忘返，虎豹堪驚日將晚。", "歸來拂榻坐虛堂，軟煮黄精薦香飯。", "千年遺跡安足誇，幻妄非真生有涯。", "奈何吾勢未能已，夢想長在金仙家。"]'),
('d8606379-b600-4fda-9f61-98733bf4be14','留題九江劉秀才西亭','郭祥正','宋','宋诗','song-poetry','','[]','南出九江城，西下五老岡。',247,'全唐诗/poet.song.42000.json','["南出九江城，西下五老岡。", "倐然一徑二三里，流水散漫桃花香。", "桃花迴環蔽深屋，犬吠遊人人扣竹。", "青衣借問來何爲，正是劉郎春酒熟。", "劉郎不厭客，撫掌邀我曹。", "西亭有榻醉可卧，下臨大江萬頃之洪濤。", "長帆出没送孤鳥，月飛不過哀猿嗥。", "更愛雙劍峰，正落南窻外。", "天公好仁不用武，太古光鋩未磨淬。", "誰懷邪佞心，見之膽應碎。", "淮山在天末，寒青亦相對。", "微風時一來，松柏搖蒼珮。", "頃刻神官驅黑龍，汹汹興雲變明晦。", "地勢雖高直可驚，酒行且止{炙火=肉}休嘬。", "劉郎顧我笑，爲言向苦悲。", "陰晴非汝職，不醉將疇歸。", "歸來乎，頻相過，西亭把酒共君歌。"]'),
('91612a4b-d19f-406c-ac9a-44220cfd6be4','留題西林寺攬秀亭','郭祥正','宋','宋诗','song-poetry','','[]','行瞻香爐峰，未出二林口。',209,'全唐诗/poet.song.42000.json','["行瞻香爐峰，未出二林口。", "一區廣地如席平，誰作新亭名攬秀。", "秀色可攬結，正對香爐峰。", "李白愛之忍去，便欲此地巢雲松。", "寂寥往事三百載，澗泉谷草依舊揚清風。", "泉可掬，草可擷，清風灑面如冰雪。", "閒來攜手四五人，倒盡金壺頰不熱。", "寸心何獨忘寵榮，形骸遺盡神超越。", "寄語世上士，勸君早歸來。", "霹靂轟車膽欲落，忠憤雖死何爲哉。", "此時竟不悟，此心徒自知。", "嵐光向晚紫翠滴，杜鵑更在深林啼。", "試拂横琴奏流水，指下忽作商聲悲。", "悲來乎，可奈何，推琴罷酒爲君歌。"]'),
('5baf0511-4aa9-43c6-ae16-aa7f6d46907a','鄭州太守王龍圖出家妓彈琵琶即席有贈','郭祥正','宋','宋诗','song-poetry','','[]','偶騎匹馬游仙關，瑤池夜宴歡未闌。',196,'全唐诗/poet.song.42000.json','["偶騎匹馬游仙關，瑤池夜宴歡未闌。", "邀予末坐聞清彈，琵琶十槽聲正繁。", "初疑饑鸞啄玉應天響，忽似霹靂數聲春氣還。", "曲徧將終檀板急，舞袖裂霞隨拍入。", "踏碎瓊筵鸞步嬌，汗透香綃露桃濕。", "解絛罷舞整花鈿，宛轉仙容雁行立。", "主人使令持酒巵，香隨羅襪成塵飛。", "銅龍無聲夜無極，煌煌燭焰回朝暉。", "桃源花落長溪凈，人着秦衣樽俎罄。", "豈如此會絕風流，主人慇懃賓客敬。", "我作短歌公聽取，人世百年能幾許。", "樂極哀來古所悲，不如立功當此時。"]'),
('8b095696-c5dd-4976-adc6-d9b00dd3a2b0','瑞昌雙溪堂夜飲呈吳令','郭祥正','宋','宋诗','song-poetry','','[]','星斗闌干月未吐，但愛溪聲似山雨。',224,'全唐诗/poet.song.42000.json','["星斗闌干月未吐，但愛溪聲似山雨。", "青燈照室並銀花，白酒傾來不知數。", "子善評文我不如，我亦談詩子深許。", "酒酣索我須論兵，拔劍畫地軍陣成。", "十萬甲兵指掌取，五方應敵旋風生。", "文武道判惜已久，聖賢相遇猶難并。", "相如謾作長門賦，屈原虚著離騷經。", "不知於世竟何補，可憐博得千年名。", "韓信收身苦不早，功成伏劍真草草。", "始終最愛嚴子陵，坐視乾坤任傾倒。", "咄嗟語險氣已傷，况復賦詩聲調長。", "卷紙連書不磨琢，子鋒大峻非我當。", "撥置萬慮付江海，收拾寸心歸老莊。", "天地得一馬喻馬，謂思前事皆佯狂。"]'),
('21c30128-deb7-4fe6-89f8-a2bf052c20ec','寄吳著作','郭祥正','宋','宋诗','song-poetry','','[]','憶與君别時，君行朝北極。',196,'全唐诗/poet.song.42000.json','["憶與君别時，君行朝北極。", "潯陽江頭車馬駭，意氣翩翩動秋色。", "君還舊廬能寄書，謂我楚辭傳上都。", "是時盜賊正紛擾，日夜奔走承使符。", "謝君後時聞已惡，交深豈必書問數。", "誠明相照期無窮，但惜遠别臨春風。", "春風來已老，落盡桃花紅。", "有時孤坐碧山裏，彈指倐忽成衰翁。", "文章不直一杯酒，功名付與千年松。", "何時逢君談，豁我此愁恨。", "攀雲不見麒麟蹤，趨泥自笑駑駘鈍。", "兒女安否今何如，親雖未成交莫疏。", "願君富貴情不改，敢將瓦礫贈明珠。"]'),
('f7dc9edd-29e9-492b-a043-281b979db142','將至江夏先寄太守李學士','郭祥正','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','二月發姑熟，三月到潯陽。',188,'全唐诗/poet.song.42000.json','["二月發姑熟，三月到潯陽。", "聞君解纜纔五日，驥尾難追空斷腸。", "十年前作潯陽吏，老狡相逢猶引避。", "中丞孤憤已沈泉，時事愈新誰敢議。", "欲吐哀音寫心曲，濛澒江聲搖地軸。", "横琴靜夜按金徽，泛到商弦斷還續。", "憂能損氣須忘憂，移船漸近黄鶴樓。", "樓前芳草漬烟碧，君今賢過奇章侯。", "試詢樂部誰工笛，曹王舊曲何人識。", "水中龍應雲不飛，月華正在江心白。", "滿傾綠酒濃如油，爲君吞却鸚鵡洲。", "開帆快意出天外，可惜礙斷長江流。"]'),
('129276ec-0b01-4c41-908e-7a544688e3d3','蔣公檜呈淮南運使金部此檜係魯侍郎漕淮日手植','郭祥正','宋','宋诗','song-poetry','','[]','淮南庭中有蒼檜，仰視團團翠爲蓋。',192,'全唐诗/poet.song.42000.json','["淮南庭中有蒼檜，仰視團團翠爲蓋。", "直榦每容鸞鳳棲，盤根深壓鯨鼇背。", "北風夜作兵陣聲，恐取蛟龍斬天外。", "呼童出屋爲我窺，摩颭清陰月光碎。", "問誰植之前蔣公，得地倐經三十載。", "不同種杏上青天，正似甘棠有遺愛。", "使華今復見公孫，太平事業鍾一門。", "祖廟冠蓋漸塵土，却嗟此檜春長存。", "孤高豈忘栽培力，秀發兼承造化恩。", "已看枝葉飽霜露，終作棟柱扶乾坤。", "新詩編聯盡珠玉，光大先烈聽篪塤。", "更憶丹青妙畫手，進入明堂逢至尊。"]'),
('2f2154d5-e2fb-40fc-b0a4-1e6fef627835','蜀道篇送别府尹吳龍圖','郭祥正','宋','宋诗','song-poetry','','[]','長吟李白蜀道難，蜀道之難難於上青天。',338,'全唐诗/poet.song.42000.json','["長吟李白蜀道難，蜀道之難難於上青天。", "長蛇并猛虎，殺人吮血毒氣何腥羶。", "錦城雖樂不可到，側身西望泣涕空漣漣。", "其辭辛酸語勢險，有如曲折頓挫萬丈之洪泉。", "世人不識寶玉璞，每欲酬價齊刀鉛。", "求之往古疑未有，惜哉不經孔子之手加鑱鐫。", "公今易節帥蜀國，爲公重吟蜀道篇。", "旌旗翻空度劍閣，甲光照雪參林顛。", "雲鼇連推谷聲碎，畫角慢引斜陽懸。", "竹馬爭迎舊令尹，指公長髯皓素非往年。", "蜀道何坦然，和氣拂拂回星躔。", "長蛇深潛猛虎伏，但愛雄飛呼雌響亮調朱弦。", "時乎樂哉，公之往也。", "九重深拱堯舜聖，廟堂論道丘軻賢。", "撫綏斯民賴良守，平平政化公能宣。", "來賓興學有源本，何必早夜開華筵。", "嘗聞家家賣釵釧，只待看舞青春前。", "此風不革久愈薄，稔歲往往成凶年。", "噫吁嘻，今我無匹馬，安得從公游，盡書政績表中州。", "獻之明堂付太史，陛下請損西顧憂。"]'),
('7df4ab3d-0e99-45d1-9d52-601f316b32c9','錢塘行送别簽判李太博','郭祥正','宋','宋诗','song-poetry','','["\u897f\u6e56"]','東南會府唯錢塘，高門雙開南斗傍。',224,'全唐诗/poet.song.42000.json','["東南會府唯錢塘，高門雙開南斗傍。", "門前碧瓦十萬戶，曉色滿城烟雨香。", "聖祖神宗造區宇，應命最先吳越王。", "不經兵火二百載，地饒沃衍民康强。", "蓮花紅白西湖芳，南山翠影臨滄浪。", "瓊樓寶塔照日月，塵埃不到炎天凉。", "畫船羅幕盡高卷，白玉美人游冶郎。", "年年中秋海潮過，萬頃銀山面前墮。", "少年輕命爭弄潮，手掣紅旗逆潮簸。", "聞君此行承辟書，伯樂能求汗血駒。", "四時風物同吟嘯，十郡兵民歸卷舒。", "公閑畜德聊自養，承平功業還吾儒。", "况君登朝未四十，慎勿出處窮歡娛。", "慎勿出處窮歡娛，臨淵履冰佩瓊琚。"]'),
('d1042226-70a5-4e0f-9615-eec2e56d8820','天台行送施山人','郭祥正','宋','宋诗','song-poetry','','[]','平生樂山水，聽客談天台。',124,'全唐诗/poet.song.42000.json','["平生樂山水，聽客談天台。", "盤石摩挲浸海月，瀑布淙射烟霞開。", "山腰噴作千巖雨，潭底晝夜轟風雷。", "諸峰攢叢護寶刹，地與世隔無纖埃。", "仙葩靈鳥四時有，石矼玉洞清風來。", "施夫子，欲長往，高謝功名脱塵網。", "况有西來老佛師，了悟無生任消長。", "若許陶潛載酒過，便駕蒼虬逐真賞。"]'),
('5904c51b-3c2e-480d-905a-0b564280287d','踸踔行送裴山人','郭祥正','宋','宋诗','song-poetry','','[]','踸踔踸踔裴山人，破帽麻衣被埃塵。',134,'全唐诗/poet.song.42000.json','["踸踔踸踔裴山人，破帽麻衣被埃塵。", "忽來訪我環峰市，醉倒不顧傍人嗔。", "壯士不得志，汙泥困修鱗。", "誰傾滄海救枯澤，矯首奮鬣乘風雲。", "回頭問燕雀，爾輩胡爲羣。", "巢寄柏梁一朝火，孤棲風雨更誰憐。", "踸踔踸踔裴山人，行路無窮鼻酸辛。", "元通獻甫儻不遇，况有特達朱純臣。", "踸踔勿踸踔，豈有壯士長遭迍。"]'),
('e359cb7b-493f-4e56-89cc-4494b9e11f3b','道林寺送别崔提刑','郭祥正','宋','宋诗','song-poetry','','[]','湘江傾瀉明河源，湘山來落如駿奔。',208,'全唐诗/poet.song.42000.json','["湘江傾瀉明河源，湘山來落如駿奔。", "尋幽乘興莫辭遠，白雲中有黄金園。", "佛師無心法愈密，徒衆先後陳卑尊。", "甘泉噴灑仙籟爽，此身已覺超籠樊。", "高堂却見山外水，古鑑磨開蒼蘚昏。", "長城深鏁萬家富，老木自作千營屯。", "兩洲半没鯨鼓鬣，雙崖斗起天爲門。", "滄溟不識幾番變，石泐猶有濤淙痕。", "茯苓愈大愈堪食，深鋤但惜傷松根。", "登高覽物亦徒爾，秋色况是當離樽。", "崔侯才思鋭無敵，蒼鷹得兔霜翎翻。", "嗟余染翰愧復正，累句何足先行軒。", "故人柄政坐東府，請君獻策安黎元。"]'),
('6eb18196-6adf-46a6-8bc8-9dcd119cad50','游石盆寺呈蔣殿院兼簡余光祿','郭祥正','宋','宋诗','song-poetry','','[]','石盆古寺蒼崖顛，斷碑皴剥無人傳。',256,'全唐诗/poet.song.42000.json','["石盆古寺蒼崖顛，斷碑皴剥無人傳。", "其文僅識隱巖字，御史飽學能推研。", "乃是鄭董之别號，洛師易節來刺宣。", "風流直欲繼謝守，行春車馬時聯翩。", "紅粉行行杏花笑，旌旛爍爍雌霓懸。", "松聲颼颼雜簫鼓，薜圍繚繞疑檀烟。", "不知身世有軒冕，且將樽酒投林泉。", "暫時樂事亦難遇，高文大字精磨鐫。", "可嗟榛棘一藏晦，清風零落三百年。", "洎逢佳士始珍賞，洗滌塵垢邀神仙。", "坐思往跡若夢寐，明河千丈傾辭源。", "啼鳥至今不避客，上下啾聒兩耳邊。", "山僧搆亭又高絕，羣峰葉葉如青蓮。", "崔嵬寶塔掛落日，沆碭冰壺撐釣船。", "余公胡爲未嘗到，美景若此寧棄捐。", "請攜吟筆窺造物，更向雲中調管弦。"]'),
('a2eb4128-8a53-41f4-bcea-537f2a67fcba','凌敲臺呈同游李察推','郭祥正','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','臘月欲盡春風來，壯士尋春上高臺。',192,'全唐诗/poet.song.42000.json','["臘月欲盡春風來，壯士尋春上高臺。", "金烏慢飛光徘徊，照散冰霜天地開。", "梅花披香柳烟裊，狂殺錢塘蘇小小。", "玉簫金笛鳴高樓，悵望傳書落青鳥。", "吾曹强飲三百杯，老去功名安在哉。", "欲駕飛魚入東海，王母爲我傾金罍。", "蓮華變碧蟠桃熟，仙家四時應不速。", "醉來拍手乘紫烟，游徧洞天三十六。", "高歌杳渺春風裏，我懷清澈西江水。", "腐儒往往咍吾狂，猶幸揚雄作知已。", "脱君身上蜀錦袍，解我腰下并州刀。", "更沽美酒共君飲，不負今朝春思豪。"]'),
('0baf1e9c-6060-4d47-95c7-cfdf9396988f','凌敲臺呈同游張兵部朱太守','郭祥正','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','江東使者武陵仙，姑孰太守南都賢。',280,'全唐诗/poet.song.42000.json','["江東使者武陵仙，姑孰太守南都賢。", "同時文采耀場屋，今日寵榮分使權。", "歲豐民樂官吏肅，登高望遠開華筵。", "凌敲古臺壓城北，天門牛渚遙相連。", "六朝盛事竟何在，白雲芳草空綿聯。", "黄鳥聲酸落花雨，青蒲風送西江船。", "鳥聲繚亂帆影没，勸君莫負杯中物。", "百歲榮華如轉輪，一半光陰已倉卒。", "寧須雜管弦，不必煩綺羅。", "紫蓴煮豉肥鱸鱠，更聽江南賤士歌。", "堯崩舜立天下治，廟室靈芝最爲瑞。", "巖穴自此無遺民，請把長戈鑄農器。", "功名來時如等閑，四皓去矣誰復還。", "一朝攘臂揖太子，社稷不動安如山。", "可笑屈夫子，憔悴長江濱。", "欲將獨醒換衆醉，竟葬江魚愁殺人。", "古來得失既如此，今朝幸會青雲士。", "功成早晚歸桃源，回首塵寰脱雙屣。"]'),
('c61f5931-cdf3-4317-bca2-e1d8b5f65e11','遊道林寺呈運判蔡中允昆仲如晦用杜甫元韻','郭祥正','宋','宋诗','song-poetry','','[]','長沙城西湘水隅，道林古寺松門紆。',256,'全唐诗/poet.song.42000.json','["長沙城西湘水隅，道林古寺松門紆。", "嘗聞秀絕超五嶽，果見氣象吞重湖。", "殿前銜花走白鹿，殿裏沈烟焚玉爐。", "何人塑出慈氏衆，冠纓動活搖明珠。", "高僧處處有遺跡，盤石坐禪龍虎俱。", "唐人妙筆數歐沈，至今板上棲羣烏。", "五言七字又奇絕，此寺此堂天下無。", "不緣薄宦豈能賞，勇往兼有兒孫扶。", "賈生前席竟憂死，屈原懷沙終自誅。", "投身及早卜幽隱，淡泊久乃勝甘腴。", "雲生岳嶠月晦影，雨過橘洲猿夜呼。", "細吟靜境足自適，忠憤未合思捐軀。", "趨玄飽讀長者論，養真默合烟蘿圖。", "千篇愧比老杜老，一節願隨孤竹孤。", "况陪使者共遊覽，二謝弟晜真友于。", "不知昔日楊常侍，何似今朝蔡大夫。"]'),
('67eaa4f9-fb14-4534-ac59-ab5ed76e4785','舒州使宅天柱閣呈朱光祿','郭祥正','宋','宋诗','song-poetry','','[]','羣山奔來一峰起，千丈芙蓉碧霄倚。',268,'全唐诗/poet.song.42000.json','["羣山奔來一峰起，千丈芙蓉碧霄倚。", "嫦娥却月愁推輪，王母呼烟結繒綺。", "分明有路金闕通，翠滑無塵玉壺洗。", "老松自作孤鳳吟，駭浪時翻三井水。", "峨嵋絕巔安足論，力不擎天亦徒爾。", "懊惱茂陵客，白日求攀天。", "遺壇猶在半蕪没，隱約龍馭回瑤鞭。", "直至唐家六皇帝，夢感異境開重玄。", "真符預告後五百，佐佑寶歷推鴻延。", "城頭建閣舊丞相，窻戶再新光祿賢。", "手攜大筆恣吟覽，老句氣焰摩星躔。", "當時數赴范公辟，秀骨照坐誰差肩。", "功名自許出絕域，歲月漫往修途邅。", "丈夫有命豈嗟慼，投老得地多雲泉。", "霜柑正熟蟹螯美，白蟻旋漉浮金船。", "伊予困躓坐小邑，悵望珠履參華筵。", "祝公自此早歸隱，幅巾藜杖詩中仙。"]'),
('437f9ea2-344e-46df-b051-c716b0472bdc','中秋登白紵山呈同遊蘇寺丞','郭祥正','宋','宋诗','song-poetry','','[]','平湖萬頃浮青玉，嫦娥更攬寒光浴。',336,'全唐诗/poet.song.42000.json','["平湖萬頃浮青玉，嫦娥更攬寒光浴。", "天高星稀魚雁沈，風靜雲消絲管逐。", "試聽郭子今宵歌，對月不飲奈愁何。", "上盡高山萬丈之絕頂，側身可以攀明河。", "明河洗君耳，明月照君面。", "暫來空洞無物逍遙鄉，安用聲名誇海縣。", "前年從軍梅山下，林黑只憂偏弩射。", "去歲點夫大河北，黄土吹衣無晝夜。", "勞勞功業安在哉，出林之木風先摧。", "有言不得見天子，卷舌却出金門來。", "流光差池鬢垂雪，幸對南山值佳節。", "更在桓公遊處遊，自紓悲歌更清越。", "登高何必須重九，零落黄花汙濃酒。", "豈如桂子散秋香，采露金人舉纖手。", "舉纖手，飲未休，月輪忽轉西山頭。", "明年此會定南北，沈思使我增離憂。", "荆榛滿眼世路惡，恩忘水覆終難收。", "田文昔日三千客，去住如今均一丘。", "噫吁嚱，達亦不足恃，窮亦不足羞。", "但願明月照我酒，古來秉燭供遨遊。", "因誰爲謝北海若，酩酊不辨馬與牛。"]'),
('70481652-1d10-40b7-973e-ca43cdd8f403','登王知白秀才跂賢亭呈同遊余萬二君','郭祥正','宋','宋诗','song-poetry','','[]','鑿山構亭鄰北郊，志慕賢哲忘喧呶。',216,'全唐诗/poet.song.42000.json','["鑿山構亭鄰北郊，志慕賢哲忘喧呶。", "豁然千里開林梢，地勢不得藏嵌坳。", "三峰重樓排卦爻，二溪聱浪飛怒蛟。", "漁翁捕魚船尾敲，稚子鎚塼爭勝抛。", "小塘圓沙來雁鵁，茂橘間錯黄金包。", "主人情深漆與膠，美酒旋漉羅珍肴。", "亦有麟脯膾海鮫，痒背只欠麻姑抓。", "浮生胡爲長繫匏，不蹈聖城徒譊譊。", "竊甘祿食憂謗嘲，有若夜鼠防饑貓。", "羡君脱屣心無殽，笑傲自足追由巢。", "猛飲未徹雞鳴嘐，新詩下筆論卷抄。", "余君酒量辭斗筲，醉帽墮地垂鬢髾。", "萬子能禪誇悟泡，我獨愛酒流涎交，同趨至樂情何聱。"]'),
('fdbed112-bd40-4f62-8444-a55fc66147c6','德化默亭觀雪呈鄭令','郭祥正','宋','宋诗','song-poetry','','[]','霜風結海天雲冰，夜寒斷盡朱絲繩。',220,'全唐诗/poet.song.42000.json','["霜風結海天雲冰，夜寒斷盡朱絲繩。", "曉來何處看猛雪，鄭令新亭最高絕。", "倒披貂鼠一登臨，飛鳥不飛旱光滅。", "時吟杜甫苦寒詩，白鵠翅垂眼流血。", "崑崙關折非吾憂，但願春泥補地裂。", "西南香鑪萬尋玉，遠思飄然看不足。", "欲騎鸞鶴飛其顛，身雖未往神明肅。", "又疑夢向瓊池過，王母樓殿高嵯峨。", "粉圖屏風畫未竟，隱隱朽筆方森羅。", "天工好奇人莫識，縱心壯觀聊唧唧。", "酒瓶倒瀝萬籟沉，客子狂歌主人默。", "默胡爲乎名斯亭，主人意深窺杳冥。", "不爲四時役，不擇萬象嘉。", "與時窮通自消息，見我狂歌應笑耶。"]'),
('dfd6d57d-82d8-4c16-ad1c-e339b9addfc4','采石亭觀浪','郭祥正','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭秋高北風起，怒浪排空日光眯。',170,'全唐诗/poet.song.42000.json','["洞庭秋高北風起，怒浪排空日光眯。", "坐見雪山飛從物外來，地軸天關恐將圮。", "移沙裂石失浦溆，羣龍呀牙鯨掉尾。", "舟人但如鸛鳴垤，咫尺存亡隔千里。", "嗟哉至柔物，澒洞安可當。", "大禹没已久，巨浸誰爲防。", "須臾風收浪亦靜，嫦娥洗月添寒光。", "湘妃妙曲鼓未徹，汨羅之魄雲徜徉。", "而今君臣正相樂，法弊一一新更張。", "監司精明郡縣肅，國無忠憤惟循良。", "洞庭怪變自出没，迴首天邊歸雁行。"]'),
('5e4c9d71-081e-47e9-9428-1a613f81b0dc','祀南嶽喜雨呈李倅','郭祥正','宋','宋诗','song-poetry','','["\u8861\u5c71"]','六月赤日方炎炎，雲不行天龍遁潛。',386,'全唐诗/poet.song.42000.json','["六月赤日方炎炎，雲不行天龍遁潛。", "陰陽失職帝怒赫，地下萬物遭炮燖。", "農夫爭陂數鬭死，驅沙擲土唯飛廉。", "湖南本錢二十有四萬，歲望何以安黎黔。", "府官惶惶使臺恐，祀壇禱嶽惟精嚴。", "君馳副車職其事，秘文在板香盈匳。", "鐶刀割牲薦肴酒，夜半奠玉抽靈籤。", "星河收光倐陰晦，雷聲羣羣來山南。", "斯須密點欲裂瓦，燭光出屋排龍髯。", "鼪鼯哀啼曉色淡，碧澗久涸銀濤添。", "田田水足稻秀拔，旱暵一洗凉颸兼。", "芬馨羅列報神貺，文實之論前賢僉。", "興雲作雨乃誰柄，坐視焦灼慳濡霑。", "待兹誠禱始感發，威福自任寧無嫌。", "至理從來莫能詰，異景聊足開吾瞻。", "孤峰翠滑犀露角，溢溜飛灑瓊爲簾。", "烟藏拱木半吞吐，湘水倒影分毫纖。", "廟門欲出尚回首，正似老筆圖霜縑。", "高吟成章又奇絕，睥睨韓杜君何謙。", "嗟余適爲簿書縛，不爾從往精神欦。", "蚊蠅休飛夏將盡，清露收拾摧圓蟾。", "何當結軌更一往，歷覽舜跡窮高尖。", "羣仙雖有路歧遠，志士豈無巖谷淹。", "收奇拔俊召和氣，一國遂除災眚占。"]'),
('f5ddb490-e8fd-4ac9-99cb-81a8d232292c','寄題鄂州李屯田家園仁安亭','郭祥正','宋','宋诗','song-poetry','','[]','頭陀樓閣坐青烟，畫屏正落南簷前。',187,'全唐诗/poet.song.42000.json','["頭陀樓閣坐青烟，畫屏正落南簷前。", "主人隱几寫風物，幅巾瑩爽南昌仙。", "仙翁讀書五千卷，道與世背多聱邅。", "安之不擾靜以養，逸我壽老全於天。", "簾櫳疏疏白光透，欄檻寂寂花陰圓。", "黄鸝弄巧子趁母，白酒釀熟金爲船。", "淵明醉矣客可去，細藤織榻閑欹眠。", "君不見黄鶴樓，鸚鵡洲，碧雲欲合天自晚，芳草無情春亦愁。", "禰衡白骨瘞何處，曹王舊曲無人收。", "沈吟往事變華髮，不飲何以銷吾憂。", "銷憂乎，君且飲，醉來天地真衾枕。"]'),
('dffd3de3-5354-4f74-8b8c-83ed02894f61','金陵賞心亭','郭祥正','宋','宋诗','song-poetry','','[]','夾淮青城幾百尺，城上高亭望無極。',80,'全唐诗/poet.song.42000.json','["夾淮青城幾百尺，城上高亭望無極。", "南還北去千萬艘，人生何苦戀驚濤。", "百年易得變塵土，後世視今今視古。", "此間風月最爲多，莫辭把酒呈高歌。", "前朝宫苑荒烟在，樂極悲來亦奈何。"]'),
('43ddb526-4f2b-499d-8dfb-9f333e158e63','鍾山寶公塔','郭祥正','宋','宋诗','song-poetry','','[]','盤盤鍾山古城北，夾道青松兩行直。',64,'全唐诗/poet.song.42000.json','["盤盤鍾山古城北，夾道青松兩行直。", "浮屠突兀倚雲烟，繪事猶存舊刀尺。", "刀裁尺量不可過，浮生不悟欲如何。", "憑欄直下視千里，多少丘墟藏綺羅。"]'),
('4c3b9c90-fd72-4e30-bfbb-241b7870d050','徐州黄樓歌寄蘇子瞻','郭祥正','宋','宋诗','song-poetry','','[]','君不見彭門之黄樓，樓角突兀凌山丘。',267,'全唐诗/poet.song.42000.json','["君不見彭門之黄樓，樓角突兀凌山丘。", "雲生霧暗失柱礎，日升月落當簾鈎。", "黄河西來駭奔流，頃刻十丈平城頭。", "渾濤舂撞怒鯨躍，危堞僅若盃盂浮。", "斯民囂囂坐恐化魚鼈，刺史當分天子憂。", "植材築土夜運晝，神物借力非人謀。", "河還故道萬家喜，匪公何以全吾州。", "公來相基疊巨石，屋成因以黄名樓。", "黄樓不獨排河流，壯觀彈壓東諸侯。", "重簷斜飛掣驚電，密瓦瑩靜蟠蒼虬。", "乘閑往往宴賓客，酒酣詩興横霜秋。", "沉思漢唐視陳跡，逆節怙險終何求。", "誰令頸血濺砧斧，千載付與山河愁。", "聖祖神宗仗仁義，中原一洗兵甲休。", "朝廷尊崇郡縣肅，彭門子弟長歡遊。", "長歡遊，隨五馬，但看紅袖舞華筵，不願黄河到樓下。"]'),
('4a77b41e-8da3-4bf3-99d4-d1f6fc728399','留題吕學士無爲軍謫居廊軒','郭祥正','宋','宋诗','song-poetry','','[]','城頭高軒跳千里，數里蒼山兼寒水。',224,'全唐诗/poet.song.42000.json','["城頭高軒跳千里，數里蒼山兼寒水。", "帆開半落有無間，鳥飛不斷丹青裏。", "北斗疏疏河漢曉，蓬萊一登天下小。", "心隨境化形亦忘，誰道霜翎老華表。", "曹公窺吳敎水戰，虎貔蹙踏鯨鼉轉。", "野父相傳此渡頭，魚網時時得遺箭。", "當場英氣安在哉，千年絕景藏蒿萊。", "地祗監護待賢者，欄干倚遍傾金罍。", "目送白雲望堯闕，忠功孝名堅一節。", "明時不作離騷經，玉上青蠅解磨滅。", "昇沈偶然安足嗟，與君高詠思無邪。", "數聲長笛奏何處，微風吹落天之涯。", "天涯桂樹清輝發，萬頃波瀾凍冰雪。", "若承紫詔返瀛洲，此地曾忘遷謫憂。"]'),
('01c7b834-49f6-4789-ae5a-d0131d15363f','漳南王園樂全亭席上呈同遊諸君坐客劉公曰有水一池有竹千竿可以賦詩浪士勇起索筆即其言綴成長調文不加點','郭祥正','宋','宋诗','song-poetry','','[]','樂全有水一池，有竹千竿。',168,'全唐诗/poet.song.42000.json','["樂全有水一池，有竹千竿。", "池通兩潮信，密竹四時寒。", "引子黄鸝弄語，探魚碧鳥忘還。", "復有佳賓命酌，水晶交錯觥船。", "空中聞玉簫，王母想乘鸞。", "問君不醉當何適，百歲憂愁今夕歡。", "嫦娥癡姑理冰盤，絳龍蠟淚癡不乾。", "孰知大海騰波瀾，自有人世藏仙源。", "劉公八十精神全，留子造古風義全。", "蔡阮名家文學全，王氏世醫陰騭全。", "兀兀浪士天機全，樂全乎，且飲酒，獨醒懷沙亦何有。"]'),
('1294e629-d80c-41c7-b3cc-e1c429c291f3','題畢文簡公撰李太白碑陰','郭祥正','宋','宋诗','song-poetry','','[]','清風無根長不死，太白高名亦如此。',186,'全唐诗/poet.song.42000.json','["清風無根長不死，太白高名亦如此。", "何人謂是王佐才，文簡雄詞瀉秋水。", "賢孫出守鐫長碑，碑成字字生光輝。", "寵胡妃子已萌亂，翩然鳳鳥來非時。", "出林秀木衆欲殺，納官贖命何其危。", "畫船載酒酌明月，不著漁蓑披錦衣。", "醉眼天地即衾枕，至今荒塚人疑之。", "丈夫闔棺事未定，後三百歲方逢知。", "知太白，文簡公。", "不誇能詩與飲酒，惜其浩氣突兀藏心胸。", "青山老碧洗秋色，姑溪濯綠涵春容。", "太白不見碑可見，螭盤鼉載傳無窮。"]'),
('11892652-908a-429b-bd45-5a456530eb01','寄題湖州東林沈氏東老庵','郭祥正','宋','宋诗','song-poetry','','[]','東林沈郎真隱居，山環水遶開方壺。',290,'全唐诗/poet.song.42000.json','["東林沈郎真隱居，山環水遶開方壺。", "何年濯足脱塵網，坐卧七言哦蕊珠。", "有時隱几佚吾老，萬事不到靈臺虚。", "甕間綠螘春欲活，仙翁夜降青雲車。", "自稱山人號回客，爲君猛飲留斯須。", "蚊蠅驅盡燭還滅，清風掃地銀蟾鋪。", "梨花蕉葉鍾與鼎，倒卷錦浪吞鯨魚。", "雙瞳湛湛翦秋碧，三山不動喬松孤。", "歘然踊起拂素壁，筆灑二韻鏗瓊琚。", "西鄰已富憂不足，東老雖貧樂有餘。", "白酒釀來緣好客，黄金散盡爲收書。", "甕乾吟罷尚攜手，寥寥天籟鳴笙竽。", "渡橋摻袂忽無跡，東方漸白飛羣烏。", "世人尋仙不可得，仙人寓世情何如。", "桃源歸路杳難問，落花流水空踟蹰。", "後來福禍固已驗，生死往復猶坦途。", "圜庵不壞子傳業，玉琴遺韻寒泉俱。", "以回易吕未可必，回生回生是亦劉方徒。"]'),
('8c7ef54b-44c8-4186-8d52-29a374042932','舟經池州先寄夏寺丞','郭祥正','宋','宋诗','song-poetry','','[]','去年收帆貴池口，聞君高歌撞玉斗。',64,'全唐诗/poet.song.42000.json','["去年收帆貴池口，聞君高歌撞玉斗。", "今朝至自大湖南，五溪新事爲君談。", "一年往返七千里，鄉國生還真可喜。", "君家白醪應已熟，正好齊山泛黄菊。"]'),
('c602936e-a063-42f9-b423-6be9d1ada027','留題方伋秀才壽樂亭','郭祥正','宋','宋诗','song-poetry','','[]','君家有亭何壯哉，參差碧瓦鴛鴦排。',264,'全唐诗/poet.song.42000.json','["君家有亭何壯哉，參差碧瓦鴛鴦排。", "重窻靜深門不闖，地布瑩甓光如揩。", "斑斑簾竹輕風簁，日影射午疑瓊階。", "疊山墮勢危相挨，木人圍棋或負柴。", "虎卧洞壑猿攀崖，好鳥上下鳴聲喈。", "真假造物微毫差，玉葩照水絕纖埃。", "絲篁調音衆伎俳，水沈焚烟凝晝霾。", "夜晦爛蠟非燃䕸，唱酬交錯并詼諧，逢逢曉鼓傳官街。", "兩入場屋隨計偕，未得藍綬持簡槐。", "吾寧汲汲同井蛙，棄去不顧如敝鞋。", "沈潛自適江與淮，滔滔動靜終無涯。", "圓天方地安形骸，雖然此樂非吾懷。", "嚴慈鬢髮霜華皆，嗟今仕祿猶暌乖。", "行聞投印早歸來，亭上致宴羅吳娃。", "吳娃醉唱敲玉釵，綵衣自舞心寧㥟。", "心寧㥟，奉親酒，壽樂之榮世希有。"]'),
('3fbbceb5-ebe1-4ac9-b2db-337d9a6f793c','寄獻荆州鄭紫微','郭祥正','宋','宋诗','song-poetry','','[]','李白不愛萬古侯，但願一識韓荆州。',240,'全唐诗/poet.song.42000.json','["李白不愛萬古侯，但願一識韓荆州。", "荆州太守古來好，至今文采傳風流。", "鄭公辭賦天下絕，殿前落筆鏗琳璆。", "相如嚴謹反枯澀，宋玉爛漫鄰倡優。", "卓然風格出天造，冰盤洗露銀蟾秋。", "麻衣脱去未十載，寶犀飾带魚懸鉤。", "道行言聽遇明主，皂蓋朱轓寧久留。", "渚宮風物最瀟灑，酒滿金罍誰獻酬。", "公嘗愛我如李白，恨不即往從公遊。", "醉看舞袖卷明月，夜聽長笛臨高樓。", "詞源感激瀉江海，筆陣頓挫排戈矛。", "駑駘蹇蹶固已困，勉之尚欲追驊騮。", "一朝公歸坐廊廟，致君事業如伊周。", "門闌從衛愈嚴密，是時願見應無由。", "行當投印佩長劍，夢魂已附西江舟。"]'),
('2737ae21-6c76-4164-9253-c02ddd172ea2','姑熟乘月泛漁艇至東城訪耿天騭','郭祥正','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','姑孰望東城，長江八十里。',199,'全唐诗/poet.song.42000.json','["姑孰望東城，長江八十里。", "思君半夜泛漁舟，明月隨人渡寒水。", "江南美酒君家無，攜來相就傾一壺。", "澄江如冰月如玉，拂拂清風生碧蘆。", "功名無成安足嗟，但令方寸無疵瑕。", "煉丹辟穀亦瑣瑣，萬物何處非生涯。", "君不見鴻溝欲將天下裂，失道陰陵遽身滅。", "玉帳周遭皆楚歌，金甲繽紛摧漢鉞。", "重瞳却傳繪塑手，瓦鼓巫歌薦神酒。", "廟前老木藏訓狐，豪氣英風亦何有。", "沈吟往事君勿悲，我曹幸遇堯舜時。", "田中穀稔牛羊肥，高會難逢易别離，今宵不醉欲安之。"]'),
('010f7fb9-959e-41eb-8ee1-9722b24b09f6','西山謠寄潘延之先生','郭祥正','宋','宋诗','song-poetry','','[]','男兒無成羈薄祿，日月相推猶轉轂。',219,'全唐诗/poet.song.42000.json','["男兒無成羈薄祿，日月相推猶轉轂。", "誰向生前悟此生，西山山人掛冠速。", "買田築室臨西山，時來石上横琴彈。", "千古萬古治亂事，一曲兩曲頓挫松風寒。", "門前禾熟醞美酒，故人車馬留盤桓。", "榮亦不足貴，辱亦不我干。", "但願青山綠水兩不變，醉醒自得窮觀玩。", "名落人間非所欲，閉門且喜辭憂患。", "君不見李太白，朝爲酒家仙，暮作金鑾客。", "醉裏題詩宫妾扶，自謂遇君今古無。", "一朝讒言入君耳，夜郎遠謫吟魂孤。", "到死空言竟何補，何如道行及妻子。", "西山人，孰可比。", "晴空矯矯孤雲飛，欲往攀援無路歧。"]'),
('69f0ab69-ff4d-4a91-b0c5-a02fc2411d15','上趙司諫','郭祥正','宋','宋诗','song-poetry','','[]','彈劍思經綸，悲歌負陽春。',216,'全唐诗/poet.song.42000.json','["彈劍思經綸，悲歌負陽春。", "逢時不自結明主，空文亦是尋常人。", "君不見太公辭渭水，謝安起東山。", "日月再開天地正，龍虎感會風雲閑。", "又不見屈原澤畔吟離騷，漁翁大笑弗餔糟。", "可行則行止則止，胡爲憔悴言空勞。", "夫君之名振朝野，道行諫聽逢時者。", "南州豈足舒君才，天門夜詔星車迴。", "紫皇之真人，造化無嫌猜。", "往將和氣輔舒慘，不令地下萬物同寒灰。", "功成收身綵雲裏，坐酌千觴浮玉蕊。", "麻姑王母相經過，醉來共泛瑤池水。", "樂亦不可盡，名亦不可窮。", "願學李賀逢韓公，他日不羞蛇作龍。"]'),
('eb69cec0-76ba-4c4c-9c98-cb14a5359720','贈張御史','郭祥正','宋','宋诗','song-poetry','','[]','我愛張御史，酒船打拍浮。',138,'全唐诗/poet.song.42000.json','["我愛張御史，酒船打拍浮。", "欲邀天下賢，盡向酒中愚。", "世人雖飲酒，只知酒味不知酒意胡爲乎。", "又聞夜歸東海頭，撫掌喚月當金壺。", "須臾蝦蟆蝕月黑，公起磨刀代天誅。", "蝦蟆吐月入地走，玉兔還家，桂樹不枯。", "公方醉卧，嫦娥驚呼。", "且語東方蒼青龍，遲遲推出赫日車。", "自然月光不滅，公飲不徹，是時應笑高陽徒。"]'),
('84ec50b9-2153-4498-a97d-2ed40c7c4cb5','贈提宮諫議沈公','郭祥正','宋','宋诗','song-poetry','','[]','神仙之府名雞籠，千尋翠玉擎寒空。',320,'全唐诗/poet.song.42000.json','["神仙之府名雞籠，千尋翠玉擎寒空。", "秀色凌風入城郭，半銜曉日金濛濛。", "賢材間出萬人傑，行脱麻衣趨紫闕。", "三朝出入持使權，凜凜聲名灑冰雪。", "往年作鎮來金陵，天子臨軒宣老成。", "問公書畫幾萬卷，品秩入奏編瑤瓊。", "延閣往往未嘗有，詔札奬與光華生。", "僉言公歸坐廊廟，易節暫刺玄暉城。", "懇請仙宮遽知止，車蓋翩翩還故里，粉娥執樂四時春。", "窈窕芙蓉新出水，嘈嘈弦管鸞鳳鳴，玉巵獻酒公解酲。", "人生快意似公少，家園乃是真蓬瀛。", "數峰飛來雲霧濕，琪樹玲瓏曉寒入。", "綠池水照百花明，芳亭小榭佳賓集。", "有時自賦歸來篇，幅巾藜杖詩中仙。", "秦晉諸子因避世，種柳栽桃安足憐。", "顧我登門二十載，貴勢能忘竟相待。", "數奇自笑無所成，亦欲浮舟往滄海。", "滄海雲濤人不爭，忘機可以超神凝。", "比公進退殊未足，若問逍遙無鷃鵬。"]'),
('71c36fbb-6524-4009-968a-ca6fbbf2c75a','贈孫郎中','郭祥正','宋','宋诗','song-poetry','','["\u8861\u5c71"]','江潮夜漲北風惡，雙櫓喜逢溪岸泊。',224,'全唐诗/poet.song.42000.json','["江潮夜漲北風惡，雙櫓喜逢溪岸泊。", "桂陽史君賢故人，借問慇懃吏來數。", "浮橋傾危暗難渡，靜枕不眠聽曉角。", "平明自笑僕乘無，破帽赤髯行踸踔。", "袖持漫刺前起居，屢歎窮愁手頻握。", "嬰兒連死瘦妻卧，病骨尚遭讒喙喙。", "壯志消盡同寒灰，生事無涯委藜藿。", "男兒有命何足論，斗酒貰衣評舊學。", "愛君新篇溢千楮，突兀寒宵見南嶽。", "龍蛇千丈老松杉，霹靂一聲揮電雹。", "豈宜偃蹇處郎曹，固合透迤步臺閣。", "天子聰明繼堯舜，廟堂論道皆伊霍。", "拔茅連茹收時才，尺寸高卑應不錯。", "君馳亨路鶚横秋，我困汙泥龜縮殻。"]'),
('9f49a026-e484-40f0-beaf-353511683b97','贈張參軍','郭祥正','宋','宋诗','song-poetry','','[]','宣城之人張待舉，高才未得見明主。',152,'全唐诗/poet.song.42000.json','["宣城之人張待舉，高才未得見明主。", "强將樽酒娛天真，猶得狂名落寰宇。", "陶陶復陶陶，意氣蛟龍豪。", "滄溟豈是遠，銀漢不爲高。", "路逢郭子陵陽津，平生未識如故人。", "相歡握手輒大笑，共訪瑤池尋玉真。", "天門夜叉識慮惡，爲我無錢謹關鑰。", "興闌却駕彩雲歸，别入紅窻共君酌。", "醉來兀兀乘扁舟，長溪水碧芙蓉秋。", "願逢萬丈龍鬚蓆，卷取月明歸玉樓。"]'),
('a5cd1a2f-ceee-4042-b5a6-cebe67948032','贈彭明微判官','郭祥正','宋','宋诗','song-poetry','','[]','昔謁公家賢侍郎，一見許我能篇章。',230,'全唐诗/poet.song.42000.json','["昔謁公家賢侍郎，一見許我能篇章。", "俸粳兵酒屢持送，時時解榻令登堂。", "今喜清風傳令子，回首亨衢脱雙屣。", "北堂歸養太夫人，水陸珍羞稱甘旨。", "深沈大第蟠蛇鱗，兒孫藍綬何詵詵。", "有時宴喜列賓客，洞房粉黛桃花春。", "玉指纖纖拂弦索，輕雲凝碧羅衣薄。", "主人快意妾爭妍，松上女蘿知有託。", "君不見景太傅，殺身本爲功名誤。", "又不見張舍人，朝爲近侍夕爲民。", "古來寵辱亦如此，安用浮雲纒此身。", "愛君進退真得所，不負青春領歌舞。", "我方兩鬢撲黄塵，夢寐江南思舊土。", "别君去，將拂衣，扁舟若渡歷陽月，願聽新歌酩酊歸。"]'),
('3f1ae61f-d327-4dcc-a6c4-83def6b3f6e2','贈陳懶散','郭祥正','宋','宋诗','song-poetry','','[]','懶散翁，何怪奇。',128,'全唐诗/poet.song.42000.json','["懶散翁，何怪奇。", "形容磊落似元亮，情性孤高如伯夷。", "靈臺瑩徹軒轅鏡，妍醜默辨毫與釐。", "生涯只寄一壺酒，萬事掉頭予弗知。", "或乘爛醉說儒佛，風雲座上騰蛟螭。", "顯晦自任不可測，頭角變化将有時。", "驚人一鳴，冲天一飛。", "豈能齪齪事小隱，堯舜君臣方有爲。", "懶散勿懶散，石渠金馬須翁來。"]'),
('70ae357f-706b-4e8f-bdca-bf536489770f','贈舒州李居士','郭祥正','宋','宋诗','song-poetry','','[]','李居士，存心最慕韓伯休。',123,'全唐诗/poet.song.42000.json','["李居士，存心最慕韓伯休。", "州城賣藥不二價，世人求我我何求。", "顔如渥丹眼如漆，和氣酣酣吐朝日。", "偶來握手爲一言，照盡五臟平生疾。", "箧中自取三粒丹，瘦骨坐使春陽還。", "便當投印棄冠带，與君海上巢名山。", "深鋤茯苓釀酒，極飲形骸可長久。", "乘槎鼓枻入雲濤，醉放一絲攜六鼇。"]'),
('099fa009-75a7-49a1-9a6b-3ff2d54af569','謝杜倅職方兼簡湯史君','郭祥正','宋','宋诗','song-poetry','','[]','李白昔遊宣城時，誰爲太守賢相宜。',208,'全唐诗/poet.song.42000.json','["李白昔遊宣城時，誰爲太守賢相宜。", "掣鈴交通喚六博，壯哉意氣凌虹霓。", "北望樓高氣象古，遺風餘思猶依依。", "我來正值青春半，雜花爛笑禽爭飛。", "輕烟繚繞淡白日，細風蕩漾吹游絲。", "高樓簾卷鄰袖出，百尺欄干横酒旗。", "銀鞍白馬不知數，龍箏鳳管相追隨。", "杜陵遠孫駕别乘，恩威得所名聲馳。", "華堂重搆喚賓客，風前共倒黄金巵。", "我爲下客最疏放，辱君許可能文詞。", "死生夤緣釋氏說，但覺時換名姓非。", "寄言太守勿感慼，共對佳人花下迷。", "莫敎流水落花去，空聞暮雨哀猿啼。"]'),
('69718b6f-a882-42af-970f-e79aa0caf540','謝劉察推','郭祥正','宋','宋诗','song-poetry','','[]','秋風吹霜入松柏，虚谷聲遙寒刺刺。',240,'全唐诗/poet.song.42000.json','["秋風吹霜入松柏，虚谷聲遙寒刺刺。", "月華正高星宿稀，獨鶴不鳴觜插翼。", "是時夫子爲我吟，逸調雄才世無敵。", "十年學詩自謂豪，一日逢君有慚色。", "恍疑醉夢太帝家，寶藏珠樓不知極。", "蟠桃結實九重春，金銀琅玕萬林直。", "須臾收拾到平淡，雨洗高峰增老碧。", "又如摩詰畫思精，一幅霜綃數拳石。", "鬼神怪變露形狀，天地英華發胸臆。", "我家江南謝朓山，山深流水長潺潺。", "獼猴摘果趁不去，白雲常在衣裳間。", "斷無車馬送塵土，獨與猿鳥期追攀。", "一杯有酌醉復醉，萬慮不到閒中閒。", "欲邀君去詠此景，願窺巨筆追揚班。", "其餘功業未足數，天馬安得趨塵寰。"]'),
('05f6717c-56e4-46f3-a085-4b1f93817f10','謝東城練尉','郭祥正','宋','宋诗','song-poetry','','[]','我聞武夷山，迺是神仙府。',216,'全唐诗/poet.song.42000.json','["我聞武夷山，迺是神仙府。", "靈丹插峭壁，異骨留深塢。", "有時風高月色靜，天樂琤淙散天宇。", "飄飄秀氣鍾爲人，往往聲名邁前古。", "練君頭角傑然奇，少年折桂登雲梯。", "陸機才華恨羞澀，相如詞調慚支離。", "青衫一命東城尉，能使斯民歌愷悌。", "鸞鳳肯與雞鶩爭，萬里雲霄終自致。", "東城烟水秋茫茫，覽古高吟應斷腸。", "白蛇血濺赤龍劍，八千子弟同時亡。", "而今戰處無青草，廟門斜掩狐狸老。", "羣巫請雨搖鐶刀，滴瀝椒漿薦蘋藻。", "力拔山兮安在哉，丹青壁畫空塵埃。", "因君吟想不能已，孤雁一聲山月頹。"]'),
('1f088ecf-111b-44ea-be89-cf339b4dc4a6','謝淮西吳提舉','郭祥正','宋','宋诗','song-poetry','','[]','瘦馬徐行三百里，撲撲黄塵眼雙眯。',224,'全唐诗/poet.song.42000.json','["瘦馬徐行三百里，撲撲黄塵眼雙眯。", "手攜簿法趨使臺，惟恐瑕玼煩摘指。", "藍衫慼慼走廊廡，與坐撫循顔色喜。", "琅琅先誦荆州吟，醉來捉住鯨魚尾。", "如今無復氣凌雲，垂首低徊逐泥滓。", "須臾又忘按察尊，羅列壺觴瞰池水。", "圓荷翻風碧玉軟，幽鷺得魚團雪起。", "正當煩暑浩如秋，更聽高談清入髓。", "君臣會合前世無，朝廷萬事圖新美。", "甲花照日御營寒，胡命懸絲朔風裏。", "自嗟雖老力未衰，命未遇知甘擯死。", "南山射虎竟殘年，不得封侯亦徒爾。", "感君欲引西江波，涸轍行將脱螻蟻。", "功名成就須報恩，莫道江南無壯士。"]'),
('6db82e94-52ed-461c-8f90-0525e2892cdd','仲春櫻桃下同許損之小飲因以贈之','郭祥正','宋','宋诗','song-poetry','','[]','君不見古人悲歌愁殺人，一片花飛減却春。',203,'全唐诗/poet.song.42000.json','["君不見古人悲歌愁殺人，一片花飛減却春。", "徑須沽取就花飲，暫時爛醉陶天真。", "借令黄金大於斗，豈買人間百年壽。", "但願青春永不歸，更得滄溟化濃酒。", "朝酌弗乾，暮傾弗竭。", "東向浮桑採日枝，西入瑤池浴明月。", "枯桐三尺安足彈，重華去矣薰風寒。", "夷齊恥食首陽粟，屈子徒佩瀟湘蘭。", "噫吁嚱哉賢與愚，同歸一死胡爲乎。", "共君極飲且爛醉，指點世路皆虚無。", "許損之，爾爲我滿斟，我爲爾高吟。", "相逢莫恨晚，結交貴知心。", "坐看南山一片霧，忽成千里萬里之春陰。"]'),
('ea68f40c-28f4-4b2a-a0fa-558fb9285254','再遊花山','郭祥正','宋','宋诗','song-poetry','','[]','去年來時春未歸，枯林扠枒露老枝。',96,'全唐诗/poet.song.42000.json','["去年來時春未歸，枯林扠枒露老枝。", "今日重來春已去，秀葉茂密藏黄鸝。", "山家景物新換故，世事塵埃朝復暮。", "白頭迤邐謝輪蹄，青塚綿聯老狐兔。", "令人歸興如浮雲，早向江山樂賤貧。", "不須訪道赤松子，但愛鱸魚并紫蓴。"]'),
('b2493c24-23c4-4772-a569-fc06b49ecb05','酬蔡尉秘校','郭祥正','宋','宋诗','song-poetry','','[]','環峰雨過烟嵐披，君醉兀兀騎驢歸。',226,'全唐诗/poet.song.42000.json','["環峰雨過烟嵐披，君醉兀兀騎驢歸。", "明朝大字送滿篋，乃是醉掃琅琊詩。", "陽冰篆筆昔未有，鐵索礧碨纒蛟螭。", "禹偁八詠不足數，永叔爛浸鐫瑤碑。", "山光水潤洗出大古色，更後敢作知爲誰。", "愛君膽大少且鋭，攙剔缺漏筆補之。", "飄然一别今七載，取讀往往生光輝。", "寧知流落尚爲尉，瀟湘邂逅令人嚱。", "又致新章溢編楮，遣僕買酒烹黄雞。", "伊予齒髮更衰落，固異往昔相逢時。", "舉杯未盡輒醉倒，跟吻雖强難扶持。", "人生老去百無益，談新憶故惟傷悲。", "勸君休吟亦勿飲，橛株拘坐真忘機。", "死生終始了爲一，清風爲我炎天吹。"]'),
('c21fad1c-d270-497e-b658-d4cd1f8c2e1a','酬李從道太博','郭祥正','宋','宋诗','song-poetry','','[]','秋水浸天無表裏，間帆已過三千里。',160,'全唐诗/poet.song.42000.json','["秋水浸天無表裏，間帆已過三千里。", "鸚鵡洲前逢故人，往事新愁還可紀。", "祖朝熙熙民物好，長憶聯車游五老。", "鳥啼花舞送春歸，倐忽官書滿三考。", "從兹南北趨塵勞，往往遭嗤兒女曹。", "斗筲之祿未能棄，回首空羡嚴陵高。", "相逢彼此驚遲暮，筆下琳琅寫心素。", "荷花十頃遶君家，豈是荒榛礙歸路。", "悲歌不覺青衫濕，酒杯未滿愁先入。", "聞說明朝趨玉京，直節如今恐難立。"]'),
('a9c266f0-b81a-4924-8710-c7206efbb48a','公擇鄂守學士三堂請雨','郭祥正','宋','宋诗','song-poetry','','[]','廟門斜開壓江浦，紅裳小巫未擊鼓。',96,'全唐诗/poet.song.42000.json','["廟門斜開壓江浦，紅裳小巫未擊鼓。", "太守焚香令致詞，願駕蒼龍作霖雨。", "三神鼎峙名謂何，子胥范蠡馬伏波。", "圖經莫載碑字滅，忠魂血食應不訛。", "朝廷日夜傳新令，輔弼賢良元首聖。", "陰陽調燮神相之，忍使斯民饑以病。"]'),
('8f8b7dbe-b2f6-4959-8795-7ab0340a4486','酬魏炎秀才','郭祥正','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','碧雲暮合廬山頭，夜蛩聲撼鄉園愁。',128,'全唐诗/poet.song.42000.json','["碧雲暮合廬山頭，夜蛩聲撼鄉園愁。", "忽然一見舊遊客，貰酒不惜千金裘。", "高談稍聽吐胸臆，歘如野燒光難收。", "虎豹哀嗥走不徹，獵網四面誰能搜。", "嗟予慄慄畏事者，兀坐視予勞雙眸。", "主人欣歡亟掃室，雁榻旋列横霜秋。", "兩溪倒碧瀉明月，松窻左右風飀飀。", "長篇贈我不可和，和聲酸澀令人羞。"]'),
('69939322-ac6d-45fe-ad47-c83f0a4d2f7c','和懶散贈葫公','郭祥正','宋','宋诗','song-poetry','','[]','葫公家在東園隅，世族蕃衍今仍孤。',160,'全唐诗/poet.song.42000.json','["葫公家在東園隅，世族蕃衍今仍孤。", "平生嗜酒少知者，請說懶散提攜初。", "杖頭世界迷日月，豁然心地無榛蕪。", "人人未飲公輒醉，坐卧只與樽罍俱。", "章華開口洩上旨，毛穎秃髮非中書。", "貪官雖得後乃辱，智慮可惜于身疏。", "豈如葫公泛滄海，不用鼓枻并乘桴。", "蓬萊頂上受玉液，酣酣至樂忘榮枯。", "劫火任滅公未醒，不復願進承明廬。", "承明侍宴盡金玉，君豈有意來相呼。"]'),
('684406de-5346-4ceb-aaad-c58c1b5aebd2','月下獨酌二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','長空無雲江水凈，月出東方掛金鏡。',92,'全唐诗/poet.song.42000.json','["長空無雲江水凈，月出東方掛金鏡。", "我時有酒何處斟，破碎寒光借漁艇。", "便邀玉兔乞靈藥，一粒爲醫天下病。", "玉兔既不報，我亦醉不知。", "舟人解事喚我起，月輪已轉西山西。", "人間萬事不可了，且與明月閒相隨。"]'),
('df654334-bd0c-40ca-88c0-09b1d1bd8dbb','月下獨酌二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','明月不解飲，何事解照琉璃鍾。',132,'全唐诗/poet.song.42000.json','["明月不解飲，何事解照琉璃鍾。", "金波蕩漾使我惜不徹，一酌萬事逃心胸。", "良時忍自棄，聖代真難逢。", "生平不知耕與戰，唯知猛飲大笑吟清風。", "竹林七子豈足數，淵明五柳方途窮。", "一身不爲萬乘屈，傲矣嚴陵垂釣翁。", "明朝官滿，歸去來兮。", "但願月輪不缺，樽酒不空。", "吾君萬歲坐法宮，四海長靜無兵戎。"]'),
('8ab8c336-c766-44ac-9858-00a8595dcfd3','魏武廟','郭祥正','宋','宋诗','song-poetry','','[]','濡須山頭祠魏武，炫轉紅裝按神鼓。',64,'全唐诗/poet.song.42000.json','["濡須山頭祠魏武，炫轉紅裝按神鼓。", "蘋藻盈筐酒滿樽，呼吸風雷激春雨。", "田疇高下春雨平，操牲飲福羅中庭。", "吞吳成魏還歸晉，血食猶參社鬼靈。"]'),
('53dd5511-f31c-40a5-a6a1-41fbee772d1e','向舜畢秘校席上贈黄州法曹杜孟堅即君懿職方之孫也','郭祥正','宋','宋诗','song-poetry','','[]','青天無雲日華滿，小妓樓中吹玉管。',192,'全唐诗/poet.song.42000.json','["青天無雲日華滿，小妓樓中吹玉管。", "卷簾不信夜霜寒，熏蘭酌桂肌膚暖。", "黄州之客最少年，醉來口角傾詞源。", "驚龍掣電繞滄海，沙場陣馬成功旋。", "殿賜新袍織春草，水溢雙瞳犀插腦。", "壯圖佇結明主知，带束黄金應未老。", "宣城憶拜乃翁時，幕中珠履皆雄奇。", "至今名姓記僧壁，當年已識麒麟兒。", "嗟予老人日零落，兩鬢衰蓬眼生瘼。", "寸心猶欲慕夷齊，險路無緣攀衛霍。", "邂逅桐鄉逢故人，槐槽瀉釀追陽春。", "形容若畫凌烟閣，第一江南尋隱淪。"]'),
('3320c11e-d5de-4069-8cdd-7d22db5575e9','懷青山草堂','郭祥正','宋','宋诗','song-poetry','','[]','三峰連延一峰尊，龍山白紵如兒孫。',236,'全唐诗/poet.song.42000.json','["三峰連延一峰尊，龍山白紵如兒孫。", "重岡複嶺控官道，北望金陵真國門。", "淙流奔激灑河漢，兩溪直接丹湖源。", "松荒檜老古佛刹，雞鳴春晚桃花村。", "石崩廢井謝公宅，龜仆斷碣長庚墳。", "斯人白骨已化土，英氣往往成烟雲。", "我昔棄官結茅宇，九品青衫安足數。", "竹筒盛酒騎白牛，醉眠看天與天語。", "如何蹭蹬隨辟書，十年又向風塵趨。", "只今兩鬢滿霜雪，功業不成思舊廬。", "山花解忘憂，山鳥名提壺。", "四鄰未必便棄我，三徑荒草還堪鋤。", "烏泥田肥種秫稻，紫蓴味美饒嘉魚。", "盈缸釀酒邀客飲，林下散髮時時梳。", "誰人縶爾不歸去，自問此心無乃愚。"]'),
('eebc3566-048c-4643-80cb-cf15b0dd39bc','憶五松山','郭祥正','宋','宋诗','song-poetry','','[]','江南富山水，忽憶五松山。',273,'全唐诗/poet.song.42000.json','["江南富山水，忽憶五松山。", "梁僧種松奪造物，至今千丈凌雲間。", "上有寒蟾吐魄凝冰雪，下有銅陵碧澗傾潺潺。", "雷公睥睨不可以揮斧，老鶴飛來勢欲止而復還，猿猱側望何由攀。", "琉璃殿閣若化出，四天之衆說法鳴金鐶。", "我嘗脱屣往棲息，六月清風無汗顔。", "濃陰可愛坐盤石，綠酒酌盡横琴彈。", "命宫叩徵天地變，聽之以氣往往生羽翰。", "紛埃不到佛凈國，豈識人間行路難。", "塵勞忽起舊緣想，倒騎匹馬來長安。", "修鱗掉尾業已困，涸轍孰與西江瀾。", "髮疏齒缺形將殘，畏塗足躡心膽寒。", "屈原懷沙賈誼貶，身後忠名何足觀。", "不如宴坐碧山裏，笑傲每攜雲月歡。", "明朝却欲渡江去，五松巖戶無人關。", "方壺員嶠太殊絕，幸有此山容我閑。"]'),
('64196940-a80f-47d9-8381-1ac9ac6685ad','清明望藏雲山懷舊遊','郭祥正','宋','宋诗','song-poetry','','[]','憶昔清明出郊去，藏雲寺前花正開。',160,'全唐诗/poet.song.42000.json','["憶昔清明出郊去，藏雲寺前花正開。", "蜜蜂銜蕊異香散，時時灑面微風來。", "溪泉甘滑碧玉色，晴山倒影無纖埃。", "紅粉佳人十七八，踏青唱歌雲鬢頹。", "黄犢行牽載酒瓮，到處便傾三百盃。", "或逢濃陰藉草坐，口横玉笛吹落梅。", "傍人問我樂何事，我心無事同嬰孩。", "誰令束带入官府，觸網修鱗難再回。", "清明依舊好時節，朱顔憔悴無由陪。", "藏雲之山亦非遠，隔江東望青崔嵬。"]'),
('55bff477-6576-412c-9548-0dc3f73ab4aa','洛中王秀才談劉伯壽動靜慕其瀟灑作詩識之','郭祥正','宋','宋诗','song-poetry','','[]','客來說劉翁，嵩山跨黄犢。',160,'全唐诗/poet.song.42000.json','["客來說劉翁，嵩山跨黄犢。", "青衣二雙鬟，顔色若明玉。", "手攜綠牙笛，隨軒奏新曲。", "倒傾酒榼松下飲，旋開氈帳雲中宿。", "少年富貴老安閑，自道此生無不足。", "令人慕高標，神魄頓蕭爽。", "何當插兩翼，乘風一飛往。", "永結斯人交，逍遙恣真賞。", "長哦紫霞篇，洞戶瓊瑤響。", "胡爲戀青衫，壯節空骯髒。", "塵埃一閧城郭卑，波瀾萬頃滄溟廣。", "明朝未作嵩少游，且向江南結魚網。"]'),
('54d90c0d-9085-4ca9-8073-31ba2ea95114','逍遙亭歌一首贈太守王君章','郭祥正','宋','宋诗','song-poetry','','[]','逍遙之亭在何許，城角西南小溪滸。',216,'全唐诗/poet.song.42000.json','["逍遙之亭在何許，城角西南小溪滸。", "水仙粉面浮清波，羽林兵仗森三畝。", "六月微風拂面寒，不信人間有煩暑。", "借問逍遙真隱徒，西山看雪倒騎驢。", "形骸兀兀天壤俱，畫手爭以丹青模。", "大言得罪僅免誅，斥參軍事來當塗。", "傳云此地舊結廬，百年荆棘遺荒墟。", "公來相址呼犂鋤，雙亭化出瓊璃鋪。", "欄干鬬角明青朱，四座瑩徹纖埃無。", "蘭芬麝裂陳罌盂，珠履珊珊陪後車。", "東瞻宣詔西浮圖，曉光夕景迷蓬壺。", "愛公心晝如明珠，落成之樂政事餘。", "爲公歌，勸公醉。", "留連亭上能幾時，行促星軺還玉陛。"]'),
('862b3208-d12e-4efa-9f74-6afb62e161a1','投獻省主李奉世密學','郭祥正','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','祖朝相國之真孫，軒軒冠蓋宜高門。',230,'全唐诗/poet.song.42000.json','["祖朝相國之真孫，軒軒冠蓋宜高門。", "拔身州掾入政府，議論挺特窮根源。", "顔淵必用孔丘鑄，自此聲名聞至尊。", "熙寧神化邁前古，屢詔馳車外循撫。", "大河之北淮之壖，民起疵癏勇歌舞。", "樞庭進直腰横金，君臣道合同一心。", "貨泉交匯指諸掌，老吏縮手隨規箴。", "如公之才世希有，突兀千丈輝喬林。", "徐冠貂蟬坐廊廟，重見成王得周召。", "泰山鏤牒天垂休，却笑鴻濛首頻掉。", "賤生流落何可言，四十栖遲埋冗員。", "涸鱗悵望一盃水，安用西江浩渺之波瀾。", "願公吐和氣，稍回巖谷春。", "養成尺寸木，爲公車下輪。", "他年青史上，報德豈無人。"]'),
('87b34813-c700-4f8d-b49a-4547a3d2bd30','俞俞堂寄鄂州李裕老','郭祥正','宋','宋诗','song-poetry','','[]','黄鶴樓南大湖側，芙蕖深遶誰家宅。',211,'全唐诗/poet.song.42000.json','["黄鶴樓南大湖側，芙蕖深遶誰家宅。", "云是裕老之宴居，高堂獨榜俞俞額。", "春山抱翠入平簷，夏竹引凉吹廣陌。", "秋江澄月天鏡開，冬雪擁林崑閬白。", "世間萬事不掛心，瓮撥香醪欣有客。", "客來乎，伴我飲，不醉無歸醉還寢。", "問君欲達逍遙鄉，信哉天地真衾枕。", "覺來何物能解酲，試作琵琶打面聲。", "俞俞和氣淡四體，安用辟穀求長生。", "君不見鸚鵡洲前殺禰衡，三赤棁杖當雄兵。", "才名誤身不自覺，恬淡晦跡無人爭。", "南北相望二千里，夢逐高帆逆秋水。", "爲翁持酒聽翁歌，衣濯黄塵眼除眯。"]'),
('c0c39ede-0cae-4339-9afe-e1e5b4ddfc7c','前雲居行寄元禪師','郭祥正','宋','宋诗','song-poetry','','[]','憶雲居，乃在匯澤西南修川之隅。',281,'全唐诗/poet.song.42000.json','["憶雲居，乃在匯澤西南修川之隅。", "山盤盤兮，石門屹立磴道絕，飛瀑萬丈淙冰壺。", "雲沈沈兮方晝而忽暝，古木交錯兮藏鼪鼯。", "攀崖欲上復自止，投險却憶騎鯨魚。", "崖向時復造平野，絕頂乃有百頃之膏腴。", "羣山下瞰若聚米，殿閣枕藉非人區。", "露華洗出太古月，桂子搖落陰扶疏。", "清風欲借羽儀展，穢念頓覺秋毫無。", "老禪底事不度我，紅日東上還驅車。", "如今正似武陵客，放舟已遠嗟迷途。", "青春一往二十二，白雪漸變千莖鬚。", "西來忽遇歸飛鳥，青紙遠寄黄金書。", "靈茶香味勝粉乳，滿篋所贈遇瓊琚。", "玉川七椀喫不得，灌頂未識真醍醐。", "南暹北訥惜已死，唯師秀出孤峰孤。", "潛深隱密自得所，豈不憫我棲榛蕪。", "倒影射巖猶入石，異日三椽容野夫。"]'),
('b5adca8a-aeae-4218-aad6-5deddb1612e2','後雲居行寄和禪師','郭祥正','宋','宋诗','song-poetry','','[]','我所思兮，歐山之巓。',309,'全唐诗/poet.song.42000.json','["我所思兮，歐山之巓。", "白石蒼木蔽窺而隔世兮，路通乎兜率之天。", "層樓複閣，觸峙絢爛。", "往即造兮，雲渤興而澶漫。", "徙倚恍惚，若奪吾魄兮，聊枚睫以盤桓。", "徐風生而霧散，卷綃縠于林端。", "洎天清而日上兮，瀑峻飛而潺湲。", "畜而爲潭，泄而爲澗。", "運之以車兮，盈乎大田。", "然復度石橋，登重門。", "睹篆玉之榜，謁金仙之尊。", "徒衆五百，厖眉皓首。", "形儀靜而不雜兮，語言要而不煩。", "齊興止以鐘鼓兮，善後先而靡難。", "舉正眼而諦瞬兮，了無一法之可觀。", "寂兮樂兮，妙復妙兮，其惟真如之禪。", "我請棄冠釋带以投依兮，師則指乎未契之緣。", "于是曳屣却步，循磴道而復返兮，歲眇眇而屢殘。", "觸網羅以系累兮，方傷羽而戢翰。", "悵昨游而欲再兮，庶已創而復完。", "亂曰：疇將歸兮，卧龍之室。", "依人道師，成佛而出。"]'),
('08227727-8271-4f13-97e4-ea1dfa66e7ad','贈潛山伊居哲先生','郭祥正','宋','宋诗','song-poetry','','[]','伊君頭戴星文冠，遨遊五嶽何時還。',144,'全唐诗/poet.song.42000.json','["伊君頭戴星文冠，遨遊五嶽何時還。", "結茅却在潛山裏，閉息自養丹田丹。", "聞說年齡七十九，髮如鴉青亦稀有。", "生平讀盡道藏書，寓興成詩僅千首。", "清風生我太古弦，彈罷時傾一壺酒。", "門前手植數本松，看爾凌雲比予壽。", "高奔日月瞻玉京，陰氣鍊盡陽氣成。", "行聞北帝呼六丁，紫書下詔鸞鳳迎。", "潛山空留千載名，白雲不斷溪長清。"]'),
('a6adcc65-c209-41b9-a6ab-8bb09ad61890','贈桐城青山隱者裴材','郭祥正','宋','宋诗','song-poetry','','[]','青山爲主身爲客，主人借客青山宅。',128,'全唐诗/poet.song.42000.json','["青山爲主身爲客，主人借客青山宅。", "白雲自在千里飛，長松不換三冬碧。", "藤枯誰與寫作龍，龜老何年化爲石。", "落花隨水眷深源，鳴雁過江悲晚色。", "家無妻子心無累，頂冒寒霜踵藏息。", "月明舞影聊盡歡，一點塵寰不留跡。", "儻來軒冕真可嗟，朝爲公卿暮遭謫。", "屈原賈誼爾爲誰，問君何似青山客。"]'),
('e1b828b3-6e96-4c42-b96a-3660d1935428','寄劉繼鄴秀才','郭祥正','宋','宋诗','song-poetry','','[]','憶昔重遊樂，尋春之宛陵。',156,'全唐诗/poet.song.42000.json','["憶昔重遊樂，尋春之宛陵。", "天機織出萬山錦，虹橋倒影銀河明。", "游絲縈空白日暖，好鳥亂響清風生。", "疊嶂樓中索美酒，坐上客子皆豪英。", "諸姬合雜奏弦管，一人妙唱爲井瓊。", "玉板斜開厚冰裂，鴛鴦索拍秋波横。", "酒盞貪歡不知數，夢入瑤池逃宿酲。", "誰知一别萬事錯，荷衣倒着來江城。", "青雲散盡落青野，長絲掣斷無長鯨。", "鄉山好在却歸去，當共故人吟此情。"]'),
('6f3101cc-4563-4d63-a74d-50d8103de210','題杏山阮氏高居','郭祥正','宋','宋诗','song-poetry','','[]','仙翁得仙朝玉皇，當時種杏盈山岡。',192,'全唐诗/poet.song.42000.json','["仙翁得仙朝玉皇，當時種杏盈山岡。", "傳聞落英堰流水，每到三月溪泉香。", "白雲霏霏出幽谷，獨鶴沉沉唳喬木。", "寒潭深處睡蟠龍，靈草芳時躍青鹿。", "丈人何年居此間，詵詵孫子如芝蘭。", "抱才求進十五六，亦有隨計鄉書還。", "步兵傲世逸千載，誰道風流至今在。", "軟炊玉粒烹黄雞，客子雖多竟相待。", "我愛長吟登好山，到此便欲辭塵寰。", "可能築室輒延我，爲君鍊熟黄金丹。", "丹成大笑分一粒，坐令綠髮回朱顔。", "浮生百歲不早悟，日月擾擾空循環。"]'),
('ca7b0901-3c12-48b3-ad09-e931d241f47e','銅山寺','郭祥正','宋','宋诗','song-poetry','','[]','田塍行盡蒼山轉，溪水滔滔晴曝練。',96,'全唐诗/poet.song.42000.json','["田塍行盡蒼山轉，溪水滔滔晴曝練。", "馬蹄怯石鞭不行，十步九蹶令人倦。", "黄昏到寺亟就榻，山僧苦來邀我飯。", "香粳新炊野菜肥，一飽令人百憂散。", "篆香欲盡象燈暗，林聲敲敲苦霜霰。", "暫來福地能清虚，何用致身居諍諫。"]'),
('a0e21b19-e418-42fb-9071-ff716ac4ecf8','隱靜寺  其一','郭祥正','宋','宋诗','song-poetry','','[]','門横大溪溪凈碧，人不捕魚魚穩潛。',64,'全唐诗/poet.song.42000.json','["門横大溪溪凈碧，人不捕魚魚穩潛。", "哀猿長嘯霧垂地，饑虎一聲風動簾。", "金仙像古苔蘚剥，鐵磬夜敲規矩嚴。", "道師達性傲時輩，不信書生來養恬。"]'),
('c0abc9ba-7d66-40a4-b31c-403647c1e246','隱靜寺  其二','郭祥正','宋','宋诗','song-poetry','','[]','碧霄峰下車輪停，道師未返誰逢迎。',64,'全唐诗/poet.song.42000.json','["碧霄峰下車輪停，道師未返誰逢迎。", "山雲情着雨正急，春水滿田人不耕。", "饑虎嘯風大石裂，倦鳥喚雛深澗鳴。", "客心欲去且復止，坐飽香飯餘何營。"]'),
('51655d06-52ed-4c73-9e34-c414b60368ff','浮丘觀','郭祥正','宋','宋诗','song-poetry','','[]','仙翁得仙二千載，滄海變田田變海。',160,'全唐诗/poet.song.42000.json','["仙翁得仙二千載，滄海變田田變海。", "浮丘却接番禺西，鐏跡蒿痕至今在。", "朱明之門敲不應，荆榛滿地誰重興。", "史君舉意要卜築，樓觀矗雲如化城。", "李白騎鯨下蓬島，嫦娥洗月來滄溟。", "相逢且勸百壺酒，蟠桃結實何時成。", "史君自有神仙骨，往往前身尋舊物。", "手探樹穴求玉環，肩拍洪崖猶彷彿。", "更提椽筆揮長篇，至理直欲追玄元。", "行當跨鳳返金闕，回首番禺空紫烟。"]'),
('c13817e1-44b2-41e3-9b5c-c41fb1d6fd28','明皇十眉圖','郭祥正','宋','宋诗','song-poetry','','[]','明皇逸事傳十眉，正是唐家零落時。',96,'全唐诗/poet.song.42000.json','["明皇逸事傳十眉，正是唐家零落時。", "霓裳曲調雖依舊，阿蠻終不似楊妃。", "畫工貌得非無意，欲使流傳警來世。", "翠翹紅粉尚爭春，隱約香風起仙袂。", "六龍真馭竟何之，泰陵荒草長孤狸。", "空將妙筆勸樽酒，醉覺人間萬事非。"]'),
('ed0456b8-2b90-492a-9976-bc3953029a1e','九疑山圖','郭祥正','宋','宋诗','song-poetry','','[]','噫吁嚱，九疑山色何雄奇。',252,'全唐诗/poet.song.42000.json','["噫吁嚱，九疑山色何雄奇。", "坡陁詰曲不足狀，九峰萬丈排天扉。", "嶄嶄儼若九老坐，乾顛坤弱能扶持。", "崖回時復見華塵，原本旋有山經題。", "白雲綿聯芳草歇，拱木夭矯狂風吹。", "上有源源不絕之寒泉，下有沄沄不斷之深溪。", "初疑青銅照碧落，忽見雲漢飛虹霓。", "丹青畫出尚如此，而况高步窮嶇崎。", "或云重瞳一來不復返，二妃血淚斑竹枝。", "惜哉不經孔子辨，後世誰能公是非。", "堯非幽囚，舜不野死。", "堯崩民如喪考妣，舜非游仙而幸此。", "羣猪聳耳聽童子，游人擊之變風雨。", "見豕負塗聖所惡，仙人護之亦何補。", "我知神仙術已卑，但愛此山雄而奇。", "背圖南望未能到，高吟盡日長吁嚱。"]'),
('01ac8672-7cb8-42c0-8dae-edcd6478c8ba','魏中舍家藏王摩詰海風圖','郭祥正','宋','宋诗','song-poetry','','[]','只聞王公畫山水，未識王公滄海圖。',152,'全唐诗/poet.song.42000.json','["只聞王公畫山水，未識王公滄海圖。", "魏侯矜誇我家有，取出十幅堂中鋪。", "誰知東海羣龍力，神妙能以一筆驅。", "洪濤翻天雪成隴，黑分雲霧藏空虚。", "高低數寸折萬丈，勢以意會無差銖。", "却嗟流傳數百載，絹素何以當涵濡。", "王公之心壯莫比，其工欲出造化初。", "惜哉已死不復得，悵望盡日將何如。", "魏侯魏侯重藏秘，直恐變化成江湖，我歌不足徒嗚呼。"]'),
('e4f8bfb7-8c04-4281-ae95-3868dfe21b1d','王元當家藏鍾隱畫三害圖','郭祥正','宋','宋诗','song-poetry','','[]','老鍾筆法何奇古，三害精靈一圖聚。',194,'全唐诗/poet.song.42000.json','["老鍾筆法何奇古，三害精靈一圖聚。", "周生自握蒼精龍，白額長蛟甘喪沮。", "危橋跨水壓波濤，巨木翻風瞑烟霧。", "挺然獨往知忘軀，敢謂誅邪天地助。", "三日生還動閭里，千載遺蹤存絹素。", "薄蝕已更人仰之，自古賢豪遺細故。", "何獨今人無此人，已覺丹青有深趣。", "江南印璽尚如新，國破蒼忙畫誰付。", "一圖分裂藏三家，離合悠悠歲時度。", "只今皆屬丞相孫，掛向高堂邀客顧。", "倐然風雲駕霹靂，雨來平地銀潢注。", "珍綈收藏卷不徹，直恐變化復入江湖去。"]'),
('3bd27196-38d4-4cba-9a3d-a2c54608c91a','燕待制秋山晚景','郭祥正','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','我朝妙畫能山水，燕公筆法精無比。',210,'全唐诗/poet.song.42000.json','["我朝妙畫能山水，燕公筆法精無比。", "燕公山水工平遠，一幅霜綃折千里。", "瀟湘洞庭日將晚，雲物蕭蕭初滿眼。", "虞帝之魂招不返，霜樹冥冥紅葉卷。", "二妃血淚知幾多，竹上遺痕深復淺。", "漁舟片帆風已滿，漁父横眠思猶懶。", "時時白鷺聚圓沙，亦有行人下前坂。", "江回岸斷數峰青，彷彿靈妃曲可聽。", "却逢深崦見茅屋，只欠桃花如武陵。", "世間何物人爭詫，請說奇書并妙畫。", "一時鑒賞安足論，流轉千年愈增價。", "珍綈一襲藏至珍，卷尾長篇更入神。", "嗚呼粉墨終成塵，唯有文章道德能日新。"]'),
('532a3c88-9c67-4d2d-8b84-c8a88bec5d2a','夏公酉家藏老高村田樂敎學圖','郭祥正','宋','宋诗','song-poetry','','[]','高生妙畫世所知，君藏兩幅尤瑰奇。',261,'全唐诗/poet.song.42000.json','["高生妙畫世所知，君藏兩幅尤瑰奇。", "春回老柳未全綠，和氣盎盎微風吹。", "負暄當案誰氏子，坐以訓詁傳童兒。", "麻鞋破穿十指露，紵衫短袖烏巾欹。", "眼吻開張手捉筆，叱怒底事揚其威。", "兩童分爭迭相挽，彼二稚子傍觀窺。", "一童獨卧守書卷，性習已見分醇醨。", "皤然老叟醉兀兀，二孫側立猶扶持。", "餘皆伶官雜村妓，插笛放鼓陳威儀。", "三犬奔來吠欲囓，二人驚顧方攢眉。", "伶家有子少亦黠，兩手據鞍驢載之。", "尊卑向背極精妙，精妙得以意思惟。", "田翁豐年固取樂，又能敎子勤書詩。", "德澤涵濡賦斂絕，致我鼓腹咸熙熙。", "畫工亦畫太平事，誰欲擾之生亂離。", "高生高生，不獨愛爾之妙筆，對此頗思三代時。"]'),
('b6bdfcf7-8779-49ca-b1ae-6deb85491cc5','寂照大師匣藏相國寺壞壁秋景','郭祥正','宋','宋诗','song-poetry','','[]','京城車馬多塵埃，一見妙畫心眼開。',192,'全唐诗/poet.song.42000.json','["京城車馬多塵埃，一見妙畫心眼開。", "深山老木秋思靜，苦霧鬰鬰諸峰埋。", "客騎蹇驢打不動，懊惱似憂寒雨來。", "崖平路轉斗然絕，筆力未斷空徘徊。", "胡爲皴剥僅盈尺，鐍以大篋過瓊瑰。", "師云昔是殿堂壁，治平大水餘皆摧。", "恰如盧仝玉碑子，中路撲折令人哀。", "玉碑一折乃無用，此畫雖缺猶堪裁。", "君不見，山前路，路長不獨憂風雨。", "前有毒蛇後猛虎，磨牙矯尾藏深塢。", "聖人皇皇嗟逆旅，畫工意思非無補。", "非無補，誰信之，紛紛門外誇輕肥。"]'),
('d5c46062-cdae-47b9-87e4-e6557c9adfe0','泗水雍秀才畫草蟲','郭祥正','宋','宋诗','song-poetry','','[]','蜻蜓點水蝶撲花，螳螂捕蟬蜂趁衙。',96,'全唐诗/poet.song.42000.json','["蜻蜓點水蝶撲花，螳螂捕蟬蜂趁衙。", "營營青蠅爭腐糝，趯趯阜螽沿草芽。", "餘生骨朽不復得，雍子筆老誰能加。", "卷開却掩恐飛去，綈襲愛護行隨車。", "况君才力日清敏，胡不放手爲龍蛇。", "龍蛇逼真看騰躍，出入天地藏烟霞。"]'),
('1a1c367d-d546-4275-a5d4-14089f8772ed','謝冲雅上人惠草書','郭祥正','宋','宋诗','song-poetry','','[]','上人胸腹包琅玕，醉目睥睨臨冰紈。',176,'全唐诗/poet.song.42000.json','["上人胸腹包琅玕，醉目睥睨臨冰紈。", "墨池頃刻波瀾翻，虬龍尾尾垂雲間。", "搖曳天矯若可攀，霹靂轟斧電火騫。", "卒章雨雹霏漫漫，澒洞恐懼坤軸掀。", "白沙縱横仆鼉黿，屋漏壁折安足言。", "鳥驚出林避彈丸，斗高復下騰修翰。", "朽木欲折枯藤攢，逸興不顧長毫乾。", "客如堵牆爭縱觀，詎知堊盡吾鼻端。", "黄金論斗珠走盤，數字不售尤爲難。", "爾嘗愛我說玄理，爲我落筆動盈紙。", "張顛懷素嗟已矣，上人之書無與比。"]'),
('0ce46d3e-4274-43e7-8ba0-4ba17a9965ae','謝鍾離中散惠草書','郭祥正','宋','宋诗','song-poetry','','[]','丈人行草天下無，體兼衆善精神俱。',160,'全唐诗/poet.song.42000.json','["丈人行草天下無，體兼衆善精神俱。", "少年弄翰今懸車，一幅不博千明珠。", "墨池翻瀾化鯨魚，老木半折傾藤枯。", "霜天一陣來雁鶩，荒陂數點眠鷗鳬。", "換鵝瘞鶴雖已矣，折釵劍舞成須臾。", "心通造化乃神速，伯英懷素真其徒。", "邇來作我醉吟贊，寶藏二妙歸江湖。", "要將垂法數百載，摩挲青玉親傳模。", "丈人善吟仍善奕，名譽豈止專能書。", "名譽豈止專能書，皎如浩雪盈冰壺。"]'),
('8f3dd26c-b6d8-4666-a3e6-e65a1d83fe1c','謝蔣穎叔惠澄心紙','郭祥正','宋','宋诗','song-poetry','','[]','李氏三世皆名書，古今筆法誰能如。',208,'全唐诗/poet.song.42000.json','["李氏三世皆名書，古今筆法誰能如。", "澄心堂中畜妙紙，敲冰搗楮惟恐粗。", "當時文物稱第一，敎勑往往親涵濡。", "赫然真龍躍中國，僭跡甘就雷霆誅。", "論功行賞盡金玉，唯有此物多贏餘。", "流傳既久乃珍絕，一軸不換千明珠。", "樂安御史輒寄我，二十五幅無纖汙。", "却疑織女秋夜醉，素段割裂天所須。", "又如美玉纔出璞，瑩采射目爭陽烏。", "文章未到一王法，寶紙謾對明窻鋪。", "廷珪煤麝銅雀瓦，氣象嵂兀尤相於。", "坐思厚貺欲爲報，累旬安得論錙銖。", "况君才力似韓愈，盡當返贈誅奸諛。"]'),
('34a2aae7-ab21-42df-9d74-f18e3dcc8a1a','謝餘干陸宰惠李廷圭墨','郭祥正','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','集仙昔與文忠遊，文采聲鳴喧九州。',240,'全唐诗/poet.song.42000.json','["集仙昔與文忠遊，文采聲鳴喧九州。", "鯤鵬未化忽搨翼，地老天荒雲海幽。", "篋中嘗秘上賜墨，紫金泥印雙脊虯。", "名題廷珪姓氏李，此物未省何年留。", "紋如堅犀刮不動，鏗鏗觸硯蒼烟浮。", "蜀牋灑落黑勝漆，欲論所直真難酬。", "麟兒字法肖家學，珍綈寶匣深藏收。", "并刀截斷輒分我，始信明珠今暗投。", "嗟予吟筆久已閣，辯舌倒卷剛腸柔。", "書陳北闕上印紱，志樂南畝親耡耰。", "得君賜墨竟安用，捧翫反覆增予羞。", "况君綠髮眸子瑩，才業自副朝廷求。", "研磨煤麝染諫草，扶擿世病蒼生瘳。", "名成功遂取上笏，世閥光焰垂千秋。", "莫如老鈍默將死，再拜謝貺長江頭。"]'),
('122eac10-c6c3-4d48-97ac-e4ecb66c210f','謝李公擇惠妙墨二餅','郭祥正','宋','宋诗','song-poetry','','[]','南山來松節，北山割麝臍。',158,'全唐诗/poet.song.42000.json','["南山來松節，北山割麝臍。", "燒烟掃煤和膠漆，篆記歲月形蛟螭。", "集賢學士久珍玩，云初得自扶桑枝。", "張翁所作又精絕，磨刮不動猶堅犀。", "鄴臺古瓦汲水試，黑雲隨手生冰池。", "况君學術老益富，六經秘法窮無遺。", "明窻靜几列毫楮，而與此物真相宜。", "草玄著就垂萬世，忠厚自任陳安危。", "嗟予吏役久零落，至寶暗贈寧非癡。", "嗚呼大禹已往不復見，一尺渾厚疑玄圭。"]'),
('5639889e-6a40-4a4b-9b8d-a7f2cb2c99e4','謝王公濟節推惠硯','郭祥正','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','歙溪之仙洗山骨，一輪琢出秋潭月。',224,'全唐诗/poet.song.42000.json','["歙溪之仙洗山骨，一輪琢出秋潭月。", "摩挲清潤無纖痕，不學寒光有時缺。", "玉川輒莫憂蝦蟆，縱爾觜吻何由齧。", "陰天著手泉脈生，三伏臨之冰炎熱。", "又如明鏡當晴窻，對面森森數毛髮。", "端江品格直頑賤，鄴臺片段多皴裂。", "中山有客先得之，獬豸峨冠爲忠血。", "竄身南過洞庭湖，覆舟幾葬蛟龍穴。", "君今贈我誠謂何，自愧閒官非補闕。", "松烟和漆法廷珪，玉兔長毫妙諸葛。", "敲冰搗楮出烏田，四物收藏豈虚設。", "乾坤俯仰存赤心，誅貶奸諛佑臣節。", "獨刊五傳扶春秋，肯趁時文校工拙。", "更衰更老心更堅，與硯相將不倉卒。"]'),
('3b31083d-6a8a-4f31-9ddf-108c1aab48a1','謝方彦德奉議惠羅文硯','郭祥正','宋','宋诗','song-poetry','','[]','歙溪古源鑿龍尾，一片寒冰瑩無比。',64,'全唐诗/poet.song.42000.json','["歙溪古源鑿龍尾，一片寒冰瑩無比。", "珍綈藏護知幾年，贈我題詩草堂裏。", "驪珠失色悲暗投，再拜置之枯木几。", "硯兮不似在君家，捧來自有纖纖指。"]'),
('0a90d649-cd1f-4802-8cf2-0565e4e364df','中秋泛月至歷陽訪太守孫公素','郭祥正','宋','宋诗','song-poetry','','[]','中秋挐輕舟，西泛采石月。',270,'全唐诗/poet.song.42000.json','["中秋挐輕舟，西泛采石月。", "初疑擢碎冰壺冰，又如飛度雪山雪。", "若非身世出塵寰，底事清光透毫髮。", "袁宏謝尚久磨滅，含情欲就何人說。", "歷陽太守孫公素，竹冒寒霜松屈鐵。", "昔從赤縣守儀真，再上天門請符節。", "紫皇詔長雞籠仙，惠浹春陽威凜冽。", "開倉出粟賙民饑，夜戶不扃無竊發。", "咄哉此事安足論，斯人自養班夔卨。", "且聞兵厨醞濃酒，桂子秋香月中有。", "請君置我三百杯，我爲君吟一千首。", "壚鎚七竅完混沌，能使頽齡遂長久。", "饑横鏌鎁鱠鯨肉，渴引明河傾北斗。", "憑誰爲問陶淵明，胡爲種菊仍栽柳。", "豈如永夜無纖雲，江光月色鋪黄銀。", "喚取三千珠履客，陶然一飲情無垠。", "劉項輸贏亦安在，笑殺今宵月下之醉人。"]'),
('9d37874a-a43e-4ce5-88af-2a59000b26e2','二月十一日倪倅敦復小園留飲','郭祥正','宋','宋诗','song-poetry','','[]','殘梅零落同寒灰，屏翳忍驅斜雨來。',160,'全唐诗/poet.song.42000.json','["殘梅零落同寒灰，屏翳忍驅斜雨來。", "濛濛點滴夜連曉，園館寂寞生青苔。", "墨雲四卷山露碧，日轂照耀天衢開。", "妖桃映竹烟酩酊，細柳拂水風徘徊。", "倪公要我共行賞，小亭草草排樽罍。", "盈筐菊芽青玉軟，滿盤鱭縷紅絲堆。", "興來一笑且爲樂，春光半被鶯啼催。", "百年已往五十八，借問餘生真可咍。", "平原豪客散烟霧，東山舞妓埋蒿萊。", "眼前不肯飲五斗，身後安能傾一杯。"]'),
('a9c6bf0c-44f2-4e9c-b705-611b5faa66ab','和州連雲觀留題呈太守王純父','郭祥正','宋','宋诗','song-poetry','','[]','連雲之觀何寥廓，碧瓦危侵天一角。',176,'全唐诗/poet.song.42000.json','["連雲之觀何寥廓，碧瓦危侵天一角。", "深排柱礎貫九江，返掛簾鉤吞五嶽。", "風檣北去烟溟溟，雁陣南飛秋漠漠。", "白衣每從欄下回，金盆正在簷前落。", "蔡公書榜妙入神，劍戟縱横挫矛槊。", "主君自是蓬萊仙，分符暫與民同樂。", "卷舒當爲天下霖，一釣能令六鼇躍。", "滕王庾亮爾何人，回視規模太卑削。", "我從姑孰飛輕舟，欲陪珠履登斯樓。", "與公酣歌相獻酬，蘭亭俗飲安足求。", "手搖麈尾拂斗牛，爲君千載揚風流。"]'),
('13e01b01-1fa6-4a82-9831-99812f9f0483','謝歷陽王守惠新釀','郭祥正','宋','宋诗','song-poetry','','[]','卓犖英才歷陽守，年來不得音書久。',80,'全唐诗/poet.song.42000.json','["卓犖英才歷陽守，年來不得音書久。", "隔江知我巖戶寒，赤泥封送兵厨酒。", "碧玉壺，黄金斗，雪樹雲峰作賓友。", "爲君一醉歌陽春，空山霹靂龍蛇走。", "只愁君返紫皇家，西望連雲謾搔首。"]'),
('0288a2a1-6cce-47ea-b654-2960e56dc34c','寄歷陽張宗孟隱士','郭祥正','宋','宋诗','song-poetry','','[]','歷陽張君心好古，冰不爲寒蘖非苦。',64,'全唐诗/poet.song.42000.json','["歷陽張君心好古，冰不爲寒蘖非苦。", "我欲見之波浪阻，安得鄰巢接飛羽。", "百年營營竟埋土，進退趦趄亦何補。", "今歲秫田收幾畝，爛醉高吟餘不數。"]'),
('a33e8410-c853-4191-9a4c-e060a2e1e87f','送余秘校','郭祥正','宋','宋诗','song-poetry','','[]','蒼山凍雲猶未消，君騎瘦馬來飄飄。',160,'全唐诗/poet.song.42000.json','["蒼山凍雲猶未消，君騎瘦馬來飄飄。", "入門下馬與我語，琅琅滿室鳴簫韶。", "一官初得遭猛守，十年困辱朱顔凋。", "恨無田園即長往，醉卧白日歌唐堯。", "去干斗粟活妻子，誰念塵滓汙瓊瑤。", "相逢太息不能已，解衣貰酒愁魂消。", "紅梅零落雪霜洗，蒼雁蹭蹬狐狸蹻。", "男兒功名顧有命，太公七十方漁樵。", "否極泰來如覆手，闊步自此凌烟霄。", "側聞丞相開東閣，肯使斯人重折腰。"]'),
('70cdd9f2-c91f-424a-a14b-91e0dc674777','送梅直講','郭祥正','宋','宋诗','song-poetry','','[]','青風吹天雲霧開，仙人騎馬天上來。',174,'全唐诗/poet.song.42000.json','["青風吹天雲霧開，仙人騎馬天上來。", "吟出人間見所不可見，常娥織女爲之生嫌猜。", "織女斷鵲橋，常娥閉月窟，從兹不放仙人迴。", "一落人間五十有四載，唯將文字傾金罍。", "李白佯狂古來少，騎鯨鬣鬣飛沿洄。", "杜甫問訊今何如，應爲怪極罹天災。", "公乎至寶勿盡吐，吐盡吾恐黄河水決崑崙摧。", "天穿地漏補不得，女媧之力何可裁。", "長安酒價不苦貴，風月但惜多塵埃。", "醒來强更飲百盞，酣酣愚智寧論哉。"]'),
('a2db66ce-6b16-4d22-bffe-42e265a81c4e','送袁殿丞','郭祥正','宋','宋诗','song-poetry','','[]','與君六年别，愁見雲開露明月。',224,'全唐诗/poet.song.42000.json','["與君六年别，愁見雲開露明月。", "樽中有酒雖獨傾，萬古情懷共誰說。", "思君彈瑤琴，琴聲爲君咽。", "孤鴻高飛不可攀，北風一送何時還。", "欲問鯉魚更難得，江頭白浪高於山。", "天書彼此絕，令人腸百結。", "昨日聞君來，我心如鑿龍門開。", "拂拭囊中白玉璞，請君辨之爲磨琢。", "感君酬價過南山，即見名聲搖海岳。", "烹羊買酒邀吳姬，今朝會合明朝離。", "莫嗟兩鬢白雪滿，請看舞袖紅雲飛。", "雲飛酒闌君遂起，篙子催行趁潮水。", "君行汲汲過西山，手植松篁春正美。", "我亦歸青山，白雲相伴閑。", "若駕鸞凰赴瑤闕，先到臨川與君别。"]'),
('fb1a89c5-b8c4-4cea-a55b-6129ddede967','送錢賢良','郭祥正','宋','宋诗','song-poetry','','[]','去年六月梓山裏，與子披襟弄泉水。',154,'全唐诗/poet.song.42000.json','["去年六月梓山裏，與子披襟弄泉水。", "高談直出堯舜前，長林爲我清風起。", "金船滿滿傾醇醪，吳娥玉指拈櫻桃。", "君令勸我盡百琖，肝腸但覺翻江濤。", "醉來騎白鹿，大笑還青山。", "倐忽歲月往，思君鬢成斑。", "今朝邂逅蕪江頭，論心握手忘離憂。", "暫時會合復言别，安得彈劍從之游。", "我聞紫微薦君策，男兒事業豈易得。", "金門慎勿閑經過，爲奏天下弊穴如蜂窠。"]'),
('e59aa4b0-817a-4ded-8ad0-0675e909ba53','送章秘書','郭祥正','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','君心抱太古，不肯屈世人。',152,'全唐诗/poet.song.42000.json','["君心抱太古，不肯屈世人。", "匹馬遍朔方，揚帆出天津。", "九疑連天洞庭闊，長歌愁殺蒼梧神。", "更將美酒弔楚屈，離騷繼作疑前身。", "兩姬不灑望夫淚，一笑岳陽樓上春。", "丈夫得意且爲樂，百年變化隨埃塵。", "如何南還過我别，却言北去朝天闕。", "上書力訴元兄冤，洗眼看君成一節。", "勸君事直還收身，速返東南弄白雲。", "功名汲汲竟何益，韓彭取笑武陵人。"]'),
('8fbc7dec-7712-48ff-81e8-12dae9540f8c','送楊主簿','郭祥正','宋','宋诗','song-poetry','','[]','浪花卷雪秋風起，開帆日行三百里。',224,'全唐诗/poet.song.42000.json','["浪花卷雪秋風起，開帆日行三百里。", "問君此去安所之，佐邑南城風俗美。", "夫君才業真雄奇，四十青衫能養卑。", "世無孔子禮樂壞，君獨勇起勤扶持。", "書成未遇聊自哂，暫向南城爲吏隱。", "閒入麻源傾酒巵，仙家好景無忙時。", "瀑綃千丈掛蒼壁，玉華萬柄搖清池。", "嫦娥東來渡銀漢，面面瑩徹皆琉璃。", "謝公秀句發天籟，顔守老筆蟠蛟螭。", "高風凜凜尚可揖，鳥聲不斷哀猿啼。", "嗟予學道苦不早，壯歲形容已枯槁。", "聞說名山心即飛，一生願向山中老。", "愛君逸興何由攀，飄如孤鶴遺塵寰。", "若見麻姑與王遠，寄我一粒黄金丹。"]'),
('7c2340f6-4c00-4bef-830e-a24a34019790','送耿少府','郭祥正','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','白沙岸上相逢時，困倚欄干醉似泥。',192,'全唐诗/poet.song.42000.json','["白沙岸上相逢時，困倚欄干醉似泥。", "忽然聽君誦新作，酒肉頓覺寒風吹。", "今朝邂逅蕪江涘，大軸蒙貺東城詩。", "雷驚電掣露怪變，山崩海瀉能扶持。", "令人壯觀不知己，倦翼欲接青雲飛。", "逸駕固當出塵滓，胡爲一命東南馳。", "洞庭波瀾洗天吼，衡嶽葱蒼掛南斗。", "窮幽歷險詩魂醒，不倦青衫困趨走。", "屈原賈誼杜子美，白骨荒丘今在否。", "款騎瘦馬一弔之，滿眼斜陽入疏柳。", "詩成寄我慎勿遲，側望陽春活殘朽。", "暫時離異何足論，酩酊江樓一樽酒。"]'),
('864b3b94-49be-4909-9cb8-fce74523aefd','送徐長官','郭祥正','宋','宋诗','song-poetry','','[]','徐夫子，能談經。',258,'全唐诗/poet.song.42000.json','["徐夫子，能談經。", "不學俗儒事章句，白首役役勞骸形。", "我嘗洗耳聽其說，寒泉潄玉聲瓏玲。", "十年茅塞一朝拔，四體自豫神安寧。", "交游得君已恨晚，歷陽幾日同醉醒。", "新詩百韻忽贈我，滿紙落落排明星。", "使我目睛眩，又若遭雷霆。", "自愧久滅没，安足煩褒稱。", "李翰林，杜工部，格新句老無今古。", "我驅弱力謾繼之，發詞寄興良辛苦。", "幾欲攀天門，擊天鼓，女媧有志終難補。", "低頭帖耳逐駑駘，倒着青衫走塵土。", "東風吹破江頭春，綠楊紅杏能笑人。", "狂來且盡一壺酒，世無賀老誰相親。", "君今别我又遠適，錦帆千丈迷空碧。", "飄然去意凌崑崙，自古雄豪少知識。", "我亦從今不復言，靜看澄江浸寒璧。"]'),
('1da725c7-296a-4f52-bd7c-f52ff60da5cb','送李節推','郭祥正','宋','宋诗','song-poetry','','[]','昨對桃花與君别，共唱離人眼中血。',64,'全唐诗/poet.song.42000.json','["昨對桃花與君别，共唱離人眼中血。", "今見桃花君復來，似與東風趁時節。", "北去南還何日休，書生道路多窮愁。", "安得巨航滿載酒，一帆風過蓬萊洲。"]'),
('33bbef14-03f4-4f36-940b-099ebf5ca150','送李察推','郭祥正','宋','宋诗','song-poetry','','[]','去年遇君陵陽峰，杜鵑聲亂桃花紅。',192,'全唐诗/poet.song.42000.json','["去年遇君陵陽峰，杜鵑聲亂桃花紅。", "佳人玉指接玉板，勸我一醉三百鍾。", "醉來騎鯨赴瑤闕，不記當時與君别。", "溪上扁舟破雪歸，樓前芳草還春發。", "白頭太守重相過，開樽大笑呼瓊娥。", "向來十客七已去，唯與杜九聞清歌。", "歌聲繞梁離思苦，聽不得終淚如雨。", "回首茫茫天地中，聚散百年能幾許。", "今朝此地重相逢，秋漢無情江月空。", "把酒與君須醉倒，已知後會皆衰翁。", "陵陽樂事那復得，官賤食貧身愈迫。", "擊劍高吟非故鄉，何時共作滄浪客。"]'),
('2d37fde1-2288-4e1a-89a5-2fd806946984','送姚太博','郭祥正','宋','宋诗','song-poetry','','[]','春風動地吹春去，行人不肯江邊住。',234,'全唐诗/poet.song.42000.json','["春風動地吹春去，行人不肯江邊住。", "片帆朝掛暮千里，烟霧蒼茫宿何處。", "夫君少年日，射策明光宫。", "同時得意三百輩，上林曾醉桃花紅。", "十餘年間事超忽，幾在青雲幾白骨。", "君雖未甚榮，亦足有餘樂。", "存心不負聖與賢，何須畫影凌烟閣。", "潯陽城頭北樓壯，邂逅相逢觀暝漲。", "魚龍奔走勢莫分，却憶當年兵火愁殺人。", "至今戰場無綠草，冤魂夜哭寒蟾老。", "臨風瀝酒一弔之，而我浮生何足道。", "聊爲君行歌數聲，青山截斷江流平。", "晴雲相對似能舞，野鳥好語如吹笙。", "却送閑愁付滄海，身雖離異心無改。", "若到蓬萊王母家，爲攀桃樹遙相待。"]'),
('a2c3036f-f6e0-4449-8f12-5f3642d2257c','送陳屯田知明州','郭祥正','宋','宋诗','song-poetry','','[]','屈指宛陵客，八九名世賢。',232,'全唐诗/poet.song.42000.json','["屈指宛陵客，八九名世賢。", "我亦駕白鹿，往往登俊筵。", "昭亭自作老龍鬭，疊嶂不礙明河躔。", "餘霞散綺入高閣，澄江似練拖晴天。", "黄金買酒不論價，壯心共許青春前。", "丞相初爲部使者，精選邑治君尤先。", "業聞上書後薦達，玉陛引對親承宣。", "付之一節使淮滸，三十二縣刑無冤。", "嗟予末路最流落，哭兒清淚雙眸穿。", "感君不棄半面雅，取之涸轍投深淵。", "稍回生意漸奮發，遽復捨我搖歸船。", "明朝勅拜四明守，四明山水君所憐。", "奈何歲旱天下歉，豈容醉卧滄溟邊。", "我疑帝命養頭角，乘春霹靂驚蟄眠。", "白蘋風靜湖月滿，謾弔賀公懷謫仙。"]'),
('17690086-14ce-42f5-8732-c614aef955a8','送劉繼鄴秀才之岳陽訪木尉','郭祥正','宋','宋诗','song-poetry','','[]','羣鳥栖霜羽毛縮，孤雁冥飛何處宿。',188,'全唐诗/poet.song.42000.json','["羣鳥栖霜羽毛縮，孤雁冥飛何處宿。", "蘆花糝白天無聲，靈妃鼓徹瀟湘曲。", "此時歸夢尋故鄉，誰道行人鬢長綠。", "平生所得惟悲歌，時命未遇君如何。", "滿懷策盡獻不售，鳳凰飄泊無嘉禾。", "困鱗不借一盃水，異時安用西江波。", "岳陽高樓掛星斗，樓中子真聞舊友。", "請舒和氣邀陽春，便釀重湖作濃酒。", "山葉撩亂舞，山鳥縱横啼。", "古人交道貴終始，樂酣醉倒君莫疑。", "否極泰來不可測，豈有壯士長棲遲。", "豈有壯士長棲遲，青雲歧路看横飛。"]'),
('09c2af1f-339b-44fb-82b4-f3f49a45f390','送吳龍圖帥真定','郭祥正','宋','宋诗','song-poetry','','[]','讀書曾不學腐儒，腐脣爛舌腸焦枯。',403,'全唐诗/poet.song.42000.json','["讀書曾不學腐儒，腐脣爛舌腸焦枯。", "又不學一詩一賦輕薄子，屑屑場屋名聲沽。", "西州治邑克肖古令尹，險欲臨水投神巫。", "政成召來御史府，彈駮庸相請賜雷霆誅。", "姦邪縮手不敢更侮祖宗法，又薦處士博士登石渠。", "富財治水各稱任，乃仗斧鉞臨湘湖。", "興學首敎士子弟，作碑後弔屈大夫。", "明年易節帥瀛莫，鐵甲百萬秋防胡。", "公曰承平勿誇武，解藏弓劍寛民租。", "詩筒交迎兩朝使，鐫金刻玉論歡愉。", "深沈不動若山嶽，節制似公誰可俱。", "少年天子聖慮遠，却顧南國成荒墟。", "拜公學士往綏撫，曾未朞月富民大姓爭來居。", "秦淮橋傾滯行邁，頃刻指畫窮精粗。", "斬材疊岸役兵校，一物不向民間須。", "月光激水夜景午，長虹矯矯當通衢。", "回思昔人政事美，盡求形像堂中圖。", "二十二人最豪傑，森森玉樹臨冰壺。", "前題姓名後書贊，文章彷彿窺典謨。", "昨朝除命下金闕，再備將印嚴邊樞。", "南民遮道留不得，老幼挽纜相攜扶。", "願言早入天朝作丞相，調燮水旱蘇寰區。", "功成異日保身退，西江秋風熟鱸魚。", "犛尾黄雀更珍絕，白糯釀美傾醍醐。"]'),
('52f066ba-b457-44f1-b806-923fb6246446','送朱王二秀才歸江西','郭祥正','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','冰霜凍海海水黑，雲霧崩騰大空塞。',80,'全唐诗/poet.song.42000.json','["冰霜凍海海水黑，雲霧崩騰大空塞。", "饑猿哀啼虎噤嘯，高鴻折翅鷹斂翮。", "苦寒大苦吾正愁，二子胡爲千里客。", "自言失意西南歸，十斛明珠已空擲。", "廬山摩天瀑布雄，請把肝腸洗愁寂。"]'),
('64df546e-04e2-45af-be82-80e7bd382083','送沈司理赴闕改官','郭祥正','宋','宋诗','song-poetry','','[]','捕寇治獄皆有聞，才力縱横真出羣。',144,'全唐诗/poet.song.42000.json','["捕寇治獄皆有聞，才力縱横真出羣。", "薦書交上三歲滿，玉陛引對瞻吾君。", "胸中策畫爛星斗，筆寫紙上虬龍奔。", "完創補弊有捷理，此時歧路挐青雲。", "雲霄問誰作霖雨，願洗邊城血中土。", "和氣油然熟禾黍，天下蒸黎免窮苦。", "男兒事業當致主，我獨沈溝亦無語。", "離亭愁懷安可數，春風自在花飛舞。", "船尾插旗轟畫鼓，摻袂青山遮别浦。"]'),
('cf0a5037-2836-43c9-aef0-e7cd2df661ed','送方奉議倅保德','郭祥正','宋','宋诗','song-poetry','','[]','太行積雪三千尺，渾河連天厚冰塞。',96,'全唐诗/poet.song.42000.json','["太行積雪三千尺，渾河連天厚冰塞。", "天台詞人不畏寒，攜家直赴并州北。", "越羅蜀錦置筐箱，狼帽氈裘付妻息。", "邊城雖道無戰塵，塞草從來少春色。", "馬上題詩泣鬼神，何時歸奏平戎策。", "我欲爲書叩相閽，喚取斯人侍君側。"]'),
('e7b608db-dede-4c3e-ae2a-309a96735c4d','送王主簿棄官歸建昌','郭祥正','宋','宋诗','song-poetry','','[]','老着青衫羞望舶，自笑風船禁不得。',64,'全唐诗/poet.song.42000.json','["老着青衫羞望舶，自笑風船禁不得。", "拂衣高詠歸去來，我有麻源三畝宅。", "朝餐太陽茹紫芝，時時更作方平客。", "肯嗟垂槖少黄金，兒孫只用傳清白。"]'),
('0a3d8411-dae3-4803-abf2-25054754daa9','送陳大夫罷太平守還臺','郭祥正','宋','宋诗','song-poetry','','[]','去年秋暮送東玉，今歲春殘送子儀。',240,'全唐诗/poet.song.42000.json','["去年秋暮送東玉，今歲春殘送子儀。", "人生不老安可得，况復年年傷别離。", "請說湓江初識面，已知磊落胸中奇。", "桐鄉之會愈相樂，是時解印予言歸。", "公乘扁舟過溪口，殷勤訪我論新詩。", "君章下車始命客，邀公與我同遨嬉。", "開懷醉倒信莫逆，十年一夢音塵稀。", "忽聞公來守吾土，餘生幸獲仁賢依。", "政成無擾威惠浹，白駒馳隙臨瓜期。", "梨花奪月爛銀白，繪盤縷玉江魚肥。", "酒傾碧盞盞嘗滿，曲度晴雲雲不飛。", "車輪未許生四角，且願逆風東北吹。", "留連更盡一壺酒，無使醒淚沾行衣。", "十科應詔公第一，出入省寺非公誰。", "欲陪後會定何許，咄嗟自此分雲泥。"]'),
('117e2eec-030c-412c-b66f-7dfe5b1648ad','峨嵋亭即席再送','郭祥正','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江奔來一山裂，兩岸崔嵬聳雙闕。',160,'全唐诗/poet.song.42000.json','["長江奔來一山裂，兩岸崔嵬聳雙闕。", "石人空老薜蘿衣，夜夜孤猿嘯寒月。", "斯亭誰作名峨嵋，顰翠含愁惜離别。", "浮生後會難再得，况復相看頭雪白。", "停盃執手聊逡巡，畫鼓銅鉦莫催客。", "客行西望紫皇家，紫皇真人駕龍車。", "海若驅鯨上金釣，玉女挾春妝寶花。", "千官稱觴祝天壽，簫韶九成奉肴酒。", "青霄闊步隨鵷鸞，肯向江頭戀楊柳。", "楊柳花飛春日遲，登峨嵋兮送君歸。"]'),
('bb98a5b8-484a-4a39-b6c7-be8345558b5e','留别宣城李節推','郭祥正','宋','宋诗','song-poetry','','[]','君作宣城幕下吏，我嘗築室青山址。',163,'全唐诗/poet.song.42000.json','["君作宣城幕下吏，我嘗築室青山址。", "三四相逢五六年，交情淡若秋江水。", "水流到海無窮時，吾輩論交無衰期。", "明主可結亦未晚，謝安四十功非遲。", "低頭感事復太息，汲汲功名亦何益。", "君不見屈原言直沉湘水，韓信功高亦誅死。", "窮達無過七十年，事業空存一張紙。", "不如飲酒臨春風，溪水綠淨山花紅。", "金絲玉管亂兩耳，一醉三百琉璃鍾。", "醉來辭君登海槎，四方上下皆吾家。"]'),
('c286cef4-9844-4648-bc93-713a59fb09db','投别發運張職方','郭祥正','宋','宋诗','song-poetry','','[]','蕭蕭乾葉欲辭柯，曉來更奈嚴霜何。',260,'全唐诗/poet.song.42000.json','["蕭蕭乾葉欲辭柯，曉來更奈嚴霜何。", "明知飄泊不得已，請君試聽離人歌。", "生平學盡經濟策，宗工大匠親琢磨。", "三入長安獻不售，困鱗悵望西江波。", "感君聊借一盃水，六月炎蒸免枯死。", "高談雄辯爲我傾，古恨今憂對君洗。", "賣薪給家妻子羞，淮陰胯下未封侯。", "故人騎龍不相助，子陵自欲追巢由。", "拔山力盡真可傷，江湖安得重相忘。", "恩仇必報乃壯士，如今孰是韓張良。", "玉手纖纖把金盞，更聽新聲碎瑤板。", "醉鄉酩酊萬事休，功名難成歲華晚。", "噫吁嚱，秋風已老白雲飛，鄉關咫尺未能歸。", "倚瑟而歌悲帝子，南山遙望淚沾衣。", "願君聞此頗矜惻，許借長帆還澤國。", "他日堯階薦姓名，投老猶能奉鞭策。"]'),
('fd35b0a3-8acc-485f-89ce-1457b4224bcb','酬吳著作','郭祥正','宋','宋诗','song-poetry','','[]','醉乘黄犢窮山河，倐然遂向桃源過。',144,'全唐诗/poet.song.42000.json','["醉乘黄犢窮山河，倐然遂向桃源過。", "桃源盡處見城郭，萬家訢訢聞弦歌。", "主人喜掃溪上榻，愛我鬢髮塵埃多。", "旋呼瓊液注玉斝，麟孫出拜能吟哦。", "使令勸我須醉倒，不知與世爲誰何。", "醒來忽别未十日，敢期佳句傳靈波。", "千年不落一字俗，凜凜秋風吹太阿。", "大才小用小有補，牛羊茁壯餘無他。", "何時赴詔玉京去，萬物待子能調和。"]'),
('82abc629-bded-4864-b417-2422cedfe643','康王洞呈同遊訥禪師','郭祥正','宋','宋诗','song-poetry','','[]','康王洞口無塵埃，青山嶄巖水邅迴。',192,'全唐诗/poet.song.42000.json','["康王洞口無塵埃，青山嶄巖水邅迴。", "飛橋百尺渡天險，下聽谷響如奔雷。", "凭欄要識物外物，泬寥寥兮何有哉。", "但見東阜聳樓閣，碧瓦鱗鱗何崔嵬。", "虹電披猖雨新歇，金雲點綴芙蓉開。", "斜陽疏光照不入，異景萬變誰能裁。", "仙家遺象已可愛，是時况與禪宗來。", "瞳人照耀骨森竦，皎如皓月凌寒梅。", "險句卷起谷簾水，真珠萬斛收蒼崖。", "猿不能啼鳥無語，巨石枯木爲之摧。", "達即善用用即妙，斯遊何異登蓬萊。", "回頭碌碌利名士，日蠧日朽令人哀。"]'),
('77b5bd51-d785-41a8-a33b-b9b1269a62df','酬李推官淮上見寄','郭祥正','宋','宋诗','song-poetry','','[]','霜寒水落平沙露，短艇悠悠尋泊處。',64,'全唐诗/poet.song.42000.json','["霜寒水落平沙露，短艇悠悠尋泊處。", "驚弦旅雁失羣飛，貪餌修鱗隨網去。", "世情翻覆可沾巾，三千食客背田文。", "不須更待年華老，便向東山卧白雲。"]'),
('298fbd46-6db2-4fb2-9fd7-85eaae8df495','南雄除夜讀老杜集至歲云暮矣多北風之句感時撫事命題爲篇','郭祥正','宋','宋诗','song-poetry','','[]','歲云暮矣多北風，怒嗥萬里吹驚鴻。',164,'全唐诗/poet.song.42000.json','["歲云暮矣多北風，怒嗥萬里吹驚鴻。", "只今我亦在行旅，陟彼庾嶺臨蒼穹。", "霜寒不復瘴霧黑，酒賤頗得樽罍紅。", "鼓角看看變新律，燭淚璀璀隨殘冬。", "一階寄祿百無補，白髮又送年華終。", "鬼章雖獲萬國賀，防邊未可旌旗空。", "中原將帥誰第一，願如衛霍皆成功。", "廟堂赫赫用耆舊，熟講仁義安羌戎。", "我甘海隅食蚌蛤，飽視兩邑調租庸。", "嗚呼不獨夔子之國杜陵翁，牙齒半落左耳聾。"]'),
('d7d18d02-5a4b-471a-af70-884686d6992f','廣州越王臺呈蔣帥待制','郭祥正','宋','宋诗','song-poetry','','[]','番禺城北越王臺，登臨下瞰何壯哉。',320,'全唐诗/poet.song.42000.json','["番禺城北越王臺，登臨下瞰何壯哉。", "三城連環鐵爲瓮，睥睨百世無傾摧。", "蕃坊翠塔卓椽筆，欲蘸河漢濡烟煤。", "滄溟忽見颶風作，雪山崩倒隨驚雷。", "有時一碧渟萬里，洗濯日月光明開。", "屯門鉦鐃雜大鼓，舶船接尾天南回。", "斛量珠璣若市米，擔束犀象如肩柴。", "越王胡爲易馴服，陸生辯與秦儀偕。", "當時貢物競何有，漢家宮殿今蒿萊。", "邦人每逢二月二，熙熙載酒傾城來。", "元戎廣宴命賓客，即時海若收風霾。", "羣心愈喜召和氣，百伎盡入呈優俳。", "樂聲珊珊送妙舞，春色盎盎浮樽罍。", "鬼奴金盤獻羊卨，薔薇缾水傾諸懷。", "嗟余老鈍已茅塞，坐視珠履慚追陪。", "青蠅何知附驥尾，伯樂底事矜駑駘。", "番禺雖盛公豈愛，亭亭自是巖廊材。", "千年故事寫長句，指畫造化回枯荄。", "昌黎氣焰遂低縮，瓦礫未足當瓊瑰。", "仙姿勸公莫妄想，元鼎久待調鹽梅。"]'),
('cedd196b-8e57-4998-8ea7-7e25a356f522','蒲澗奉呈蔣帥待制','郭祥正','宋','宋诗','song-poetry','','[]','菖蒲澗底生九節，流水遂作菖蒲香。',288,'全唐诗/poet.song.42000.json','["菖蒲澗底生九節，流水遂作菖蒲香。", "安期服之已仙去，漫脱雙舄留秦皇。", "秦皇殺伐自無度，年齡社稷何由長。", "蓬萊畢竟不可見，十祠千載聊相望。", "散髮追之又無跡，後來詭譎傳崔郎。", "至今正月二十五，城北夾道珠簾張。", "元戎要賓鎚大鼓，老蠻獻饌燒肥羊。", "傾城盡作蒲澗飲，美俗眷戀神仙鄉。", "穿雲絲竹度别浦，遶山金翠明殘陽。", "我乘款段到已晚，越臺僅得參壺觴。", "公攜大句使我讀，冰澌戛齒清琅琅。", "張侯繼作亦精敏，蘭茝相倚傳芬芳。", "却尋陳事考僭跡，死佗稱帝鋹稱王。", "基山控海恃遠嶮，大明一出旋消亡。", "豈如戴主効臣節，白骨雖朽忠名彰。", "只今神孫太母聖，天下擊壤歌時康。", "佳期不邀墓中鬼，樂民之樂真循良。", "勒詞蒼崖告萬古，蒲澗之會無淫荒。"]'),
('7224862d-85ad-465f-8ba9-922d1ffd1c61','石屏臺致酒呈蔣帥待制','郭祥正','宋','宋诗','song-poetry','','[]','石屏臺下玉池水，遶岸石屏青齒齒。',192,'全唐诗/poet.song.42000.json','["石屏臺下玉池水，遶岸石屏青齒齒。", "鐫劖初自人力成，一石十牛車不起。", "輦置應須費萬金，園囿森羅供宴喜。", "蒼蘚昏埋歲月遠，修藤纒絡根相倚。", "劉鋹族氏已無餘，此物猶存舊基址。", "曾經戰鼓轟雷霆，屢對春風閲羅綺。", "老榕交陰不透日，客袂生寒冰雪洗。", "小橋斷處棧梯連，一綫崎嶇劣容跬。", "未知深窟藏龍蛇，但見枯荷閣螻蟻。", "摩挲題字考前人，名姓班班少奇偉。", "請公椽筆賦大篇，歌頌永平誅僭擬。", "光焰須令萬丈長，一時行樂何足紀。"]'),
('fe2f602d-7197-49b6-8cfa-6bc9bbbd8cbd','朝漢臺寄呈蔣帥待制','郭祥正','宋','宋诗','song-poetry','','[]','鹿入望夷秦欲滅，真劍先流白蛇血。',192,'全唐诗/poet.song.42000.json','["鹿入望夷秦欲滅，真劍先流白蛇血。", "尉佗椎髻爾何爲，漫占海隅蛟蜃穴。", "祝融之符天下歸，豈假陸生三寸舌。", "千金裝槖未爲多，更上高臺拜堯闕。", "至今人說朝漢臺，不知此地藏蒿萊。", "使君好事一登賞，譬若古鏡初磨開。", "香爐烟生石門曉，三山翠擁浮丘來。", "風松自作笙簫響，暮霞却捲旌旗回。", "長空無礙鳥無跡，人事寧須問今昔。", "瓊漿且泛琉璃船，滿眼夕陽留不得。", "登臺何似登金門，爛吐文章侍君側。", "願公歸作老姚崇，莫學江東窮李白。"]'),
('674d6728-e024-405f-9152-b4c3d4a2882d','白玉笙','郭祥正','宋','宋诗','song-poetry','','[]','白玉笙，咸通十三年琢成。',152,'全唐诗/poet.song.42000.json','["白玉笙，咸通十三年琢成。", "琢成匠人十指秃，進奉明堂聲妙曲。", "當時應賜恩澤家，流傳至煜煜好奢。", "高堂日日聽吹笙，不知國內非和平。", "仁兵萬衆一旦至，國破蒼黄笙墮地。", "雖然訛缺未苦多，却落人間爲寶器。", "管長纖纖剥筍束，况值吳姬指如玉。", "不見排星換掩時，自然天韻來相續。", "昔時禍亂曲，今日太平歌。", "興亡不繫白玉笙，但看君王政若何。"]'),
('48f7c6cb-ba16-483b-9e5b-8f3ed2d22e8c','金熨斗','郭祥正','宋','宋诗','song-poetry','','[]','金熨斗，酌醇酒。',40,'全唐诗/poet.song.42000.json','["金熨斗，酌醇酒。", "熨開萬斛之愁腸，贈爾千年之眉壽。", "酣酣笑臉坐生春，安用逢人嗟白首。"]'),
('28c4fab2-7b38-48d7-af20-c65feddacec5','翠碧盃','郭祥正','宋','宋诗','song-poetry','','[]','翠碧盃，滿酌正是桃花開。',44,'全唐诗/poet.song.42000.json','["翠碧盃，滿酌正是桃花開。", "一年三百六十日，幾人待得春歸來。", "春歸來，不飲酒，翠碧之盃爾何有。"]'),
('9883a3c3-24e7-4e97-a7c2-bae113128053','魏王臺','郭祥正','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','金城東，百尺高臺臨遠空。',92,'全唐诗/poet.song.42000.json','["金城東，百尺高臺臨遠空。", "長江浩蕩劍門險，欲平吳蜀難爲功。", "誰傾黄金建佛廟，擊鼓撞鐘夜還曉。", "香厨供辦老僧閒，玉欄花謝游人少。", "我來獨立想英雄，戰艦連雲氣概中。", "猶有斯臺存舊址，可憐銅雀起悲風。"]'),
('e6ac0c3b-9eaa-499b-83ec-3e227a237dea','藏舟浦','郭祥正','宋','宋诗','song-poetry','','[]','金城北，荒荒野水連雲白。',92,'全唐诗/poet.song.42000.json','["金城北，荒荒野水連雲白。", "島嶼相望一徑通，遶堤楊柳迷春色。", "天下三分血戰秋，張遼鑿浦暗藏舟。", "吳蜀雖亡晉已起，山川自結寒烟愁。", "永平只作尋春處，關門鏁斷春歸路。", "畫船載酒歌白紵，不忍醒時送春去。"]'),
('c957ee8b-e122-4fbf-a2c2-a54978c865a2','悲陽春','郭祥正','宋','宋诗','song-poetry','','[]','悲陽春，陽春可樂胡爲悲。',132,'全唐诗/poet.song.42000.json','["悲陽春，陽春可樂胡爲悲。", "桃花枝上開未足，數片已逐狂風吹。", "陽春能來不能久，年少看花今白首。", "擊毬馳馬力已疲，欲傍樽罍先怕酒。", "佳人如皓月，顧我猶衰蓬。", "相倚不相似，兩心何可同。", "請折並蔕花，更看鴛鴦鳥。", "容華與毛羽，相鮮乃爲好。", "揮手謝佳人，浩歌悲陽春。", "陽春易衰歇，爾貌豈長新。"]'),
('1ae51404-0396-4008-b840-46ae067447d6','江上游','郭祥正','宋','宋诗','song-poetry','','[]','我乘逸興浮扁舟，楊花渡江飛滿頭。',96,'全唐诗/poet.song.42000.json','["我乘逸興浮扁舟，楊花渡江飛滿頭。", "河豚初熟鱭魚爛，借問春光須少留。", "人間乍聽黄金鳥，物外誰憐白雪鷗。", "但願滄波化爲酒，青山兩岸皆糟丘。", "人生快意天地小，登覽何必須瀛洲。", "漁歌聲斷自起舞，酩酊更看江月流。"]'),
('22850c8a-7fe8-49dd-98ea-27d29c0fc938','望夫石','郭祥正','宋','宋诗','song-poetry','','[]','杜鵑啼血春林碧，妾有離愁異今昔。',96,'全唐诗/poet.song.42000.json','["杜鵑啼血春林碧，妾有離愁異今昔。", "上盡高山第一峰，目亂魂飛化爲石。", "化爲石，可奈何，淚懸白露衣薜蘿。", "千古萬古望夫恨，一江秋水寒蟾多。", "漢家天子點征役，良人荷戈歸不得。", "此身未老將何從，不似山頭化爲石。"]'),
('c042acb0-31f4-4df7-9f3b-bbf77e4778cb','兩山間','郭祥正','宋','宋诗','song-poetry','','[]','江南南山連北山，蒼藤翠水水潺潺。',64,'全唐诗/poet.song.42000.json','["江南南山連北山，蒼藤翠水水潺潺。", "水深藤老木拱矣，不知遊子何時還。", "白雲孤飛歲華晚，獨鶴一聲星斗殘。", "兩山秀色手可攬，嗟我不得山中閒。"]'),
('e8f171c6-10e7-4c6b-8397-b17af3aad623','蓮根有長絲','郭祥正','宋','宋诗','song-poetry','','[]','蓮根有長絲，不供貧女機。',56,'全唐诗/poet.song.42000.json','["蓮根有長絲，不供貧女機。", "柳梢有飛綿，不暖寒者衣。", "朝歌悠悠暮歌短，下地沉沉上天遠。", "東生白日還西流，志士長懷萬古愁。"]'),
('508071c6-7c48-40db-b3f8-5ad57e0a1427','朝出青閨裏','郭祥正','宋','宋诗','song-poetry','','[]','朝出青閨裏，自汲井華水。',84,'全唐诗/poet.song.42000.json','["朝出青閨裏，自汲井華水。", "井水如磨銅，妾面似芙蓉。", "照影返自歎，淨洗鉛華濃。", "郎騎白馬玉關去，令人繡被冷春風。", "春風欲盡來何遲，蠶蛾散子鴉哺兒。", "寫得短書無寄處，幽恨填膺淚如雨。"]'),
('6c22ea6f-5f8c-42af-aa35-93d1c2bc9baf','墨染絲','郭祥正','宋','宋诗','song-poetry','','[]','繰絲自喜如霜白，輸入官家吏嫌黑。',64,'全唐诗/poet.song.42000.json','["繰絲自喜如霜白，輸入官家吏嫌黑。", "手持退印競傳呼，倐見長條染深墨。", "墨絲歸織家人衣，别買輸官吏嗔遲。", "寄言夷狄與三軍，汝得豐衣民苦辛。"]'),
('31463cf5-16a0-4868-939e-35649fec6344','苦雨行','郭祥正','宋','宋诗','song-poetry','','[]','陰風黑塞雲漫漫，虚空晝夜騰波瀾。',96,'全唐诗/poet.song.42000.json','["陰風黑塞雲漫漫，虚空晝夜騰波瀾。", "羣龍淫怒煩神官，銀河源源來未乾。", "日月暗行天豈安，地下萬物泥潦沈。", "角鷹快鵠摧羽翰，小魚爲鳳蛙爲鸞。", "君子有憂心盤盤，欲上問天造化端。", "蒼天無路不可干，哀歌空屋聲何酸。"]'),
('9bca6106-0c9e-4d5f-ae01-96a5ab3ec6ae','曉晴歌','郭祥正','宋','宋诗','song-poetry','','[]','霜風刮刮侵人膚，宿雲卷卷歸江湖。',90,'全唐诗/poet.song.42000.json','["霜風刮刮侵人膚，宿雲卷卷歸江湖。", "天開碧幕萬里鋪，飛出東來三足烏。", "羽毛渾丹光焰敷，地下萬物凍以舒。", "我今踴躍行樵蘇，白粳可糴酒可沽。", "烏爲母，吾爲雛，致我之暖，令我之餔，嗟不能報烏區區。"]'),
('15ece25d-2906-4c4f-b507-93c88cf75854','麟州歎','郭祥正','宋','宋诗','song-poetry','','[]','邊兵不覺西人至，麟州倉卒城門閉。',64,'全唐诗/poet.song.42000.json','["邊兵不覺西人至，麟州倉卒城門閉。", "城中带甲僅防城，城外生靈任凋斃。", "元戎底事不防秋，千里郊原戰血流。", "謾說知兵范僕射，未免君王西顧憂。"]'),
('eb0ff024-307f-4915-bb38-e7c80fba40db','雲月歌  其一','郭祥正','宋','宋诗','song-poetry','','[]','白雲微散月華生，月下白雲和月明。',64,'全唐诗/poet.song.42000.json','["白雲微散月華生，月下白雲和月明。", "白雲猶解背人去，明月只知隨我行。", "我行不停月未落，心期白雲出寥廓。", "披雲揖月邀嫦娥，願攜素手濯銀河。"]'),
('305b78c0-e2f2-41d6-a41d-c66b76180b23','雲月歌  其二','郭祥正','宋','宋诗','song-poetry','','[]','月下聽吟雲月歌，歌聲寥亮舞婆娑。',64,'全唐诗/poet.song.42000.json','["月下聽吟雲月歌，歌聲寥亮舞婆娑。", "勸君一酌千萬壽，今宵雲月情偏多。", "不知雲月誰爲主，愁看月落雲飛去。", "願如明月有圓時，不學白雲無定處。"]'),
('8caf0416-a50f-47bc-a202-13764b2195ab','勸酒二首呈袁世弼  其一','郭祥正','宋','宋诗','song-poetry','','[]','湛湛酒杯綠，酣酣炭爐紅。',96,'全唐诗/poet.song.42000.json','["湛湛酒杯綠，酣酣炭爐紅。", "佳人放玉板，拂鏡照芙蓉。", "四海無波瀾，吾曹方宴閒。", "大笑凌白日，高吟動南山。", "百歲能幾何，會少别離多。", "少年嗟賈誼，壯士憶廉頗。", "不如醉魂魄，冠巾任傾側。", "冥然逍遙鄉，杳與塵寰隔。"]'),
('979b8089-fdce-45ea-9aeb-92481d8746b6','勸酒二首呈袁世弼  其二','郭祥正','宋','宋诗','song-poetry','','[]','陰雲蔽白日，長風卷驚濤。',76,'全唐诗/poet.song.42000.json','["陰雲蔽白日，長風卷驚濤。", "江上崢嶸百怪嗥，挽君船纜勸君住。", "且飲百琖之醇醪，吳姬笑臉如櫻桃。", "鯉魚紅絲落霜刀，醉來不識天爲高。", "共君攀天跨鯨鼇，下視萬物皆勞勞。"]'),
('78206b68-1cfc-4217-afd7-c38600eade61','牡丹吟','郭祥正','宋','宋诗','song-poetry','','[]','三月金張啟仙館，百種名花此尤罕。',64,'全唐诗/poet.song.42000.json','["三月金張啟仙館，百種名花此尤罕。", "昭君曉怯胡地寒，太真晝卧華清暖。", "夢爲莊叟蝴蝶狂，散作襄王雲雨短。", "莫笑空山芝與蘭，冷豔不隨金剪斷。"]'),
('44efedee-7d0c-439c-a46c-788b6b187adc','左真觀','郭祥正','宋','宋诗','song-poetry','','[]','逸士騎魚入滄海，石壇遺跡今猶在。',64,'全唐诗/poet.song.42000.json','["逸士騎魚入滄海，石壇遺跡今猶在。", "桂烟散景夜寥寥，玉露凝華春璀璨。", "重來舊隱經幾年，挈笠攜鋤姓名改。", "主人不識何當留，墨灑梁塵爛星彩。"]'),
('c89fc635-890c-4ec4-919c-53babe8168ed','雜言寄耿天隲','郭祥正','宋','宋诗','song-poetry','','[]','耿夫子，聞懸車。',167,'全唐诗/poet.song.42000.json','["耿夫子，聞懸車。", "齒清髮紺殊未老，璨璨滿腹懷明珠。", "恥隨黄雀啄官粟，矯翼直與冥鴻俱。", "東城之下，言還舊廬。", "田有秫稻，池有嘉魚。", "林有美木，圃有青蔬。", "笑傲樽俎，俯仰琴書。", "與其折腰以羣辱，孰若潔身而自娛。", "予將蹴滔天之高浪，跨横海之長鯨。", "攬午夜之明月，邀逸駕于赤城。", "酌王母之瓊液，獻商皓之玉觥。", "於是揮手景駐，長嘯風生。", "投冠纓于下土，化鱗鬣于北溟也。"]'),
('f9773c83-7a8c-48b9-90ae-fd5c816f725d','琅琊行','郭祥正','宋','宋诗','song-poetry','','[]','琅琊異他山，坡陀晦諸峰。',140,'全唐诗/poet.song.42000.json','["琅琊異他山，坡陀晦諸峰。", "惟有山下水，其源與天通。", "尋源見樓閣，鴛瓦青重重。", "寶鏡遞華燈，空巖散疏鐘。", "薫成香積界，回首非塵籠。", "陽冰俗篆未足數，禹偁八詠元無功。", "我來獨酌惜已晚，醉倒不見歐陽公。", "摩挲蒼崖讀舊記，誰掣玉索纒蛟龍。", "不憂石泐解磨滅，斯文自與元氣同。", "徘徊落日跨馬去，老松爲我搖悲風。"]'),
('c1116042-bf92-4f82-8f4b-61609d31702a','交難','郭祥正','宋','宋诗','song-poetry','','[]','馬蕭蕭，車轣轣，道上行人半相識。',138,'全唐诗/poet.song.42000.json','["馬蕭蕭，車轣轣，道上行人半相識。", "識面雖多心友難，滄海可量人莫測。", "君不見張陳昔日刎頸交，臨陣彎弓返相射。", "又不見坐中耳語程將軍，背罵一錢猶不直。", "噫吁嚱，休休休。", "猿鳥可爲伴，麋鹿可與游。", "春日晴暉暉，春風思悠悠。", "春泉滑涓涓，春林碧柔柔。", "行止任所適，歌嘯忘吾憂。", "逢人輒掩口，語發多爲讎。"]'),
('46a4cf34-f4f6-441e-b08e-52a53622656a','楊白花  其一','郭祥正','宋','宋诗','song-poetry','','[]','池水滿，宫柳長，胡地沙晴日色黄。',48,'全唐诗/poet.song.42000.json','["池水滿，宫柳長，胡地沙晴日色黄。", "自知憔悴容華改，朝來臨鏡懶梳妝。", "却尋攜手舊游處，拾得落花空斷腸。"]'),
('d2e20137-9adf-4ad4-8f82-59e7b217e803','楊白花  其二','郭祥正','宋','宋诗','song-poetry','','[]','秋風起，黄葉飛，宫門深鏁日還西。',48,'全唐诗/poet.song.42000.json','["秋風起，黄葉飛，宫門深鏁日還西。", "背人一去音書斷，塞雁無情亦解歸。", "此恨此愁無處託，暗塵消盡縷金衣。"]'),
('488c5f1a-a076-40d9-842c-2c8d629c79fa','靈芝宫','郭祥正','宋','宋诗','song-poetry','','[]','靈芝宫，乃在滄海之上，白雲之中。',160,'全唐诗/poet.song.42000.json','["靈芝宫，乃在滄海之上，白雲之中。", "樓閣縹緲金間碧，玉花露濕香隨風。", "寒光長瑩别有月，笙簫間作春冲融。", "來時不記夢中路，覺後唯聞長樂鐘。", "神仙誰云與世隔，暫游復返精誠通。", "倐然物化豈真往，舉杯彷彿聲傳空。", "蓬萊異館信非妄，羅池廟食今猶豐。", "仕途機穽了可畏，天地雖廣身不容。", "低催至死寄僧榻，曠達一念超樊籠。", "揮毫不似人間世，想見光焰如長虹。"]'),
('1075cb71-9b3c-4458-be81-9a5f1149c367','圓山謠','郭祥正','宋','宋诗','song-poetry','','[]','廟食圓山忘歲年，自言耽酒未能還。',224,'全唐诗/poet.song.42000.json','["廟食圓山忘歲年，自言耽酒未能還。", "身披羽衣手提藥，時時混跡來人間。", "七言四句又奇絕，固非俗士能追攀。", "蓬萊却在漳水上，鼇頭突起滄波環。", "長蘿秀木鏁春色，石泉自瀉秋聲潺。", "伊予來漳四十日，始造秘殿瞻威顔。", "歸鞍未解疾遽作，寒氣束縛形骸跧。", "夜夢青衣捧玉盤，琉璃十顆傳靈丹。", "欣然投齒咀三四，若飲沆瀣生修翰。", "精神頓覺枕上醒，五鼓未送蟾光殘。", "明朝視事若平昔，僚吏爭賀詢其端。", "真仙垂祐必終始，凡骨豈易當珍丸。", "便思勇決謝塵網，往跨皓鶴參翔鸞。", "吟詩賣藥同至樂，安用包羞拘一官。"]'),
('0d22f7f0-18b0-45b9-8599-7f486bf9c700','芳草渡','郭祥正','宋','宋诗','song-poetry','','[]','落日渡頭芳草碧，傷如之何送行客。',64,'全唐诗/poet.song.42000.json','["落日渡頭芳草碧，傷如之何送行客。", "客行無盡草相隨，塞北江南同一色。", "秋霜野燒年年事，綠芽迸地先春力。", "芳草多情不變常，行人自去無消息。"]'),
('afe57991-7d48-450a-a831-6cd1106d8768','我歸矣','郭祥正','宋','宋诗','song-poetry','','[]','我歸矣，江之南，一蓑一釣桃花潭。',96,'全唐诗/poet.song.42000.json','["我歸矣，江之南，一蓑一釣桃花潭。", "桃花潭水深千丈，金鱗尾尾密如蠶。", "得魚輒笑放魚去，我不貪餌爾何貪。", "移船就月還一飲，天爲方牀月爲枕。", "水紅芙蓉爛雲錦，醉則縱横看花寢。", "看花寢，如之何，向來憂患付烟波。"]'),
('0de7f73d-f7c7-4eda-82e7-87f0584a238f','卧龍山泉上茗酌呈太守陳元輿','郭祥正','宋','宋诗','song-poetry','','[]','君不見，歐陽公，在瑯琊。',255,'全唐诗/poet.song.42000.json','["君不見，歐陽公，在瑯琊。", "釀泉爲酒飲輒醉，自號醉翁樂無涯。", "醉來落筆驅龍蛇，電雹萬里轟雷車。", "濃陰却掃吐朝日，草木妍媚春爭華。", "斯人往矣道將喪，雖遇絕景誰能誇。", "又不見卧龍山下一泓水，源接銀河甘且美。", "惜哉無名人不聞，唯有寒雲弄清泚。", "君攜天上小團月，來就斯泉烹一啜。", "不覺兩腋習習清風生，便欲飛歸紫金闕。", "挽君且住君少留，人生難得名山游。", "汲泉滌硯請君發佳唱，鏗金戛玉搖商秋。", "斯泉便與釀泉比，泉價詩名無表裏。", "自愧學詩三十年，縮手袖間驚血指。", "君如歐陽公，我非蘇與梅。", "但能泉上伴君飲，高詠閣筆無由陪。", "明年茶熟君應去，愁對蒼崖詠佳句。"]'),
('71dfd957-9356-4b63-9905-571f96e80df4','酬運判毛正仲','郭祥正','宋','宋诗','song-poetry','','[]','明公青霄我平地，才不超羣懷厚媿。',96,'全唐诗/poet.song.42000.json','["明公青霄我平地，才不超羣懷厚媿。", "小邦苟祿度殘年，側望車塵掩玼癘。", "海浪翻雲古渡頭，感公爲我須臾留。", "請說相逢在何處，上下梅山成昨游。", "忽得新詩驚老格，飄飄真是金門客。", "蹇驢已困何由攀，一夜微吟添鬢白。"]'),
('9f64e973-2ee5-4eff-be16-0cbbdb43b4b4','奉和運判吳翼道留題石室','郭祥正','宋','宋诗','song-poetry','','[]','雙峽天開控江水，水自䍧牁來萬里。',384,'全唐诗/poet.song.42000.json','["雙峽天開控江水，水自䍧牁來萬里。", "端州正在雙峽間，石室嵩臺壓孤壘。", "誰傾北斗酌明河，化作七山平地起。", "修蘿高張翠羽蓋，錦壁深藏赤鳳髓。", "鳴禽交應杵臼聲，馴鹿見人行復止。", "一洞能容百兩車，三溪却接滄溟底。", "仰瞻圓頂碧玲瓏，傍穿小竇陰迤邐。", "不應融結施鐫鑱，浪磅乳滴何年始。", "森然物象難悉名，古圖脱落猶堪比。", "老龜闖首龍縮角，猛虎磨牙鯨卷尾。", "又如壯士披肺肝，戴主之忠死無已。", "蒼崖題字多唐人，彷彿銀鉤唯二李。", "山祇不放雲霧開，海神屢汲蟾光洗。", "歐陽古録遺此碑，我漬香煤傳以紙。", "寂寥相望三百年，乃有高才繼瑰瑋。", "滁陽吳公富文采，來擁皇華宣使指。", "霜威暫霽持謙尊，許接清游攜酒醴。", "長絲千結盤彫梅，簌簌并刀膾頳鯉。", "尋仙未遇飲正豪，落日嵐烟催返軌。", "明朝大句揮長篇，戛玉鏘金轟兩耳。", "有靈持護歸羊城，論價欲酬誰可擬。", "蔣公毛公並詩伯，筆陣酣戰秋風裏。", "越臺朱明被題遍，鵠奔此洞重新美。", "沈侯湘寺陪俊游，韓子連山書宴喜。"]'),
('0e44b383-11dd-4c3a-b83c-d56b02935489','奉和廣帥蔣穎叔留題石室','郭祥正','宋','宋诗','song-poetry','','[]','西江赴海穿雙峽，十里寒青半天插。',384,'全唐诗/poet.song.42000.json','["西江赴海穿雙峽，十里寒青半天插。", "晴空倒影連明河，滔滔不礙鯨魚呷。", "絞綃高覆紫微冠，翠簟平鋪玉皇榻。", "中藏石室與嵩臺，巨壁稜層老鱗甲。", "欲飛未去鳳逶迤，將蟄還伸龍匼匝。", "浪搖蓬島何其危，桂塞廣寒無乃狹。", "大匠不由基構成，洞門大啟無人扃。", "六月來游乃挾纊，酌酒向口疑冰生。", "三溪詰曲愈難涉，舉燭但愛烟溟溟。", "返似霜縑見山水，畫手只許吳生是。", "有誰文采如昌黎，物物爲我從頭記。", "自慚才短空冥搜，俚語未足蒼崖留。", "元戎聞之索大筆，默坐遠想書勝游。", "憑凌風力若捕虎，窘束景象如縳仇。", "那知子厚號雅健，不識謝守爲風流。", "桓桓斯人富學海，少陵重生謫仙在。", "琮琤擊玉敲黄金，倚馬千言未嘗改。", "高下豈必世俗知，浩氣已充天壤內。", "又如淮陰善將略，不戰能令敵先敗。", "暫辭侍從來東南，羊城異日爲傅巖。", "不唯巴牋吟詠足，即看玉牒功名鑱。", "滁陽吳公昔曾賦，落落文華精注措。", "毛侯亦許送和章，馬上横戈寫長句。", "孰云高要陋且遐，三篇入石神鬼嗟。"]'),
('1347cf08-b9b3-4978-8e50-b5521fbea093','奉和梧守蔡希蘧留題石室','郭祥正','宋','宋诗','song-poetry','','[]','疊石稜層萬尋碧，老仙自作琉璃宅。',176,'全唐诗/poet.song.42000.json','["疊石稜層萬尋碧，老仙自作琉璃宅。", "翛然一徑出人寰，北斗三臺無咫尺。", "大巖杳杳吞滄溟，小竇疏疏吐朝日。", "芙蓉羃瀝乳成花，鱗鬣摧頹龍蜕骨。", "危弦脆管遞仙飇，爛錦輕綃變雲物。", "二李能書玉鈕懸，僭鋹未是真王質。", "人亡國變今幾年，唯有文章記崷崒。", "勝游况遇中郎孫，詩擬杜陵相彷彿。", "洪河噴作三門流，突騎長驅五千匹。", "令人驚嗟但縮手，近世雄豪無此筆。", "不唯險韻難追攀，學道輸君先得一。"]'),
('e858d0d8-b166-4216-ba88-5dd71035b9da','奉和蔡希蘧鵠奔亭留别','郭祥正','宋','宋诗','song-poetry','','[]','欄干去天無一尺，簾外三山蘸天碧。',192,'全唐诗/poet.song.42000.json','["欄干去天無一尺，簾外三山蘸天碧。", "樽傾濁酒延故人，拂拂輕寒添暮色。", "雙鵠飛奔跡已陳，滿庭細草自涵春。", "孤城不復有冤氣，法座垂衣逢聖神。", "惟君萬里分符去，蒼梧之邦舜遊處。", "九疑七澤皆相連，墨海濡毫寫長句。", "又如李白才清新，無數篇章思不羣。", "挺特千松霜後見，孤高一笛隴頭聞。", "我於詩學非無意，黄蘆不並琅玕翠。", "漫甘薄祿養殘年，兩鬢垂絲成底事。", "聲出還吞淚如雨，同氣相求别離苦。", "老來頻寄一行書，江邊魚雁無今古。"]'),
('d83e72de-bce5-4cda-95a7-d9f56b7fcdeb','南安劉太守席上勸曾叔達酒','郭祥正','宋','宋诗','song-poetry','','[]','金盞莫辭瓊液滿，寶檠休嫌燈焰短。',64,'全唐诗/poet.song.42000.json','["金盞莫辭瓊液滿，寶檠休嫌燈焰短。", "圓荷翻雨碧雲香，小妓近人紅玉暖。", "百年流轉能幾時，一日相逢須款款。", "扁舟明發下前灘，此會清吟應亦罕。"]'),
('4dffc8a6-05bc-41a7-97c6-7d19f7cbc712','勸君歸示南康太守吳子正','郭祥正','宋','宋诗','song-poetry','','[]','勸君歸，腰下懸金祿及兒。',84,'全唐诗/poet.song.42000.json','["勸君歸，腰下懸金祿及兒。", "家有良田秫稻肥，種菜結實栗與梨。", "江山滿目烟雲披，長年之樂吾無羈。", "何須七十乃言歸，行將七十能幾時，分符持節力已疲。", "才德及人固無盡，此身抱病欲何爲。"]'),
('9c36db14-b35f-482b-b182-6065b329fc10','櫧溪重九阻風戲呈同行黎東美','郭祥正','宋','宋诗','song-poetry','','[]','不登高，不飲酒，漠漠黄沙翳衰柳。',64,'全唐诗/poet.song.42000.json','["不登高，不飲酒，漠漠黄沙翳衰柳。", "扁舟繫纜未敢行，江頭白浪蛟龍吼。", "故園菊花應爛漫，客路無窮但搔首。", "却憶齊山小杜歌，人世難逢笑開口。"]'),
('65b9a951-9469-47c3-8a94-97b871cdcffa','左蠡亭重九夕同東美翫月勸酒','郭祥正','宋','宋诗','song-poetry','','[]','平生看月無今宵，一亭危在山之椒。',164,'全唐诗/poet.song.42000.json','["平生看月無今宵，一亭危在山之椒。", "下瞰揚瀾連左蠡，白琉璃地覆鮫綃。", "欲披錦袍搥鼓過，世無賀老誰相和。", "屈原憔悴湘水濱，夷齊自守西山餓。", "且來登高望明月，拂拂霜風濯煩熱。", "身心都在清凉宮，一點無塵光皎潔。", "與君同游執君手，况逢令節當重九。", "不憂短髮還吹帽，頭上有巾先漉酒。", "飲醇酒，望明月。", "我歸姑孰溪，君赴黄金闕。", "明年此會知誰健，細看茱茰莫輕别。"]'),
('58ae8aa3-e138-4dc3-92cc-97e43858d100','將遊五峰度夏代别倪倅敦復','郭祥正','宋','宋诗','song-poetry','','[]','六月執熱思雲泉，五峰參差如紺蓮。',80,'全唐诗/poet.song.42000.json','["六月執熱思雲泉，五峰參差如紺蓮。", "修松傑柏上參天，老鶴棲唳哀猿懸。", "嫦娥夜濯清冷淵，巖戶晃白飛羣仙。", "胡不往矣逃塵緣，散髮赤脚臨風前。", "高軒朱衣君自便，去住彼此遙相憐。"]'),
('3e621ed0-424d-425f-8842-16ce3b958675','和守訥上人五峰見寄之作','郭祥正','宋','宋诗','song-poetry','','[]','木杯足躡浮驚湍，却愛五峰如戲鸞。',132,'全唐诗/poet.song.42000.json','["木杯足躡浮驚湍，却愛五峰如戲鸞。", "一錫飛來卓出蒼玉髓，又有黄金百鎰藏蒲團。", "道人得道每如此，倐來忽往非生死。", "叢林成就八百年，香厨日供三千指。", "訥師今亦浮杯徒，問答言詞瀉秋水。", "脱去儒冠披壞衣，一生長在名山裏。", "殷勤笑我騎鯨魚，詩狂酒怪何時已。", "七言哦罷欲無言，坐看峰頭片雲起。"]'),
('f1b260c6-65e3-47e8-87f6-e41c4298cfe3','送上饒道士吳師韓復遊淮西','郭祥正','宋','宋诗','song-poetry','','[]','水精之仙降人間，身披羽衣目澄瀾。',64,'全唐诗/poet.song.42000.json','["水精之仙降人間，身披羽衣目澄瀾。", "或求福禍語必驗，手中開闔陰陽關。", "淮西太守喜賓客，鶴駕却欲乘風還。", "勸君飲酒莫言術，龍虎收藏歸抱一。"]'),
('02eb51dc-e382-434b-ac03-be724d6b2f31','重九日同修顒惠雲二禪師遊浮山訪洪璉長老','郭祥正','宋','宋诗','song-poetry','','[]','邑城東南百餘里，穿盡荒山渡重水。',192,'全唐诗/poet.song.42000.json','["邑城東南百餘里，穿盡荒山渡重水。", "林傾路轉大壑開，峭壁崔嵬半空倚。", "上無勾連下無根，鐫鑱難成畫難比。", "回環巖竇碧玲瓏，月華吞吐湖光洗。", "石鼓晝鳴雲雨垂，金雞夜鬭龍蛇起。", "成公說法已千年，事載龜趺尚新美。", "嗟予平生慕佛學，空洞忘機造玄理。", "暫來福地神愈清，况接高禪揮麈尾。", "晉顒悟道天下師，雲璉聲名自予始。", "精藍際會付三人，凈衆如歸聞法喜。", "今朝更結名山遊，寶閣珠樓同踐履。", "達了無生無不生，一聲猿嘯清風裏。"]'),
('a004ed97-a9ec-4b5e-83af-9fab267b515c','龍眠行留别修顒禪師','郭祥正','宋','宋诗','song-poetry','','[]','桐鄉山水天下名，龍眠氣勢如長城。',288,'全唐诗/poet.song.42000.json','["桐鄉山水天下名，龍眠氣勢如長城。", "重岡複嶺跨三郡，磐壓厚地攢青冥。", "東南佛寺號投子，寺門洞啟原無扃。", "雪峰三來道方契，鑿井百尺穿重冰。", "至今善利永不泯，轆轤夜轉聞寒聲。", "慈濟玄談載金刻，龜趺鱗甲光熒熒。", "誰憂怪變碎以斧，半落崖下莓苔青。", "時移歲晚人事塞，高座竊據非真僧。", "白雲徒侶半凋落，泉石往往荒柴荆。", "我來抉弊眼除眯，顒自壽至人天迎。", "隨車貝葉五千卷，寶藏突兀同時成。", "張翁好施古亦少，助我福地還中興。", "老禪咒龍未三日，泉發石上吁可驚。", "晨厨千僧用無盡，琅玕引溜何泠泠。", "城中客少民事簡，屢攜茗酌來煎烹。", "叩師玄關問至理，心地拂拭菱花明。", "妙峰勝會豈殊此，迷即成凡隨死生。", "明朝官滿重回首，别師寫作龍眠行。"]'),
('774f7f46-fdbe-438f-8c5f-73d7981fde0e','留别金陵府尹黄安中尚書','郭祥正','宋','宋诗','song-poetry','','[]','扁舟載月入金陵，金陵尚書倒屣迎。',64,'全唐诗/poet.song.42000.json','["扁舟載月入金陵，金陵尚書倒屣迎。", "白髮愧彼商山皓，青眼欣逢阮步兵。", "開壺傾酒飲未已，卷紙連書吟不停。", "願如賀監憐太白，莫作曹公嗔禰衡。"]'),
('762a5414-f00a-4241-86bd-e1273e43d080','奉和安中尚書同漕憲登長干塔','郭祥正','宋','宋诗','song-poetry','','[]','攬衣登塔窺泬寥，黄金篆牌神所摽。',352,'全唐诗/poet.song.42000.json','["攬衣登塔窺泬寥，黄金篆牌神所摽。", "層梯轉道二千尺，鈴索交響風常飄。", "天厨曉送阿育供，海月夜領飛仙朝。", "南溟安在心欲化，九萬一舉期今朝。", "我宋真人啟閶闔，堯舜之運重昭昭。", "佛老并儒鼎足盛，理歸一善無煩條。", "凈緣勝賞固莫逆，足力强健朋儕要。", "昌黎首唱城南句，東野繼作芬蘭椒。", "諸公筆力鬭穎發，七言紙上鏗琨瑤。", "聚沙疊甓付童子，秀實始自春之苗。", "凌空得路未足恃，遇險驚魂安可招。", "龍虎低沈鳳鳥散，藉此彈壓無祲妖。", "四郊松柏列兵衛，萬家弦管均咸韶。", "廣莊黔烏類蠛蠓，歲望已覺元鼎調。", "晴川疏樹歷陽近，浮雲蔽日長安遙。", "貫輪巨木徹十地，斜飛八角穿重霄。", "扶持故國肖父老，綜領諸刹如孩髫。", "循欄作禮共悲仰，絕頂進步誰騰超。", "跡雖有爲志頗壯，報且不盡功何遼。", "揮毫題識未云畢，城頭魯角聲迢迢。", "兜綿鋪舒換塵境，寶燈照耀銀爲橋。", "乃知此會世稀有，請君審聽長干謠。"]'),
('661735f0-9fe5-4b8e-8cd8-4c8b9c0d97d9','即席和酬金陵狄倅伯通','郭祥正','宋','宋诗','song-poetry','','[]','虎踞龍盤古名郡，勢欲凌波予未信。',128,'全唐诗/poet.song.42000.json','["虎踞龍盤古名郡，勢欲凌波予未信。", "偶搖雙槳下天門，白鷺三山隨一瞬。", "捨舟登岸青溪濱，濛濛柳眼初含春。", "感君攜酒喚小妾，要我一飲頽冠巾。", "開懷猛酌寧辭醉，明朝且入梁朝寺。", "刀裁赤量非扇迷，興來欲跨横空使。", "南風更送琳瑯篇，明珠十斛投歸船。", "與君定交增浩然，誰謂此行垂槖還。"]'),
('68dd563e-e4af-408e-b50d-d1ba6a4ea0e7','治水謠','郭祥正','宋','宋诗','song-poetry','','[]','去年圩破官不救，闕食逋亡十八九。',192,'全唐诗/poet.song.42000.json','["去年圩破官不救，闕食逋亡十八九。", "今年大水如去年，民困適遭何令賢。", "賢哉何令能治水，槍木編蘆多准擬。", "賞罰公平貧富均，赤脚親臨食亡匕。", "每趨危墊必身先，往復連宵幾百里。", "浪頭作惡工莫施，一拜能令二龍起。", "白龍先去黑龍隨，鱗鬣分明皆見之。", "須臾浪定埂可禦，父老驚嗟咸涕洟。", "西門投巫安足比，亦勝乘輿濟溱洧。", "活我生靈十萬家，惠澤陰功浹神理。", "天子臨軒方用才，時時有詔搜草萊。", "請歌何令能治水，願採斯言獻天子。"]'),
('6948024f-c574-4f36-a92f-e3ad743544a8','遊陵陽謁王左丞代先書寄獻','郭祥正','宋','宋诗','song-poetry','','[]','布衣射策趨蓬萊，十年得志聯三台。',188,'全唐诗/poet.song.42000.json','["布衣射策趨蓬萊，十年得志聯三台。", "懷仁附義天下悦，忠言屢叩宸聰回。", "不唯盡赦息錢息，曾均惠澤覃枯骸。", "先皇晏駕舊臣老，白雲黄鶴空徘徊。", "藩城六見換符節，直道自任寧嫌猜。", "昭亭扶春入畫戟，句溪洗月供吟盃。", "佳賓三千集珠履，赤子十萬登熙臺。", "玄暉比公固不足，我攀太白慚非才。", "披雲拂霧一何晚，泥滑不敢鞭駑駘。", "明朝迤邐造賓榻，願逢浩氣吹寒灰。", "玉上青蠅本無有，都人爭望公歸來。", "公歸來，至尊夢吉天顔開。"]'),
('12ef8ea3-ca1d-4457-bb8e-a7452e60b4b8','謝王左丞惠冰酒十五斗','郭祥正','宋','宋诗','song-poetry','','[]','昨夕發姑孰，今朝泊敬亭。',140,'全唐诗/poet.song.42000.json','["昨夕發姑孰，今朝泊敬亭。", "輕雲淡日天地暖，杏花吐萼梅飄零。", "春光一瞬豈足賞，聽公亹亹高談傾。", "昔年庭爭動丹陛，君臣道合趨昇平。", "巖廊辭位已十載，氣度杳杳涵滄溟。", "公田種秫作新酒，槐槽旋注琉璃瓶。", "不將歌舞效俗飲，時時一酌差獨醒。", "感公贈我十五斗，酒量安得如劉伶。", "願公歸去廟堂上，盡使斯民醉醇釀。"]'),
('55ef9a72-f04d-4d09-b7c7-887dfb9b5025','題横山陶弘景書堂寺','郭祥正','宋','宋诗','song-poetry','','[]','先生燒丹騎竹馬，情戀蕭公碧城下。',64,'全唐诗/poet.song.42000.json','["先生燒丹騎竹馬，情戀蕭公碧城下。", "故物無餘只五泉，亦有松風伴瀟灑。", "誰來洗耳復洗心，寥寥千載聞遺音。", "寺門不掩象燈暗，猿隔數峰時一吟。"]'),
('4c57f955-4e12-491b-9d14-a45ba35cf88e','代先書寄廬郡朱龍圖','郭祥正','宋','宋诗','song-poetry','','[]','楊花塞路春無聲，鳴鳩喚婦留春晴。',192,'全唐诗/poet.song.42000.json','["楊花塞路春無聲，鳴鳩喚婦留春晴。", "揚鞭朝發浚遒縣，卷簾暮宿金斗城。", "城中主人漢賈誼，妙年射策都羣英。", "峨冠獨立御史府，冰霜凜凜清朝廷。", "忽乘白雲渡銀海，十年望闕心常傾。", "只今淮西課異等，沉沉玉帳閑府兵。", "神機照物辨毫髮，提刀四顧新發硎。", "行聞召節返西掖，至尊開閣思談經。", "豈容燕寢自頤養，畫戟森衛清香凝。", "陳公雖解豫章榻，白頭重愧非徐生。", "飄零漁艇荷蓑笠，揣摩舊學荒柴荆。", "願公一吐太和氣，朽株巖下逢春榮。"]'),
('9797dfbe-4a3e-4c33-81b3-bb96b82ae80a','合肥李天貺朝請招鍾離公序中散吳淵卿長官洎予同飲家園懷疏閣','郭祥正','宋','宋诗','song-poetry','','[]','一閣横空連野水，久客歸來洗雙耳。',193,'全唐诗/poet.song.42000.json','["一閣横空連野水，久客歸來洗雙耳。", "二疏雖解散黄金，家園未必臨清泚。", "坐見紛紛烟雨入，千里瀟湘畫圖濕。", "魚鳥相忘蒲荇深，兩岸桃花爲春泣。", "鍾離辭榮已三品，吳令早休今八十。", "我亦棄官姑孰閑，邂逅相過手重執。", "閣前旋解青板船，呼童移櫂選清淵。", "四人白髮笑且飲，岸人疑是商山仙。", "亦如賀監在東吳，醉下山陰弄鏡湖。", "月色蓮香迷近遠，且要李白騎鯨魚。", "古人今人樂如此，出處無瑕傲生死。", "君不見功成不退人，重著藍衫脱金紫。"]'),
('c96c0c80-8fc5-475d-9634-3cf29a7da6d3','麗人曲贈鍾離中散侍姬','郭祥正','宋','宋诗','song-poetry','','[]','髮如盤鴉面如玉，飄飄羅袖長芬馥。',64,'全唐诗/poet.song.42000.json','["髮如盤鴉面如玉，飄飄羅袖長芬馥。", "妙年得侍碧虚鄉，自道一生心已足。", "黄鶯流語春日長，綠窻繡出金鴛鴦。", "朝暮祝卿千萬壽，不識相思能斷腸。"]'),
('f027eb02-d512-47c3-a124-6e791b1bd6af','中書舍人陳公元輿以詩送吾兒鼎赴尉慎邑卒章見及遂次原韻和答','郭祥正','宋','宋诗','song-poetry','','[]','嚼君老句勝牛乳，又如旱稼濛甘雨。',144,'全唐诗/poet.song.42000.json','["嚼君老句勝牛乳，又如旱稼濛甘雨。", "龍眠一别魚雁稀，幾度看雲與雲語。", "鳳池搖筆贊帝齡，珠璣灑落黄金城。", "鼻端去堊鬼膽破，霹靂轟車風雨驚。", "事君以道非難事，不羡昔人囊有智。", "柏梁屹屹漢庭材，寶鼎顒顒周廟器。", "我在江湖寄此身，碧蘆青荇遠黄塵。", "感君問我尚安否，病樹前頭萬木春。", "强汎月船追李白，無人愛客似田文。"]'),
('d77a51ec-a4f6-42d7-99b7-1ce2e604cafa','次韻和元輿待制後浦宴集三首  其一','郭祥正','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','往歲遭風洞庭浦，悔不攜耡從老圃。',96,'全唐诗/poet.song.42000.json','["往歲遭風洞庭浦，悔不攜耡從老圃。", "昨日金城逢故人，萬丈虹蜺思一吐。", "更在芙蓉池上游，桂枝爲檝木蘭舟。", "舞妓相將櫂歌去，疑是西施浣紗處。", "皓腕翩翻雪藕絲，婉若游龍或驚鶩。", "願公對客少留連，早晚沙堤問歸路。"]'),
('54f26ef7-8f44-4682-9f72-e17b5010a3b0','次韻和元輿待制後浦宴集三首  其二','郭祥正','宋','宋诗','song-poetry','','[]','欲飛太白嫌秋暑，約我留連菊花圃。',96,'全唐诗/poet.song.42000.json','["欲飛太白嫌秋暑，約我留連菊花圃。", "擷芳持酒聽君吟，冰絲軋軋吳蠶吐。", "只今且挈茗盃遊，滄浪同泛採蓮舟。", "君當復入玉堂去，爲吾還思採蓮處。", "葉間爭看戲鴛鴦，花底誰曾愛鷗鶩。", "柳州烟島自迷人，員嶠方壺豈無路。"]'),
('1d600b33-1111-43e2-b1ea-f9d9719838cc','次韻和元輿待制後浦宴集三首  其三','郭祥正','宋','宋诗','song-poetry','','[]','誰爲宓妃尋洛浦，且看芙蓉照秋圃。',96,'全唐诗/poet.song.42000.json','["誰爲宓妃尋洛浦，且看芙蓉照秋圃。", "爛漫折隨羅袖歸，芬香忍對西風吐。", "官池不屬野人遊，畫鼓喧喧駕鷁舟。", "賓從欣陪史君去，筵開正在紅雲處。", "獨攜椽筆發清唱，老鶴昂藏映雞鶩。", "敢辭倒載委籃輿，絳臘行行夾城路。"]'),
('fb9980f2-ebcd-4071-baca-7276636b9ff9','醉歌謝太平李倅自明除夜惠酒','郭祥正','宋','宋诗','song-poetry','','[]','一年醉，三百六十日。',167,'全唐诗/poet.song.42000.json','["一年醉，三百六十日。", "今朝年盡酒未盡，自顧形骸無得失。", "浮生七十行六十，猛飲狂歌須汲汲。", "吾邦倅貳李自明，愛我頹然荷蓑笠。", "雙壺滿送瓊瑤漿，春風爭從四支入。", "君不見劉項存亡安在哉，暫時龍虎轟風雷。", "袁盎說行晁錯戮，躡蹝刺客横刀來。", "又云舜野死，堯幽囚，九疑連延雲霧愁。", "不如飲酒醒復醉，抱甕負鍤渠無仇。", "滄海化爲酒，蓬萊作糟丘。", "與君攜手去，赤脚踏鼇頭。"]'),
('34b6c35e-a1aa-4ec8-8773-e0306195a2f0','同蔣穎叔林和中游鬰孤臺','郭祥正','宋','宋诗','song-poetry','','[]','匹馬初從瘴嶺來，登臨喜上鬰孤臺。',176,'全唐诗/poet.song.42000.json','["匹馬初從瘴嶺來，登臨喜上鬰孤臺。", "鬰然而孤插天半，亂山却出晴雲堆。", "雙溪倒流玉綃颭，萬屋蘸碧長城開。", "捫參歷井豈足數，俯欄引手持斗魁。", "月空銀浪試一酌，坐憂桂樹生黄埃。", "妙娥舞袖回白雪，琵琶十面轟春雷。", "吟牋分軸造險語，酒令行賞無停盃。", "哀猿不斷片帆没，歸鳥自送殘陽頽。", "脱身我作耕釣客，兩翁均是巖廊材。", "共游絕境發佳唱，驪珠射目精光皚。", "升沈從此遂分手，願借惠澤蘇蒿萊。"]'),
('682bd291-0cfd-47c6-bc5c-72799d94b226','贈南康劉叔和秀才','郭祥正','宋','宋诗','song-poetry','','[]','俊才落落如君少，養之九年應大妙。',64,'全唐诗/poet.song.42000.json','["俊才落落如君少，養之九年應大妙。", "滿懷騷雅輒見投，圭璧琮璜予所要。", "勸君且學充其科，殿前筆陳揮長戈。", "錦標奪取獻天子，寵祿及親榮耀多。"]'),
('0de1eb97-62bd-4e72-8c26-72df41f75023','姑蘇行送胡唐臣奉議入幕','郭祥正','宋','宋诗','song-poetry','','[]','登姑蘇，望五湖。',184,'全唐诗/poet.song.42000.json','["登姑蘇，望五湖。", "范蠡扁舟竟何在，吳王宫殿惟荒墟。", "民貪吏狡郡多事，煮鹽爲盜無完膚。", "使君誰何好平恕，寛則脂韋猛則虎。", "只今卧治聞黄公，更得高才歸幕府。", "願令里巷歌召南，風化流行成樂土。", "昔年引對大明殿，國論軒軒動人主。", "往持使節臨朔方，威霽秋霜愛春雨。", "玉上青蠅誰强指，鼻端白堊寧傷斧。", "升沈偶爾非吾嗟，不用東方且爲鼠。", "豈聞絕代無佳人，何必西施妙歌舞。", "盛傾綠酒鱠肥鱸，承詔還從大梁去。"]'),
('933af783-df3f-4f89-ab22-187391675cc8','嵩山歸送劉伯壽秘監','郭祥正','宋','宋诗','song-poetry','','[]','松荒菊老嵩山秋，翁將歸兮邈難留。',226,'全唐诗/poet.song.42000.json','["松荒菊老嵩山秋，翁將歸兮邈難留。", "幅巾短袖騎黄牛，翛然自作山中游。", "山中游，誰與伴，兩姬窈窕吹牙管。", "千巖萬壑鸞鳳吟，嫦娥側耳冰輪款。", "五音和暢王道成，不是嵇康廣陵散。", "問公此曲誰爲之，曲曲新翻公自爲。", "古人今人不到處，能與陰陽四序相推移。", "我知公心通造物，豈止人間妙音律。", "天子呼來換舊章，樂成四十有五日。", "奏之明堂奉祖宗，天地清明和氣溢。", "至尊寵賜腰横金，自謂榮華非本心。", "再拜辭魏闕，揚鞭歸故林。", "故林在嵩山，白雲幽徑深。", "濯我衣上塵，重瀉山水音。", "只應王子晉，跨鶴每相尋。"]'),
('0aedb83b-7105-4f28-811a-6003674ee0a5','補到難','郭祥正','宋','宋诗','song-poetry','','[]','到乎難哉，碧落之洞天。',305,'全唐诗/poet.song.42000.json','["到乎難哉，碧落之洞天。", "上有嵐壁之瑤局，下有澄溪之碧瀾。", "碧瀾之下，寸寸秋色。", "目窺之而可量，手搴之而莫得。", "竇容光而練飛，巖漬陰而乳滴。", "如長人，如巨蛇，如翔龍，如鏌鋣，如倒植之蓮，如已剖之瓜，如觸邪之獬豸，如蝕月之蝦蟆。", "或斷而卧，或起而立，或欲鬬而摶，或驚顧而呀。", "若斯石也，吁可怪耶。", "何詭絕之異觀，嘗置之于幽遐。", "到乎難哉，長蘿美秀，瘦木竦直。", "香攖寒而自媚，名概詢而鮮識。", "烟霏霏而引素，雲悠悠而奮翼。", "亟模似其變態，已滅然而無跡。", "崩澌遠響，罄落瑟續。", "聆之愈深，詠之不足。", "欲幽棲而忘返，尚徘徊而眷祿。", "彼寧待乎世人，蓋有要于仙躅。", "到乎難哉，信夫到之難也。", "匪到之難，知樂此以爲難。", "知樂此矣，能久處之又爲難。", "余故補到難以題篇些。"]'),
('0d82c761-221f-4e5c-8f7f-73d1923674ac','巫山送吳延之出宰巫山','郭祥正','宋','宋诗','song-poetry','','[]','送子之邑兮，山之峨峨。',190,'全唐诗/poet.song.42000.json','["送子之邑兮，山之峨峨。", "繄物之可賦兮，曰如之何。", "虚徐怳耀兮，匪車匪馬。", "匪足匪翼兮，奮于巖阿。", "薄萬象兮周四海，爛五采兮揚天波。", "倐然悄然以自歛，妥輕素兮縈翠螺。", "容與兮窈窕，行止兮委蛇。", "吐兮若英，攢兮若葩。", "聚若白蟻，散若楊花。", "爰有靈依兮，遂異于他。", "對之自然，又不可求。", "逐之無跡，愴我離憂。", "上下無窮，變化周流。", "亂曰：綿延夭矯兮竟何補，贊天工兮濡厚土。", "舒則有時兮卷則有所，不爲神女兮而爲君子。"]'),
('ab14e054-bb1a-4e67-8f1b-ae3e6a97c515','山中','郭祥正','宋','宋诗','song-poetry','','[]','風蕭蕭兮雲藹藹，泉淙淙兮石皚皚。',176,'全唐诗/poet.song.42000.json','["風蕭蕭兮雲藹藹，泉淙淙兮石皚皚。", "禽驚人兮，遠飛去以復還。", "客醉其間兮，殊不知爲冠带。", "髮被衣頽以自顧兮，誰爲吾仇。", "山花爲我一笑兮，山草爲我以忘憂。", "嗟世人之愚兮，竟營營以何求。", "求百年之寵榮兮，取萬世之奴囚。", "怵讒舌之甚兮，尚毁孔而謗周。", "咄何得而何失兮，孰爲馬而爲牛。", "歌數作兮飲未休，石駭以走兮泉凝而不流。", "起挽石以道泉兮，爾何我尤。", "吾將去乎世兮，結爾以長年之遊。"]'),
('8c6d978d-9d30-423f-885d-d5fe7b710fb9','招遯','郭祥正','宋','宋诗','song-poetry','','[]','遯兮樂歟，吾能爲子言之。',199,'全唐诗/poet.song.42000.json','["遯兮樂歟，吾能爲子言之。", "山高水長兮，遯歲月而忘歸。", "朝採木兮遯而食，暮葺蓑兮遯而衣。", "雲徜徉兮出岫，奮吾心兮與期。", "日躅躅兮行天，弔吾影兮沉西。", "委吾形兮自信，豈塗險之詰曲兮能屈伸而騖馳。", "遯其樂兮，吾能爲子重言之。", "林之深則鳥獸遯而樂，水之深則魚龍遯而樂，帝者之道備則生民遯而樂。", "遯將獨樂乎哉，吾弗與也。", "于是作招遯之辭，辭曰：來。", "馬肥馭良兮遲子以歸，虎豹齧人兮胡獨爲宜。", "朝有好爵兮廩有好祿，遯勿遯兮于斯之時。"]'),
('d448b102-7dba-44b0-b5d7-cda34be23919','言歸','郭祥正','宋','宋诗','song-poetry','','[]','休歟歸乎，何爲而言哉。',243,'全唐诗/poet.song.42000.json','["休歟歸乎，何爲而言哉。", "予七齡而孤兮，託慈育以苟生。", "捉手以筆兮，口授以經。", "緒先子之素訓兮，夜未央而丁寧。", "既束髮以就學兮，入必問其與游。", "聞道之進兮，曰使我以忘憂。", "課蠶而織兮，紉衣以先汝。", "使弗墜業兮，我勞而汝處。", "慨薄德之眇末兮，今愈壯而不揚。", "吾母耄兮，戀故鄉。", "雖得邑而祿兮，曾寤寐之弗遑。", "與音問之吉兮，孰若朝夕而在傍。", "誰縶予足兮，眷白雲之徜徉。", "還印綬于有司兮，賢守足以往訴。", "將俟代而返兮，念歲月之云暮。", "休歟歸乎，春山崺崺，春水瀰瀰，春蒲濯濯，春魚尾尾。", "吾親在前，吾子在後，飲甘滌潔，以介眉壽。"]'),
('2aca5104-6af4-4648-a38c-a9732975847a','廣言歸','郭祥正','宋','宋诗','song-poetry','','[]','予將歸兮而有言，德眇薄兮言弗見信。',155,'全唐诗/poet.song.42000.json','["予將歸兮而有言，德眇薄兮言弗見信。", "孝乎爲孝兮友于弟晜，奚爲爲政兮予之所存。", "慨日月兮往而不返，吾親八十兮事之云晚。", "朝廷清明兮予忠曷施，道弗行于家兮何以敎吾民之爲哉。", "嗚呼，耕吾土兮足以食，條吾桑兮足以衣。", "予奉親兮孰不可樂，予治身兮尤以爲宜。", "蹇何憂兮何思，恬無悶兮無知。", "休歟歸乎，以退爲進乎，予發諸誠乎，言誰弗信乎。"]'),
('3a56fee6-aef0-4e9e-91dd-1c33769b6081','泛江','郭祥正','宋','宋诗','song-poetry','','[]','士有以處兮，無畝以耕。',309,'全唐诗/poet.song.42000.json','["士有以處兮，無畝以耕。", "眷餘緒之尚抽兮，慨慈親以遲榮。", "徐虚縮瑟以內習兮，予實愧乎先民之心。", "惚怳惻愴其不得已兮，被命于九江之潯。", "戴皇天之休兮，廩足以飽。", "度白日之難兮，誰察予情。", "汹汹兮北風，怒浪兮滔天。", "撫慈膝兮出門，淚漣洏兮就船。", "事將有責兮，死豈予之所畏。", "蓋忠未足以盡報兮，孝未克以自信。", "惟行止之坎坎兮，適簡罪以冀生。", "度白日之難兮，誰察予情。", "蛟囓齒兮岸摧，蜃矯首兮渡分。", "妖鱗怪鬛曾莫識其名兮，怒谺牙以相矚。", "數將傾而還復兮，予委命乎上靈。", "幸生全而就泊兮，夜風止而月吐。", "曠上下之澄澈兮，適縱觀乎琉璃之府。", "北斗揚光兮，百怪潛伏。", "岸芷露翠兮，汀蘭放芬。", "起予思之無窮兮，既跼影以自慰，又苦辭以招魂。", "辭曰：始凶終吉，魂兮歸來，奚往而失。"]'),
('8dd9ef11-2cc8-41f0-975a-37b340e94441','殤愁','郭祥正','宋','宋诗','song-poetry','','[]','氣氛氛兮隘如，魂颺颺兮寧居。',105,'全唐诗/poet.song.42000.json','["氣氛氛兮隘如，魂颺颺兮寧居。", "慧言在耳兮疇能捨諸，異質沈壤兮委夫頑虚。", "鴻雁零飛兮若獨何趨，蘭茞早悴兮天孰與辜。", "雄嗥雌啼兮巢失佳雛，天地黯黯兮風雨呼呼。", "旐翩翩兮導衢，夜冥冥兮永殊。", "樽有醑兮鼎有魚，享弗享兮日月云徂。"]'),
('0efef462-9504-4bf3-a343-5ce6cb36663f','醉翁操','郭祥正','宋','宋诗','song-poetry','','[]','泠泠潺潺，寒泉。',113,'全唐诗/poet.song.42000.json','["泠泠潺潺，寒泉。", "瀉雲間，如彈。", "醉翁洗心逃區寰，自期猿鶴俱閒。", "情未闌，日暮向深源。", "異芳誰與搴，忘還。", "瓊樓玉闕，歸去何年。", "遺風餘思，猶有猿吟鶴怨。", "花落溪邊，蕭然。", "鶯語林中清圜，空山。", "春又殘，客懷文章仙。", "度曲響涓涓，泛商回徵星斗寒。"]'),
('bcfcb745-196e-406c-a519-498f9a93f379','古思歸引','郭祥正','宋','宋诗','song-poetry','','[]','昔人思歸兮，宅林藪之邃深。',205,'全唐诗/poet.song.42000.json','["昔人思歸兮，宅林藪之邃深。", "阻長隄而臨清渠兮，芬翳翳以交陰。", "有觀閣池沼兮，通泉溜而附嶔崟。", "蹇美羽之翔集兮，嘉魚樂而浮沉。", "時則命宴于芳晨兮，連親戚與佳賓。", "執樂而侍兮，列秦趙之艷人。", "管弦奏兮，歌悠揚而絕塵。", "漿蘭桂兮，羞肴珍。", "左琴右書兮，助爲娛而養真。", "又期于不朽兮，志慠然而陵雲。", "孰能婆娑于九列兮，顧牽羈于繁文。", "曲有弦而無辭兮，述予懷以自信。", "歌曰：日轂馳兮老將至，鑠外紛兮中系累。", "歸去來兮予之思，放吾形兮聊逍遙以卒歲。"]'),
('58f370da-c94e-4414-960d-c9df2b02d21e','補易水歌','郭祥正','宋','宋诗','song-poetry','','[]','燕雲悲兮易水愁，壯士行兮專報仇。',100,'全唐诗/poet.song.42000.json','["燕雲悲兮易水愁，壯士行兮專報仇。", "車轔轔兮馬蕭蕭，客送發兮酌蘭椒。", "擊筑兮喑咽，歌變徵兮思以絕。", "易水愁兮燕雲悲，四座傷兮皆素衣。", "歌復羽兮慷慨，髮上指兮淚交揮。", "又前爲歌曰：風蕭蕭兮易水寒，壯士一去兮不復還。"]'),
('38bdbfad-918b-456d-a8f8-3560a60963fb','思嵩送劉推官赴幕府','郭祥正','宋','宋诗','song-poetry','','[]','我思嵩兮，三十六峰之葱蒼。',335,'全唐诗/poet.song.42000.json','["我思嵩兮，三十六峰之葱蒼。", "雲霞卷舒兮，紛五色而爛朝陽。", "渺羣仙之不可見兮，時有鸞鶴雙翺翔。", "窮崖斷壑兮，飛泉吼怒舂琳琅。", "儼修松與美竹兮，碧離離而低昂。", "考周室之卜世兮，顧八表爲中央。", "天乃寵于吾宋兮，六陵相差而永藏。", "惟傳祚之億萬兮，豈八百以爲之長。", "引伊洛之二水兮，聿通汴而注揚。", "回黄流于故道兮，滅湍射而汪洋。", "横星橋于河漢兮，紫闕峙而煒煌。", "列槐植之行秀兮，歷五代而經唐。", "承太平之雨露兮，幸不遭乎伐戕。", "爲衆木之耆艾兮，如羽蓋之迭張。", "慨離彼而適此兮，亦出處之靡常。", "既寓情于物表兮，獨思嵩之未忘。", "忽有客兮鼓檝，言别我兮靈羊。", "將度庾嶺，沿濤江。", "涉淮泝汴，入幕乎洛陽。", "詞氣有餘，頓挫鏗鏘。", "誠南士之穎出，然未始離乎炎荒。", "請陟嵩而遠覽，循今古而徜徉。", "矯垂天之翼，燦瓊瑤之章。", "于是被詔音，登玉堂。"]'),
('03e6e866-0d77-4363-af6a-bd8ada202200','王逢原哀詞','郭祥正','宋','宋诗','song-poetry','','[]','追彷彿兮，故國之高丘。',198,'全唐诗/poet.song.42000.json','["追彷彿兮，故國之高丘。", "與子之相遇兮，聽其言而若秋。", "雍雍而肆兮，嚴嚴而收。", "樂我之心兮，以遨以遊。", "予將娶兮，于南州。", "莫克從子兮，翻自省以幽幽。", "川陸兮沉浮，日月兮再周。", "云子之長逝兮，愴我之深憂。", "子不可見兮，道將誰求。", "彼蒼者天兮，胡慘胡仇。", "奪子之速兮，使不位于公侯。", "雖窮德之特立兮，弗與世以綢繆。", "嗟坎水之未盈兮，竟何澤以休休。", "瘖予之聲兮，血予之眸。", "猶不足以止兮，靈何在而薦羞。", "惟永絕兮奈何，悵平昔兮悠悠。"]'),
('d8defeb7-af10-4412-b08f-068f347ca490','徐孺興哀詞','郭祥正','宋','宋诗','song-poetry','','[]','嗟乎孺興之不幸兮，上有高堂白髪之慈親。',175,'全唐诗/poet.song.42000.json','["嗟乎孺興之不幸兮，上有高堂白髪之慈親。", "孝不克以自信兮，魂將逝而復返。", "目冥冥而莫勝兮，顧天命之予短。", "業修修兮志與道配，寂不少振兮遽沉幽而終蹇。", "蘭未芳兮先凋，月將昇兮俄隕。", "孺人囂囂兮，追話言之弗足。", "夢悠悠兮，魂去來而數蹙。", "撫稚子兮秋夜長，暗明璫兮摧腕玉。", "魂何知兮，興予之哀。", "體與道化兮，歲月徂而屢周。", "情纒綿兮，若俱往則已矣。", "詞不足以盡寄兮，託餘思于江流。"]'),
('b7e17448-b0e6-432c-8432-41e6df676384','留君儀哀詞','郭祥正','宋','宋诗','song-poetry','','[]','懷伊人兮，漳水之湄。',361,'全唐诗/poet.song.42000.json','["懷伊人兮，漳水之湄。", "爰結好之初兮，予方出乎陷穽之羈縻。", "彼知予之横罹兮，眷煢煢而弗支。", "氛侵侵而襲人兮，子獨贈我以蘭芝。", "芳芬芬而爽吾衷兮，雖厄窮而弗疑。", "言涓涓而洗吾耳兮，寂塵聽而凄其。", "炊嘉黍而納吾腹兮，使朝則忘饑。", "采薜荔爲予之服兮，慨前修之可追。", "脂吾車而秣吾駟兮，造仙的之幽奇。", "煮甘溜而茗酌兮，珍盤進乎離支。", "唱則和兮，迭指摘其醇醨。", "同底于道兮，遵聖渚爲之歸。", "聊容與以卒歲兮，曾弗察乎白駒之騖馳。", "泊中吉而啟行兮，觴桂漿以違離。", "惕南北之緬邈兮，蹇形影之頽衰。", "歌激揚而再發兮，淚浪浪以沾衣。", "馬悲鳴而仰顧，僕弛負以增欷。", "行雲住而黯慘，去鳥返而低迷。", "歲聘介而一至兮，孰敢爲之後期。", "幸再往而再復兮，釋予心之思也。", "忽承訃以躑躅兮，行不知其所之也。", "嗟若人之藴美兮，天其奪之速也。", "蹇松柏之枯折兮，惡植則滋以榮也。", "考大空之役物兮，必善摶而化之也。"]'),
('c14eb711-a358-490e-ad60-e5d9d1132548','山中樂','郭祥正','宋','宋诗','song-poetry','','[]','歸乎樂哉，山中之樂兮，其樂無窮。',290,'全唐诗/poet.song.42000.json','["歸乎樂哉，山中之樂兮，其樂無窮。", "藹葱蒼而杳巑叢兮，眷青瑤之諸峰。", "琉璃一碧兮，湖波止而溶溶。", "層樓相望，曲徑相通。", "魚龍轉影于汀瀾之際，鐘梵答響于烟雲之中。", "鳥嚶日暖兮，花氣濛濛。", "搴密葉而成幄兮，風颯颯而吹松。", "巖谷玲瓏，霜木落也。", "玉宇浮空，冰澌凝也。", "天高月朗兮，定省乎華嚴之境。", "雷奔雨驟兮，作新乎水墨之宮。", "達僧擬王孫之葬，逸士躡淵明之蹤。", "方爾祖之得名兮，考其言于廬陵之醉翁。", "曰嗟世之人兮，曷不歸來乎山中。", "山中之樂不可見，今予其往兮誰逢。", "後四十年，爾復好吟。", "遠遊不返，求我之從。", "勸爾之歸兮，栖老乎山中。", "爾之材兮甚良，當自適其無庸之庸。", "違世絕俗，黜明塞聰。", "山中之樂兮乃可以久，非我與爾兮誰同。"]'),
('15c9d0c1-0fe0-48f6-ac5c-c0fe7e182c02','石室游','郭祥正','宋','宋诗','song-poetry','','[]','端城之北，徑五六里。',301,'全唐诗/poet.song.42000.json','["端城之北，徑五六里。", "有石室兮洞開，其上則七山建斗司天之喉舌，其下則淵泉不流渟碧一杯。", "窺之則肌髮冰，酌之則煩心灰。", "四傍則石乳玲瓏，中敞圓蓋。", "窈窈萬丈，莫窮其厓。", "孰納忠兮，嗟肺肝之已露。", "孰止戈兮，束兵仗而相挨。", "儼衛士之行列，肅庭臣之序排。", "紛披披兮蒂萼，粲樅樅兮條枚。", "安而不可動者爲梁爲棟，奔而不可止者爲虎爲豺。", "龜闖首兮屏息，虬奮鱗兮摶雷。", "怪怪奇奇兮，千變萬態。", "愈視愈久兮，惚恍驚猜。", "何人境之俯近而仙宇之秘異如此者哉。", "蘿卷風兮窈窕，春漬芳兮不回。", "或命佳客，或寓幽懷。", "考二李之勁筆，皆一時之遺材。", "援玉琴以寫詠，悵夕陽之易頽。", "方謝事以言返，眷兹室而徘徊。", "雲愀容兮泱漭，鳥送音兮悲哀。", "况百年之將盡，邈夫萬里奚復來。"]'),
('e965401f-3cb0-4f06-a70d-26401d312ad4','逍遙園','郭祥正','宋','宋诗','song-poetry','','[]','逍遙有水一溪，有竹三畝。',246,'全唐诗/poet.song.42000.json','["逍遙有水一溪，有竹三畝。", "蘭芬菊芳，松老石瘦。", "堂居其中，亭列左右。", "菲菲兮春榮，陰陰兮夏茂。", "孤猿嘯兮秋夜長，空桑嗥兮冬雪晝。", "山之名兮人莫知，公爲主兮天所授。", "其或要佳賓，酌醇酎。", "清吟得韻兮，非人世之絲篁。", "屬筆成篇兮，發天機之錦繡。", "方且登高臺，挹遠岫。", "俯仰羣仙，咨詢遐壽。", "脱輪蹄之縈，服烟霞之秀。", "于斯時也，一舉九萬兮，吾不知其爲用。", "嗒焉自喪兮，吾不知其爲偶。", "翛兮窅兮，非無之無。", "寂兮息兮，非有之有。", "無何亦何得而名，有竅則竅遽能久。", "至若聽出于垣，觀入于牖。", "此鄙士之常習，又安得與夫逍遙主人而爲之友也哉。"]'),
('f218d471-51a4-49dd-8fc3-1005e52b4fd7','孤雲寄潘延之先生','郭祥正','宋','宋诗','song-poetry','','[]','望孤雲兮山之巔，漭弗雨兮何油然。',256,'全唐诗/poet.song.42000.json','["望孤雲兮山之巔，漭弗雨兮何油然。", "送孤鴻兮海之涘，高舉翼兮游無邊。", "彼君子之如似兮，脱世俗以不返。", "奚無悶而止兮，又放意以窮年。", "川有航兮陸有馬，園有佳木兮池有芳蓮。", "坐卧兮白日，笑歌兮朱弦。", "客至止兮，樂我之樂。", "豈公侯之下兮，曾弗擇乎愚賢。", "僕夫以耕兮，妾女以織。", "恬弗愧兮，我衣我食。", "神仙之逍遙兮，固不得以見之。", "君子之宴息兮，舉斯世以誰敵。", "嗟世人之自徇兮，莫知其求。", "勢得而傲兮，勢失而囚。", "靡後先之思兮，孰進退之由。", "苟歲月之徙兮，託冠带以包羞。", "惟勇子之從兮，貧未足以自周。", "匪妻子之累兮，實吾親之憂。", "慨負重兮執熱，慕坦跣兮臨流。"]'),
('5af74b0e-684c-4dcc-a0d8-e236bff5b786','采薇山之巔贈張無夢先生','郭祥正','宋','宋诗','song-poetry','','[]','先生曰采薇山之巔兮，吾非求爲之仙。',230,'全唐诗/poet.song.42000.json','["先生曰采薇山之巔兮，吾非求爲之仙。", "吾無一畝之宅，一丘之田。", "饑食山之薇，渴飲山之泉。", "巖爲吾居兮，鹿爲吾馬。", "吾豈不足兮，翺翔乎山之間。", "彼世俗之混混兮，嗟苦短之白日。", "此一身之悠悠兮，聊自樂以窮年。", "彼塵埃之荏苒兮，此雲烟之綿聯。", "誰謂才之大兮，慨匠氏之弗取。", "吾獨幸其弗取兮，森葱蒼而自全。", "粤吾君之爲治兮，三王之聖。", "而吾相之爲輔兮，伊周之賢。", "吾父吾母兮，皆善終以天算。", "進何憂而退何憾兮，養吾氣之浩然。", "弟子進而贊曰：采薇山之巔兮，其樂也如此。", "衣曳曳而情飄飄兮，願執轡而往焉。"]'),
('08958924-6e24-47fe-9fa4-d493e64ecd60','游仙一十九首  其一','郭祥正','宋','宋诗','song-poetry','','[]','漠漠出寒霧，悠悠趨太清。',48,'全唐诗/poet.song.42000.json','["漠漠出寒霧，悠悠趨太清。", "珠樓被重綃，靈花紛素馨。", "青衣捧綠章，磨丹書姓名。", "爲我横玉笛，一奏雌龍聲。"]'),
('29bacd7f-ce4c-4b42-92d4-d691bd051f39','游仙一十九首  其二','郭祥正','宋','宋诗','song-poetry','','[]','非塵復非烟，氳氳散紫清。',48,'全唐诗/poet.song.42000.json','["非塵復非烟，氳氳散紫清。", "乃知泠風御，翛翛恣游行。", "忽逢黄金闕，云是玉帝京。", "逍遙侍御者，不假精鋭兵。"]'),
('9a0de93a-cb2d-4377-967a-e8c594872fa5','游仙一十九首  其三','郭祥正','宋','宋诗','song-poetry','','[]','扶桑并咸池，窅窅殊在下。',48,'全唐诗/poet.song.42000.json','["扶桑并咸池，窅窅殊在下。", "真陽涵素光，無晝亦無夜。", "神體當自保，不與物俱化。", "運齡從此長，塵緣頓消謝。"]'),
('10bf757d-9a75-414c-b1a2-c383b7846c84','游仙一十九首  其四','郭祥正','宋','宋诗','song-poetry','','[]','至道不由學，頽齡安可住。',48,'全唐诗/poet.song.42000.json','["至道不由學，頽齡安可住。", "宿命無纖罹，重玄乃遐悟。", "鮮明女蘿裙，致我火澣布。", "稽首存至誠，欣會如所度。"]'),
('ef36f226-5dd6-4643-aeb3-e4fc50f35e57','游仙一十九首  其五','郭祥正','宋','宋诗','song-poetry','','[]','至音非樂音，玲瓏聞自然。',48,'全唐诗/poet.song.42000.json','["至音非樂音，玲瓏聞自然。", "殊絕洞房景，亦超鬰羅天。", "靈嬪下鶴馭，問我來何緣。", "却驚與世隔，一别三千年。"]'),
('7c0f0bcc-9f82-4005-bfb3-3682ab50d5c9','游仙一十九首  其六','郭祥正','宋','宋诗','song-poetry','','[]','澡心華池液，薰手玉樓香。',48,'全唐诗/poet.song.42000.json','["澡心華池液，薰手玉樓香。", "一披寶神經，衆真共來翔。", "七言詠良遇，至音迭琅琅。", "珍重衛夫人，行草記瑤章。"]'),
('eef558d7-f46f-4aff-84b5-b34dbfbd9220','游仙一十九首  其七','郭祥正','宋','宋诗','song-poetry','','[]','太微無烈風，紫臺多靈露。',48,'全唐诗/poet.song.42000.json','["太微無烈風，紫臺多靈露。", "逍遙三五客，披衣縱高步。", "回首笑復歌，游此今幾度。", "却嗟寰中人，枉爲死所誤。"]'),
('98f02155-a96c-46d9-b681-d93a9fefbe35','游仙一十九首  其八','郭祥正','宋','宋诗','song-poetry','','[]','仙家無四時，瑤草常芬芳。',48,'全唐诗/poet.song.42000.json','["仙家無四時，瑤草常芬芳。", "五嶽倐來爾，玉鞭驅鳳凰。", "得道迭相度，不聞嫉賢良。", "所以心無邪，人人自年長。"]'),
('50e8580f-0111-4893-bbea-4f883967df75','游仙一十九首  其九','郭祥正','宋','宋诗','song-poetry','','[]','妙景素無雜，玉界涵虚明。',48,'全唐诗/poet.song.42000.json','["妙景素無雜，玉界涵虚明。", "妙聲清不淫，洞歌奏金鈴。", "真遇非遐想，忘心乃全生。", "噫哉百年內，得失安足營。"]'),
('c36962e5-b685-4cb5-bd92-3eebc3a2da34','游仙一十九首  其一○','郭祥正','宋','宋诗','song-poetry','','[]','峨峨金精巾，飄飄清霞裙。',48,'全唐诗/poet.song.42000.json','["峨峨金精巾，飄飄清霞裙。", "手持紫毛節，身乘三素雲。", "駕言欲何適，上朝玉宸君。", "隱書謝所賜，洞明道之根。"]'),
('e032fd35-5262-4666-bc6e-47b9fdfd688c','游仙一十九首  其一一','郭祥正','宋','宋诗','song-poetry','','[]','翛然乘一氣，來往游太空。',48,'全唐诗/poet.song.42000.json','["翛然乘一氣，來往游太空。", "閒歌內景章，遂登蕊珠宫。", "華英不知名，激齒甘液濃。", "此樂無憂釁，固非侯與公。"]'),
('5937c817-80f1-4f7a-8872-acf3712fc970','游仙一十九首  其一二','郭祥正','宋','宋诗','song-poetry','','[]','投真落人世，倐經四九年。',48,'全唐诗/poet.song.42000.json','["投真落人世，倐經四九年。", "覩紛未嘗競，內顧淨且淵。", "果逢飛行羽，得披紫微仙。", "攜手浮絳波，絳波春渺然。"]'),
('e05f92f5-b4af-4337-bb5b-11cf2cd9caf8','游仙一十九首  其一三','郭祥正','宋','宋诗','song-poetry','','[]','攀沿日月窟，遂觀天地樞。',48,'全唐诗/poet.song.42000.json','["攀沿日月窟，遂觀天地樞。", "搗金鑄豪英，摶糟醞庸愚。", "校量宿所造，報應無差銖。", "丁寧與世言，安分勿浪圖。"]'),
('adce760a-9276-4af0-b1ef-c79342652f51','游仙一十九首  其一四','郭祥正','宋','宋诗','song-poetry','','[]','在天不擇友，天人皆正一。',48,'全唐诗/poet.song.42000.json','["在天不擇友，天人皆正一。", "雲漢共翺翔，隱耀無固必。", "豈同濁世游，自謂膠投漆。", "毫端利害分，白眼永相失。"]'),
('a3986e25-7552-464e-bc82-89c1e5273f04','游仙一十九首  其一五','郭祥正','宋','宋诗','song-poetry','','[]','款逢九華妃，授我磨鏡石。',48,'全唐诗/poet.song.42000.json','["款逢九華妃，授我磨鏡石。", "一磨日月朗，萬古永不蝕。", "緘之紫錦囊，匪同趙氏璧。", "纔落猛士手，睨柱曾莫惜。"]'),
('8caa69fc-a754-4f61-8f47-9e7bdf784ff3','游仙一十九首  其一六','郭祥正','宋','宋诗','song-poetry','','[]','二景結良匹，曾非塵慮侵。',48,'全唐诗/poet.song.42000.json','["二景結良匹，曾非塵慮侵。", "欣欣啟皓齒，玉珮揚清音。", "碧河并絳實，採濯期追尋。", "言舒意亦散，雙好永齊心。"]'),
('3398caab-bde5-44f1-8372-6623a7b685bb','游仙一十九首  其一七','郭祥正','宋','宋诗','song-poetry','','[]','神凝光自生，洞房玄照映。',48,'全唐诗/poet.song.42000.json','["神凝光自生，洞房玄照映。", "青絲散垂腰，目采流玉鏡。", "共談上清事，精微寄餘詠。", "樂酣會既分，雙駕還霄嶺。"]'),
('ce0dbca6-3b9e-48dc-b097-4e1e7b7aae7f','游仙一十九首  其一八','郭祥正','宋','宋诗','song-poetry','','[]','清僚真可慕，振衣願所歸。',48,'全唐诗/poet.song.42000.json','["清僚真可慕，振衣願所歸。", "既絕世上緣，吾寧抱愁悲。", "雲韶自相諧，虚聽方達微。", "是將跨靈羽，逸麟復攀追。"]'),
('5cbf65ee-92c6-42ad-a25b-6c3ce38b95c9','游仙一十九首  其一九','郭祥正','宋','宋诗','song-poetry','','[]','窺天見天根，步玄入玄門。',48,'全唐诗/poet.song.42000.json','["窺天見天根，步玄入玄門。", "素光流一氣，默默復渾渾。", "揮手散餘景，至心揖靈尊。", "從今乃忘言，大道多子孫。"]'),
('eb0356aa-be36-4b87-b9fc-f326fe20b8e6','春日獨酌十首  其一','郭祥正','宋','宋诗','song-poetry','','[]','桃花不解飲，向我如情親。',48,'全唐诗/poet.song.42000.json','["桃花不解飲，向我如情親。", "迎風更低昂，狂殺對酒人。", "桃無十日花，人無百歲身。", "竟須醒復醉，不負花上春。"]'),
('f961aff5-5830-4d17-87c5-e08e1a4e984d','春日獨酌十首  其二','郭祥正','宋','宋诗','song-poetry','','[]','江草綠未齊，林花飛已亂。',36,'全唐诗/poet.song.42000.json','["江草綠未齊，林花飛已亂。", "霽景殊可樂，陰雲幸飄散。", "且致百斛酒，醉倒落花畔。"]'),
('ac22c9aa-9989-461e-992c-7f29545cb47a','春日獨酌十首  其三','郭祥正','宋','宋诗','song-poetry','','[]','平生最嗜酒，况復就花飲。',36,'全唐诗/poet.song.42000.json','["平生最嗜酒，况復就花飲。", "明月正照人，吳姬安得寢。", "更起盡餘杯，擊碎珊瑚枕。"]'),
('af1b59c0-21e9-4af1-97ea-b6dbd53fd5a1','春日獨酌十首  其四','郭祥正','宋','宋诗','song-poetry','','[]','芳華無十日，自勸頻舉盃。',84,'全唐诗/poet.song.42000.json','["芳華無十日，自勸頻舉盃。", "素髮易凋落，青春難再來。", "林間黄鳥囀，日下浮雲開。", "吳歌梁塵飛，越舞白雪回。", "英雄既長往，珠金安在哉。", "僅存一丘土，石麟卧蒿萊。", "誰曾將濁酒，爲君傾夜臺。"]'),
('ce98947a-8001-4a06-978a-1a0ad6960dae','春日獨酌十首  其五','郭祥正','宋','宋诗','song-poetry','','[]','醉去卧蘭茞，安用張蜀錦。',72,'全唐诗/poet.song.42000.json','["醉去卧蘭茞，安用張蜀錦。", "何必黄金盃，癭杓亦足飲。", "物理不可齊，好惡乃天稟。", "真精既洞達，空無仍諦審。", "所以陶淵明，北窻自欹枕。", "起作無弦彈，此音殊妙甚。"]');
